async fn init_lane(
    json: bool,
    lane: &Path,
    wheelbase_pid: &str,
    operator: &str,
    overwrite: bool,
) -> Result<()> {
    let pid = parse_hex_selector(wheelbase_pid)
        .ok_or_else(|| anyhow!("--wheelbase-pid must be a hex PID, e.g. 0x0014"))?;
    if !matches!(pid, product_ids::R5_V1 | product_ids::R5_V2) {
        return Err(anyhow!(
            "--wheelbase-pid must be 0x0004 or 0x0014 for the Moza R5 lane"
        ));
    }

    let captures_dir = lane.join("captures");
    fs::create_dir_all(&captures_dir)
        .with_context(|| format!("failed to create '{}'", captures_dir.display()))?;

    let manifest_path = lane.join("manifest.json");
    if manifest_path.exists() && !overwrite {
        return Err(anyhow!(
            "{} already exists; pass --overwrite to replace it",
            manifest_path.display()
        ));
    }

    let manifest = moza_lane_manifest_value(pid, operator, "not_started", false, false);
    write_json_file(&manifest_path, &manifest)?;

    let receipt = InitLaneReceipt {
        success: true,
        command: "wheelctl moza init-lane",
        generated_at_utc: now_utc(),
        no_hid_device_opened: true,
        no_ffb_writes: true,
        no_serial_config_commands: true,
        no_firmware_or_dfu_commands: true,
        lane: lane.display().to_string(),
        manifest: manifest_path.display().to_string(),
        captures_dir: captures_dir.display().to_string(),
        wheelbase_pid: hex_u16(pid),
        operator: operator.to_string(),
        completion_state: "not_started",
        notes: vec![
            "init-lane creates only local filesystem artifacts; it opens no HID device".to_string(),
            "the generated manifest is pre-validation and makes no hardware or simulator claim"
                .to_string(),
        ],
    };

    print_init_lane_receipt(json, &receipt)
}

async fn probe(json: bool, json_out: Option<&Path>) -> Result<()> {
    let api = HidApi::new().context("failed to initialize HID API")?;
    let devices = enumerate_moza_devices(&api, false, false);
    let receipt = ProbeReceipt {
        success: true,
        command: "wheelctl moza probe",
        generated_at_utc: now_utc(),
        vendor_id: hex_u16(MOZA_VENDOR_ID),
        no_hid_device_opened: true,
        no_ffb_writes: true,
        no_output_reports: true,
        no_feature_reports: true,
        no_serial_config_commands: true,
        no_firmware_or_dfu_commands: true,
        devices,
        notes: vec!["probe enumerates HID metadata only; no device writes are sent".to_string()],
    };

    write_json_receipt(json_out, &receipt)?;
    print_probe_receipt(json, json_out, &receipt)
}

async fn status(
    json: bool,
    selector: Option<&str>,
    lane: Option<&Path>,
    json_out: Option<&Path>,
) -> Result<()> {
    let api = HidApi::new().context("failed to initialize HID API")?;
    let devices: Vec<_> = enumerate_moza_devices(&api, false, false)
        .into_iter()
        .filter(|device| selector_matches(device, selector))
        .collect();

    if selector.is_some() && devices.is_empty() {
        return Err(anyhow!(
            "no Moza HID device matched selector '{}'",
            selector.unwrap_or_default()
        ));
    }

    let receipt = moza_status_receipt(devices, selector, lane);
    write_json_receipt(json_out, &receipt)?;
    print_status_receipt(json, json_out, &receipt)
}

async fn artifact_index(
    json: bool,
    lane: &Path,
    json_out: Option<&Path>,
    md_out: Option<&Path>,
) -> Result<()> {
    let receipt = moza_artifact_index_receipt(lane, json_out, md_out)?;
    write_json_receipt(json_out, &receipt)?;
    if let Some(path) = md_out {
        write_text_file(path, &render_moza_lane_artifact_index_markdown(&receipt))?;
    }
    print_artifact_index_receipt(json, json_out, md_out, &receipt)
}

fn moza_artifact_index_receipt(
    lane: &Path,
    json_out: Option<&Path>,
    md_out: Option<&Path>,
) -> Result<Value> {
    if !lane.is_dir() {
        return Err(anyhow!(
            "--lane must point at an existing Moza lane directory: {}",
            lane.display()
        ));
    }

    let support_status = artifact_navigation_status(lane);
    let readiness = artifact_index_readiness_summary(lane, &support_status);
    let lane_artifacts = discover_lane_artifacts(lane)?;
    let frontier = moza_lane_frontier_label(lane, &support_status);
    let input_role_semantics = moza_input_role_semantics_summary(lane);
    let pit_house_compatibility = moza_pit_house_compatibility_summary(lane);
    let simulator_compatibility = moza_simulator_compatibility_summary(lane);
    let vendor_authority_navigation = moza_vendor_authority_navigation_summary(lane);
    let passive_sniff_navigation = moza_passive_sniff_navigation_summary(lane);

    Ok(serde_json::json!({
        "success": true,
        "command": "wheelctl moza artifact-index",
        "artifact_kind": "moza_lane_artifact_index",
        "generated_at_utc": now_utc(),
        "lane": lane.display().to_string(),
        "json_out": json_out.map(|path| path.display().to_string()),
        "md_out": md_out.map(|path| path.display().to_string()),
        "frontier": frontier,
        "no_hid_device_opened": true,
        "no_ffb_writes": true,
        "no_output_reports": true,
        "no_feature_reports": true,
        "no_serial_config_commands": true,
        "no_firmware_or_dfu_commands": true,
        "hardware_output_authorized": false,
        "native_visible_claimed": false,
        "readiness_claims": NonClaimingReadinessClaims::default(),
        "readiness": readiness,
        "input_role_semantics": input_role_semantics,
        "pit_house_compatibility": pit_house_compatibility,
        "simulator_compatibility": simulator_compatibility,
        "vendor_authority_navigation": vendor_authority_navigation,
        "passive_sniff_navigation": passive_sniff_navigation,
        "required_artifact_index": support_status
            .get("artifact_index")
            .cloned()
            .unwrap_or_else(|| Value::Array(Vec::new())),
        "lane_artifacts": lane_artifacts,
        "notes": [
            "artifact-index reads lane files only; it opens no HID device and sends no output, feature, serial, firmware, or DFU commands",
            "artifact-index is diagnostic navigation only; it is not a readiness promotion and does not authorize hardware output"
        ]
    }))
}

