fn moza_vendor_authority_serial_port_hints(lane: &Path) -> Vec<String> {
    moza_vendor_authority_serial_hints(lane, true)
}

fn moza_vendor_authority_serial_interface_hints(lane: &Path) -> Vec<String> {
    moza_vendor_authority_serial_hints(lane, false)
}

fn moza_vendor_authority_serial_hints(lane: &Path, ports_only: bool) -> Vec<String> {
    let Ok(receipt) = read_json_value(lane, "hardware-doctor.json") else {
        return Vec::new();
    };
    let mut hints = BTreeSet::new();
    let Some(devices) = receipt
        .pointer("/windows_pnp/devices")
        .and_then(Value::as_array)
    else {
        return Vec::new();
    };
    for device in devices {
        if json_string(device, "class") != Some("Ports")
            || json_string(device, "vendor_id") != Some(MOZA_VENDOR_HEX)
            || json_string(device, "product_id") != Some(VENDOR_AUTHORITY_HANDOFF_PRODUCT_ID)
        {
            continue;
        }
        let Some(friendly_name) = json_string(device, "friendly_name") else {
            continue;
        };
        if ports_only {
            if let Some(port) = windows_com_port_from_friendly_name(friendly_name) {
                hints.insert(port);
            }
        } else {
            hints.insert(friendly_name.to_string());
        }
    }
    hints.into_iter().collect()
}

fn windows_com_port_from_friendly_name(friendly_name: &str) -> Option<String> {
    let marker = "(COM";
    let start = friendly_name.find(marker)? + 1;
    let suffix = &friendly_name[start..];
    let end = suffix.find(')')?;
    let candidate = &suffix[..end];
    if candidate.len() > 3
        && candidate.starts_with("COM")
        && candidate[3..].chars().all(|ch| ch.is_ascii_digit())
    {
        Some(candidate.to_string())
    } else {
        None
    }
}

fn moza_post_authority_pidff_response_next_operator_step(lane: &Path) -> Value {
    let post_response_recorded = lane.join(VENDOR_AUTHORITY_POST_PIDFF_SMOKE_FILE).is_file();
    let comparison_recorded = lane
        .join(VENDOR_AUTHORITY_POST_PIDFF_RESPONSE_FILE)
        .is_file();
    let protocol_review_recorded = lane.join(VENDOR_PROTOCOL_EVIDENCE_REVIEW_FILE).is_file();
    if protocol_review_recorded {
        if let Some(mut step) = moza_passive_sniff_next_operator_step(lane) {
            let label = json_string(&step, "label")
                .unwrap_or("next passive correlation")
                .to_string();
            if let Some(step) = step.as_object_mut() {
                step.insert(
                    "summary".to_string(),
                    Value::String(format!(
                        "vendor protocol evidence review is recorded; next no-output semantic correlation evidence is the {label} passive USB capture, followed by non-claiming sniff receipt, operator notes, summary, and bundle artifacts"
                    )),
                );
                step.insert(
                    "source_reason".to_string(),
                    Value::String("vendor_protocol_evidence_review_recorded".to_string()),
                );
                step.insert(
                    "vendor_protocol_evidence_review_receipt".to_string(),
                    Value::String(VENDOR_PROTOCOL_EVIDENCE_REVIEW_FILE.to_string()),
                );
                step.insert(
                    "vendor_authority_attempt_receipt".to_string(),
                    Value::String(VENDOR_AUTHORITY_ATTEMPT_FILE.to_string()),
                );
                step.insert(
                    "post_authority_pidff_response_receipt".to_string(),
                    Value::String(VENDOR_AUTHORITY_POST_PIDFF_RESPONSE_FILE.to_string()),
                );
                step.insert(
                    "hardware_attempt_command_emitted".to_string(),
                    Value::Bool(false),
                );
                step.insert(
                    "blocked_actions".to_string(),
                    serde_json::json!(vendor_authority_handoff_blocked_actions()),
                );
            }
            return step;
        }
        return serde_json::json!({
            "kind": "vendor_protocol_evidence_review_recorded",
            "summary": "vendor protocol evidence review is recorded; continue no-output protocol investigation before any future output plan",
            "hardware_output_allowed_now": false,
            "authorization_created_by_wizard": false,
            "no_openracing_output": true,
            "hardware_attempt_command_emitted": false,
            "vendor_authority_attempt_receipt": VENDOR_AUTHORITY_ATTEMPT_FILE,
            "post_authority_pidff_response_receipt": VENDOR_AUTHORITY_POST_PIDFF_RESPONSE_FILE,
            "vendor_protocol_evidence_review_receipt": VENDOR_PROTOCOL_EVIDENCE_REVIEW_FILE,
            "blocked_actions": vendor_authority_handoff_blocked_actions()
        });
    }
    if comparison_recorded {
        return serde_json::json!({
            "kind": "post_authority_pidff_response_comparison_recorded",
            "summary": "post-authority PIDFF response comparison is recorded; run the no-output vendor protocol evidence review before any future output plan",
            "hardware_output_allowed_now": false,
            "authorization_created_by_wizard": false,
            "no_openracing_output": true,
            "hardware_attempt_command_emitted": false,
            "vendor_authority_attempt_receipt": VENDOR_AUTHORITY_ATTEMPT_FILE,
            "post_authority_pidff_response_receipt": VENDOR_AUTHORITY_POST_PIDFF_RESPONSE_FILE,
            "planned_vendor_protocol_evidence_review_receipt": VENDOR_PROTOCOL_EVIDENCE_REVIEW_FILE,
            "commands": [
                {
                    "name": "review_vendor_protocol_evidence",
                    "output_enabled": false,
                    "opens_hid": false,
                    "opens_serial": false,
                    "sends_read_only_query": false,
                    "sends_output": false,
                    "command": vendor_protocol_evidence_review_command(lane)
                }
            ],
            "blocked_actions": vendor_authority_handoff_blocked_actions()
        });
    }
    if post_response_recorded {
        return serde_json::json!({
            "kind": "post_authority_pidff_response_comparison",
            "summary": "a bounded vendor-authority attempt receipt and post-authority PIDFF response receipt are recorded; run the no-output comparison before any motion claim or further output",
            "hardware_output_allowed_now": false,
            "authorization_created_by_wizard": false,
            "no_openracing_output": true,
            "hardware_attempt_command_emitted": false,
            "vendor_authority_attempt_receipt": VENDOR_AUTHORITY_ATTEMPT_FILE,
            "baseline_response_receipt": "native-actuator-visible-smoke-response-only.json",
            "post_authority_pidff_smoke_receipt": VENDOR_AUTHORITY_POST_PIDFF_SMOKE_FILE,
            "planned_post_authority_receipt": VENDOR_AUTHORITY_POST_PIDFF_RESPONSE_FILE,
            "commands": [
                {
                    "name": "compare_post_authority_pidff_response",
                    "output_enabled": false,
                    "opens_hid": false,
                    "opens_serial": false,
                    "sends_read_only_query": false,
                    "sends_output": false,
                    "command": vendor_post_authority_pidff_response_command(lane)
                }
            ],
            "blocked_actions": vendor_authority_handoff_blocked_actions()
        });
    }
    serde_json::json!({
        "kind": "awaiting_post_authority_pidff_response_receipt",
        "summary": "a bounded vendor-authority attempt receipt is recorded; capture a separately authorized post-authority PIDFF response receipt, then compare it without making a motion claim",
        "hardware_output_allowed_now": false,
        "authorization_created_by_wizard": false,
        "no_openracing_output": true,
        "hardware_attempt_command_emitted": false,
        "vendor_authority_attempt_receipt": VENDOR_AUTHORITY_ATTEMPT_FILE,
        "baseline_response_receipt": "native-actuator-visible-smoke-response-only.json",
        "planned_post_authority_pidff_smoke_receipt": VENDOR_AUTHORITY_POST_PIDFF_SMOKE_FILE,
        "planned_post_authority_receipt": VENDOR_AUTHORITY_POST_PIDFF_RESPONSE_FILE,
        "blocked_actions": vendor_authority_handoff_blocked_actions()
    })
}

fn moza_vendor_authority_navigation_summary(lane: &Path) -> Value {
    let authorization_recorded = lane.join(VENDOR_AUTHORITY_AUTHORIZATION_FILE).is_file();
    let smoke_dry_run_recorded = lane.join(VENDOR_AUTHORITY_SMOKE_DRY_RUN_FILE).is_file();
    let attempt_recorded = lane.join(VENDOR_AUTHORITY_ATTEMPT_FILE).is_file();
    let blocked_attempt_recorded = lane.join(VENDOR_AUTHORITY_ATTEMPT_BLOCKED_FILE).is_file();
    let post_pidff_smoke_recorded = lane.join(VENDOR_AUTHORITY_POST_PIDFF_SMOKE_FILE).is_file();
    let post_pidff_comparison_recorded = lane
        .join(VENDOR_AUTHORITY_POST_PIDFF_RESPONSE_FILE)
        .is_file();
    let protocol_evidence_review_recorded =
        lane.join(VENDOR_PROTOCOL_EVIDENCE_REVIEW_FILE).is_file();
    let closed_loop_undertravel_recorded = lane
        .join(NATIVE_CONTROLLED_ANGLE_CLOSED_LOOP_SMOKE_FILE)
        .is_file();
    let standard_pidff_diagnosis_recorded = lane
        .join(NATIVE_PIDFF_STANDARD_PATH_DIAGNOSIS_FILE)
        .is_file();
    let vendor_protocol_decode_priority = moza_vendor_protocol_decode_priority(lane);
    let native_motion_blocker = moza_native_motion_blocker_navigation(lane);
    let native_motion_blocker_active = !native_motion_blocker.is_null();
    let state = if native_motion_blocker_active {
        "native_motion_timing_source_blocked"
    } else if protocol_evidence_review_recorded {
        "protocol_evidence_review_recorded"
    } else if post_pidff_comparison_recorded {
        "post_authority_pidff_response_recorded"
    } else if attempt_recorded {
        "vendor_authority_attempt_recorded"
    } else if blocked_attempt_recorded {
        "vendor_authority_attempt_blocked_before_send"
    } else if authorization_recorded && smoke_dry_run_recorded {
        "awaiting_separate_bounded_attempt"
    } else if authorization_recorded {
        "awaiting_no_output_smoke_dry_run"
    } else if closed_loop_undertravel_recorded && standard_pidff_diagnosis_recorded {
        "ready_for_exact_authority_handoff"
    } else {
        "awaiting_closed_loop_undertravel_evidence"
    };
    let next_allowed_action = if native_motion_blocker_active {
        json_string(&native_motion_blocker, "next_allowed_action")
            .unwrap_or("Run the staged passive Pit House 0x8E event-marker capture and no-output timing review before any live probe, authorization, PIDFF rerun, or motion.")
            .to_string()
    } else if protocol_evidence_review_recorded {
        "Continue no-output vendor protocol investigation; finish remaining passive sniff scenarios or decode reviewed protocol candidates before any future output plan.".to_string()
    } else if post_pidff_comparison_recorded {
        "Review post-authority PIDFF response comparison and run strict verifier before any motion claim.".to_string()
    } else if attempt_recorded {
        "Record post-authority PIDFF response comparison before any motion claim.".to_string()
    } else if blocked_attempt_recorded {
        "Release the serial-port owner, then create fresh bench-clear, authorization, smoke dry-run, and attempt receipts before retry.".to_string()
    } else if authorization_recorded && smoke_dry_run_recorded {
        "A separately requested bounded hardware attempt may consume the exact receipts; this navigation does not emit the serial write command.".to_string()
    } else if authorization_recorded {
        "Run the no-output vendor-authority smoke dry-run before any separate bounded attempt."
            .to_string()
    } else if closed_loop_undertravel_recorded && standard_pidff_diagnosis_recorded {
        "Create an exact authorization receipt after fresh command-bound bench-clear, then run a no-output smoke dry-run.".to_string()
    } else {
        "Preserve undertravel evidence and finish the vendor-authority prerequisites before any hardware attempt.".to_string()
    };

    serde_json::json!({
        "artifact_kind": "moza_vendor_authority_navigation",
        "claim_scope": "native_control_vendor_authority_navigation_only",
        "state": state,
        "native_control_evidence": false,
        "hardware_output_authorized": false,
        "native_visible_ready": false,
        "smoke_ready": false,
        "no_hid_device_opened": true,
        "no_ffb_writes": true,
        "no_output_reports": true,
        "no_feature_reports": true,
        "no_serial_config_commands": true,
        "no_firmware_or_dfu_commands": true,
        "pit_house_dependency": false,
        "simulator_dependency": false,
        "closed_loop_undertravel_recorded": closed_loop_undertravel_recorded,
        "standard_pidff_diagnosis_recorded": standard_pidff_diagnosis_recorded,
        "authorization_receipt_recorded": authorization_recorded,
        "smoke_dry_run_receipt_recorded": smoke_dry_run_recorded,
        "vendor_authority_attempt_recorded": attempt_recorded,
        "vendor_authority_attempt_blocked_recorded": blocked_attempt_recorded,
        "post_authority_pidff_smoke_recorded": post_pidff_smoke_recorded,
        "post_authority_pidff_response_recorded": post_pidff_comparison_recorded,
        "vendor_protocol_evidence_review_recorded": protocol_evidence_review_recorded,
        "vendor_protocol_decode_priority": vendor_protocol_decode_priority,
        "native_motion_blocker": native_motion_blocker,
        "hardware_attempt_command_emitted": false,
        "next_allowed_action": next_allowed_action,
        "exact_command": {
            "command_id": VENDOR_AUTHORITY_HANDOFF_COMMAND_ID,
            "frame_hex": VENDOR_AUTHORITY_HANDOFF_FRAME_HEX,
            "payload_hex": VENDOR_AUTHORITY_HANDOFF_PAYLOAD_HEX,
            "risk_class": "vendor_output_candidate",
            "requires_exact_authorization": true,
            "hardware_attempt_command_emitted": false
        },
        "artifacts": {
            "authorization_receipt": VENDOR_AUTHORITY_AUTHORIZATION_FILE,
            "smoke_dry_run_receipt": VENDOR_AUTHORITY_SMOKE_DRY_RUN_FILE,
            "attempt_receipt": VENDOR_AUTHORITY_ATTEMPT_FILE,
            "blocked_attempt_receipt": VENDOR_AUTHORITY_ATTEMPT_BLOCKED_FILE,
            "post_authority_pidff_smoke_receipt": VENDOR_AUTHORITY_POST_PIDFF_SMOKE_FILE,
            "post_authority_pidff_response_receipt": VENDOR_AUTHORITY_POST_PIDFF_RESPONSE_FILE,
            "vendor_protocol_evidence_review_receipt": VENDOR_PROTOCOL_EVIDENCE_REVIEW_FILE
        },
        "required_bench_clear_evidence": VENDOR_AUTHORITY_HANDOFF_BENCH_CLEAR_EVIDENCE,
        "serial_precondition": moza_vendor_authority_serial_precondition(lane),
        "blocked_actions": vendor_authority_handoff_blocked_actions(),
        "notes": [
            "Vendor-authority navigation is native-control research support; it is not a Pit House, SimHub, or simulator dependency.",
            "Pit House may still own the R5 serial/CDC port; release exclusive serial owners before creating short-lived authorization or running the separate bounded attempt.",
            "The bench wizard may surface no-output authorization and smoke commands, but it must not emit the hardware attempt command.",
            "A consumed attempt receipt remains non-claiming until later PIDFF response comparison and native-visible verification pass.",
            "A vendor protocol evidence review receipt is no-output diagnosis and does not authorize a future output family."
        ]
    })
}

fn moza_vendor_protocol_decode_priority(lane: &Path) -> Value {
    let Ok(review) = read_json_value(lane, VENDOR_PROTOCOL_EVIDENCE_REVIEW_FILE) else {
        return Value::Null;
    };
    let Some(coverage) = review.get("passive_tuple_registry_coverage") else {
        return serde_json::json!({
            "claim_scope": "no_output_vendor_protocol_decode_priority_navigation",
            "source_receipt": VENDOR_PROTOCOL_EVIDENCE_REVIEW_FILE,
            "status": "missing_passive_tuple_registry_coverage",
            "hardware_output_authorized": false,
            "native_control_evidence": false,
            "native_visible_ready": false,
            "output_sendability_claim": false,
            "protocol_evidence_sufficient_for_output_plan": false,
            "unknown_tuple_risk_class": "unknown_do_not_send",
            "notes": [
                "Vendor protocol review exists but does not contain passive tuple registry coverage."
            ]
        });
    };
    let tuple_summaries = coverage
        .get("tuple_frequency_summary")
        .and_then(Value::as_array)
        .map(|tuples| {
            let mut tuples = tuples
                .iter()
                .filter(|tuple| json_string(tuple, "registry_status") == Some("unknown_commanded"))
                .collect::<Vec<_>>();
            tuples.sort_by(|left, right| {
                json_u64(right, "total_count")
                    .unwrap_or(0)
                    .cmp(&json_u64(left, "total_count").unwrap_or(0))
                    .then_with(|| {
                        json_string(left, "tuple_id")
                            .unwrap_or("unknown")
                            .cmp(json_string(right, "tuple_id").unwrap_or("unknown"))
                    })
            });
            tuples
                .into_iter()
                .take(5)
                .map(|tuple| {
                    serde_json::json!({
                        "tuple_id": json_string(tuple, "tuple_id").unwrap_or("unknown"),
                        "registry_status": json_string(tuple, "registry_status").unwrap_or("unknown"),
                        "total_count": json_u64(tuple, "total_count").unwrap_or(0),
                        "payload_len_min": json_u64(tuple, "payload_len_min").unwrap_or(0),
                        "payload_len_max": json_u64(tuple, "payload_len_max").unwrap_or(0),
                        "scenario_count": json_u64(tuple, "scenario_count").unwrap_or(0),
                        "hardware_output_authorized": false,
                        "output_sendability_claim": false
                    })
                })
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    let highest_frequency_unknown_commanded_tuple_ids = coverage
        .get("highest_frequency_unknown_commanded_tuple_ids")
        .and_then(Value::as_array)
        .map(|tuples| {
            tuples
                .iter()
                .filter_map(Value::as_str)
                .take(5)
                .map(str::to_string)
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    let decode_candidate_sample_scope =
        json_string(coverage, "decode_candidate_sample_scope").unwrap_or("not_recorded");
    let decode_candidate_sample_count =
        json_u64(coverage, "decode_candidate_sample_count").unwrap_or(0);
    let decode_candidate_sample_tuple_ids = coverage
        .get("decode_candidate_sample_tuple_ids")
        .and_then(Value::as_array)
        .map(|tuples| {
            tuples
                .iter()
                .filter_map(Value::as_str)
                .take(5)
                .map(str::to_string)
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    let decode_candidate_sample_fixtures = coverage
        .get("decode_candidate_sample_fixtures")
        .and_then(Value::as_array)
        .map(|fixtures| {
            fixtures
                .iter()
                .take(5)
                .map(|fixture| {
                    let sample_frame_examples = fixture
                        .get("sample_frames")
                        .and_then(Value::as_array)
                        .map(|samples| {
                            samples
                                .iter()
                                .take(3)
                                .map(|sample| {
                                    serde_json::json!({
                                        "scenario": json_string(sample, "scenario").unwrap_or("unknown"),
                                        "frame_hex": json_string(sample, "frame_hex").unwrap_or(""),
                                        "payload_len": json_u64(sample, "payload_len").unwrap_or(0),
                                        "payload_hex": json_string(sample, "payload_hex").unwrap_or(""),
                                        "checksum_valid": sample.get("checksum_valid").and_then(Value::as_bool).unwrap_or(false),
                                        "hardware_output_authorized": false,
                                        "output_sendability_claim": false
                                    })
                                })
                                .collect::<Vec<_>>()
                        })
                        .unwrap_or_default();
                    serde_json::json!({
                        "tuple_id": json_string(fixture, "tuple_id").unwrap_or("unknown"),
                        "registry_status": json_string(fixture, "registry_status").unwrap_or("unknown"),
                        "total_count": json_u64(fixture, "total_count").unwrap_or(0),
                        "sample_count": json_u64(fixture, "sample_count").unwrap_or(0),
                        "sample_frame_examples": sample_frame_examples,
                        "hardware_output_authorized": false,
                        "output_sendability_claim": false
                    })
                })
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    let decode_candidate_payload_shape_summary = coverage
        .get("decode_candidate_payload_shape_summary")
        .cloned()
        .unwrap_or_else(|| {
            serde_json::json!({
                "claim_scope": "no_output_passive_tuple_payload_shape_review",
                "sample_scope": "not_recorded",
                "tuple_count": 0,
                "sample_count": 0,
                "unique_payload_shape_count": 0,
                "all_samples_checksum_valid": false,
                "all_samples_unknown_commanded": false,
                "all_sample_payloads_empty_or_zero_filled": false,
                "tuple_payload_shapes": [],
                "hardware_output_authorized": false,
                "native_control_evidence": false,
                "output_sendability_claim": false,
                "protocol_evidence_sufficient_for_output_plan": false
            })
        });
    let decode_candidate_packet_group_summary = coverage
        .get("decode_candidate_packet_group_summary")
        .cloned()
        .unwrap_or_else(|| {
            serde_json::json!({
                "claim_scope": "no_output_passive_tuple_packet_group_review",
                "sample_scope": "not_recorded",
                "packet_group_count": 0,
                "sample_count": 0,
                "unique_packet_pattern_count": 0,
                "repeated_contiguous_motif_count": 0,
                "all_packet_groups_checksum_valid": false,
                "all_packet_groups_unknown_commanded": false,
                "all_packet_groups_non_sendable": false,
                "packet_groups": [],
                "packet_patterns": [],
                "repeated_contiguous_motifs": [],
                "hardware_output_authorized": false,
                "native_control_evidence": false,
                "output_sendability_claim": false,
                "protocol_evidence_sufficient_for_output_plan": false
            })
        });
    let decode_candidate_semantic_hypothesis_summary = coverage
        .get("decode_candidate_semantic_hypothesis_summary")
        .cloned()
        .unwrap_or_else(|| {
            serde_json::json!({
                "claim_scope": "no_output_passive_tuple_semantic_hypothesis_review",
                "sample_scope": "not_recorded",
                "tuple_count": 0,
                "hypothesis_count": 0,
                "all_hypotheses_unknown_commanded": false,
                "all_hypotheses_non_sendable": false,
                "tuple_hypotheses": [],
                "semantic_decode_claim": false,
                "registry_promotion_claim": false,
                "hardware_output_authorized": false,
                "native_control_evidence": false,
                "output_sendability_claim": false,
                "protocol_evidence_sufficient_for_output_plan": false
            })
        });
    let decode_candidate_semantic_correlation_plan = coverage
        .get("decode_candidate_semantic_correlation_plan")
        .cloned()
        .unwrap_or_else(|| {
            serde_json::json!({
                "claim_scope": "no_output_passive_tuple_semantic_correlation_plan",
                "source_hypothesis_scope": "no_output_passive_tuple_semantic_hypothesis_review",
                "hypothesis_count": 0,
                "correlation_target_count": 0,
                "all_targets_non_sendable": false,
                "targets": [],
                "next_allowed_action": "capture or summarize named passive correlation scenarios; no output",
                "blocked_actions": [
                    "send unknown vendor tuples",
                    "promote semantic command registry entries",
                    "create vendor authorization receipts",
                    "run hardware output",
                    "claim native-visible readiness"
                ],
                "required_artifacts": [],
                "semantic_decode_claim": false,
                "registry_promotion_claim": false,
                "hardware_output_authorized": false,
                "native_control_evidence": false,
                "output_sendability_claim": false,
                "protocol_evidence_sufficient_for_output_plan": false
            })
        });
    let decode_candidate_mode_enable_review = coverage
        .get("decode_candidate_mode_enable_review")
        .cloned()
        .unwrap_or_else(|| {
            serde_json::json!({
                "claim_scope": "no_output_passive_tuple_mode_enable_candidate_review",
                "source_hypothesis_scope": "no_output_passive_tuple_semantic_hypothesis_review",
                "candidate_count": 0,
                "candidates": [],
                "all_candidates_unknown_do_not_send": false,
                "semantic_decode_claim": false,
                "registry_promotion_claim": false,
                "hardware_output_authorized": false,
                "native_control_evidence": false,
                "output_sendability_claim": false,
                "protocol_evidence_sufficient_for_output_plan": false
            })
        });
    let payload_export_gap_summary = review
        .pointer("/sniff_evidence/payload_export_gap_summary")
        .cloned()
        .unwrap_or_else(|| {
            serde_json::json!({
                "claim_scope": "no_output_passive_payload_export_gap_review",
                "total_missing_packet_count": 0,
                "scenario_count": 0,
                "scenarios": [],
                "hardware_output_authorized": false,
                "native_control_evidence": false,
                "output_sendability_claim": false,
                "protocol_evidence_sufficient_for_output_plan": false
            })
        });
    serde_json::json!({
        "claim_scope": "no_output_vendor_protocol_decode_priority_navigation",
        "source_receipt": VENDOR_PROTOCOL_EVIDENCE_REVIEW_FILE,
        "status": if tuple_summaries.is_empty() {
            "no_unknown_commanded_tuple_frequency"
        } else {
            "frequency_ranked_unknown_commanded_tuples"
        },
        "priority_basis": "descending_checked_in_passive_tuple_frequency",
        "highest_frequency_unknown_commanded_tuple_ids": highest_frequency_unknown_commanded_tuple_ids,
        "top_unknown_commanded_tuples": tuple_summaries,
        "decode_candidate_sample_scope": decode_candidate_sample_scope,
        "decode_candidate_sample_count": decode_candidate_sample_count,
        "decode_candidate_sample_tuple_ids": decode_candidate_sample_tuple_ids,
        "decode_candidate_sample_fixtures": decode_candidate_sample_fixtures,
        "decode_candidate_payload_shape_summary": decode_candidate_payload_shape_summary,
        "decode_candidate_packet_group_summary": decode_candidate_packet_group_summary,
        "decode_candidate_semantic_hypothesis_summary": decode_candidate_semantic_hypothesis_summary,
        "decode_candidate_semantic_correlation_plan": decode_candidate_semantic_correlation_plan,
        "decode_candidate_mode_enable_review": decode_candidate_mode_enable_review,
        "payload_export_gap_summary": payload_export_gap_summary,
        "unknown_tuple_risk_class": json_string(coverage, "unknown_tuple_risk_class").unwrap_or("unknown_do_not_send"),
        "hardware_output_authorized": false,
        "native_control_evidence": false,
        "native_visible_ready": false,
        "output_sendability_claim": false,
        "protocol_evidence_sufficient_for_output_plan": false,
        "next_required_evidence": [
            "semantic command decode",
            "fixture-backed decoder coverage",
            "reviewed no-output plan",
            "fresh exact authorization before any future write"
        ],
        "notes": [
            "Frequency ranking is decode priority only; it is not evidence that any tuple is safe to send.",
            "Unknown commanded tuples remain unknown_do_not_send until future semantic decode and reviewed authorization gates exist."
        ]
    })
}

fn vendor_authority_authorization_command(lane: &Path) -> String {
    format!(
        "wheelctl moza authorize-vendor-authority --command-id {} --frame-hex {} --precondition-hardware-doctor {} --authorized-by {} --bench-clear-evidence '{}' --expires-after-minutes {} --json-out {} --json --confirm-exact-vendor-authority-authorization",
        VENDOR_AUTHORITY_HANDOFF_COMMAND_ID,
        VENDOR_AUTHORITY_HANDOFF_FRAME_HEX,
        VENDOR_AUTHORITY_LIVE_HARDWARE_DOCTOR_TARGET,
        VENDOR_AUTHORITY_HANDOFF_AUTHORIZED_BY,
        VENDOR_AUTHORITY_HANDOFF_BENCH_CLEAR_EVIDENCE,
        VENDOR_AUTHORITY_HANDOFF_EXPIRES_AFTER_MINUTES,
        lane.join(VENDOR_AUTHORITY_AUTHORIZATION_FILE).display()
    )
}

fn vendor_authority_live_hardware_doctor_command() -> String {
    format!(
        "wheelctl hardware doctor --json-out {} --json",
        VENDOR_AUTHORITY_LIVE_HARDWARE_DOCTOR_TARGET
    )
}

fn vendor_authority_smoke_dry_run_command(lane: &Path) -> String {
    format!(
        "wheelctl moza vendor-authority-smoke-dry-run --authorization {} --json-out {} --json --confirm-no-output-smoke-dry-run",
        lane.join(VENDOR_AUTHORITY_AUTHORIZATION_FILE).display(),
        lane.join(VENDOR_AUTHORITY_SMOKE_DRY_RUN_FILE).display()
    )
}

fn vendor_post_authority_pidff_response_command(lane: &Path) -> String {
    format!(
        "wheelctl moza vendor-post-authority-pidff-response --lane {} --attempt {} --baseline-response {} --post-response {} --json-out {} --json",
        lane.display(),
        lane.join(VENDOR_AUTHORITY_ATTEMPT_FILE).display(),
        lane.join("native-actuator-visible-smoke-response-only.json")
            .display(),
        lane.join(VENDOR_AUTHORITY_POST_PIDFF_SMOKE_FILE).display(),
        lane.join(VENDOR_AUTHORITY_POST_PIDFF_RESPONSE_FILE)
            .display()
    )
}

fn vendor_protocol_evidence_review_command(lane: &Path) -> String {
    format!(
        "wheelctl moza vendor-protocol-evidence-review --lane {} --json-out {} --json --overwrite",
        lane.display(),
        lane.join(VENDOR_PROTOCOL_EVIDENCE_REVIEW_FILE).display()
    )
}

fn vendor_authority_handoff_blocked_actions() -> Vec<&'static str> {
    vec![
        "hardware attempt command from bench-wizard",
        "authorization reuse",
        "payload drift",
        "configuration drift",
        "firmware or DFU command",
        "unknown host-to-device command",
        "direct HID report 0xaf",
        "high torque",
        "native-control claim",
        "native-visible claim",
        "smoke-ready claim",
        "release-ready claim",
    ]
}

fn moza_passive_sniff_next_operator_step(lane: &Path) -> Option<Value> {
    for (scenario, label, _focus, warning) in moza_passive_sniff_navigation_requirements() {
        let committed_dir = moza_passive_sniff_committed_dir(lane, scenario);
        let plan_artifact = committed_dir.join("sniff-plan.json");
        let receipt_artifact = committed_dir.join("sniff-receipt.json");
        let summary_artifact = committed_dir.join("sniff-summary.json");
        let bundle_manifest_artifact = committed_dir.join("sniff-bundle-manifest.json");
        let low_yield_classification_artifact =
            committed_dir.join(PASSIVE_SNIFF_LOW_YIELD_CLASSIFICATION_FILE);
        let plan_status =
            passive_sniff_artifact_status(&plan_artifact, "wheelctl hardware sniff-plan");
        if !matches!(plan_status, "present_non_claiming") {
            continue;
        }
        let receipt_status =
            passive_sniff_artifact_status(&receipt_artifact, "wheelctl hardware sniff-receipt");
        let summary_status =
            passive_sniff_artifact_status(&summary_artifact, "wheelctl hardware sniff-summary");
        if matches!(receipt_status, "present_non_claiming")
            && matches!(summary_status, "present_non_claiming")
        {
            continue;
        }
        let low_yield_classification_status = passive_sniff_low_yield_classification_status(
            &low_yield_classification_artifact,
            scenario,
        );

        let local_dir = PathBuf::from("target").join("sniff").join(scenario);
        let local_pcapng = local_dir.join("capture.pcapng");
        let local_summary_md = local_dir.join("sniff-summary.md");
        let local_operator_notes = local_dir.join("operator-notes.md");
        let local_operator_notes_receipt = local_dir.join("sniff-notes-template-receipt.json");
        let local_bundle = local_dir.join("openracing-sniff-bundle.zip");
        let app = moza_passive_sniff_external_app(scenario);
        let evidence = format!(
            "operator-recorded passive USB capture for {scenario}; OpenRacing opened no HID device and sent no output, feature, serial, firmware, or DFU commands"
        );

        return Some(serde_json::json!({
            "kind": "capture_passive_vendor_sniff",
            "summary": format!(
                "standard PIDFF path diagnosis is recorded; next evidence is the {label} passive USB capture, followed by non-claiming sniff receipt, operator notes, and summary artifacts"
            ),
            "scenario": scenario,
            "label": label,
            "warning": warning,
            "hardware_output_allowed_now": false,
            "authorization_created_by_wizard": false,
            "no_openracing_output": true,
            "no_hid_device_opened_by_openracing": true,
            "plan_artifact": plan_artifact.display().to_string(),
            "receipt_artifact": receipt_artifact.display().to_string(),
            "summary_artifact": summary_artifact.display().to_string(),
            "bundle_manifest_artifact": bundle_manifest_artifact.display().to_string(),
            "low_yield_classification_artifact": low_yield_classification_artifact.display().to_string(),
            "low_yield_classification_status": low_yield_classification_status,
            "local_pcapng": local_pcapng.display().to_string(),
            "external_capture_checklist": moza_passive_sniff_capture_checklist(
                scenario,
                label,
                warning,
                &local_dir,
                &local_pcapng
            ),
            "external_capture_commands": moza_passive_sniff_external_capture_commands(&local_pcapng),
            "commands": [
                {
                    "name": "record_sniff_receipt",
                    "output_enabled": false,
                    "command": format!(
                        "wheelctl hardware sniff-receipt --plan {} --pcapng {} --operator Steven --app {} --scenario {} --evidence {} --json-out {}",
                        command_arg(&plan_artifact.display().to_string()),
                        command_arg(&local_pcapng.display().to_string()),
                        command_arg(app),
                        command_arg(scenario),
                        command_arg(&evidence),
                        command_arg(&receipt_artifact.display().to_string())
                    )
                },
                {
                    "name": "write_operator_notes_template",
                    "output_enabled": false,
                    "command": format!(
                        "wheelctl hardware sniff-notes-template --plan {} --hardware-doctor target/moza-current/passive-sniff-capture-hardware-doctor.json --out {} --json-out {}",
                        command_arg(&plan_artifact.display().to_string()),
                        command_arg(&local_operator_notes.display().to_string()),
                        command_arg(&local_operator_notes_receipt.display().to_string())
                    )
                },
                {
                    "name": "summarize_sniff_capture",
                    "output_enabled": false,
                    "command": format!(
                        "wheelctl hardware sniff-summary --pcapng {} --vendor {} --product {} --json-out {} --md-out {}",
                        command_arg(&local_pcapng.display().to_string()),
                        MOZA_VENDOR_HEX,
                        hex_u16(product_ids::R5_V1),
                        command_arg(&summary_artifact.display().to_string()),
                        command_arg(&local_summary_md.display().to_string())
                    )
                },
                {
                    "name": "bundle_sniff_evidence",
                    "output_enabled": false,
                    "requires_operator_notes": true,
                    "command": format!(
                        "wheelctl hardware sniff-bundle --plan {} --receipt {} --summary {} --operator-notes {} --operator-notes-receipt {} --out {} --json-out {}",
                        command_arg(&plan_artifact.display().to_string()),
                        command_arg(&receipt_artifact.display().to_string()),
                        command_arg(&summary_artifact.display().to_string()),
                        command_arg(&local_operator_notes.display().to_string()),
                        command_arg(&local_operator_notes_receipt.display().to_string()),
                        command_arg(&local_bundle.display().to_string()),
                        command_arg(&bundle_manifest_artifact.display().to_string())
                    )
                }
            ],
            "notes": [
                "commands are no-output OpenRacing artifact commands; the pcapng capture itself is created by USBPcap/Wireshark/tshark outside OpenRacing",
                "if a low-yield classification exists, repeat the passive setting-change capture instead of treating it as decoded protocol evidence",
                "do not commit raw pcapng unless separate review approves raw capture, size, sensitivity, and operator consent",
                "sniff receipt, operator notes, summary, and bundle artifacts remain protocol research/support evidence only"
            ]
        }));
    }
    None
}

fn moza_passive_sniff_capture_checklist(
    scenario: &str,
    label: &str,
    warning: &str,
    local_dir: &Path,
    local_pcapng: &Path,
) -> Value {
    let mut operator_notes_required = vec![
        "scenario performed",
        "external app or simulator observed",
        "capture duration or start/stop times",
        "device stack attached",
        "whether firmware/update/DFU pages stayed closed",
        "whether raw pcapng was kept local or reviewed for bundling",
    ];
    if scenario == "simhub-open-idle" {
        operator_notes_required.push("SimHub version/source if known");
        operator_notes_required.push("SimHub launch/open time");
        operator_notes_required.push("SimHub idle/stable confirmation");
        operator_notes_required.push("no SimHub output session started");
        operator_notes_required.push("no simulator started");
        operator_notes_required
            .push("firmware/update/DFU pages stayed closed or no prompt/page observed");
        operator_notes_required.push("raw pcap kept local only");
        operator_notes_required.push("OpenRacing no-output boundary");
    }
    serde_json::json!({
        "owner": "operator_external_capture_tool",
        "scenario": scenario,
        "label": label,
        "local_directory": local_dir.display().to_string(),
        "local_pcapng": local_pcapng.display().to_string(),
        "capture_tools": ["USBPcap", "Wireshark", "tshark"],
        "openracing_output": false,
        "openracing_hid_open": false,
        "openracing_feature_reports": false,
        "external_app_may_send_output": true,
        "raw_pcap_commit_default": false,
        "steps": [
            format!(
                "Create the local scratch directory {} before starting the capture.",
                local_dir.display()
            ),
            "Run wheelctl hardware doctor --json-out target/moza-current/passive-sniff-capture-hardware-doctor.json --json and prefer any /tools/usbpcap_descriptor_capture/usbpcap_moza_device_hints entry when selecting the USBPcap interface and device filter.".to_string(),
            "Do not reuse stale --devices values from earlier captures; the bounded sniff-capture helper should receive --hardware-doctor so the requested selector can be checked against the fresh Moza hint.".to_string(),
            "Start the bounded wheelctl hardware sniff-capture helper, USBPcap, Wireshark, or tshark capture on the USB controller that contains the Moza R5 before starting the external app.".to_string(),
            moza_passive_sniff_capture_action(scenario),
            format!(
                "Stop capture and save the pcapng as {}.",
                local_pcapng.display()
            ),
            "Run the no-output wheelctl hardware sniff-receipt, sniff-notes-template, and sniff-summary commands from this bench-wizard handoff.".to_string(),
            "Fill operator notes before bundling and do not commit raw pcapng unless separately reviewed.".to_string()
        ],
        "operator_notes_required": operator_notes_required,
        "forbidden_actions": [
            "OpenRacing output commands",
            "OpenRacing HID output reports",
            "OpenRacing HID feature reports",
            "driver replacement",
            "Zadig",
            "WinUSB conversion",
            "serial configuration",
            "firmware update",
            "DFU"
        ],
        "warning": warning,
        "notes": [
            "capture is produced outside OpenRacing; this checklist does not open HID or send reports",
            "external app traffic is protocol research evidence only and is not OpenRacing native-visible or smoke-ready proof"
        ]
    })
}

fn moza_passive_sniff_external_capture_commands(local_pcapng: &Path) -> Vec<Value> {
    let capture_receipt = moza_passive_sniff_capture_receipt_path(local_pcapng);
    vec![
        serde_json::json!({
            "name": "run_bounded_wheelctl_usbpcap_capture",
            "owner": "operator_external_capture_tool",
            "openracing_command": true,
            "output_enabled": false,
            "openracing_hardware_output": false,
            "openracing_hid_open": false,
            "openracing_feature_reports": false,
            "openracing_serial_config_commands": false,
            "openracing_firmware_or_dfu_commands": false,
            "external_capture_tool_invoked": true,
            "requires_hardware_doctor_hint": true,
            "hardware_doctor_path": "target/moza-current/passive-sniff-capture-hardware-doctor.json",
            "duration_ms": 60_000,
            "raw_pcapng_commit_default": false,
            "command_template": format!(
                "wheelctl hardware sniff-capture --usbpcapcmd {} --usbpcap-interface {} --devices <capture_devices_value> --hardware-doctor target/moza-current/passive-sniff-capture-hardware-doctor.json --duration-ms 60000 --out {} --confirm-external-passive-capture --json-out {}",
                command_arg("<USBPcapCMD.exe from hardware doctor>"),
                command_arg("<USBPcap interface from hardware doctor>"),
                command_arg(&local_pcapng.display().to_string()),
                command_arg(&capture_receipt.display().to_string())
            ),
            "notes": [
                "preferred bounded helper after refreshing hardware doctor and before launching or changing the external app",
                "replace placeholders with the USBPcap interface, device filter, and extcap path from the hardware doctor USBPcap Moza device hint",
                "the helper records whether the requested selector matches the current Moza hint; stale or non-Moza selectors fail closed for the local capture receipt",
                "wheelctl starts and stops only the external passive USBPcapCMD capture process; it does not open HID or serial and it sends no hardware output",
                "the local sniff-capture receipt is not a sniff receipt, sniff summary, readiness claim, or accepted lane evidence"
            ]
        }),
        serde_json::json!({
            "name": "run_external_usbpcap_capture",
            "owner": "operator_external_capture_tool",
            "openracing_command": false,
            "output_enabled": false,
            "openracing_hardware_output": false,
            "requires_hardware_doctor_hint": true,
            "hardware_doctor_path": "target/moza-current/passive-sniff-capture-hardware-doctor.json",
            "raw_pcapng_commit_default": false,
            "command_template": format!(
                "& \"<USBPcapCMD.exe from hardware doctor>\" -d \"<USBPcap interface from hardware doctor>\" --devices <capture_devices_value> --inject-descriptors -o {}",
                command_arg(&local_pcapng.display().to_string())
            ),
            "notes": [
                "fallback raw USBPcapCMD form after refreshing hardware doctor and before launching or changing the external app",
                "replace the placeholders with the USBPcap interface, device filter, and extcap path from the hardware doctor USBPcap Moza device hint",
                "do not reuse stale --devices values from earlier captures; verify the raw selector against the fresh hardware doctor hint before capture",
                "this command creates a local raw pcapng only; it is not OpenRacing hardware output and it is not a readiness claim"
            ]
        }),
    ]
}

fn moza_passive_sniff_capture_receipt_path(local_pcapng: &Path) -> PathBuf {
    local_pcapng
        .parent()
        .map(Path::to_path_buf)
        .unwrap_or_default()
        .join("sniff-capture-receipt.json")
}

fn moza_passive_sniff_capture_action(scenario: &str) -> String {
    match scenario {
        "pit-house-open-idle" => {
            "Open MOZA Pit House, wait for device discovery to settle, leave the app idle, and do not open firmware or update pages.".to_string()
        }
        "pit-house-full-controls" => {
            "With MOZA Pit House open and settled, move the wheel, pedals, HBP handbrake, paddles, wheel buttons, thumb controls, and encoders in the recorded operator order; do not open firmware or update pages.".to_string()
        }
        "pit-house-setting-change" => {
            "Open MOZA Pit House before capture, let it settle, change one explicit reversible setting, record the setting name plus start/end/restored values, restore it before accepting evidence, and do not open firmware or update pages.".to_string()
        }
        "simhub-open-idle" => {
            "After capture starts, open SimHub, allow device discovery or idle polling to settle into an idle/stable state, record the SimHub version/source if known plus launch/open time, do not start a SimHub output session, do not start a simulator, and do not open firmware/update/DFU pages or prompts.".to_string()
        }
        "simhub-output-session" => {
            "Run the reviewed external SimHub output scenario only; record that any output traffic is external-app traffic, not OpenRacing FFB proof.".to_string()
        }
        "simulator-session-start-stop" => {
            "Start and stop the external simulator or bridge session and record the simulator/bridge name; do not run OpenRacing simulator FFB.".to_string()
        }
        _ => {
            "Perform the named external observation scenario and record exactly what changed during the capture.".to_string()
        }
    }
}

fn moza_passive_sniff_external_app(scenario: &str) -> &'static str {
    match scenario {
        "pit-house-open-idle" | "pit-house-full-controls" | "pit-house-setting-change" => {
            "MOZA Pit House"
        }
        "simhub-open-idle" | "simhub-output-session" => "SimHub",
        "simulator-session-start-stop" => "external simulator or bridge",
        _ => "external USB observer",
    }
}

