fn moza_bench_wizard_active_blockers(lane: &Path) -> Vec<Value> {
    let mut blockers = Vec::new();
    if !stored_verification_gate_passed(
        lane,
        MozaBundleStage::NativeVisibleReady,
        "native_actuator_visible_smoke",
    ) {
        blockers.push(serde_json::json!({
            "name": "native_visible_motion",
            "scope": "native",
            "blocking_stage": "native_visible_ready",
            "status": "blocked",
            "summary": "no passing same-lane visible-motion receipt exists"
        }));
    }
    for (name, path) in [
        ("pit_house_coexistence", "pit-house-coexistence.json"),
        ("simulator_telemetry", "simulator-telemetry-proof.json"),
        ("simulator_ffb_bounded", "simulator-ffb-smoke.json"),
    ] {
        if !lane.join(path).is_file() {
            blockers.push(serde_json::json!({
                "name": name,
                "scope": "external_smoke",
                "blocking_stage": "smoke_ready",
                "status": "missing",
                "artifact": path
            }));
        }
    }
    blockers
}

fn moza_pit_house_compatibility_summary(lane: &Path) -> Value {
    let availability_artifact = "pit-house-availability.json";
    let availability_receipt = read_json_value(lane, availability_artifact).ok();
    let availability_receipt_valid = availability_receipt
        .as_ref()
        .map(pit_house_availability_receipt_is_safe)
        .unwrap_or(false);
    let availability_status = availability_receipt
        .as_ref()
        .and_then(|receipt| json_string(receipt, "availability_status"))
        .unwrap_or("missing_or_invalid");
    let pit_house_available = availability_receipt
        .as_ref()
        .and_then(|receipt| receipt.get("pit_house_available").and_then(Value::as_bool))
        .unwrap_or(false);
    let official_download_page = availability_receipt
        .as_ref()
        .and_then(|receipt| json_string(receipt, "official_download_page"))
        .unwrap_or(MOZA_PIT_HOUSE_DOWNLOADS_URL);
    let install_guidance = availability_receipt
        .as_ref()
        .and_then(|receipt| json_string(receipt, "install_guidance"))
        .unwrap_or(MOZA_PIT_HOUSE_INSTALL_GUIDANCE);

    let mut recorded_cases = Vec::new();
    let mut missing_cases = Vec::new();
    let mut observation_only_cases = Vec::new();
    for (case_id, label, case_artifact, observation_artifact) in
        pit_house_case_navigation_requirements()
    {
        let case_recorded = pit_house_case_receipt_is_safe(lane, case_artifact, case_id);
        let observation_recorded =
            pit_house_observation_receipt_is_safe(lane, observation_artifact, case_id);
        let entry = serde_json::json!({
            "case": case_id,
            "label": label,
            "case_artifact": case_artifact,
            "observation_artifact": observation_artifact,
            "case_recorded": case_recorded,
            "observation_recorded": observation_recorded,
            "readiness_claim": false
        });
        if case_recorded {
            recorded_cases.push(entry);
        } else {
            missing_cases.push(case_id.to_string());
            if observation_recorded {
                observation_only_cases.push(entry);
            }
        }
    }

    let parent_gate = verify_pit_house_coexistence_gate_with_support_validation(
        lane,
        SupportBundleValidationMode::Fresh,
    );
    let parent_claimed = parent_gate.status == "pass";
    let required_case_count = pit_house_case_navigation_requirements().len() as u64;
    let recorded_case_count = recorded_cases.len() as u64;
    serde_json::json!({
        "artifact_kind": "pit_house_external_compatibility_navigation",
        "claim_scope": "external_compatibility_navigation_only",
        "availability_artifact": availability_artifact,
        "availability_artifact_exists": lane.join(availability_artifact).is_file(),
        "availability_receipt_valid": availability_receipt_valid,
        "availability_status": availability_status,
        "pit_house_available": pit_house_available,
        "official_download_page": official_download_page,
        "install_guidance": install_guidance,
        "coexistence_artifact": "pit-house-coexistence.json",
        "pit_house_coexistence_claimed": parent_claimed,
        "coexistence_gate_status": parent_gate.status,
        "coexistence_gate_details": parent_gate.details,
        "required_case_count": required_case_count,
        "recorded_case_count": recorded_case_count,
        "missing_case_count": required_case_count.saturating_sub(recorded_case_count),
        "recorded_cases": recorded_cases,
        "observation_only_cases": observation_only_cases,
        "missing_cases": missing_cases,
        "blocks_native_control": false,
        "blocks_native_visible": false,
        "blocks_smoke_ready": !parent_claimed,
        "readiness_claim": false,
        "no_hid_device_opened": true,
        "no_ffb_writes": true,
        "no_output_reports": true,
        "no_feature_reports": true,
        "no_serial_config_commands": true,
        "no_firmware_or_dfu_commands": true,
        "notes": [
            "Pit House compatibility is external smoke evidence only; it is not a native-control prerequisite.",
            "Pit House install/source guidance is operator navigation only and does not prove coexistence.",
            "Availability and case receipts are navigation evidence until pit-house-coexistence.json passes the verifier.",
            "If Pit House is absent, keep open-state cases and smoke-ready blocked instead of fabricating evidence."
        ]
    })
}

fn moza_simulator_compatibility_summary(lane: &Path) -> Value {
    let telemetry_artifact = "simulator-telemetry-proof.json";
    let ffb_artifact = "simulator-ffb-smoke.json";
    let telemetry_receipt = read_json_value(lane, telemetry_artifact).ok();
    let ffb_receipt = read_json_value(lane, ffb_artifact).ok();
    let telemetry_gate = verify_simulator_telemetry_gate(lane);
    let ffb_gate = verify_simulator_ffb_gate(lane);
    let telemetry_claimed = telemetry_gate.status == "pass";
    let ffb_claimed = ffb_gate.status == "pass";
    let telemetry_artifact_exists = lane.join(telemetry_artifact).is_file();
    let ffb_artifact_exists = lane.join(ffb_artifact).is_file();
    let recorded_artifact_count = (telemetry_artifact_exists as u64) + (ffb_artifact_exists as u64);
    let missing_artifacts = [
        (telemetry_artifact, telemetry_artifact_exists),
        (ffb_artifact, ffb_artifact_exists),
    ]
    .into_iter()
    .filter(|(_, exists)| !exists)
    .map(|(artifact, _)| Value::String(artifact.to_string()))
    .collect::<Vec<_>>();

    serde_json::json!({
        "artifact_kind": "simulator_external_compatibility_navigation",
        "claim_scope": "external_compatibility_navigation_only",
        "telemetry": {
            "artifact": telemetry_artifact,
            "artifact_exists": telemetry_artifact_exists,
            "gate_status": telemetry_gate.status,
            "gate_details": telemetry_gate.details,
            "claim_status": simulator_navigation_claim_status(
                telemetry_artifact_exists,
                telemetry_claimed,
            ),
            "simulator_telemetry_claimed": telemetry_claimed,
            "readiness_claim": false,
            "game": telemetry_claimed.then(|| telemetry_receipt
                .as_ref()
                .and_then(|receipt| json_string(receipt, "game"))).flatten(),
            "telemetry_source": telemetry_claimed.then(|| telemetry_receipt
                .as_ref()
                .and_then(|receipt| json_string(receipt, "telemetry_source"))).flatten(),
            "recorder_artifact": telemetry_claimed.then(|| telemetry_receipt
                .as_ref()
                .and_then(|receipt| json_string(receipt, "recorder_artifact")
                    .or_else(|| json_string(receipt, "normalized_snapshot_artifact")))).flatten(),
            "normalized_snapshot_count": telemetry_claimed.then(|| telemetry_receipt
                .as_ref()
                .and_then(|receipt| json_u64(receipt, "normalized_snapshot_count")
                    .or_else(|| json_u64(receipt, "snapshots_recorded")))).flatten(),
            "hardware_output_enabled": telemetry_claimed.then(|| telemetry_receipt
                .as_ref()
                .and_then(|receipt| json_bool(receipt, "hardware_output_enabled"))).flatten(),
            "no_ffb_writes": telemetry_claimed.then(|| telemetry_receipt
                .as_ref()
                .and_then(|receipt| json_bool(receipt, "no_ffb_writes"))).flatten(),
        },
        "bounded_ffb": {
            "artifact": ffb_artifact,
            "artifact_exists": ffb_artifact_exists,
            "gate_status": ffb_gate.status,
            "gate_details": ffb_gate.details,
            "claim_status": simulator_navigation_claim_status(ffb_artifact_exists, ffb_claimed),
            "bounded_simulator_ffb_claimed": ffb_claimed,
            "readiness_claim": false,
            "game": ffb_claimed.then(|| ffb_receipt
                .as_ref()
                .and_then(|receipt| json_string(receipt, "game"))).flatten(),
            "telemetry_source": ffb_claimed.then(|| ffb_receipt
                .as_ref()
                .and_then(|receipt| json_string(receipt, "telemetry_source"))).flatten(),
            "output_log_artifact": ffb_claimed.then(|| ffb_receipt
                .as_ref()
                .and_then(|receipt| json_string(receipt, "output_log_artifact")
                    .or_else(|| json_string(receipt, "output_receipt_artifact")))).flatten(),
            "max_output_percent": ffb_claimed.then(|| ffb_receipt
                .as_ref()
                .and_then(|receipt| json_f64(receipt, "max_output_percent")
                    .or_else(|| json_f64(receipt, "max_percent"))
                    .or_else(|| json_f64(receipt, "max_command_percent")))).flatten(),
            "hardware_output_enabled": ffb_claimed.then(|| ffb_receipt
                .as_ref()
                .and_then(|receipt| json_bool(receipt, "hardware_output_enabled"))).flatten(),
            "final_zero_sent": ffb_claimed.then(|| ffb_receipt
                .as_ref()
                .and_then(|receipt| json_bool(receipt, "final_zero_sent"))).flatten(),
        },
        "simulator_telemetry_claimed": telemetry_claimed,
        "bounded_simulator_ffb_claimed": ffb_claimed,
        "required_artifact_count": 2,
        "recorded_artifact_count": recorded_artifact_count,
        "missing_artifacts": missing_artifacts,
        "blocks_native_control": false,
        "blocks_native_visible": false,
        "blocks_smoke_ready": !(telemetry_claimed && ffb_claimed),
        "readiness_claim": false,
        "no_hid_device_opened": true,
        "no_ffb_writes": true,
        "no_output_reports": true,
        "no_feature_reports": true,
        "no_serial_config_commands": true,
        "no_firmware_or_dfu_commands": true,
        "notes": [
            "Simulator telemetry and bounded simulator FFB are smoke/external compatibility evidence; they are not native-control prerequisites.",
            "Telemetry-only proof must remain no-output and cannot satisfy bounded FFB by itself.",
            "Bounded simulator FFB can claim smoke evidence only after the telemetry gate and all safety prerequisites pass."
        ]
    })
}

fn moza_passive_sniff_navigation_summary(lane: &Path) -> Value {
    let mut scenarios = Vec::new();
    let mut recorded_scenarios = Vec::new();
    let mut missing_scenarios = Vec::new();
    let mut next_passive_gap: Option<(&'static str, &'static str, &'static str, &'static str)> =
        None;
    for (scenario, label, focus, warning) in moza_passive_sniff_navigation_requirements() {
        let committed_dir = moza_passive_sniff_committed_dir(lane, scenario);
        let plan_artifact = committed_dir.join("sniff-plan.json");
        let receipt_artifact = committed_dir.join("sniff-receipt.json");
        let summary_artifact = committed_dir.join("sniff-summary.json");
        let bundle_manifest_artifact = committed_dir.join("sniff-bundle-manifest.json");
        let low_yield_classification_artifact =
            committed_dir.join(PASSIVE_SNIFF_LOW_YIELD_CLASSIFICATION_FILE);
        let plan_status =
            passive_sniff_artifact_status(&plan_artifact, "wheelctl hardware sniff-plan");
        let receipt_status =
            passive_sniff_artifact_status(&receipt_artifact, "wheelctl hardware sniff-receipt");
        let summary_status =
            passive_sniff_artifact_status(&summary_artifact, "wheelctl hardware sniff-summary");
        let bundle_manifest_status = passive_sniff_artifact_status(
            &bundle_manifest_artifact,
            "wheelctl hardware sniff-bundle",
        );
        let low_yield_classification_status = passive_sniff_low_yield_classification_status(
            &low_yield_classification_artifact,
            scenario,
        );
        let low_yield_capture_recorded = matches!(
            low_yield_classification_status,
            "present_low_yield_incomplete"
        );
        let scenario_recorded = matches!(plan_status, "present_non_claiming")
            && matches!(receipt_status, "present_non_claiming")
            && matches!(summary_status, "present_non_claiming");
        let scenario_status = if scenario_recorded {
            recorded_scenarios.push(Value::String((*scenario).to_string()));
            "summary_recorded"
        } else if low_yield_capture_recorded {
            if next_passive_gap.is_none() {
                next_passive_gap = Some((*scenario, *label, *focus, *warning));
            }
            missing_scenarios.push(Value::String((*scenario).to_string()));
            "low_yield_incomplete"
        } else {
            if next_passive_gap.is_none() {
                next_passive_gap = Some((*scenario, *label, *focus, *warning));
            }
            missing_scenarios.push(Value::String((*scenario).to_string()));
            if plan_artifact.is_file()
                || receipt_artifact.is_file()
                || summary_artifact.is_file()
                || low_yield_classification_artifact.is_file()
            {
                "partial_or_unaccepted"
            } else {
                "missing"
            }
        };
        scenarios.push(serde_json::json!({
            "scenario": scenario,
            "label": label,
            "focus": focus,
            "warning": warning,
            "status": scenario_status,
            "recorded": scenario_recorded,
            "navigation_blocker_only": !scenario_recorded,
            "plan_artifact": plan_artifact.display().to_string(),
            "plan_status": plan_status,
            "receipt_artifact": receipt_artifact.display().to_string(),
            "receipt_status": receipt_status,
            "summary_artifact": summary_artifact.display().to_string(),
            "summary_status": summary_status,
            "bundle_manifest_artifact": bundle_manifest_artifact.display().to_string(),
            "bundle_manifest_status": bundle_manifest_status,
            "low_yield_classification_artifact": low_yield_classification_artifact.display().to_string(),
            "low_yield_classification_status": low_yield_classification_status,
            "low_yield_capture_recorded": low_yield_capture_recorded,
            "readiness_claim": false,
            "blocks_native_control": false,
            "blocks_native_visible": false,
            "blocks_smoke_ready": false,
        }));
    }
    let required_scenario_count = moza_passive_sniff_navigation_requirements().len() as u64;
    let recorded_scenario_count = recorded_scenarios.len() as u64;
    let next_passive_gap = next_passive_gap.map(|(scenario, label, focus, warning)| {
        serde_json::json!({
            "scenario": scenario,
            "label": label,
            "focus": focus,
            "warning": warning,
            "next_physical_operator_step": true,
            "capture_required": true,
            "hardware_output_authorized": false,
            "native_control_evidence": false,
            "native_visible_ready": false,
            "smoke_ready": false,
            "release_ready": false
        })
    });
    serde_json::json!({
        "artifact_kind": "moza_passive_sniff_navigation",
        "claim_scope": "protocol_research_support_navigation_only",
        "evidence_status": "passive_external_usb_observation",
        "protocol_research_only": true,
        "support_evidence_only": true,
        "hardware_output_authorized": false,
        "native_control_evidence": false,
        "openracing_hardware_output": false,
        "external_app_may_have_sent_output": true,
        "required_scenario_count": required_scenario_count,
        "recorded_scenario_count": recorded_scenario_count,
        "missing_scenario_count": required_scenario_count.saturating_sub(recorded_scenario_count),
        "recorded_scenarios": recorded_scenarios,
        "missing_scenarios": missing_scenarios,
        "next_passive_gap": next_passive_gap,
        "scenarios": scenarios,
        "recommended_local_root": "target/sniff",
        "recommended_committed_root": moza_passive_sniff_committed_root(lane)
            .map(|path| path.display().to_string()),
        "blocks_native_control": false,
        "blocks_native_visible": false,
        "blocks_smoke_ready": false,
        "readiness_claim": false,
        "satisfies_native_response_ready": false,
        "satisfies_native_visible_ready": false,
        "satisfies_smoke_ready": false,
        "satisfies_release_ready": false,
        "no_hid_device_opened": true,
        "no_ffb_writes": true,
        "no_output_reports": true,
        "no_feature_reports": true,
        "no_serial_config_commands": true,
        "no_firmware_or_dfu_commands": true,
        "notes": [
            "Passive USB sniffing is protocol research/support navigation only; it is not OpenRacing hardware output.",
            "Missing sniff scenarios do not block native response, native visible motion, smoke-ready, or release-ready gates.",
            "External apps observed during sniffing may send output, but that traffic is not OpenRacing output evidence."
        ]
    })
}

fn passive_sniff_artifact_status(path: &Path, expected_command: &str) -> &'static str {
    if !path.is_file() {
        return "missing";
    }
    match read_json_path(path) {
        Ok(value)
            if passive_sniff_artifact_is_non_claiming(&value, expected_command)
                && passive_sniff_artifact_success_is_accepted(&value) =>
        {
            "present_non_claiming"
        }
        Ok(_) => "present_not_accepted",
        Err(_) => "invalid_json",
    }
}

fn passive_sniff_artifact_success_is_accepted(value: &Value) -> bool {
    json_bool(value, "success") == Some(true)
}

fn passive_sniff_artifact_is_non_claiming(value: &Value, expected_command: &str) -> bool {
    let carries_required_plan_handoff = expected_command != "wheelctl hardware sniff-plan"
        || (json_array_contains_string(
            value,
            "pre_capture_checklist",
            "keep OpenRacing hardware output commands stopped for this passive capture",
        ) && json_array_contains_string(
            value,
            "pre_capture_checklist",
            "keep firmware, update, DFU, driver replacement, Zadig, and WinUSB conversion flows closed",
        ) && json_array_contains_string(
            value,
            "post_capture_checklist",
            "record operator notes before bundling",
        ) && json_array_contains_string(
            value,
            "post_capture_checklist",
            PASSIVE_SNIFF_POST_CAPTURE_EVIDENCE_COMMANDS_CHECKLIST_ITEM,
        ) && json_array_contains_string(
            value,
            "post_capture_checklist",
            "do not commit raw pcapng unless it is separately reviewed for size, sensitivity, and operator consent",
        ) && json_array_contains_string(
            value,
            "operator_notes_required",
            "scenario performed",
        ) && json_array_contains_string(
            value,
            "operator_notes_required",
            "device stack attached",
        ) && json_array_contains_string(
            value,
            "operator_notes_required",
            "whether firmware/update/DFU pages stayed closed",
        ) && json_bool(value, "raw_pcap_commit_default") == Some(false));

    carries_required_plan_handoff
        && json_string(value, "command") == Some(expected_command)
        && json_bool(value, "native_control_evidence") == Some(false)
        && json_bool(value, "openracing_hardware_output") == Some(false)
        && json_bool(value, "satisfies_native_response_ready") == Some(false)
        && json_bool(value, "satisfies_native_visible_ready") == Some(false)
        && json_bool(value, "satisfies_smoke_ready") == Some(false)
        && json_bool(value, "satisfies_release_ready") == Some(false)
}

fn passive_sniff_low_yield_classification_status(path: &Path, scenario: &str) -> &'static str {
    if !path.is_file() {
        return "missing";
    }
    match read_json_path(path) {
        Ok(value) if passive_sniff_low_yield_classification_is_valid(&value, scenario) => {
            "present_low_yield_incomplete"
        }
        Ok(_) => "present_not_accepted",
        Err(_) => "invalid_json",
    }
}

fn passive_sniff_low_yield_classification_is_valid(value: &Value, scenario: &str) -> bool {
    json_string(value, "artifact_kind")
        == Some("moza_passive_sniff_low_yield_capture_classification")
        && json_string(value, "scenario") == Some(scenario)
        && json_string(value, "classification") == Some("low_yield_incomplete_capture")
        && json_bool(value, "accepted_protocol_evidence") == Some(false)
        && json_bool(value, "setting_change_protocol_evidence") == Some(false)
        && json_bool(value, "pit_house_setting_change_complete") == Some(false)
        && json_bool(value, "native_control_evidence") == Some(false)
        && json_bool(value, "hardware_output_authorized") == Some(false)
        && json_bool(value, "native_visible_ready") == Some(false)
        && json_bool(value, "smoke_ready") == Some(false)
        && json_bool(value, "release_ready") == Some(false)
        && value
            .get("next_allowed_actions")
            .and_then(Value::as_array)
            .is_some_and(|actions| !actions.is_empty())
        && value
            .get("blocked_actions")
            .and_then(Value::as_array)
            .is_some_and(|actions| !actions.is_empty())
        && value
            .get("required_artifacts")
            .and_then(Value::as_array)
            .is_some_and(|artifacts| !artifacts.is_empty())
}

fn json_array_contains_string(value: &Value, field: &str, expected: &str) -> bool {
    value
        .get(field)
        .and_then(Value::as_array)
        .is_some_and(|items| items.iter().any(|item| item.as_str() == Some(expected)))
}

fn moza_passive_sniff_committed_dir(lane: &Path, scenario: &str) -> PathBuf {
    moza_passive_sniff_committed_root(lane)
        .unwrap_or_else(|| lane.join("sniff"))
        .join(scenario)
}

fn moza_passive_sniff_committed_root(lane: &Path) -> Option<PathBuf> {
    let date = lane.file_name()?.to_str()?;
    let family_dir = lane.parent()?;
    let family = family_dir.file_name()?.to_str()?;
    let hardware_root = family_dir.parent()?;
    if hardware_root.file_name().and_then(|name| name.to_str()) != Some("hardware") {
        return None;
    }
    Some(hardware_root.join("sniff").join(family).join(date))
}

