async fn authorize_visible_output(request: AuthorizeVisibleOutputRequest<'_>) -> Result<()> {
    let AuthorizeVisibleOutputRequest {
        json,
        lane,
        selector,
        operator,
        bench_clear_evidence,
        ffb_mode_evidence,
        prior_actuator_proof,
        steering_proof,
        profile,
        strategy,
        max_percent,
        duration_ms,
        movement_threshold_degrees,
        preserve_receipt,
        planned_output,
        json_out,
        overwrite,
    } = request;

    validate_actuator_visible_smoke_args(
        profile,
        strategy,
        max_percent,
        duration_ms,
        20,
        1080.0,
        movement_threshold_degrees,
    )?;
    validate_lane_manifest_endpoint_selector(
        lane,
        Some(selector),
        "native visible-motion output authorization",
    )?;
    if let Some(path) = prior_actuator_proof {
        require_lane_artifact_path(
            lane,
            path,
            "native-actuator-profile-smoke.json",
            "--prior-actuator-proof",
        )?;
    }
    if let Some(path) = steering_proof {
        require_lane_artifact_path(
            lane,
            path,
            "steering-angle-stream-proof.json",
            "--steering-proof",
        )?;
    }

    let prior_receipt = failed_real_native_visible_smoke_receipt(lane).ok_or_else(|| {
        anyhow!(
            "{} requires an existing real response-only native-actuator-visible-smoke.json receipt",
            "wheelctl moza authorize-visible-output"
        )
    })?;
    let mut plan =
        read_json_value(lane, NATIVE_VISIBLE_FOLLOW_UP_PLAN_FILE).with_context(|| {
            format!(
                "failed to read required follow-up plan {}",
                lane.join(NATIVE_VISIBLE_FOLLOW_UP_PLAN_FILE).display()
            )
        })?;
    let expected_plan_path = lane.join(NATIVE_VISIBLE_FOLLOW_UP_PLAN_FILE);
    let plan_path = json_out
        .map(Path::to_path_buf)
        .unwrap_or_else(|| expected_plan_path.clone());
    if !path_value_matches(&expected_plan_path, Some(&plan_path.display().to_string())) {
        return Err(anyhow!(
            "--json-out '{}' must resolve to same-lane artifact '{}'",
            plan_path.display(),
            expected_plan_path.display()
        ));
    }
    if json_bool(&plan, "hardware_output_authorized") == Some(true) && !overwrite {
        return Err(anyhow!(
            "{} already authorizes hardware output; pass --overwrite only after re-reviewing the exact command",
            NATIVE_VISIBLE_FOLLOW_UP_PLAN_FILE
        ));
    }

    let current_visible_path = lane.join(NATIVE_ACTUATOR_VISIBLE_SMOKE_FILE);
    let planned_output_path = planned_output
        .map(|path| lane_output_artifact_path(lane, path))
        .transpose()?
        .unwrap_or_else(|| current_visible_path.clone());
    let planned_output_file =
        native_visible_output_relative_path(lane, &planned_output_path, "--planned-output")?;
    let replaces_live_visible_receipt = planned_output_file == NATIVE_ACTUATOR_VISIBLE_SMOKE_FILE;
    if planned_output_file == VENDOR_AUTHORITY_POST_PIDFF_SMOKE_FILE {
        validate_post_authority_pidff_smoke_context(lane)?;
        if planned_output_path.exists() && !overwrite {
            return Err(anyhow!(
                "{} already exists; pass --overwrite only after confirming the post-authority PIDFF response receipt can be replaced",
                planned_output_path.display()
            ));
        }
    }

    let preserved_path = if replaces_live_visible_receipt {
        let preserved_path = preserve_receipt
            .map(|path| lane_output_artifact_path(lane, path))
            .transpose()?
            .unwrap_or_else(|| lane.join(NATIVE_ACTUATOR_VISIBLE_RESPONSE_ONLY_FILE));
        if path_value_matches(
            &current_visible_path,
            Some(&preserved_path.display().to_string()),
        ) {
            return Err(anyhow!(
                "--preserve-receipt must not point at the live replacement receipt '{}'",
                current_visible_path.display()
            ));
        }
        if preserved_path.exists() && !overwrite {
            return Err(anyhow!(
                "{} already exists; pass --overwrite only after confirming it is the same preserved response-only receipt",
                preserved_path.display()
            ));
        }
        if let Some(parent) = preserved_path
            .parent()
            .filter(|parent| !parent.as_os_str().is_empty())
        {
            fs::create_dir_all(parent)
                .with_context(|| format!("failed to create '{}'", parent.display()))?;
        }
        fs::copy(&current_visible_path, &preserved_path).with_context(|| {
            format!(
                "failed to preserve response-only receipt '{}' as '{}'",
                current_visible_path.display(),
                preserved_path.display()
            )
        })?;
        preserved_path
    } else {
        if preserve_receipt.is_some() {
            return Err(anyhow!(
                "--preserve-receipt is only valid when --planned-output replaces '{}'",
                current_visible_path.display()
            ));
        }
        lane.join(NATIVE_ACTUATOR_VISIBLE_RESPONSE_ONLY_FILE)
    };

    let planned_command = native_visible_output_command(
        lane,
        selector,
        profile,
        strategy,
        max_percent,
        duration_ms,
        movement_threshold_degrees,
        planned_output_file,
    );
    validate_authorized_native_visible_command(
        lane,
        &planned_command,
        selector,
        profile,
        strategy,
        max_percent,
        duration_ms,
        movement_threshold_degrees,
        &planned_output_path,
    )?;

    let authorized_at = now_utc();
    plan["command"] = serde_json::json!("wheelctl moza authorize-visible-output");
    plan["evidence_status"] = serde_json::json!("exact_output_authorized_pending_run");
    plan["review_decision"] =
        serde_json::json!("exact_output_command_authorized_after_fresh_bench_clear");
    plan["hardware_output_authorized"] = serde_json::json!(true);
    plan["force_escalation_authorized"] = serde_json::json!(false);
    plan["authorized_at_utc"] = serde_json::json!(authorized_at);
    plan["authorized_by"] = serde_json::json!(operator);
    plan["bench_clear_evidence"] = serde_json::json!(bench_clear_evidence);
    plan["ffb_mode_review_evidence"] = serde_json::json!(ffb_mode_evidence);
    plan["authorization_recorded"] = serde_json::json!(true);
    plan["success"] = serde_json::json!(false);
    plan["template"] = serde_json::json!(false);
    plan["prior_receipt_preserved_artifact"] =
        serde_json::json!(lane_relative_or_display(lane, &preserved_path));
    plan["planned_next_output"] = serde_json::json!({
        "allowed": true,
        "command": planned_command,
        "profile": actuator_profile_cli_name(profile),
        "strategy": low_torque_strategy_cli_name(strategy),
        "duration_ms": duration_ms,
        "force_percent": max_percent,
        "movement_threshold_degrees": movement_threshold_degrees,
        "operator": operator,
        "authorized_at_utc": plan["authorized_at_utc"].clone(),
        "must_preserve_failed_receipt": replaces_live_visible_receipt,
        "preserved_receipt": lane_relative_or_display(lane, &preserved_path),
        "planned_output": planned_output_file,
        "post_authority_pidff_response_capture": planned_output_file == VENDOR_AUTHORITY_POST_PIDFF_SMOKE_FILE,
        "requires_fresh_bench_clear": false
    });
    update_native_visible_authorization_checks(
        &mut plan,
        bench_clear_evidence,
        ffb_mode_evidence,
        &preserved_path,
    );
    plan["notes"] = serde_json::json!([
        "Authorization artifact only: this file is not evidence that visible motion passed.",
        if replaces_live_visible_receipt {
            "The response-only visible-motion receipt was preserved before authorizing replacement."
        } else {
            "The post-authority PIDFF response command writes a separate receipt and does not replace native-visible evidence."
        },
        "The planned output command is exact and remains capped at 5 percent for up to 2000 ms through descriptor-proven PIDFF bounded-effect reports."
    ]);
    plan["observed_failure_summary"]["preserved_receipt"] =
        serde_json::json!(lane_relative_or_display(lane, &preserved_path));
    plan["observed_failure_summary"]["prior_angle_delta_degrees"] =
        serde_json::json!(json_f64(&prior_receipt, "angle_delta_degrees"));

    write_json_file(&plan_path, &plan)?;
    print_authorize_visible_output_receipt(json, &plan_path, &plan)
}

async fn authorize_controlled_angle_output(
    request: AuthorizeControlledAngleOutputRequest<'_>,
) -> Result<()> {
    let AuthorizeControlledAngleOutputRequest {
        json,
        lane,
        selector,
        operator,
        bench_clear_evidence,
        prior_response_proof,
        prior_actuator_proof,
        steering_proof,
        controlled_angle_preflight,
        planned_output,
        target_degrees,
        profile,
        strategy,
        max_percent,
        timeout_ms,
        json_out,
        overwrite,
    } = request;

    validate_controlled_angle_smoke_args(
        strategy,
        target_degrees,
        max_percent,
        timeout_ms,
        20,
        1080.0,
    )?;
    validate_controlled_angle_actual_output_limits(target_degrees, max_percent, timeout_ms)?;
    validate_controlled_angle_bench_clear_evidence(bench_clear_evidence, profile)?;
    validate_lane_manifest_endpoint_selector(
        lane,
        Some(selector),
        "native controlled-angle output authorization",
    )?;
    if let Some(path) = prior_response_proof {
        require_lane_artifact_path(
            lane,
            path,
            "native-actuator-visible-smoke.json",
            "--prior-response-proof",
        )?;
    }
    if let Some(path) = prior_actuator_proof {
        require_lane_artifact_path(
            lane,
            path,
            "native-actuator-profile-smoke.json",
            "--prior-actuator-proof",
        )?;
    }
    if let Some(path) = steering_proof {
        require_lane_artifact_path(
            lane,
            path,
            "steering-angle-stream-proof.json",
            "--steering-proof",
        )?;
    }
    let preflight_file =
        controlled_angle_preflight_relative_path(lane, controlled_angle_preflight)?;
    let planned_output_file = match planned_output {
        Some(path) => controlled_angle_output_relative_path(lane, path, "--planned-output")?,
        None if preflight_file == NATIVE_CONTROLLED_ANGLE_RETRY_PREFLIGHT_FILE => {
            NATIVE_CONTROLLED_ANGLE_RETRY_SMOKE_FILE
        }
        None if preflight_file == NATIVE_CONTROLLED_ANGLE_ATTEMPT_03_PREFLIGHT_FILE => {
            NATIVE_CONTROLLED_ANGLE_ATTEMPT_03_SMOKE_FILE
        }
        None if preflight_file == NATIVE_CONTROLLED_ANGLE_CLOSED_LOOP_PREFLIGHT_FILE => {
            NATIVE_CONTROLLED_ANGLE_CLOSED_LOOP_SMOKE_FILE
        }
        None => NATIVE_CONTROLLED_ANGLE_SMOKE_FILE,
    };
    if planned_output_file != NATIVE_CONTROLLED_ANGLE_SMOKE_FILE
        && controlled_angle_preflight.is_none()
    {
        return Err(anyhow!(
            "--controlled-angle-preflight is required when --planned-output uses {planned_output_file}; preserve earlier controlled-angle receipts and use the matching no-output preflight artifact"
        ));
    }

    let response_gate = verify_native_actuator_response_smoke_gate(lane);
    if response_gate.status != "pass" {
        return Err(anyhow!(
            "native controlled-angle output authorization requires a passing native actuator-response receipt: {}",
            response_gate.details
        ));
    }
    let prior_response = read_json_value(lane, "native-actuator-visible-smoke.json")?;
    let controlled_angle_plan = validate_native_controlled_angle_plan_artifact(lane)?;
    let effect_lifecycle_plan = if controlled_angle_profile_requires_effect_lifecycle_plan(profile)
    {
        Some(validate_native_pidff_effect_lifecycle_plan_artifact(lane)?)
    } else {
        None
    };
    let controlled_angle_preflight = validate_native_controlled_angle_dry_run_preflight(
        lane,
        preflight_file,
        selector,
        target_degrees,
        profile,
        strategy,
        max_percent,
    )?;

    let default_authorization_file =
        if planned_output_file == NATIVE_CONTROLLED_ANGLE_RETRY_SMOKE_FILE {
            NATIVE_CONTROLLED_ANGLE_RETRY_AUTHORIZATION_FILE
        } else if planned_output_file == NATIVE_CONTROLLED_ANGLE_ATTEMPT_03_SMOKE_FILE {
            NATIVE_CONTROLLED_ANGLE_ATTEMPT_03_AUTHORIZATION_FILE
        } else if planned_output_file == NATIVE_CONTROLLED_ANGLE_CLOSED_LOOP_SMOKE_FILE {
            NATIVE_CONTROLLED_ANGLE_CLOSED_LOOP_AUTHORIZATION_FILE
        } else {
            NATIVE_CONTROLLED_ANGLE_AUTHORIZATION_FILE
        };
    let expected_plan_path = lane.join(default_authorization_file);
    let plan_path = json_out
        .map(Path::to_path_buf)
        .unwrap_or_else(|| expected_plan_path.clone());
    let authorization_file = require_one_of_lane_artifact_paths(
        lane,
        &plan_path,
        NATIVE_CONTROLLED_ANGLE_AUTHORIZATION_FILES,
        "--json-out",
    )?;
    if authorization_file != default_authorization_file {
        return Err(anyhow!(
            "--json-out '{}' must resolve to same-lane artifact '{}' for planned output '{}'",
            plan_path.display(),
            expected_plan_path.display(),
            lane.join(planned_output_file).display()
        ));
    }
    if plan_path.exists() && !overwrite {
        return Err(anyhow!(
            "{} already exists; pass --overwrite only after re-reviewing the exact controlled-angle command",
            plan_path.display()
        ));
    }

    let output_path = lane.join(planned_output_file);
    let authorization_proof_arg = (authorization_file
        != NATIVE_CONTROLLED_ANGLE_AUTHORIZATION_FILE)
        .then_some(authorization_file);
    let planned_command = native_controlled_angle_output_command(
        lane,
        selector,
        target_degrees,
        profile,
        strategy,
        max_percent,
        timeout_ms,
        planned_output_file,
        authorization_proof_arg,
    );
    validate_authorized_native_controlled_angle_command(
        lane,
        &planned_command,
        selector,
        target_degrees,
        profile,
        max_percent,
        timeout_ms,
        strategy,
        &output_path,
        authorization_proof_arg,
    )?;

    let authorized_at = now_utc();
    let mut receipt = serde_json::json!({
        "success": false,
        "command": "wheelctl moza authorize-controlled-angle-output",
        "generated_at_utc": authorized_at,
        "lane": lane.display().to_string(),
        "selector": selector,
        "authorization_recorded": true,
        "authorization_consumed": false,
        "hardware_output_authorized": true,
        "force_escalation_authorized": false,
        "authorized_by": operator,
        "bench_clear_evidence": bench_clear_evidence,
        "no_hid_device_opened": true,
        "no_feature_reports": true,
        "no_output_reports": true,
        "no_ffb_writes": true,
        "no_direct_torque_reports": true,
        "no_high_torque": true,
        "high_torque": false,
        "no_serial_config_commands": true,
        "no_firmware_or_dfu_commands": true,
        "prior_response_receipt": {
            "path": "native-actuator-visible-smoke.json",
            "gate": response_gate.status,
            "angle_delta_degrees": json_f64(&prior_response, "angle_delta_degrees"),
            "movement_threshold_degrees": json_f64(&prior_response, "movement_threshold_degrees"),
            "movement_observed": json_bool(&prior_response, "movement_observed"),
            "final_stop_all_sent": json_bool(&prior_response, "final_stop_all_sent"),
            "post_stop_stable": json_bool(&prior_response, "post_stop_stable"),
            "no_direct_torque_reports": json_bool(&prior_response, "no_direct_torque_reports"),
            "no_high_torque": json_bool(&prior_response, "no_high_torque")
        },
        "controlled_angle_plan_artifact": {
            "path": NATIVE_CONTROLLED_ANGLE_PLAN_FILE,
            "command_ok": json_string(&controlled_angle_plan, "command")
                == Some("wheelctl moza receipt-template"),
            "no_output_ok": native_controlled_angle_plan_no_output_ok(&controlled_angle_plan),
            "ladder_ok": native_controlled_angle_plan_ladder_ok(&controlled_angle_plan),
            "retry_profile_ok": native_controlled_angle_plan_retry_profile_ok(&controlled_angle_plan),
            "review_scope": json_string(&controlled_angle_plan, "review_scope")
        },
        "controlled_angle_preflight_receipt": {
            "path": preflight_file,
            "dry_run": json_bool(&controlled_angle_preflight, "dry_run"),
            "preflight_only": json_bool(&controlled_angle_preflight, "preflight_only"),
            "target_degrees": json_f64(&controlled_angle_preflight, "target_degrees"),
            "max_percent": json_f64(&controlled_angle_preflight, "max_percent"),
            "safety_timeout_ms": json_u64(&controlled_angle_preflight, "safety_timeout_ms"),
            "no_hid_device_opened": json_bool(&controlled_angle_preflight, "no_hid_device_opened"),
            "no_output_reports": json_bool(&controlled_angle_preflight, "no_output_reports"),
            "no_ffb_writes": json_bool(&controlled_angle_preflight, "no_ffb_writes")
        },
        "planned_next_output": {
            "allowed": true,
            "requires_fresh_bench_clear": false,
            "command": planned_command,
            "target_degrees": target_degrees,
            "max_percent": max_percent,
            "force_percent": max_percent,
            "timeout_ms": timeout_ms,
            "duration_ms": timeout_ms,
            "strategy": low_torque_strategy_cli_name(strategy),
            "prior_response_proof": "native-actuator-visible-smoke.json",
            "prior_actuator_proof": "native-actuator-profile-smoke.json",
            "steering_proof": "steering-angle-stream-proof.json",
            "json_out": planned_output_file,
            "authorization_proof": authorization_file,
            "operator": operator,
            "authorized_at_utc": authorized_at
        },
        "required_before_output": [
            {
                "check": "native_actuator_response_smoke",
                "status": "passed",
                "evidence": response_gate.details
            },
            {
                "check": "controlled_angle_plan",
                "status": "passed",
                "evidence": NATIVE_CONTROLLED_ANGLE_PLAN_FILE
            },
            {
                "check": "controlled_angle_dry_run_preflight",
                "status": "passed",
                "evidence": preflight_file
            },
            {
                "check": "fresh_operator_bench_clear_for_exact_controlled_angle_command",
                "status": "passed",
                "evidence": bench_clear_evidence
            }
        ],
        "notes": [
            "Authorization artifact only: this file is not evidence that controlled-angle motion passed.",
            "The planned output command is exact and permits one feedback-bounded 1 degree controlled-angle attempt.",
            "No direct report 0x20, high torque, serial config, firmware, DFU, Pit House, SimHub, or simulator evidence is required for this native controlled-angle authorization."
        ]
    });
    receipt["profile"] = serde_json::json!(controlled_angle_profile_name(profile));
    receipt["profile_cli"] = serde_json::json!(controlled_angle_profile_cli_name(profile));
    if let Some(plan) = effect_lifecycle_plan.as_ref() {
        receipt["pidff_effect_lifecycle_plan_artifact"] =
            native_pidff_effect_lifecycle_plan_summary(plan);
    }
    if matches!(profile, MozaControlledAngleProfile::ClosedLoopPidffAngleV1) {
        receipt["closed_loop_controller"] = serde_json::json!({
            "algorithm": "proportional_angle_error_pidff_constant_force",
            "torque_command_source": "steering_angle_error",
            "target_delta_degrees": target_degrees,
            "return_target_delta_degrees": 0.0,
            "max_percent": max_percent,
            "min_active_percent": NATIVE_CONTROLLED_ANGLE_CLOSED_LOOP_MIN_ACTIVE_PERCENT,
            "proportional_gain_percent_per_degree": NATIVE_CONTROLLED_ANGLE_CLOSED_LOOP_GAIN_PERCENT_PER_DEGREE,
            "deadband_degrees": NATIVE_CONTROLLED_ANGLE_CLOSED_LOOP_DEADBAND_DEGREES,
            "planned_feedback_inputs": [
                "start_angle_degrees",
                "current_angle_degrees",
                "target_angle_degrees",
                "error_degrees"
            ],
            "planned_stop_reason": "target, return, safety timeout, stale samples, wrong-way guard, overshoot guard, HID error, or final cleanup"
        });
    }
    receipt["controlled_angle_preflight_receipt"]["profile"] =
        serde_json::json!(json_string(&controlled_angle_preflight, "profile"));
    receipt["planned_next_output"]["profile"] =
        serde_json::json!(controlled_angle_profile_name(profile));
    receipt["planned_next_output"]["profile_cli"] =
        serde_json::json!(controlled_angle_profile_cli_name(profile));

    write_json_file(&plan_path, &receipt)?;
    print_authorize_controlled_angle_output_receipt(json, &plan_path, &receipt)
}

async fn receipt_template(
    json: bool,
    kind: MozaReceiptTemplateKind,
    json_out: &Path,
    overwrite: bool,
) -> Result<()> {
    if json_out.exists() && !overwrite {
        return Err(anyhow!(
            "'{}' already exists; pass --overwrite to replace it",
            json_out.display()
        ));
    }

    let receipt = moza_receipt_template(kind);
    write_json_file(json_out, &receipt)?;
    print_receipt_template(json, kind, json_out, &receipt)
}

async fn pit_house_observation(request: PitHouseObservationRequest<'_>) -> Result<()> {
    let PitHouseObservationRequest {
        json,
        case,
        evidence_kind,
        evidence_artifact,
        operator,
        evidence,
        json_out,
        overwrite,
    } = request;

    if evidence.trim().is_empty() {
        return Err(anyhow!(
            "--evidence must describe the observed Pit House state"
        ));
    }
    if operator.trim().is_empty() {
        return Err(anyhow!("--operator must not be empty"));
    }
    if matches!(evidence_kind, MozaPitHouseEvidenceKind::OperatorNotes) {
        return Err(anyhow!(
            "--evidence-kind operator-notes is not sufficient for verifier-accepted Pit House observations"
        ));
    }
    let evidence_artifact = evidence_artifact
        .ok_or_else(|| anyhow!("--evidence-artifact is required for Pit House observations"))?;
    let evidence_artifact =
        simple_lane_relative_path_string(evidence_artifact, "evidence artifact")?;
    let evidence_root = json_out
        .parent()
        .filter(|path| !path.as_os_str().is_empty())
        .unwrap_or_else(|| Path::new("."));
    let evidence_path = evidence_root.join(&evidence_artifact);
    if !evidence_path.is_file() {
        return Err(anyhow!(
            "Pit House evidence artifact '{}' must exist before writing observation receipt '{}'",
            evidence_path.display(),
            json_out.display()
        ));
    }
    if matches!(
        evidence_kind,
        MozaPitHouseEvidenceKind::ProcessWindowSnapshot
    ) {
        validate_known_pit_house_process_window_snapshot(&evidence_path, case)?;
    }

    let receipt = serde_json::json!({
        "success": true,
        "command": "wheelctl moza pit-house-observation",
        "generated_at_utc": now_utc(),
        "case": pit_house_observation_case_id(case),
        "observed": true,
        "pit_house_observed_state": pit_house_observation_state(case),
        "evidence_kind": pit_house_evidence_kind_label(evidence_kind),
        "observed_at_utc": now_utc(),
        "operator": operator,
        "evidence": evidence,
        "evidence_artifact": evidence_artifact,
        "no_hid_device_opened": true,
        "no_ffb_writes": true,
        "no_serial_config_commands": true,
        "no_firmware_or_dfu_commands": true
    });

    ensure_receipt_writable(json_out, overwrite)?;
    write_json_receipt(Some(json_out), &receipt)?;
    print_proof_receipt(json, json_out, "Pit House observation", &receipt)
}

async fn pit_house_evidence(request: PitHouseEvidenceRequest<'_>) -> Result<()> {
    let PitHouseEvidenceRequest {
        json,
        case,
        operator,
        evidence,
        require_match,
        json_out,
        overwrite,
    } = request;

    if operator.trim().is_empty() {
        return Err(anyhow!("--operator must not be empty"));
    }
    if let Some(evidence) = evidence
        && evidence.trim().is_empty()
    {
        return Err(anyhow!("--evidence must not be empty when provided"));
    }

    let receipt =
        pit_house_evidence_receipt(case, operator, evidence, scan_pit_house_process_windows());
    validate_pit_house_evidence_required_match(&receipt, case, require_match)?;

    ensure_receipt_writable(json_out, overwrite)?;
    write_json_receipt(Some(json_out), &receipt)?;
    print_proof_receipt(
        json,
        json_out,
        "Pit House process/window evidence",
        &receipt,
    )
}

async fn pit_house_availability(request: PitHouseAvailabilityRequest<'_>) -> Result<()> {
    let PitHouseAvailabilityRequest {
        json,
        operator,
        evidence,
        json_out,
        overwrite,
    } = request;

    if operator.trim().is_empty() {
        return Err(anyhow!("--operator must not be empty"));
    }
    if let Some(evidence) = evidence
        && evidence.trim().is_empty()
    {
        return Err(anyhow!("--evidence must not be empty when provided"));
    }

    let receipt = pit_house_availability_receipt(
        operator,
        evidence,
        scan_pit_house_process_windows(),
        scan_pit_house_installation(),
    );

    ensure_receipt_writable(json_out, overwrite)?;
    write_json_receipt(Some(json_out), &receipt)?;
    print_proof_receipt(json, json_out, "Pit House availability", &receipt)
}

async fn pit_house_case(request: PitHouseCaseRequest<'_>) -> Result<()> {
    let PitHouseCaseRequest {
        json,
        lane,
        case,
        observation_artifact,
        evidence,
        json_out,
        overwrite,
    } = request;

    if evidence.trim().is_empty() {
        return Err(anyhow!(
            "--evidence must describe the Pit House case result"
        ));
    }

    let observation_artifact = lane_relative_artifact_path(lane, observation_artifact)?;
    let mut receipt = pit_house_case_artifact_receipt(case, &observation_artifact, evidence);
    align_pit_house_init_source_record_kinds(lane, &mut receipt);
    let case_id = pit_house_observation_case_id(case);
    if !pit_house_case_observation_is_safe(lane, &receipt, case_id) {
        return Err(anyhow!(
            "Pit House observation artifact '{}' does not match case {}",
            observation_artifact,
            case_id
        ));
    }
    if !pit_house_case_source_is_safe(lane, &receipt, case_id, SupportBundleValidationMode::Fresh) {
        return Err(anyhow!(
            "Pit House source receipt for case {} is missing or failed verification",
            case_id
        ));
    }

    let (output_write_path, output_artifact_path) = lane_relative_output_path(lane, json_out)?;
    ensure_receipt_writable(&output_write_path, overwrite)?;
    write_json_receipt(Some(&output_write_path), &receipt)?;
    if !pit_house_case_artifact_is_safe(
        lane,
        &output_artifact_path,
        case_id,
        json_string(&receipt, "result"),
        SupportBundleValidationMode::Fresh,
    ) {
        return Err(anyhow!(
            "generated Pit House case artifact '{}' failed verifier contract",
            output_write_path.display()
        ));
    }

    print_proof_receipt(json, &output_write_path, "Pit House case", &receipt)
}

async fn pit_house_proof(request: PitHouseProofRequest<'_>) -> Result<()> {
    let PitHouseProofRequest {
        json,
        lane,
        closed_artifact,
        open_standard_artifact,
        direct_artifact,
        mode_change_artifact,
        firmware_page_artifact,
        shared_control_risk,
        json_out,
        overwrite,
    } = request;

    let cases = [
        pit_house_proof_case(lane, "pit_house_closed", closed_artifact)?,
        pit_house_proof_case(lane, "pit_house_open_idle_standard", open_standard_artifact)?,
        pit_house_proof_case(lane, "pit_house_open_direct", direct_artifact)?,
        pit_house_proof_case(
            lane,
            "pit_house_mode_change_during_run",
            mode_change_artifact,
        )?,
        pit_house_proof_case(
            lane,
            "pit_house_firmware_update_page_open",
            firmware_page_artifact,
        )?,
    ];
    let direct_requires_ack = cases
        .iter()
        .find(|case| case.case_id == "pit_house_open_direct")
        .map(|case| {
            json_bool(&case.artifact, "blocked") == Some(true)
                || json_bool(&case.artifact, "operator_ack_required") == Some(true)
        })
        .unwrap_or(false);
    let firmware_page_blocks_high_risk = cases
        .iter()
        .find(|case| case.case_id == "pit_house_firmware_update_page_open")
        .map(|case| json_bool(&case.artifact, "high_risk_refused") == Some(true))
        .unwrap_or(false);
    let detection_scope_ok = matches!(
        shared_control_risk,
        "detected" | "warned" | "documented_limit"
    );
    let success = detection_scope_ok
        && direct_requires_ack
        && firmware_page_blocks_high_risk
        && cases.iter().all(|case| case.safe);
    let entries: Vec<Value> = cases.into_iter().map(|case| case.entry).collect();
    let receipt = serde_json::json!({
        "success": success,
        "template": false,
        "evidence_status": "observed_on_real_hardware",
        "command": "wheelctl moza pit-house-proof",
        "generated_at_utc": now_utc(),
        "no_hid_device_opened": true,
        "no_ffb_writes": true,
        "high_torque": false,
        "no_serial_config_commands": true,
        "no_firmware_or_dfu_commands": true,
        "direct_requires_ack": direct_requires_ack,
        "firmware_page_blocks_high_risk": firmware_page_blocks_high_risk,
        "shared_control_risk": shared_control_risk,
        "cases": entries
    });

    let output = proof_output_path(lane, json_out, "pit-house-coexistence.json");
    ensure_receipt_writable(&output, overwrite)?;
    write_json_receipt(Some(&output), &receipt)?;
    print_proof_receipt(json, &output, "Pit House coexistence", &receipt)?;
    if !success {
        return Err(receipt_failure(
            "Moza Pit House coexistence proof failed safety checks",
        ));
    }
    Ok(())
}

async fn simulator_telemetry_proof(
    json: bool,
    lane: &Path,
    game: &str,
    telemetry_source: &str,
    recorder_artifact: &Path,
    duration_ms: u64,
    json_out: Option<&Path>,
    overwrite: bool,
) -> Result<()> {
    let recorder_artifact = lane_relative_artifact_path(lane, recorder_artifact)?;
    let records = read_telemetry_artifact_records(lane, &recorder_artifact)
        .ok_or_else(|| anyhow!("failed to read normalized telemetry artifact"))?;
    let snapshot_count = u64::try_from(records.len()).context("too many telemetry records")?;
    let source_ok = matches!(telemetry_source, "real_game" | "simhub_bridge");
    let telemetry_provenance = simulator_telemetry_provenance_for_records(&records);
    let provenance_matches_run = telemetry_provenance
        .as_ref()
        .map(|provenance| {
            provenance.game == game && provenance.telemetry_source == telemetry_source
        })
        .unwrap_or(false);
    let artifact_valid = simulator_telemetry_artifact_is_valid(
        lane,
        &recorder_artifact,
        snapshot_count,
        duration_ms,
    );
    let success = !game.trim().is_empty()
        && source_ok
        && provenance_matches_run
        && duration_ms > 0
        && snapshot_count > 0
        && artifact_valid;
    let recorder_command = telemetry_provenance
        .as_ref()
        .map(|provenance| provenance.recorder_command.as_str());
    let recorder_session_id = telemetry_provenance
        .as_ref()
        .map(|provenance| provenance.recorder_session_id.as_str());
    let receipt = serde_json::json!({
        "success": success,
        "command": "wheelctl moza simulator-telemetry-proof",
        "generated_at_utc": now_utc(),
        "game": game,
        "telemetry_source": telemetry_source,
        "recorder_command": recorder_command,
        "recorder_session_id": recorder_session_id,
        "hardware_output_enabled": false,
        "no_hid_device_opened": true,
        "no_ffb_writes": true,
        "no_serial_config_commands": true,
        "no_firmware_or_dfu_commands": true,
        "normalized_snapshot_count": snapshot_count,
        "duration_ms": duration_ms,
        "recorder_artifact": recorder_artifact,
        "faults": []
    });

    let output = proof_output_path(lane, json_out, "simulator-telemetry-proof.json");
    ensure_receipt_writable(&output, overwrite)?;
    write_json_receipt(Some(&output), &receipt)?;
    print_proof_receipt(json, &output, "simulator telemetry", &receipt)?;
    if !success {
        return Err(receipt_failure(
            "Moza simulator telemetry proof failed safety checks",
        ));
    }
    Ok(())
}

async fn simulator_ffb_smoke(request: SimulatorFfbSmokeRequest<'_>) -> Result<()> {
    let SimulatorFfbSmokeRequest {
        json,
        lane,
        game,
        telemetry_source,
        output_log_artifact,
        strategy,
        descriptor_trusted,
        explicit_operator_override,
        watchdog_timeout_ms,
        stop_cleared_output,
        pause_cleared_output,
        game_exit_cleared_output,
        json_out,
        overwrite,
    } = request;

    let telemetry_receipt = read_json_value(lane, "simulator-telemetry-proof.json")?;
    let input_telemetry_artifact = json_string(&telemetry_receipt, "recorder_artifact")
        .or_else(|| json_string(&telemetry_receipt, "normalized_snapshot_artifact"))
        .ok_or_else(|| anyhow!("simulator-telemetry-proof.json is missing recorder_artifact"))?;
    let input_telemetry_snapshot_count = json_u64(&telemetry_receipt, "normalized_snapshot_count")
        .ok_or_else(|| {
            anyhow!("simulator-telemetry-proof.json is missing normalized_snapshot_count")
        })?;
    let input_telemetry_recorder_session_id =
        json_string(&telemetry_receipt, "recorder_session_id").ok_or_else(|| {
            anyhow!("simulator-telemetry-proof.json is missing recorder_session_id")
        })?;
    let telemetry_receipt_ok = verify_simulator_telemetry_gate(lane).status == "pass";
    let telemetry_receipt_matches_run = json_string(&telemetry_receipt, "game") == Some(game)
        && json_string(&telemetry_receipt, "telemetry_source") == Some(telemetry_source);
    let output_pid = lane_manifest_r5_pid(lane).unwrap_or(product_ids::R5_V2);
    let output_log_artifact = lane_relative_artifact_path(lane, output_log_artifact)?;
    let records = read_receipt_artifact_records(
        lane,
        &output_log_artifact,
        &["output_log", "records", "commands", "reports"],
    )
    .ok_or_else(|| anyhow!("failed to read simulator FFB output log artifact"))?;
    let output_report_count = u64::try_from(records.len()).context("too many output records")?;
    let mut nonzero_output_count = 0u64;
    let mut zero_output_count = 0u64;
    let mut max_abs_output_percent = 0.0f64;
    let mut output_records_match_strategy = true;
    match strategy {
        MozaLowTorqueStrategy::DirectReport0x20 => {
            for record in &records {
                let Some(output) = direct_torque_artifact_record(record) else {
                    output_records_match_strategy = false;
                    continue;
                };
                max_abs_output_percent = max_abs_output_percent.max(output.percent.abs());
                if output.torque_raw == 0 {
                    zero_output_count += 1;
                } else {
                    nonzero_output_count += 1;
                }
            }
        }
        MozaLowTorqueStrategy::PidffBoundedEffect => {
            for record in &records {
                let Some(output) = pidff_output_artifact_record(record) else {
                    output_records_match_strategy = false;
                    continue;
                };
                max_abs_output_percent = max_abs_output_percent.max(output.percent.abs());
                match output.kind.as_str() {
                    "pidff_set_constant_force" if output.torque_raw != 0 => {
                        nonzero_output_count += 1;
                    }
                    "clear_zero" | "final_stop_all" | "final_zero"
                        if pidff_stop_all_record_is_safe(record) =>
                    {
                        zero_output_count += 1;
                    }
                    "pidff_set_effect" | "pidff_effect_start" => {}
                    _ => output_records_match_strategy = false,
                }
            }
        }
    }
    let output_provenance = simulator_ffb_output_provenance_for_records(lane, &records, output_pid);
    let writer_started_at_utc = output_provenance
        .as_ref()
        .map(|provenance| provenance.writer_started_at_utc.as_str());
    let writer_completed_at_utc = output_provenance
        .as_ref()
        .map(|provenance| provenance.writer_completed_at_utc.as_str());
    let prerequisite_artifacts =
        simulator_ffb_prerequisite_artifact_summaries(lane).unwrap_or_default();
    let prerequisite_artifacts_bound = simulator_ffb_prerequisite_artifacts_are_ordered(
        &prerequisite_artifacts,
        writer_started_at_utc,
    );
    let prerequisite_artifacts_value = serde_json::to_value(&prerequisite_artifacts)?;
    let last_record = records.last();
    let final_zero_attempted = matches!(
        last_record.and_then(|record| json_string(record, "kind")),
        Some("final_zero" | "final_stop_all")
    );
    let final_zero_sent = last_record
        .map(|record| {
            json_string(record, "result") == Some("ok")
                && match strategy {
                    MozaLowTorqueStrategy::DirectReport0x20 => zero_payload_record_is_safe(record),
                    MozaLowTorqueStrategy::PidffBoundedEffect => {
                        pidff_stop_all_record_is_safe(record)
                    }
                }
        })
        .unwrap_or(false);
    let final_zero_payload_hex = last_record
        .and_then(|record| json_string(record, "payload_hex"))
        .unwrap_or_default();
    let final_zero_report_id = last_record
        .and_then(|record| json_string(record, "report_id"))
        .unwrap_or_default();
    let final_zero_torque_raw = last_record.and_then(|record| json_i64(record, "torque_raw"));
    let final_zero_flags = last_record.and_then(|record| json_u64(record, "flags"));
    let mode_mismatch_cleared_output = simulator_ffb_clear_events_for_records(&records)
        .mode_mismatch
        .is_some();
    let source_ok = matches!(telemetry_source, "real_game" | "simhub_bridge");
    let direct_descriptor_trust_observed =
        lane_descriptor_trusted_for_pid(lane, &hex_u16(output_pid));
    let pidff_descriptor_trust_observed = validate_zero_output_pidff_stop_all_report_metadata(lane)
        .is_ok()
        && pidff_bounded_effect_descriptor_blockers(lane).is_empty();
    let descriptor_trust_observed = match strategy {
        MozaLowTorqueStrategy::DirectReport0x20 => direct_descriptor_trust_observed,
        MozaLowTorqueStrategy::PidffBoundedEffect => pidff_descriptor_trust_observed,
    };
    let descriptor_trust_valid = !descriptor_trusted || descriptor_trust_observed;
    let direct_mode_allowed = ((descriptor_trusted && descriptor_trust_observed)
        || explicit_operator_override)
        && descriptor_trust_valid;
    let prerequisite_gates = simulator_ffb_prerequisite_gates(lane);
    let hardware_prerequisites_validated =
        prerequisite_gates.iter().all(|gate| gate.status == "pass");
    let prerequisite_gates_value = serde_json::to_value(&prerequisite_gates)?;
    let ffb_scalars_by_sequence = simulator_telemetry_ffb_scalars_by_sequence(
        lane,
        input_telemetry_artifact,
        input_telemetry_snapshot_count,
    )
    .unwrap_or_default();
    let telemetry_link = SimulatorFfbTelemetryLink {
        artifact: input_telemetry_artifact.to_string(),
        snapshot_count: input_telemetry_snapshot_count,
        recorder_session_id: input_telemetry_recorder_session_id.to_string(),
        game: game.to_string(),
        telemetry_source: telemetry_source.to_string(),
        ffb_scalars_by_sequence,
    };
    let output_artifact_safe = output_records_match_strategy
        && match strategy {
            MozaLowTorqueStrategy::DirectReport0x20 => simulator_ffb_output_artifact_is_safe(
                lane,
                &output_log_artifact,
                output_report_count,
                nonzero_output_count,
                zero_output_count,
                max_abs_output_percent,
                output_pid,
                &telemetry_link,
            ),
            MozaLowTorqueStrategy::PidffBoundedEffect => {
                simulator_ffb_pidff_output_artifact_is_safe(
                    lane,
                    &output_log_artifact,
                    output_report_count,
                    nonzero_output_count,
                    zero_output_count,
                    max_abs_output_percent,
                    &telemetry_link,
                )
            }
        };
    let output_strategy_allowed = match strategy {
        MozaLowTorqueStrategy::DirectReport0x20 => direct_mode_allowed,
        MozaLowTorqueStrategy::PidffBoundedEffect => {
            descriptor_trusted
                && descriptor_trust_observed
                && descriptor_trust_valid
                && !explicit_operator_override
        }
    };
    let success = !game.trim().is_empty()
        && source_ok
        && telemetry_receipt_ok
        && telemetry_receipt_matches_run
        && hardware_prerequisites_validated
        && prerequisite_artifacts_bound
        && output_strategy_allowed
        && watchdog_timeout_ms > 0
        && output_report_count > 0
        && nonzero_output_count > 0
        && zero_output_count > 0
        && output_provenance.is_some()
        && max_abs_output_percent > 0.0
        && max_abs_output_percent <= 5.0
        && final_zero_attempted
        && final_zero_sent
        && stop_cleared_output
        && pause_cleared_output
        && game_exit_cleared_output
        && mode_mismatch_cleared_output
        && simulator_telemetry_artifact_is_valid(
            lane,
            input_telemetry_artifact,
            input_telemetry_snapshot_count,
            json_u64(&telemetry_receipt, "duration_ms").unwrap_or(0),
        )
        && output_artifact_safe;
    let writer_command = output_provenance
        .as_ref()
        .map(|provenance| provenance.writer_command.as_str());
    let writer_session_id = output_provenance
        .as_ref()
        .map(|provenance| provenance.writer_session_id.as_str());
    let writer_device_path = output_provenance
        .as_ref()
        .map(|provenance| provenance.device_path.as_str());
    let writer_product_id = output_provenance
        .as_ref()
        .map(|provenance| provenance.product_id.as_str());
    let writer_endpoint_selector = output_provenance
        .as_ref()
        .map(|provenance| provenance.endpoint_selector.as_str());
    let writer_hardware_lane = output_provenance
        .as_ref()
        .map(|provenance| provenance.hardware_lane.as_str());
    let mut receipt = serde_json::Map::new();
    receipt.insert("success".to_string(), Value::Bool(success));
    receipt.insert(
        "command".to_string(),
        Value::String("wheelctl moza simulator-ffb-smoke".to_string()),
    );
    receipt.insert("generated_at_utc".to_string(), Value::String(now_utc()));
    receipt.insert("game".to_string(), Value::String(game.to_string()));
    receipt.insert(
        "telemetry_source".to_string(),
        Value::String(telemetry_source.to_string()),
    );
    receipt.insert("hardware".to_string(), Value::String("moza-r5".to_string()));
    receipt.insert(
        "ffb_mode".to_string(),
        Value::String(
            match strategy {
                MozaLowTorqueStrategy::DirectReport0x20 => "direct",
                MozaLowTorqueStrategy::PidffBoundedEffect => "pidff",
            }
            .to_string(),
        ),
    );
    receipt.insert(
        "output_strategy".to_string(),
        Value::String(low_torque_strategy_name(strategy).to_string()),
    );
    receipt.insert(
        "descriptor_trusted".to_string(),
        Value::Bool(descriptor_trusted),
    );
    receipt.insert(
        "descriptor_trust_observed".to_string(),
        Value::Bool(descriptor_trust_observed),
    );
    receipt.insert(
        "explicit_operator_override".to_string(),
        Value::Bool(explicit_operator_override),
    );
    receipt.insert("high_torque".to_string(), Value::Bool(false));
    receipt.insert("no_high_torque".to_string(), Value::Bool(true));
    receipt.insert(
        "no_direct_torque_reports".to_string(),
        Value::Bool(strategy == MozaLowTorqueStrategy::PidffBoundedEffect),
    );
    receipt.insert("no_hid_device_opened".to_string(), Value::Bool(false));
    receipt.insert("no_ffb_writes".to_string(), Value::Bool(false));
    receipt.insert("no_serial_config_commands".to_string(), Value::Bool(true));
    receipt.insert("no_firmware_or_dfu_commands".to_string(), Value::Bool(true));
    receipt.insert(
        "hardware_prerequisites_validated".to_string(),
        Value::Bool(hardware_prerequisites_validated),
    );
    receipt.insert("prerequisite_gates".to_string(), prerequisite_gates_value);
    receipt.insert(
        "prerequisite_artifacts".to_string(),
        prerequisite_artifacts_value,
    );
    receipt.insert(
        "device".to_string(),
        serde_json::json!({
            "vendor_id": "0x346E",
            "product_id": hex_u16(output_pid),
            "product_name": "Moza R5",
            "output_capable": true
        }),
    );
    receipt.insert("hardware_output_enabled".to_string(), Value::Bool(true));
    receipt.insert(
        "max_output_percent".to_string(),
        serde_json::json!(max_abs_output_percent),
    );
    receipt.insert(
        "max_abs_output_percent".to_string(),
        serde_json::json!(max_abs_output_percent),
    );
    receipt.insert("watchdog_active".to_string(), Value::Bool(true));
    receipt.insert(
        "watchdog_timeout_ms".to_string(),
        Value::Number(watchdog_timeout_ms.into()),
    );
    receipt.insert(
        "output_report_count".to_string(),
        Value::Number(output_report_count.into()),
    );
    receipt.insert(
        "nonzero_output_count".to_string(),
        Value::Number(nonzero_output_count.into()),
    );
    receipt.insert(
        "zero_output_count".to_string(),
        Value::Number(zero_output_count.into()),
    );
    receipt.insert(
        "input_telemetry_artifact".to_string(),
        Value::String(input_telemetry_artifact.to_string()),
    );
    receipt.insert(
        "input_telemetry_snapshot_count".to_string(),
        Value::Number(input_telemetry_snapshot_count.into()),
    );
    receipt.insert(
        "input_telemetry_recorder_session_id".to_string(),
        Value::String(input_telemetry_recorder_session_id.to_string()),
    );
    receipt.insert(
        "output_log_artifact".to_string(),
        Value::String(output_log_artifact),
    );
    receipt.insert(
        "output_log_provenance_valid".to_string(),
        Value::Bool(output_provenance.is_some()),
    );
    receipt.insert(
        "writer_command".to_string(),
        writer_command.map(Value::from).unwrap_or(Value::Null),
    );
    receipt.insert(
        "writer_session_id".to_string(),
        writer_session_id.map(Value::from).unwrap_or(Value::Null),
    );
    receipt.insert(
        "writer_device_path".to_string(),
        writer_device_path.map(Value::from).unwrap_or(Value::Null),
    );
    receipt.insert(
        "writer_product_id".to_string(),
        writer_product_id.map(Value::from).unwrap_or(Value::Null),
    );
    receipt.insert(
        "writer_endpoint_selector".to_string(),
        writer_endpoint_selector
            .map(Value::from)
            .unwrap_or(Value::Null),
    );
    receipt.insert(
        "writer_hardware_lane".to_string(),
        writer_hardware_lane.map(Value::from).unwrap_or(Value::Null),
    );
    receipt.insert(
        "writer_started_at_utc".to_string(),
        writer_started_at_utc
            .map(Value::from)
            .unwrap_or(Value::Null),
    );
    receipt.insert(
        "writer_completed_at_utc".to_string(),
        writer_completed_at_utc
            .map(Value::from)
            .unwrap_or(Value::Null),
    );
    receipt.insert(
        "final_zero_attempted".to_string(),
        Value::Bool(final_zero_attempted),
    );
    receipt.insert("final_zero_sent".to_string(), Value::Bool(final_zero_sent));
    receipt.insert(
        "final_zero_payload_hex".to_string(),
        Value::String(final_zero_payload_hex.to_string()),
    );
    receipt.insert(
        "final_zero_report_id".to_string(),
        Value::String(final_zero_report_id.to_string()),
    );
    receipt.insert(
        "final_zero_torque_raw".to_string(),
        final_zero_torque_raw
            .map(|value| serde_json::json!(value))
            .unwrap_or(Value::Null),
    );
    receipt.insert(
        "final_zero_flags".to_string(),
        final_zero_flags
            .map(|value| serde_json::json!(value))
            .unwrap_or(Value::Null),
    );
    receipt.insert(
        "stop_cleared_output".to_string(),
        Value::Bool(stop_cleared_output),
    );
    receipt.insert(
        "pause_cleared_output".to_string(),
        Value::Bool(pause_cleared_output),
    );
    receipt.insert(
        "game_exit_cleared_output".to_string(),
        Value::Bool(game_exit_cleared_output),
    );
    receipt.insert(
        "mode_mismatch_cleared_output".to_string(),
        Value::Bool(mode_mismatch_cleared_output),
    );
    receipt.insert("faults".to_string(), Value::Array(Vec::new()));
    let receipt = Value::Object(receipt);

    let output = proof_output_path(lane, json_out, "simulator-ffb-smoke.json");
    ensure_receipt_writable(&output, overwrite)?;
    write_json_receipt(Some(&output), &receipt)?;
    print_proof_receipt(json, &output, "simulator FFB smoke", &receipt)?;
    if !success {
        return Err(receipt_failure(
            "Moza simulator FFB smoke proof failed safety checks",
        ));
    }
    Ok(())
}

struct ProducedPitHouseCase {
    case_id: &'static str,
    entry: Value,
    artifact: Value,
    safe: bool,
}

fn pit_house_proof_case(
    lane: &Path,
    case_id: &'static str,
    artifact_path: &Path,
) -> Result<ProducedPitHouseCase> {
    let artifact_path = lane_relative_artifact_path(lane, artifact_path)?;
    let artifact = read_json_value(lane, &artifact_path)?;
    let result = json_string(&artifact, "result")
        .ok_or_else(|| anyhow!("{artifact_path} is missing result"))?;
    let observed = json_bool(&artifact, "observed").unwrap_or(false);
    let high_torque = json_bool(&artifact, "high_torque").unwrap_or(true);
    let evidence = json_string(&artifact, "evidence")
        .or_else(|| json_string(&artifact, "operator_notes"))
        .unwrap_or_default();
    let safe = pit_house_case_artifact_is_safe(
        lane,
        &artifact_path,
        case_id,
        Some(result),
        SupportBundleValidationMode::Fresh,
    );
    let mut entry = serde_json::json!({
        "case": case_id,
        "observed": observed,
        "result": result,
        "high_torque": high_torque,
        "evidence": evidence,
        "artifact": artifact_path
    });
    if let Some(object) = entry.as_object_mut() {
        for key in [
            "source_receipt",
            "source_gate",
            "source_log",
            "source_record_kind",
            "source_clear_event",
            "pit_house_observation_artifact",
            "blocked",
            "operator_ack_required",
            "mismatch_detected",
            "failed_safe",
            "high_risk_refused",
        ] {
            if let Some(value) = json_bool(&artifact, key) {
                object.insert(key.to_string(), Value::Bool(value));
            } else if let Some(value) = json_string(&artifact, key) {
                object.insert(key.to_string(), Value::String(value.to_string()));
            }
        }
        for key in ["source_record_kinds", "source_requires_final_zero"] {
            if let Some(value) = artifact.get(key) {
                object.insert(key.to_string(), value.clone());
            }
        }
    }
    Ok(ProducedPitHouseCase {
        case_id,
        entry,
        artifact,
        safe,
    })
}

fn lane_manifest_r5_pid(lane: &Path) -> Option<u16> {
    let manifest = read_json_value(lane, "manifest.json").ok()?;
    let hardware = manifest.get("hardware")?;
    let pid = json_string(hardware, "wheelbase_pid").and_then(parse_hex_selector)?;
    matches!(pid, product_ids::R5_V1 | product_ids::R5_V2).then_some(pid)
}

fn lane_manifest_r5_hid_observe_selector(lane: &Path) -> Option<String> {
    let manifest = read_json_value(lane, "manifest.json").ok()?;
    let expected_pid = lane_manifest_r5_pid(lane);
    let endpoints = manifest
        .get("topology")?
        .get("endpoints")
        .and_then(Value::as_array)?;

    endpoints.iter().find_map(|endpoint| {
        if json_string(endpoint, "kind") != Some("wheelbase_hub") {
            return None;
        }
        let vendor_id = json_string(endpoint, "vendor_id").and_then(parse_hex_selector)?;
        let product_id = json_string(endpoint, "product_id").and_then(parse_hex_selector)?;
        if vendor_id != MOZA_VENDOR_ID
            || !matches!(product_id, product_ids::R5_V1 | product_ids::R5_V2)
            || expected_pid.is_some_and(|expected| expected != product_id)
        {
            return None;
        }
        let interface_number = json_u64(endpoint, "interface_number")?;
        let usage_page = json_string(endpoint, "usage_page").and_then(parse_hex_selector)?;
        let usage = json_string(endpoint, "usage").and_then(parse_hex_selector)?;
        Some(format!(
            "hid-{}-{}-if{}-{}-{}",
            hex_u16(vendor_id),
            hex_u16(product_id),
            interface_number,
            hex_u16(usage_page),
            hex_u16(usage)
        ))
    })
}

fn proof_output_path(lane: &Path, json_out: Option<&Path>, default_file: &str) -> PathBuf {
    json_out
        .map(Path::to_path_buf)
        .unwrap_or_else(|| lane.join(default_file))
}

fn ensure_receipt_writable(path: &Path, overwrite: bool) -> Result<()> {
    if path.exists() && !overwrite {
        return Err(anyhow!(
            "{} already exists; pass --overwrite to replace it",
            path.display()
        ));
    }
    if let Some(parent) = path.parent().filter(|p| !p.as_os_str().is_empty()) {
        fs::create_dir_all(parent)
            .with_context(|| format!("failed to create '{}'", parent.display()))?;
    }
    Ok(())
}

fn lane_relative_artifact_path(lane: &Path, artifact: &Path) -> Result<String> {
    let relative = if artifact.is_absolute() {
        let absolute_lane = std::path::absolute(lane)
            .with_context(|| format!("failed to absolutize lane '{}'", lane.display()))?;
        let absolute_artifact = std::path::absolute(artifact)
            .with_context(|| format!("failed to absolutize artifact '{}'", artifact.display()))?;
        absolute_artifact
            .strip_prefix(&absolute_lane)
            .with_context(|| {
                format!(
                    "artifact '{}' must be under lane '{}'",
                    artifact.display(),
                    lane.display()
                )
            })?
            .to_path_buf()
    } else if let Some(relative) = lane_prefixed_relative_path(lane, artifact) {
        relative
    } else if let Some(relative) = cwd_relative_lane_prefixed_path(lane, artifact)? {
        relative
    } else {
        artifact.to_path_buf()
    };
    if relative.as_os_str().is_empty()
        || relative
            .components()
            .any(|component| !matches!(component, Component::Normal(_)))
    {
        return Err(anyhow!(
            "artifact '{}' must be a simple lane-relative path",
            artifact.display()
        ));
    }
    Ok(relative.to_string_lossy().replace('\\', "/"))
}

fn simple_lane_relative_path_string(path: &Path, label: &str) -> Result<String> {
    if path.as_os_str().is_empty()
        || path
            .components()
            .any(|component| !matches!(component, Component::Normal(_)))
    {
        return Err(anyhow!(
            "{label} '{}' must be a simple lane-relative path",
            path.display()
        ));
    }
    Ok(path.to_string_lossy().replace('\\', "/"))
}

fn lane_prefixed_relative_path(lane: &Path, artifact: &Path) -> Option<PathBuf> {
    if lane.is_absolute() || artifact.is_absolute() {
        return None;
    }

    let relative = artifact.strip_prefix(lane).ok()?;
    (!relative.as_os_str().is_empty()).then(|| relative.to_path_buf())
}

fn cwd_relative_lane_prefixed_path(lane: &Path, artifact: &Path) -> Result<Option<PathBuf>> {
    if artifact.is_absolute() {
        return Ok(None);
    }

    let absolute_lane = std::path::absolute(lane)
        .with_context(|| format!("failed to absolutize lane '{}'", lane.display()))?;
    let absolute_artifact = std::path::absolute(artifact)
        .with_context(|| format!("failed to absolutize artifact '{}'", artifact.display()))?;
    let Some(relative) = absolute_artifact
        .strip_prefix(&absolute_lane)
        .ok()
        .filter(|path| !path.as_os_str().is_empty())
    else {
        return Ok(None);
    };
    Ok(Some(relative.to_path_buf()))
}

fn lane_relative_output_path(lane: &Path, output: &Path) -> Result<(PathBuf, String)> {
    let artifact_path = lane_relative_artifact_path(lane, output)?;
    let write_path = if output.is_absolute() {
        output.to_path_buf()
    } else {
        lane.join(Path::new(&artifact_path))
    };
    Ok((write_path, artifact_path))
}

async fn promote_manifest(
    json: bool,
    lane: &Path,
    stage: MozaBundleStage,
    json_out: Option<&Path>,
) -> Result<()> {
    let manifest_path = lane.join("manifest.json");
    let mut manifest = read_json_path(&manifest_path)?;
    let previous_completion_state = json_string(&manifest, "completion_state")
        .unwrap_or("missing")
        .to_string();
    let previous_hardware_validated = json_bool(&manifest, "hardware_validated");
    let previous_simulator_validated = json_bool(&manifest, "simulator_validated");

    let verification_before = verify_bundle_dir(lane, stage);
    if !verification_before.success {
        return Err(anyhow!(
            "cannot promote manifest to {}: live bundle verification failed with {} missing artifact(s), {} invalid artifact(s), and {} failed gate(s)",
            stage_label(stage),
            verification_before.missing_artifacts,
            verification_before.invalid_artifacts,
            verification_before.failed_gates
        ));
    }

    let (completion_state, hardware_validated, simulator_validated) =
        manifest_promotion_values(stage);
    let verification_after = promote_manifest_with_post_verification(
        &manifest_path,
        &mut manifest,
        completion_state,
        hardware_validated,
        simulator_validated,
        || {
            verify_bundle_dir_with_support_validation(
                lane,
                stage,
                SupportBundleValidationMode::ShapeOnly,
            )
        },
    )?;

    let receipt = serde_json::json!({
        "success": true,
        "command": "wheelctl moza promote-manifest",
        "generated_at_utc": now_utc(),
        "lane": lane.display().to_string(),
        "manifest": manifest_path.display().to_string(),
        "stage": stage_label(stage),
        "previous_completion_state": previous_completion_state,
        "previous_hardware_validated": previous_hardware_validated,
        "previous_simulator_validated": previous_simulator_validated,
        "completion_state": completion_state,
        "hardware_validated": hardware_validated,
        "simulator_validated": simulator_validated,
        "high_torque_validated": false,
        "release_ready": false,
        "no_hid_device_opened": true,
        "no_ffb_writes": true,
        "no_serial_config_commands": true,
        "no_firmware_or_dfu_commands": true,
        "verification_before": bundle_verification_summary_value(&verification_before),
        "verification_after": bundle_verification_summary_value(&verification_after),
        "notes": [
            "promote-manifest runs live bundle verification before changing manifest claims",
            "post-promotion verification uses shape-only support bundle validation because manifest promotion intentionally changes the lane snapshot that support-bundle records",
            "release_ready and high_torque_validated remain false"
        ]
    });
    write_json_receipt(json_out, &receipt)?;
    print_manifest_promotion_receipt(json, json_out, &receipt)
}

fn promote_manifest_with_post_verification(
    manifest_path: &Path,
    manifest: &mut Value,
    completion_state: &str,
    hardware_validated: bool,
    simulator_validated: bool,
    verify_after: impl FnOnce() -> BundleVerificationReceipt,
) -> Result<BundleVerificationReceipt> {
    let previous_manifest = manifest.clone();
    apply_manifest_promotion(
        manifest,
        completion_state,
        hardware_validated,
        simulator_validated,
    )?;
    write_json_file(manifest_path, manifest)?;

    let verification_after = verify_after();
    if verification_after.success {
        return Ok(verification_after);
    }

    write_json_file(manifest_path, &previous_manifest).with_context(|| {
        format!(
            "post-promotion verification failed and rollback failed for '{}'",
            manifest_path.display()
        )
    })?;
    *manifest = previous_manifest;
    Err(anyhow!(
        "manifest promotion wrote '{}', but post-promotion verification failed with {} missing artifact(s), {} invalid artifact(s), and {} failed gate(s); previous manifest restored",
        manifest_path.display(),
        verification_after.missing_artifacts,
        verification_after.invalid_artifacts,
        verification_after.failed_gates
    ))
}

fn enumerate_moza_devices(
    api: &HidApi,
    include_descriptor: bool,
    include_descriptor_hex: bool,
) -> Vec<MozaDeviceRecord> {
    let mut devices: Vec<_> = api
        .device_list()
        .filter(|device| device.vendor_id() == MOZA_VENDOR_ID)
        .map(|device| {
            MozaDeviceRecord::from_device_info(device, include_descriptor, include_descriptor_hex)
        })
        .collect();

    devices.sort_by_key(|device| {
        (
            device.product_id.clone(),
            device.interface_number.unwrap_or(-1),
            device.usage_page.clone().unwrap_or_default(),
            device.usage.clone().unwrap_or_default(),
            device.path.clone(),
        )
    });
    devices
}

fn open_single_moza_device(
    api: &HidApi,
    selector: Option<&str>,
) -> Result<(hidapi::HidDevice, MozaDeviceRecord)> {
    let mut selected_info = None;
    let mut selected_snapshot = None;
    let mut match_count = 0usize;

    for info in api.device_list() {
        if info.vendor_id() != MOZA_VENDOR_ID {
            continue;
        }

        let snapshot = MozaDeviceRecord::from_device_info(info, false, false);
        if !selector_matches(&snapshot, selector) {
            continue;
        }

        match_count += 1;
        if match_count == 1 {
            selected_info = Some(info);
            selected_snapshot = Some(snapshot);
        }
    }

    validate_single_moza_match_count(match_count, selector)?;

    let info = selected_info.ok_or_else(|| match selector {
        Some(value) => anyhow!("no Moza HID device matched selector '{value}'"),
        None => anyhow!("no Moza HID devices found"),
    })?;
    let snapshot =
        selected_snapshot.ok_or_else(|| anyhow!("matched Moza HID device disappeared"))?;

    let device = info.open_device(api).with_context(|| {
        format!(
            "failed to open Moza HID device {} ({})",
            snapshot.product_id, snapshot.path
        )
    })?;
    Ok((device, snapshot))
}

fn validate_single_moza_match_count(match_count: usize, selector: Option<&str>) -> Result<()> {
    match match_count {
        0 => Err(match selector {
            Some(value) => anyhow!("no Moza HID device matched selector '{value}'"),
            None => anyhow!("no Moza HID devices found"),
        }),
        1 => Ok(()),
        _ => Err(anyhow!(
            "multiple Moza HID devices matched; pass --device with an exact HID endpoint selector"
        )),
    }
}

fn validate_zero_torque_args(repeat: u32, hz: u32, watchdog_timeout_ms: u64) -> Result<()> {
    if repeat == 0 || repeat > 10_000 {
        return Err(anyhow!("--repeat must be in 1..=10000"));
    }
    if hz == 0 || hz > 1000 {
        return Err(anyhow!("--hz must be in 1..=1000"));
    }
    if watchdog_timeout_ms == 0 {
        return Err(anyhow!("--watchdog-timeout-ms must be greater than zero"));
    }
    Ok(())
}

fn validate_watchdog_proof_args(
    pre_zero_count: u32,
    hz: u32,
    watchdog_timeout_ms: u64,
) -> Result<()> {
    if pre_zero_count == 0 || pre_zero_count > 1_000 {
        return Err(anyhow!("--pre-zero-count must be in 1..=1000"));
    }
    if hz == 0 || hz > 1000 {
        return Err(anyhow!("--hz must be in 1..=1000"));
    }
    if watchdog_timeout_ms == 0 || watchdog_timeout_ms > 5_000 {
        return Err(anyhow!("--watchdog-timeout-ms must be in 1..=5000"));
    }
    Ok(())
}

fn validate_disconnect_proof_args(max_duration_ms: u64, hz: u32) -> Result<()> {
    if max_duration_ms == 0 || max_duration_ms > 60_000 {
        return Err(anyhow!("--max-duration-ms must be in 1..=60000"));
    }
    if hz == 0 || hz > 1000 {
        return Err(anyhow!("--hz must be in 1..=1000"));
    }
    Ok(())
}

fn validate_torque_test_args(max_percent: f32, duration_ms: u64, hz: u32) -> Result<()> {
    if !max_percent.is_finite() || !(0.1..=2.0).contains(&max_percent) {
        return Err(anyhow!("--max-percent must be in 0.1..=2.0"));
    }
    if duration_ms == 0 || duration_ms > 1_000 {
        return Err(anyhow!("--duration-ms must be in 1..=1000"));
    }
    if hz == 0 || hz > 1000 {
        return Err(anyhow!("--hz must be in 1..=1000"));
    }
    Ok(())
}

fn validate_actuator_profile_smoke_args(
    profile: MozaActuatorProfile,
    strategy: MozaLowTorqueStrategy,
    max_percent: f32,
    duration_ms: u64,
) -> Result<()> {
    if profile != MozaActuatorProfile::ConstantLowForce {
        return Err(anyhow!(
            "native actuator-profile smoke only supports --profile constant-low-force"
        ));
    }
    if strategy != MozaLowTorqueStrategy::PidffBoundedEffect {
        return Err(anyhow!(
            "native actuator-profile smoke only supports --strategy pidff-bounded-effect"
        ));
    }
    if !max_percent.is_finite() || !(0.1..=1.0).contains(&max_percent) {
        return Err(anyhow!("--max-percent must be in 0.1..=1.0"));
    }
    if duration_ms == 0 || duration_ms > 2_000 {
        return Err(anyhow!("--duration-ms must be in 1..=2000"));
    }
    Ok(())
}

fn validate_actuator_visible_smoke_args(
    profile: MozaActuatorProfile,
    strategy: MozaLowTorqueStrategy,
    max_percent: f32,
    duration_ms: u64,
    read_timeout_ms: i32,
    degrees_of_rotation: f64,
    movement_threshold_degrees: f64,
) -> Result<()> {
    if !matches!(
        profile,
        MozaActuatorProfile::ConstantLowForce | MozaActuatorProfile::BoundedShapedPidffMicroProfile
    ) {
        return Err(anyhow!(
            "unsupported native actuator visible-motion profile"
        ));
    }
    if strategy != MozaLowTorqueStrategy::PidffBoundedEffect {
        return Err(anyhow!(
            "native actuator visible-motion smoke only supports --strategy pidff-bounded-effect"
        ));
    }
    if !max_percent.is_finite() || !(0.1..=5.0).contains(&max_percent) {
        return Err(anyhow!("--max-percent must be in 0.1..=5.0"));
    }
    if duration_ms == 0 || duration_ms > 2_000 {
        return Err(anyhow!("--duration-ms must be in 1..=2000"));
    }
    if read_timeout_ms < 0 {
        return Err(anyhow!("--read-timeout-ms must be non-negative"));
    }
    if !degrees_of_rotation.is_finite() || degrees_of_rotation <= 0.0 {
        return Err(anyhow!(
            "--degrees-of-rotation must be a positive finite value"
        ));
    }
    if !movement_threshold_degrees.is_finite() || movement_threshold_degrees <= 0.0 {
        return Err(anyhow!(
            "--movement-threshold-degrees must be a positive finite value"
        ));
    }
    Ok(())
}

fn validate_controlled_angle_smoke_args(
    strategy: MozaLowTorqueStrategy,
    target_degrees: f64,
    max_percent: f32,
    timeout_ms: u64,
    read_timeout_ms: i32,
    degrees_of_rotation: f64,
) -> Result<()> {
    if strategy != MozaLowTorqueStrategy::PidffBoundedEffect {
        return Err(anyhow!(
            "native controlled-angle smoke only supports --strategy pidff-bounded-effect"
        ));
    }
    if !native_controlled_angle_ladder_degrees()
        .iter()
        .any(|target| (target_degrees - *target).abs() <= f64::EPSILON)
    {
        return Err(anyhow!(
            "--target-degrees must use the staged native controlled-angle ladder: 1, 3, 5, 10, 30, or 90"
        ));
    }
    if !max_percent.is_finite() || !(0.1..=5.0).contains(&max_percent) {
        return Err(anyhow!("--max-percent must be in 0.1..=5.0"));
    }
    if timeout_ms == 0 || timeout_ms > NATIVE_CONTROLLED_ANGLE_FIRST_MAX_DURATION_MS {
        return Err(anyhow!(
            "--timeout-ms must be in 1..={}; it is a safety cutoff, not an open-loop dwell",
            NATIVE_CONTROLLED_ANGLE_FIRST_MAX_DURATION_MS
        ));
    }
    if read_timeout_ms < 0 {
        return Err(anyhow!("--read-timeout-ms must be non-negative"));
    }
    if !degrees_of_rotation.is_finite() || degrees_of_rotation <= 0.0 {
        return Err(anyhow!(
            "--degrees-of-rotation must be a positive finite value"
        ));
    }
    Ok(())
}

fn validate_controlled_angle_actual_output_limits(
    target_degrees: f64,
    max_percent: f32,
    timeout_ms: u64,
) -> Result<()> {
    if (target_degrees - NATIVE_CONTROLLED_ANGLE_FIRST_TARGET_DEGREES).abs() > f64::EPSILON {
        return Err(anyhow!(
            "native controlled-angle writes currently allow only --target-degrees {} until smaller staged receipts authorize the next ladder step",
            compact_f64(NATIVE_CONTROLLED_ANGLE_FIRST_TARGET_DEGREES)
        ));
    }
    if (max_percent - NATIVE_CONTROLLED_ANGLE_FIRST_MAX_PERCENT).abs() > f32::EPSILON {
        return Err(anyhow!(
            "native controlled-angle writes currently require exactly --max-percent {}",
            compact_f32(NATIVE_CONTROLLED_ANGLE_FIRST_MAX_PERCENT)
        ));
    }
    if timeout_ms == 0 || timeout_ms > NATIVE_CONTROLLED_ANGLE_FIRST_MAX_DURATION_MS {
        return Err(anyhow!(
            "native controlled-angle writes currently require --timeout-ms in 1..={}",
            NATIVE_CONTROLLED_ANGLE_FIRST_MAX_DURATION_MS
        ));
    }
    Ok(())
}

fn contains_any(haystack: &str, needles: &[&str]) -> bool {
    needles.iter().any(|needle| haystack.contains(needle))
}

fn validate_controlled_angle_bench_clear_evidence(
    evidence: &str,
    profile: MozaControlledAngleProfile,
) -> Result<()> {
    if matches!(
        profile,
        MozaControlledAngleProfile::BoundedPidffEffectLifecycleV1
    ) {
        if evidence.trim() != NATIVE_CONTROLLED_ANGLE_ATTEMPT_03_BENCH_CLEAR_EVIDENCE {
            return Err(anyhow!(
                "--bench-clear-evidence must exactly match the pinned attempt-03 clearance phrase for bounded-pidff-effect-lifecycle-v1"
            ));
        }
        return Ok(());
    }

    let normalized = evidence.trim().to_ascii_lowercase();
    let mut missing = Vec::new();

    if !contains_any(&normalized, &["bench clear", "bench-clear"]) {
        missing.push("bench clear");
    }
    if !contains_any(&normalized, &["exactly one", "one exact"]) {
        missing.push("exactly one command");
    }
    if !contains_any(
        &normalized,
        &["target 1 degree", "target 1 degrees", "1 degree"],
    ) {
        missing.push("target 1 degree");
    }
    if !contains_any(
        &normalized,
        &["max 5%", "max 5 percent", "max-percent 5", "max 5"],
    ) {
        missing.push("max 5 percent");
    }
    if !contains_any(
        &normalized,
        &["timeout 2000 ms", "timeout 2000ms", "2000 ms"],
    ) {
        missing.push("timeout 2000 ms");
    }
    if !normalized.contains("pidff-bounded-effect") {
        missing.push("strategy pidff-bounded-effect");
    }
    if !normalized.contains(controlled_angle_profile_cli_name(profile)) {
        missing.push(controlled_angle_profile_cli_name(profile));
    }
    if !normalized.contains("retry") {
        missing.push("controlled-angle retry");
    }
    if !normalized.contains("prior failed receipt preserved") {
        missing.push("prior failed receipt preserved");
    }
    if !(normalized.contains("r5") && normalized.contains("stable")) {
        missing.push("R5 stable");
    }
    if !(normalized.contains("attached") && normalized.contains("secure")) {
        missing.push("rim attached securely");
    }
    if !normalized.contains("hands clear") {
        missing.push("hands clear");
    }
    if !normalized.contains("wheel clear") {
        missing.push("wheel clear");
    }

    if !missing.is_empty() {
        return Err(anyhow!(
            "--bench-clear-evidence must be command-bound for the exact controlled-angle retry; missing: {}",
            missing.join(", ")
        ));
    }

    Ok(())
}

fn disconnect_max_writes(max_duration_ms: u64, hz: u32) -> u32 {
    max_duration_ms
        .saturating_mul(u64::from(hz))
        .div_ceil(1000)
        .max(1)
        .min(u64::from(u32::MAX)) as u32
}

fn init_mode_to_ffb_mode(mode: MozaInitMode) -> FfbMode {
    match mode {
        MozaInitMode::Off => FfbMode::Off,
        MozaInitMode::Standard => FfbMode::Standard,
    }
}

fn init_mode_label(mode: MozaInitMode) -> &'static str {
    match mode {
        MozaInitMode::Off => "off",
        MozaInitMode::Standard => "standard",
    }
}

fn ffb_mode_wire_hex(mode: MozaInitMode) -> String {
    hex_u8(init_mode_to_ffb_mode(mode) as u8)
}

fn init_state_label(state: MozaInitState) -> &'static str {
    match state {
        MozaInitState::Uninitialized => "uninitialized",
        MozaInitState::Initializing => "initializing",
        MozaInitState::Ready => "ready",
        MozaInitState::Failed => "failed",
        MozaInitState::PermanentFailure => "permanent_failure",
    }
}

fn feature_report_kind(report_id: u8) -> &'static str {
    match report_id {
        0x02 => "high_torque",
        0x03 => "start_input_reports",
        0x11 => "ffb_mode",
        _ => "unknown",
    }
}

fn zero_torque_dry_run_pid(selector: Option<&str>, pid_override: Option<&str>) -> Result<u16> {
    if let Some(pid) = pid_override {
        return parse_required_hex_u16(pid);
    }
    if let Some(selector) = selector {
        if let Some((_vid, pid)) = parse_vid_pid_selector(selector) {
            return Ok(pid);
        }
        if let Some(identity) = parse_hid_observe_selector(selector) {
            return Ok(identity.product_id);
        }
        if let Some(pid) = parse_hex_selector(selector) {
            return Ok(pid);
        }
    }
    Err(anyhow!(
        "--dry-run requires --pid or --device as a PID/VID:PID selector"
    ))
}

fn zero_torque_payload_for_pid(pid: u16) -> [u8; REPORT_LEN] {
    let protocol = MozaProtocol::new_with_config(pid, FfbMode::Off, false);
    let encoder = MozaDirectTorqueEncoder::new(protocol.model().max_torque_nm());
    let mut payload = [0u8; REPORT_LEN];
    let _ = encoder.encode_zero(&mut payload);
    payload
}

fn low_torque_payload_for_pid_percent(pid: u16, percent: f32) -> ([u8; REPORT_LEN], f32) {
    let protocol = MozaProtocol::new_with_config(pid, FfbMode::Off, false);
    let max_torque_nm = protocol.model().max_torque_nm();
    let encoder = MozaDirectTorqueEncoder::new(max_torque_nm);
    let torque_nm = max_torque_nm * (percent / 100.0);
    let mut payload = [0u8; REPORT_LEN];
    let _ = encoder.encode(torque_nm, 0, &mut payload);
    (payload, torque_nm)
}

fn r5_v1_pidff_set_effect_payload(
    block_index: u8,
    effect_type: u8,
    duration_ms: u16,
    gain: u8,
    direction_x: u16,
    direction_y: u16,
) -> [u8; PIDFF_SET_EFFECT_R5_V1_REPORT_LEN] {
    let mut payload = [0_u8; PIDFF_SET_EFFECT_R5_V1_REPORT_LEN];
    payload[0] = PIDFF_SET_EFFECT_REPORT_ID_BYTE;
    payload[1] = block_index;
    payload[2] = effect_type;
    payload[3..5].copy_from_slice(&duration_ms.to_le_bytes());
    payload[11] = gain;
    payload[12] = PIDFF_TRIGGER_BUTTON_NONE;
    payload[13] = 0b0000_0101; // X axis enabled and direction enabled; other bits are padding.
    payload[14..16].copy_from_slice(&direction_x.to_le_bytes());
    payload[16..18].copy_from_slice(&direction_y.to_le_bytes());
    payload
}

fn r5_v1_pidff_set_effect_encoder_available() -> bool {
    let payload = r5_v1_pidff_set_effect_payload(1, PIDFF_EFFECT_TYPE_CONSTANT_FORCE, 150, 1, 0, 0);
    payload.len() == PIDFF_SET_EFFECT_R5_V1_REPORT_LEN
        && payload[0] == PIDFF_SET_EFFECT_REPORT_ID_BYTE
        && payload[12] == PIDFF_TRIGGER_BUTTON_NONE
}

fn pidff_gain_for_percent(percent: f32) -> u8 {
    ((255.0 * (percent / 100.0)).round() as u16).clamp(1, u16::from(u8::MAX)) as u8
}

fn pidff_constant_force_for_percent(percent: f32) -> i16 {
    pidff_signed_constant_force_for_percent(percent.max(0.0))
}

fn pidff_signed_constant_force_for_percent(percent: f32) -> i16 {
    if percent == 0.0 {
        return 0;
    }
    let raw = ((f32::from(i16::MAX) * (percent / 100.0)).round() as i32)
        .clamp(i32::from(i16::MIN), i32::from(i16::MAX));
    if raw == 0 {
        percent.signum() as i16
    } else {
        raw as i16
    }
}

fn pidff_low_torque_reports(max_percent: f32, duration_ms: u64) -> Vec<PidffLowTorqueReport> {
    let duration = duration_ms.min(u64::from(u16::MAX)) as u16;
    let gain = pidff_gain_for_percent(max_percent);
    let magnitude = pidff_constant_force_for_percent(max_percent);
    vec![
        PidffLowTorqueReport::new(
            "pidff_set_effect",
            max_percent,
            r5_v1_pidff_set_effect_payload(
                PIDFF_LOW_TORQUE_EFFECT_BLOCK_INDEX,
                EffectType::Constant as u8,
                duration,
                gain,
                PIDFF_LOW_TORQUE_DIRECTION_X,
                PIDFF_LOW_TORQUE_DIRECTION_Y,
            )
            .to_vec(),
            0,
            false,
            PIDFF_EFFECT_SETUP_CLASSIFICATION,
        ),
        PidffLowTorqueReport::new(
            "pidff_set_constant_force",
            max_percent,
            pidff::encode_set_constant_force(PIDFF_LOW_TORQUE_EFFECT_BLOCK_INDEX, magnitude)
                .to_vec(),
            magnitude,
            true,
            PIDFF_BOUNDED_EFFECT_CLASSIFICATION,
        ),
        PidffLowTorqueReport::new(
            "pidff_effect_start",
            max_percent,
            pidff::encode_effect_operation(
                PIDFF_LOW_TORQUE_EFFECT_BLOCK_INDEX,
                EffectOp::Start,
                PIDFF_LOW_TORQUE_LOOP_COUNT,
            )
            .to_vec(),
            0,
            true,
            PIDFF_BOUNDED_EFFECT_CLASSIFICATION,
        ),
    ]
}

fn pidff_actuator_visible_reports(
    profile: MozaActuatorProfile,
    max_percent: f32,
    duration_ms: u64,
) -> Vec<PidffLowTorqueReport> {
    match profile {
        MozaActuatorProfile::ConstantLowForce => pidff_low_torque_reports(max_percent, duration_ms),
        MozaActuatorProfile::BoundedShapedPidffMicroProfile => {
            pidff_shaped_micro_visible_reports(max_percent, duration_ms)
        }
    }
}

fn pidff_shaped_micro_visible_reports(
    max_percent: f32,
    duration_ms: u64,
) -> Vec<PidffLowTorqueReport> {
    let duration = duration_ms.min(u64::from(u16::MAX)) as u16;
    let gain = pidff_gain_for_percent(max_percent);
    let outbound_ms = duration_ms.saturating_mul(55).div_ceil(100).max(1);
    let remaining_ms = duration_ms.saturating_sub(outbound_ms);
    let return_ms = remaining_ms.saturating_mul(2).div_ceil(3);
    let settle_ms = remaining_ms.saturating_sub(return_ms);
    let outbound_magnitude = pidff_signed_constant_force_for_percent(max_percent);
    let return_percent = -(max_percent * 0.5);
    let return_magnitude = pidff_signed_constant_force_for_percent(return_percent);

    let mut reports = vec![
        PidffLowTorqueReport::new(
            "pidff_set_effect",
            max_percent,
            r5_v1_pidff_set_effect_payload(
                PIDFF_LOW_TORQUE_EFFECT_BLOCK_INDEX,
                EffectType::Constant as u8,
                duration,
                gain,
                PIDFF_LOW_TORQUE_DIRECTION_X,
                PIDFF_LOW_TORQUE_DIRECTION_Y,
            )
            .to_vec(),
            0,
            false,
            PIDFF_EFFECT_SETUP_CLASSIFICATION,
        )
        .with_profile_phase("setup", None),
        PidffLowTorqueReport::new(
            "pidff_set_constant_force_outbound",
            max_percent,
            pidff::encode_set_constant_force(
                PIDFF_LOW_TORQUE_EFFECT_BLOCK_INDEX,
                outbound_magnitude,
            )
            .to_vec(),
            outbound_magnitude,
            true,
            PIDFF_BOUNDED_EFFECT_CLASSIFICATION,
        )
        .with_profile_phase("outbound", None),
        PidffLowTorqueReport::new(
            "pidff_effect_start",
            max_percent,
            pidff::encode_effect_operation(
                PIDFF_LOW_TORQUE_EFFECT_BLOCK_INDEX,
                EffectOp::Start,
                PIDFF_LOW_TORQUE_LOOP_COUNT,
            )
            .to_vec(),
            0,
            true,
            PIDFF_BOUNDED_EFFECT_CLASSIFICATION,
        )
        .with_profile_phase("outbound_hold", Some(outbound_ms)),
    ];

    if return_ms > 0 {
        reports.push(
            PidffLowTorqueReport::new(
                "pidff_set_constant_force_return",
                return_percent,
                pidff::encode_set_constant_force(
                    PIDFF_LOW_TORQUE_EFFECT_BLOCK_INDEX,
                    return_magnitude,
                )
                .to_vec(),
                return_magnitude,
                true,
                PIDFF_BOUNDED_EFFECT_CLASSIFICATION,
            )
            .with_profile_phase("return", Some(return_ms)),
        );
    }
    if settle_ms > 0 {
        reports.push(
            PidffLowTorqueReport::new(
                "pidff_set_constant_force_settle",
                0.0,
                pidff::encode_set_constant_force(PIDFF_LOW_TORQUE_EFFECT_BLOCK_INDEX, 0).to_vec(),
                0,
                false,
                PIDFF_BOUNDED_EFFECT_CLASSIFICATION,
            )
            .with_profile_phase("settle", Some(settle_ms)),
        );
    }

    reports
}

fn low_torque_ladder_for_pid(
    pid: u16,
    max_percent: f32,
    duration_ms: u64,
    hz: u32,
) -> Vec<LowTorqueStage> {
    let write_count = duration_ms
        .saturating_mul(u64::from(hz))
        .div_ceil(1000)
        .max(1)
        .min(u64::from(u32::MAX)) as u32;
    let mut stages = Vec::new();
    for target_percent in [0.1_f32, 0.5, 1.0, max_percent] {
        let percent = target_percent.min(max_percent);
        if stages
            .last()
            .map(|stage: &LowTorqueStage| (stage.percent - percent).abs() < f32::EPSILON)
            .unwrap_or(false)
        {
            continue;
        }
        let (payload, torque_nm) = low_torque_payload_for_pid_percent(pid, percent);
        stages.push(LowTorqueStage::new(
            percent,
            torque_nm,
            write_count,
            payload,
        ));
    }
    stages
}

struct LowTorqueRealHardwarePreflight {
    zero_proof: ZeroProofSummary,
    init_proofs: InitProofSet,
    direct_mode_gate: DirectModeGateSummary,
    target_product_id: String,
}

struct PidffLowTorqueRealHardwarePreflight {
    zero_proof: ZeroProofSummary,
    init_proofs: InitProofSet,
    target_product_id: String,
}

struct NativeActuatorProfileSmokePreflight {
    target_product_id: String,
    low_torque_generated_at: Option<String>,
    steering_generated_at: Option<String>,
}

struct NativeActuatorVisibleSmokePreflight {
    target_product_id: String,
    prior_actuator_profile_smoke_validated: bool,
    prior_actuator_generated_at: Option<String>,
    steering_proof_validated: bool,
    steering_generated_at: Option<String>,
}

#[allow(clippy::too_many_arguments)]
fn validate_low_torque_real_hardware_preflight(
    selector: Option<&str>,
    pid_override: Option<&str>,
    lane: Option<&Path>,
    zero_proof: Option<&Path>,
    init_off: Option<&Path>,
    init_standard: Option<&Path>,
    descriptor: Option<&Path>,
    explicit_operator_override: bool,
) -> Result<LowTorqueRealHardwarePreflight> {
    let lane = lane.ok_or_else(|| {
        anyhow!("--lane is required before actual low-torque writes so prerequisites are resolved from the dated hardware lane")
    })?;
    let zero_proof_path = zero_proof
        .ok_or_else(|| anyhow!("--zero-proof is required before actual low-torque writes"))?;
    require_lane_artifact_path(
        lane,
        zero_proof_path,
        "zero-torque-proof.json",
        "--zero-proof",
    )?;
    if let Some(path) = init_off {
        require_lane_artifact_path(lane, path, "init-off.json", "--init-off")?;
    }
    if let Some(path) = init_standard {
        require_lane_artifact_path(lane, path, "init-standard.json", "--init-standard")?;
    }
    if let Some(path) = descriptor {
        require_lane_artifact_path(lane, path, "descriptor.json", "--descriptor")?;
    }
    validate_lane_manifest_endpoint_selector(lane, selector, "actual low-torque writes")?;

    let preflight_at_utc = now_utc();
    let zero_receipt = read_json_value(lane, "zero-torque-proof.json")?;
    if !receipt_path_matches(lane, &zero_receipt, "zero-torque-proof.json") {
        return Err(anyhow!(
            "zero proof receipt_path must match lane artifact zero-torque-proof.json"
        ));
    }
    let zero_proof = validate_zero_proof_for_torque_test(zero_proof_path)?;
    if !utc_timestamp_pair_is_ordered(&zero_proof.generated_at_utc, &preflight_at_utc) {
        return Err(anyhow!(
            "zero proof generated_at_utc must be before the low-torque preflight timestamp"
        ));
    }

    let init_proofs = validate_init_proofs_for_torque_test(
        Some(lane),
        init_off,
        init_standard,
        false,
    )?
    .ok_or_else(|| {
        anyhow!("--lane or both --init-off and --init-standard are required before actual low-torque writes")
    })?;
    require_lane_receipt_path(lane, "init-off.json")?;
    require_lane_receipt_path(lane, "init-standard.json")?;
    if !utc_timestamp_pair_is_ordered(&init_proofs.off.generated_at_utc, &preflight_at_utc)
        || !utc_timestamp_pair_is_ordered(&init_proofs.standard.generated_at_utc, &preflight_at_utc)
    {
        return Err(anyhow!(
            "init proof generated_at_utc values must be before the low-torque preflight timestamp"
        ));
    }

    let target_product_id = low_torque_preflight_target_product_id(
        selector,
        pid_override,
        lane,
        &zero_proof,
        &init_proofs,
    )?;
    if zero_proof.product_id.as_deref() != Some(target_product_id.as_str()) {
        return Err(anyhow!(
            "zero proof PID {:?} does not match low-torque preflight target PID {}",
            zero_proof.product_id,
            target_product_id
        ));
    }
    if !init_proofs.match_product_id(&target_product_id) {
        return Err(anyhow!(
            "init proof PID(s) {:?}/{:?} do not match low-torque preflight target PID {}",
            init_proofs.off.product_id,
            init_proofs.standard.product_id,
            target_product_id
        ));
    }

    if !explicit_operator_override {
        let descriptor_path = descriptor.ok_or_else(|| {
            anyhow!("actual low-torque direct report writes require --descriptor with a trusted R5 descriptor receipt or --explicit-operator-override")
        })?;
        let descriptor_receipt = read_json_path(descriptor_path)?;
        let generated_at_utc = json_string(&descriptor_receipt, "generated_at_utc")
            .ok_or_else(|| anyhow!("descriptor receipt is missing generated_at_utc"))?;
        if !utc_timestamp_pair_is_ordered(generated_at_utc, &preflight_at_utc) {
            return Err(anyhow!(
                "descriptor generated_at_utc must be before the low-torque preflight timestamp"
            ));
        }
        let _descriptor_crc32 = receipt_file_crc32(descriptor_path)?;
    }
    let direct_mode_gate = validate_direct_mode_gate_for_torque_test(
        descriptor,
        &target_product_id,
        explicit_operator_override,
    )?;

    Ok(LowTorqueRealHardwarePreflight {
        zero_proof,
        init_proofs,
        direct_mode_gate,
        target_product_id,
    })
}

fn validate_pidff_low_torque_real_hardware_preflight(
    selector: Option<&str>,
    pid_override: Option<&str>,
    lane: Option<&Path>,
    zero_proof: Option<&Path>,
    init_off: Option<&Path>,
    init_standard: Option<&Path>,
) -> Result<PidffLowTorqueRealHardwarePreflight> {
    let lane = lane.ok_or_else(|| {
        anyhow!("--lane is required before actual PIDFF low-torque writes so prerequisites are resolved from the dated hardware lane")
    })?;
    let zero_proof_path = zero_proof
        .ok_or_else(|| anyhow!("--zero-proof is required before actual PIDFF low-torque writes"))?;
    require_lane_artifact_path(
        lane,
        zero_proof_path,
        "zero-torque-proof.json",
        "--zero-proof",
    )?;
    if let Some(path) = init_off {
        require_lane_artifact_path(lane, path, "init-off.json", "--init-off")?;
    }
    if let Some(path) = init_standard {
        require_lane_artifact_path(lane, path, "init-standard.json", "--init-standard")?;
    }
    validate_lane_manifest_endpoint_selector(lane, selector, "actual PIDFF low-torque writes")?;
    validate_zero_output_pidff_stop_all_report_metadata(lane)?;
    let descriptor_blockers = pidff_bounded_effect_descriptor_blockers(lane);
    if !descriptor_blockers.is_empty() {
        return Err(anyhow!(
            "actual PIDFF low-torque writes require descriptor-proven bounded-effect reports: {}",
            descriptor_blockers.join("; ")
        ));
    }

    let preflight_at_utc = now_utc();
    let zero_receipt = read_json_value(lane, "zero-torque-proof.json")?;
    if !receipt_path_matches(lane, &zero_receipt, "zero-torque-proof.json") {
        return Err(anyhow!(
            "zero proof receipt_path must match lane artifact zero-torque-proof.json"
        ));
    }
    let zero_proof = validate_zero_proof_for_low_torque_strategy(
        zero_proof_path,
        MozaLowTorqueStrategy::PidffBoundedEffect,
    )?;
    if !utc_timestamp_pair_is_ordered(&zero_proof.generated_at_utc, &preflight_at_utc) {
        return Err(anyhow!(
            "zero proof generated_at_utc must be before the PIDFF low-torque preflight timestamp"
        ));
    }

    let init_proofs = validate_init_proofs_for_torque_test(
        Some(lane),
        init_off,
        init_standard,
        false,
    )?
    .ok_or_else(|| {
        anyhow!("--lane or both --init-off and --init-standard are required before actual PIDFF low-torque writes")
    })?;
    require_lane_receipt_path(lane, "init-off.json")?;
    require_lane_receipt_path(lane, "init-standard.json")?;
    if !utc_timestamp_pair_is_ordered(&init_proofs.off.generated_at_utc, &preflight_at_utc)
        || !utc_timestamp_pair_is_ordered(&init_proofs.standard.generated_at_utc, &preflight_at_utc)
    {
        return Err(anyhow!(
            "init proof generated_at_utc values must be before the PIDFF low-torque preflight timestamp"
        ));
    }

    let target_product_id = low_torque_preflight_target_product_id(
        selector,
        pid_override,
        lane,
        &zero_proof,
        &init_proofs,
    )?;
    if zero_proof.product_id.as_deref() != Some(target_product_id.as_str()) {
        return Err(anyhow!(
            "zero proof PID {:?} does not match PIDFF low-torque preflight target PID {}",
            zero_proof.product_id,
            target_product_id
        ));
    }
    if !init_proofs.match_product_id(&target_product_id) {
        return Err(anyhow!(
            "init proof PID(s) {:?}/{:?} do not match PIDFF low-torque preflight target PID {}",
            init_proofs.off.product_id,
            init_proofs.standard.product_id,
            target_product_id
        ));
    }

    Ok(PidffLowTorqueRealHardwarePreflight {
        zero_proof,
        init_proofs,
        target_product_id,
    })
}

fn validate_native_actuator_profile_smoke_preflight(
    selector: &str,
    lane: &Path,
    low_torque_proof: Option<&Path>,
    steering_proof: Option<&Path>,
    json_out: Option<&Path>,
    dry_run: bool,
) -> Result<NativeActuatorProfileSmokePreflight> {
    validate_lane_manifest_endpoint_selector(
        lane,
        Some(selector),
        "native actuator-profile smoke",
    )?;
    if let Some(path) = low_torque_proof {
        require_lane_artifact_path(lane, path, "low-torque-proof.json", "--low-torque-proof")?;
    }
    if let Some(path) = steering_proof {
        require_lane_artifact_path(
            lane,
            path,
            "steering-angle-stream-proof.json",
            "--steering-proof",
        )?;
    }
    if !dry_run {
        let json_out = json_out.ok_or_else(|| {
            anyhow!("--json-out is required before actual native actuator-profile smoke writes")
        })?;
        require_lane_artifact_path(
            lane,
            json_out,
            "native-actuator-profile-smoke.json",
            "--json-out",
        )?;
    }

    validate_zero_output_pidff_stop_all_report_metadata(lane)?;
    let descriptor_blockers = pidff_bounded_effect_descriptor_blockers(lane);
    if !descriptor_blockers.is_empty() {
        return Err(anyhow!(
            "native actuator-profile smoke requires descriptor-proven PIDFF bounded-effect reports: {}",
            descriptor_blockers.join("; ")
        ));
    }

    let low_torque_gate = verify_low_torque_gate(lane);
    if low_torque_gate.status != "pass" {
        return Err(anyhow!(
            "same-lane low-torque proof must pass before native actuator-profile smoke: {}",
            low_torque_gate.details
        ));
    }
    let steering_gate = verify_steering_angle_stream_gate(lane);
    if steering_gate.status != "pass" {
        return Err(anyhow!(
            "same-lane steering stream proof must pass before native actuator-profile smoke: {}",
            steering_gate.details
        ));
    }

    let low_torque_receipt = read_json_value(lane, "low-torque-proof.json")?;
    if json_string(&low_torque_receipt, "low_torque_strategy")
        != Some(low_torque_strategy_name(
            MozaLowTorqueStrategy::PidffBoundedEffect,
        ))
    {
        return Err(anyhow!(
            "native actuator-profile smoke requires a same-lane PIDFF low-torque proof"
        ));
    }
    let target_product_id = low_torque_receipt
        .get("device")
        .and_then(|device| json_string(device, "product_id"))
        .map(str::to_string)
        .ok_or_else(|| anyhow!("low-torque proof device.product_id is missing"))?;
    let steering_receipt = read_json_value(lane, "steering-angle-stream-proof.json")?;
    let steering_product_id = steering_receipt
        .get("device")
        .and_then(|device| json_string(device, "product_id"));
    if steering_product_id != Some(target_product_id.as_str()) {
        return Err(anyhow!(
            "steering proof PID {:?} does not match low-torque proof PID {}",
            steering_product_id,
            target_product_id
        ));
    }

    Ok(NativeActuatorProfileSmokePreflight {
        target_product_id,
        low_torque_generated_at: json_string(&low_torque_receipt, "generated_at_utc")
            .map(str::to_string),
        steering_generated_at: json_string(&steering_receipt, "generated_at_utc")
            .map(str::to_string),
    })
}

#[allow(clippy::too_many_arguments)]
fn validate_native_actuator_visible_smoke_preflight(
    selector: &str,
    lane: &Path,
    prior_actuator_proof: Option<&Path>,
    steering_proof: Option<&Path>,
    json_out: Option<&Path>,
    profile: MozaActuatorProfile,
    strategy: MozaLowTorqueStrategy,
    max_percent: f32,
    duration_ms: u64,
    movement_threshold_degrees: f64,
    dry_run: bool,
) -> Result<NativeActuatorVisibleSmokePreflight> {
    validate_lane_manifest_endpoint_selector(
        lane,
        Some(selector),
        "native actuator visible-motion smoke",
    )?;
    if let Some(path) = prior_actuator_proof {
        require_lane_artifact_path(
            lane,
            path,
            "native-actuator-profile-smoke.json",
            "--prior-actuator-proof",
        )?;
    }
    if let Some(path) = steering_proof {
        require_lane_artifact_path(
            lane,
            path,
            "steering-angle-stream-proof.json",
            "--steering-proof",
        )?;
    }
    if !dry_run {
        let json_out = json_out.ok_or_else(|| {
            anyhow!("--json-out is required before actual native actuator visible-motion writes")
        })?;
        let output_file = native_visible_output_relative_path(lane, json_out, "--json-out")?;
        if output_file == VENDOR_AUTHORITY_POST_PIDFF_SMOKE_FILE {
            validate_post_authority_pidff_smoke_context(lane)?;
        }
        validate_native_visible_retry_authorization(
            lane,
            selector,
            profile,
            strategy,
            max_percent,
            duration_ms,
            movement_threshold_degrees,
            json_out,
        )?;
    }

    validate_zero_output_pidff_stop_all_report_metadata(lane)?;
    let descriptor_blockers = pidff_bounded_effect_descriptor_blockers(lane);
    if !descriptor_blockers.is_empty() {
        return Err(anyhow!(
            "native actuator visible-motion smoke requires descriptor-proven PIDFF bounded-effect reports: {}",
            descriptor_blockers.join("; ")
        ));
    }

    let prior_gate = verify_native_actuator_profile_smoke_gate(lane);
    if prior_gate.status != "pass" {
        return Err(anyhow!(
            "same-lane native actuator-profile smoke must pass before visible-motion smoke: {}",
            prior_gate.details
        ));
    }
    let steering_gate = verify_steering_angle_stream_gate(lane);
    if steering_gate.status != "pass" {
        return Err(anyhow!(
            "same-lane steering stream proof must pass before visible-motion smoke: {}",
            steering_gate.details
        ));
    }

    let prior_receipt = read_json_value(lane, "native-actuator-profile-smoke.json")?;
    if json_string(&prior_receipt, "output_strategy")
        != Some(low_torque_strategy_name(
            MozaLowTorqueStrategy::PidffBoundedEffect,
        ))
    {
        return Err(anyhow!(
            "native actuator visible-motion smoke requires a same-lane PIDFF actuator-profile proof"
        ));
    }
    let target_product_id = prior_receipt
        .get("device")
        .and_then(|device| json_string(device, "product_id"))
        .map(str::to_string)
        .ok_or_else(|| anyhow!("native actuator-profile receipt device.product_id is missing"))?;
    let steering_receipt = read_json_value(lane, "steering-angle-stream-proof.json")?;
    let steering_product_id = steering_receipt
        .get("device")
        .and_then(|device| json_string(device, "product_id"));
    if steering_product_id != Some(target_product_id.as_str()) {
        return Err(anyhow!(
            "steering proof PID {:?} does not match prior actuator proof PID {}",
            steering_product_id,
            target_product_id
        ));
    }

    Ok(NativeActuatorVisibleSmokePreflight {
        target_product_id,
        prior_actuator_profile_smoke_validated: true,
        prior_actuator_generated_at: json_string(&prior_receipt, "generated_at_utc")
            .map(str::to_string),
        steering_proof_validated: true,
        steering_generated_at: json_string(&steering_receipt, "generated_at_utc")
            .map(str::to_string),
    })
}

#[allow(clippy::too_many_arguments)]
fn validate_native_visible_retry_authorization(
    lane: &Path,
    selector: &str,
    profile: MozaActuatorProfile,
    strategy: MozaLowTorqueStrategy,
    max_percent: f32,
    duration_ms: u64,
    movement_threshold_degrees: f64,
    json_out: &Path,
) -> Result<()> {
    if failed_real_native_visible_smoke_receipt(lane).is_none() {
        return Ok(());
    }

    let plan = read_json_value(lane, NATIVE_VISIBLE_FOLLOW_UP_PLAN_FILE).with_context(|| {
        format!(
            "a response-only native visible-motion receipt already exists; record {} before another hardware-output attempt",
            NATIVE_VISIBLE_FOLLOW_UP_PLAN_FILE
        )
    })?;
    let planned_next_output = plan.get("planned_next_output").ok_or_else(|| {
        anyhow!(
            "{} is missing planned_next_output",
            NATIVE_VISIBLE_FOLLOW_UP_PLAN_FILE
        )
    })?;
    let allowed = json_bool(planned_next_output, "allowed") == Some(true);
    let hardware_authorized = json_bool(&plan, "hardware_output_authorized") == Some(true);
    let fresh_clear_recorded =
        json_bool(planned_next_output, "requires_fresh_bench_clear") == Some(false);

    if !allowed || !hardware_authorized || !fresh_clear_recorded {
        return Err(anyhow!(
            "existing response-only native visible-motion receipt blocks another hardware-output attempt until {} sets hardware_output_authorized=true, planned_next_output.allowed=true, planned_next_output.requires_fresh_bench_clear=false, and records the exact command",
            NATIVE_VISIBLE_FOLLOW_UP_PLAN_FILE
        ));
    }
    let command = json_string(planned_next_output, "command")
        .map(str::trim)
        .filter(|command| !command.is_empty())
        .ok_or_else(|| anyhow!("planned_next_output.command is empty"))?;
    validate_authorized_native_visible_command(
        lane,
        command,
        selector,
        profile,
        strategy,
        max_percent,
        duration_ms,
        movement_threshold_degrees,
        json_out,
    )
}

#[allow(clippy::too_many_arguments)]
fn consume_native_visible_output_authorization(
    lane: &Path,
    selector: &str,
    profile: MozaActuatorProfile,
    strategy: MozaLowTorqueStrategy,
    max_percent: f32,
    duration_ms: u64,
    movement_threshold_degrees: f64,
    json_out: &Path,
    receipt: &Value,
) -> Result<()> {
    let plan_path = lane.join(NATIVE_VISIBLE_FOLLOW_UP_PLAN_FILE);
    if !plan_path.is_file() {
        return Ok(());
    }

    let mut plan = read_json_value(lane, NATIVE_VISIBLE_FOLLOW_UP_PLAN_FILE)?;
    let planned_next_output = plan.get("planned_next_output").ok_or_else(|| {
        anyhow!(
            "{} is missing planned_next_output",
            NATIVE_VISIBLE_FOLLOW_UP_PLAN_FILE
        )
    })?;
    let allowed = json_bool(planned_next_output, "allowed") == Some(true);
    let hardware_authorized = json_bool(&plan, "hardware_output_authorized") == Some(true);
    if !allowed && !hardware_authorized {
        return Ok(());
    }

    let command = json_string(planned_next_output, "command")
        .map(str::trim)
        .filter(|command| !command.is_empty())
        .ok_or_else(|| anyhow!("planned_next_output.command is empty"))?;
    validate_authorized_native_visible_command(
        lane,
        command,
        selector,
        profile,
        strategy,
        max_percent,
        duration_ms,
        movement_threshold_degrees,
        json_out,
    )?;

    let output_file = native_visible_output_relative_path(lane, json_out, "--json-out")?;
    let post_authority_pidff_capture = output_file == VENDOR_AUTHORITY_POST_PIDFF_SMOKE_FILE;
    let visible_passed = json_bool(receipt, "success") == Some(true);
    let evidence_status = if post_authority_pidff_capture {
        "post_authority_pidff_response_consumed_no_motion_claim"
    } else if visible_passed {
        "exact_output_attempt_consumed_visible_motion_proven"
    } else {
        "exact_output_attempt_consumed_visible_motion_unproven"
    };
    let review_decision = if post_authority_pidff_capture {
        "post_authority_pidff_response_recorded_pending_comparison"
    } else if visible_passed {
        "authorized_output_consumed_visible_motion_proven"
    } else {
        "authorized_output_consumed_visible_motion_unproven"
    };

    plan["hardware_output_authorized"] = serde_json::json!(false);
    plan["authorization_consumed"] = serde_json::json!(true);
    plan["authorization_consumed_at_utc"] = serde_json::json!(now_utc());
    plan["authorization_consumed_by_receipt"] =
        serde_json::json!(lane_relative_or_display(lane, json_out));
    plan["evidence_status"] = serde_json::json!(evidence_status);
    plan["review_decision"] = serde_json::json!(review_decision);
    plan["planned_next_output"]["allowed"] = serde_json::json!(false);
    plan["planned_next_output"]["command"] = serde_json::json!("");
    plan["planned_next_output"]["requires_fresh_bench_clear"] = serde_json::json!(true);
    plan["planned_next_output"]["duration_ms"] = serde_json::json!("not_authorized");
    plan["planned_next_output"]["force_percent"] = serde_json::json!("not_authorized");
    plan["last_output_attempt"] = serde_json::json!({
        "status": if post_authority_pidff_capture {
            if visible_passed {
                "post_authority_visible_motion_candidate_requires_verifier"
            } else {
                "post_authority_pidff_response_recorded_no_motion_claim"
            }
        } else if visible_passed {
            "visible_motion_proven"
        } else {
            "visible_motion_unproven"
        },
        "receipt": lane_relative_or_display(lane, json_out),
        "post_authority_pidff_response_capture": post_authority_pidff_capture,
        "profile": json_string(receipt, "profile"),
        "strategy": json_string(receipt, "output_strategy"),
        "max_percent": json_f64(receipt, "max_percent"),
        "duration_ms": json_u64(receipt, "duration_ms"),
        "movement_threshold_degrees": json_f64(receipt, "movement_threshold_degrees"),
        "angle_delta_degrees": json_f64(receipt, "angle_delta_degrees"),
        "movement_observed": json_bool(receipt, "movement_observed"),
        "steering_sample_count": json_u64(receipt, "steering_sample_count"),
        "write_attempts": json_u64(receipt, "write_attempts"),
        "writes_ok": json_u64(receipt, "writes_ok"),
        "write_errors": json_u64(receipt, "write_errors"),
        "final_stop_all_sent": json_bool(receipt, "final_stop_all_sent"),
        "post_stop_stable": json_bool(receipt, "post_stop_stable"),
        "no_direct_torque_reports": json_bool(receipt, "no_direct_torque_reports"),
        "no_high_torque": json_bool(receipt, "no_high_torque"),
        "no_serial_config_commands": json_bool(receipt, "no_serial_config_commands"),
        "no_firmware_or_dfu_commands": json_bool(receipt, "no_firmware_or_dfu_commands")
    });
    update_native_visible_consumed_authorization_checks(&mut plan, visible_passed);
    plan["notes"] = serde_json::json!([
        "Authorization artifact only: this file is not evidence that visible motion passed.",
        if post_authority_pidff_capture {
            "The exact authorized post-authority PIDFF response command has been consumed by a separate non-claiming receipt."
        } else {
            "The exact authorized native visible-motion command has been consumed by the recorded output receipt."
        },
        "No further hardware-output command is authorized by this artifact; use a separate reviewed plan and fresh bench-clear before any rerun, longer duration, higher force, or controlled-angle profile."
    ]);

    write_json_file(&plan_path, &plan)
}

fn update_native_visible_consumed_authorization_checks(plan: &mut Value, visible_passed: bool) {
    let Some(checks) = plan
        .get_mut("required_before_next_output")
        .and_then(Value::as_array_mut)
    else {
        return;
    };
    for check in checks {
        match json_string(check, "check") {
            Some("bench_clearance")
            | Some("fresh_operator_bench_clear_for_exact_next_output_command") => {
                check["status"] = serde_json::json!("pending");
                check["evidence"] = serde_json::json!(
                    "The prior bench-clear was consumed by the recorded native visible-motion output attempt; a new exact-command bench-clear is required before any later output."
                );
            }
            Some("wheelbase_ffb_mode_and_vendor_state") if visible_passed => {
                check["status"] = serde_json::json!("not_required_after_visible_pass");
                check["evidence"] = serde_json::json!(
                    "The authorized output attempt passed the visible-motion gate; no follow-up output is authorized by this plan."
                );
            }
            Some("wheelbase_ffb_mode_and_vendor_state") => {
                check["status"] = serde_json::json!("pending_review_after_consumed_output");
                check["evidence"] = serde_json::json!(
                    "The authorized output attempt did not prove visible motion; review wheelbase FFB/vendor state and command semantics before planning any later output."
                );
            }
            _ => {}
        }
    }
}

#[allow(clippy::too_many_arguments)]
fn validate_authorized_native_visible_command(
    lane: &Path,
    command: &str,
    selector: &str,
    profile: MozaActuatorProfile,
    strategy: MozaLowTorqueStrategy,
    max_percent: f32,
    duration_ms: u64,
    movement_threshold_degrees: f64,
    json_out: &Path,
) -> Result<()> {
    if command.contains('<') || command.contains('>') {
        return Err(anyhow!(
            "planned_next_output.command must be the exact command, not a template"
        ));
    }
    let tokens: Vec<&str> = command.split_whitespace().collect();
    let command_prefix_ok = tokens.starts_with(&["wheelctl", "moza", "actuator-visible-smoke"]);
    let selector_ok = command_arg_matches(&tokens, "--device", selector);
    let lane_ok = command_arg_path_matches(&tokens, "--lane", lane);
    let prior_ok = command_arg_path_matches(
        &tokens,
        "--prior-actuator-proof",
        &lane.join("native-actuator-profile-smoke.json"),
    );
    let steering_ok = command_arg_path_matches(
        &tokens,
        "--steering-proof",
        &lane.join("steering-angle-stream-proof.json"),
    );
    let profile_ok = command_arg_matches(&tokens, "--profile", actuator_profile_cli_name(profile));
    let strategy_ok = command_arg_matches(
        &tokens,
        "--strategy",
        low_torque_strategy_cli_name(strategy),
    );
    let max_percent_ok = command_arg_f32_matches(&tokens, "--max-percent", max_percent);
    let duration_ok = command_arg_u64_matches(&tokens, "--duration-ms", duration_ms);
    let threshold_ok = command_arg_f64_matches(
        &tokens,
        "--movement-threshold-degrees",
        movement_threshold_degrees,
    );
    let confirm_ok = tokens.contains(&"--confirm-actuator-visible");
    let dry_run_absent = !tokens.contains(&"--dry-run");
    let json_out_ok = command_arg_path_matches(&tokens, "--json-out", json_out);
    if command_prefix_ok
        && selector_ok
        && lane_ok
        && prior_ok
        && steering_ok
        && profile_ok
        && strategy_ok
        && max_percent_ok
        && duration_ok
        && threshold_ok
        && confirm_ok
        && dry_run_absent
        && json_out_ok
    {
        Ok(())
    } else {
        Err(anyhow!(
            "planned_next_output.command does not match this native visible-motion output request: command_prefix_ok={command_prefix_ok}, selector_ok={selector_ok}, lane_ok={lane_ok}, prior_ok={prior_ok}, steering_ok={steering_ok}, profile_ok={profile_ok}, strategy_ok={strategy_ok}, max_percent_ok={max_percent_ok}, duration_ok={duration_ok}, threshold_ok={threshold_ok}, confirm_ok={confirm_ok}, dry_run_absent={dry_run_absent}, json_out_ok={json_out_ok}"
        ))
    }
}

#[allow(clippy::too_many_arguments)]
fn validate_native_controlled_angle_output_authorization(
    lane: &Path,
    selector: &str,
    target_degrees: f64,
    profile: MozaControlledAngleProfile,
    max_percent: f32,
    timeout_ms: u64,
    strategy: MozaLowTorqueStrategy,
    json_out: &Path,
    authorization_proof: Option<&Path>,
) -> Result<()> {
    let authorization_file =
        controlled_angle_authorization_relative_path(lane, authorization_proof)?;
    let plan = read_json_value(lane, authorization_file).with_context(|| {
        format!(
            "actual native controlled-angle writes require an exact same-lane authorization receipt at {}",
            lane.join(authorization_file).display()
        )
    })?;
    let command_ok =
        json_string(&plan, "command") == Some("wheelctl moza authorize-controlled-angle-output");
    let authorization_recorded = json_bool(&plan, "authorization_recorded") == Some(true);
    let authorization_unused = json_bool(&plan, "authorization_consumed") != Some(true);
    let hardware_authorized = json_bool(&plan, "hardware_output_authorized") == Some(true);
    let planned_next_output = plan
        .get("planned_next_output")
        .ok_or_else(|| anyhow!("{} is missing planned_next_output", authorization_file))?;
    let allowed = json_bool(planned_next_output, "allowed") == Some(true);
    let fresh_clear_recorded =
        json_bool(planned_next_output, "requires_fresh_bench_clear") == Some(false);
    let target_ok = json_f64(planned_next_output, "target_degrees")
        .map(|value| (value - target_degrees).abs() <= f64::EPSILON)
        .unwrap_or(false);
    let profile_ok = json_string(planned_next_output, "profile")
        == Some(controlled_angle_profile_name(profile))
        && json_string(planned_next_output, "profile_cli")
            == Some(controlled_angle_profile_cli_name(profile));
    let max_percent_ok = json_f64(planned_next_output, "max_percent")
        .or_else(|| json_f64(planned_next_output, "force_percent"))
        .map(|value| (value - f64::from(max_percent)).abs() <= f64::EPSILON)
        .unwrap_or(false);
    let timeout_ok = json_u64(planned_next_output, "timeout_ms")
        .or_else(|| json_u64(planned_next_output, "duration_ms"))
        == Some(timeout_ms);
    let strategy_ok = json_string(planned_next_output, "strategy")
        == Some(low_torque_strategy_cli_name(strategy));
    let output_file = controlled_angle_output_relative_path(lane, json_out, "--json-out")?;
    let authorization_proof_arg = (authorization_file
        != NATIVE_CONTROLLED_ANGLE_AUTHORIZATION_FILE)
        .then_some(authorization_file);

    let command = json_string(planned_next_output, "command")
        .map(str::trim)
        .filter(|command| !command.is_empty())
        .ok_or_else(|| anyhow!("planned_next_output.command is empty"))?;
    let exact_command_text_ok = command
        == native_controlled_angle_output_command(
            lane,
            selector,
            target_degrees,
            profile,
            strategy,
            max_percent,
            timeout_ms,
            output_file,
            authorization_proof_arg,
        );
    validate_authorized_native_controlled_angle_command(
        lane,
        command,
        selector,
        target_degrees,
        profile,
        max_percent,
        timeout_ms,
        strategy,
        json_out,
        authorization_proof_arg,
    )?;

    if command_ok
        && authorization_recorded
        && authorization_unused
        && hardware_authorized
        && allowed
        && fresh_clear_recorded
        && target_ok
        && profile_ok
        && max_percent_ok
        && timeout_ok
        && strategy_ok
        && exact_command_text_ok
    {
        Ok(())
    } else {
        Err(anyhow!(
            "{} does not authorize this exact native controlled-angle output request: command_ok={command_ok}, authorization_recorded={authorization_recorded}, authorization_unused={authorization_unused}, hardware_authorized={hardware_authorized}, allowed={allowed}, fresh_clear_recorded={fresh_clear_recorded}, target_ok={target_ok}, profile_ok={profile_ok}, max_percent_ok={max_percent_ok}, timeout_ok={timeout_ok}, strategy_ok={strategy_ok}, exact_command_text_ok={exact_command_text_ok}",
            authorization_file
        ))
    }
}

#[allow(clippy::too_many_arguments)]
fn consume_native_controlled_angle_output_authorization(
    lane: &Path,
    selector: &str,
    target_degrees: f64,
    profile: MozaControlledAngleProfile,
    max_percent: f32,
    timeout_ms: u64,
    strategy: MozaLowTorqueStrategy,
    json_out: &Path,
    authorization_proof: Option<&Path>,
    receipt: &Value,
) -> Result<()> {
    let authorization_file =
        controlled_angle_authorization_relative_path(lane, authorization_proof)?;
    let plan_path = lane.join(authorization_file);
    if !plan_path.is_file() {
        return Ok(());
    }

    let mut plan = read_json_value(lane, authorization_file)?;
    let planned_next_output = plan
        .get("planned_next_output")
        .ok_or_else(|| anyhow!("{} is missing planned_next_output", authorization_file))?;
    let allowed = json_bool(planned_next_output, "allowed") == Some(true);
    let hardware_authorized = json_bool(&plan, "hardware_output_authorized") == Some(true);
    if !allowed && !hardware_authorized {
        return Ok(());
    }
    let command = json_string(planned_next_output, "command")
        .map(str::trim)
        .filter(|command| !command.is_empty())
        .ok_or_else(|| anyhow!("planned_next_output.command is empty"))?;
    let authorization_proof_arg = (authorization_file
        != NATIVE_CONTROLLED_ANGLE_AUTHORIZATION_FILE)
        .then_some(authorization_file);
    validate_authorized_native_controlled_angle_command(
        lane,
        command,
        selector,
        target_degrees,
        profile,
        max_percent,
        timeout_ms,
        strategy,
        json_out,
        authorization_proof_arg,
    )?;

    let controlled_angle_passed = json_bool(receipt, "success") == Some(true);
    plan["hardware_output_authorized"] = serde_json::json!(false);
    plan["authorization_consumed"] = serde_json::json!(true);
    plan["authorization_consumed_at_utc"] = serde_json::json!(now_utc());
    plan["authorization_consumed_by_receipt"] =
        serde_json::json!(lane_relative_or_display(lane, json_out));
    plan["evidence_status"] = serde_json::json!(if controlled_angle_passed {
        "exact_output_attempt_consumed_controlled_angle_proven"
    } else {
        "exact_output_attempt_consumed_controlled_angle_unproven"
    });
    plan["planned_next_output"]["allowed"] = serde_json::json!(false);
    plan["planned_next_output"]["command"] = serde_json::json!("");
    plan["planned_next_output"]["requires_fresh_bench_clear"] = serde_json::json!(true);
    plan["planned_next_output"]["target_degrees"] = serde_json::json!("not_authorized");
    plan["planned_next_output"]["max_percent"] = serde_json::json!("not_authorized");
    plan["planned_next_output"]["timeout_ms"] = serde_json::json!("not_authorized");
    plan["last_output_attempt"] = serde_json::json!({
        "status": if controlled_angle_passed {
            "controlled_angle_motion_proven"
        } else {
            "controlled_angle_motion_unproven"
        },
        "receipt": lane_relative_or_display(lane, json_out),
        "target_degrees": json_f64(receipt, "target_degrees"),
        "profile": json_string(receipt, "profile"),
        "max_percent": json_f64(receipt, "max_percent"),
        "duration_ms": json_u64(receipt, "duration_ms"),
        "angle_delta_degrees": json_f64(receipt, "angle_delta_degrees"),
        "target_reached": json_bool(receipt, "target_reached"),
        "return_to_start_proven": json_bool(receipt, "return_to_start_proven"),
        "write_attempts": json_u64(receipt, "write_attempts"),
        "writes_ok": json_u64(receipt, "writes_ok"),
        "write_errors": json_u64(receipt, "write_errors"),
        "final_stop_all_sent": json_bool(receipt, "final_stop_all_sent"),
        "post_stop_stable": json_bool(receipt, "post_stop_stable"),
        "no_direct_torque_reports": json_bool(receipt, "no_direct_torque_reports"),
        "no_high_torque": json_bool(receipt, "no_high_torque"),
        "no_serial_config_commands": json_bool(receipt, "no_serial_config_commands"),
        "no_firmware_or_dfu_commands": json_bool(receipt, "no_firmware_or_dfu_commands")
    });
    plan["notes"] = serde_json::json!([
        "Authorization artifact only: this file is not evidence that controlled-angle motion passed.",
        "The exact authorized native controlled-angle command has been consumed by the recorded output receipt.",
        "No further hardware-output command is authorized by this artifact."
    ]);

    write_json_file(&plan_path, &plan)
}

#[allow(clippy::too_many_arguments)]
fn validate_authorized_native_controlled_angle_command(
    lane: &Path,
    command: &str,
    selector: &str,
    target_degrees: f64,
    profile: MozaControlledAngleProfile,
    max_percent: f32,
    timeout_ms: u64,
    strategy: MozaLowTorqueStrategy,
    json_out: &Path,
    authorization_proof: Option<&str>,
) -> Result<()> {
    if command.contains('<') || command.contains('>') {
        return Err(anyhow!(
            "planned_next_output.command must be the exact command, not a template"
        ));
    }
    let tokens: Vec<&str> = command.split_whitespace().collect();
    let command_prefix_ok = tokens.starts_with(&["wheelctl", "moza", "controlled-angle-smoke"]);
    let selector_ok = command_arg_matches(&tokens, "--device", selector);
    let lane_ok = command_arg_path_matches(&tokens, "--lane", lane);
    let prior_ok = command_arg_path_matches(
        &tokens,
        "--prior-actuator-proof",
        &lane.join("native-actuator-profile-smoke.json"),
    );
    let steering_ok = command_arg_path_matches(
        &tokens,
        "--steering-proof",
        &lane.join("steering-angle-stream-proof.json"),
    );
    let target_ok = command_arg_f64_matches(&tokens, "--target-degrees", target_degrees);
    let profile_ok = command_arg_matches(
        &tokens,
        "--profile",
        controlled_angle_profile_cli_name(profile),
    );
    let strategy_ok = command_arg_matches(
        &tokens,
        "--strategy",
        low_torque_strategy_cli_name(strategy),
    );
    let max_percent_ok = command_arg_f32_matches(&tokens, "--max-percent", max_percent);
    let timeout_ok = command_arg_u64_matches(&tokens, "--timeout-ms", timeout_ms);
    let confirm_ok = tokens.contains(&"--confirm-controlled-angle");
    let dry_run_absent = !tokens.contains(&"--dry-run");
    let json_out_ok = command_arg_path_matches(&tokens, "--json-out", json_out);
    let authorization_proof_ok = match authorization_proof {
        Some(relative_path) => {
            command_arg_path_matches(&tokens, "--authorization-proof", &lane.join(relative_path))
        }
        None => !tokens.contains(&"--authorization-proof"),
    };
    if command_prefix_ok
        && selector_ok
        && lane_ok
        && prior_ok
        && steering_ok
        && target_ok
        && profile_ok
        && strategy_ok
        && max_percent_ok
        && timeout_ok
        && confirm_ok
        && dry_run_absent
        && json_out_ok
        && authorization_proof_ok
    {
        Ok(())
    } else {
        Err(anyhow!(
            "planned_next_output.command does not match this native controlled-angle output request: command_prefix_ok={command_prefix_ok}, selector_ok={selector_ok}, lane_ok={lane_ok}, prior_ok={prior_ok}, steering_ok={steering_ok}, target_ok={target_ok}, profile_ok={profile_ok}, strategy_ok={strategy_ok}, max_percent_ok={max_percent_ok}, timeout_ok={timeout_ok}, confirm_ok={confirm_ok}, dry_run_absent={dry_run_absent}, json_out_ok={json_out_ok}, authorization_proof_ok={authorization_proof_ok}"
        ))
    }
}

fn command_arg_value<'a>(tokens: &'a [&str], flag: &str) -> Option<&'a str> {
    tokens
        .windows(2)
        .find(|window| window[0] == flag)
        .map(|window| window[1])
}

fn command_arg_matches(tokens: &[&str], flag: &str, expected: &str) -> bool {
    command_arg_value(tokens, flag) == Some(expected)
}

fn command_arg_path_matches(tokens: &[&str], flag: &str, expected: &Path) -> bool {
    command_arg_value(tokens, flag)
        .map(|recorded| artifact_path_value_matches(expected, Some(recorded)))
        .unwrap_or(false)
}

fn command_arg_f32_matches(tokens: &[&str], flag: &str, expected: f32) -> bool {
    command_arg_value(tokens, flag)
        .and_then(|value| value.parse::<f32>().ok())
        .map(|value| (value - expected).abs() <= f32::EPSILON)
        .unwrap_or(false)
}

fn command_arg_f64_matches(tokens: &[&str], flag: &str, expected: f64) -> bool {
    command_arg_value(tokens, flag)
        .and_then(|value| value.parse::<f64>().ok())
        .map(|value| (value - expected).abs() <= f64::EPSILON)
        .unwrap_or(false)
}

fn command_arg_u64_matches(tokens: &[&str], flag: &str, expected: u64) -> bool {
    command_arg_value(tokens, flag).and_then(|value| value.parse::<u64>().ok()) == Some(expected)
}

#[allow(clippy::too_many_arguments)]
fn native_visible_output_command(
    lane: &Path,
    selector: &str,
    profile: MozaActuatorProfile,
    strategy: MozaLowTorqueStrategy,
    max_percent: f32,
    duration_ms: u64,
    movement_threshold_degrees: f64,
    json_out_relative_path: &str,
) -> String {
    format!(
        "wheelctl moza actuator-visible-smoke --device {} --lane {} --prior-actuator-proof {} --steering-proof {} --profile {} --strategy {} --max-percent {} --duration-ms {} --movement-threshold-degrees {} --confirm-actuator-visible --json-out {} --json",
        command_arg(selector),
        command_arg(&lane.display().to_string()),
        lane_path_arg(lane, "native-actuator-profile-smoke.json"),
        lane_path_arg(lane, "steering-angle-stream-proof.json"),
        actuator_profile_cli_name(profile),
        low_torque_strategy_cli_name(strategy),
        compact_f32(max_percent),
        duration_ms,
        compact_f64(movement_threshold_degrees),
        lane_path_arg(lane, json_out_relative_path)
    )
}

#[allow(clippy::too_many_arguments)]
fn native_controlled_angle_output_command(
    lane: &Path,
    selector: &str,
    target_degrees: f64,
    profile: MozaControlledAngleProfile,
    strategy: MozaLowTorqueStrategy,
    max_percent: f32,
    timeout_ms: u64,
    json_out_relative_path: &str,
    authorization_proof_relative_path: Option<&str>,
) -> String {
    let authorization_proof = authorization_proof_relative_path
        .map(|relative_path| {
            format!(
                " --authorization-proof {}",
                lane_path_arg(lane, relative_path)
            )
        })
        .unwrap_or_default();
    format!(
        "wheelctl moza controlled-angle-smoke --device {} --lane {} --prior-actuator-proof {} --steering-proof {} --target-degrees {} --profile {} --max-percent {} --timeout-ms {} --strategy {}{} --confirm-controlled-angle --json-out {} --json",
        command_arg(selector),
        command_arg(&lane.display().to_string()),
        lane_path_arg(lane, "native-actuator-profile-smoke.json"),
        lane_path_arg(lane, "steering-angle-stream-proof.json"),
        compact_f64(target_degrees),
        controlled_angle_profile_cli_name(profile),
        compact_f32(max_percent),
        timeout_ms,
        low_torque_strategy_cli_name(strategy),
        authorization_proof,
        lane_path_arg(lane, json_out_relative_path)
    )
}

fn compact_f32(value: f32) -> String {
    if value.fract() == 0.0 {
        format!("{value:.0}")
    } else {
        value.to_string()
    }
}

fn compact_f64(value: f64) -> String {
    if value.fract() == 0.0 {
        format!("{value:.0}")
    } else {
        value.to_string()
    }
}

fn lane_output_artifact_path(lane: &Path, path: &Path) -> Result<PathBuf> {
    if path
        .components()
        .any(|component| matches!(component, Component::ParentDir))
    {
        return Err(anyhow!(
            "lane output artifact '{}' must not contain '..'",
            path.display()
        ));
    }

    if path.is_absolute() {
        let lane_norm = normalized_path_string(&lane.display().to_string());
        let path_norm = normalized_path_string(&path.display().to_string());
        if path_norm == lane_norm || path_norm.starts_with(&format!("{lane_norm}/")) {
            return Ok(path.to_path_buf());
        }
        return Err(anyhow!(
            "lane output artifact '{}' must stay under '{}'",
            path.display(),
            lane.display()
        ));
    }

    let lane_norm = normalized_path_string(&lane.display().to_string());
    let path_norm = normalized_path_string(&path.display().to_string());
    if path_norm == lane_norm || path_norm.starts_with(&format!("{lane_norm}/")) {
        Ok(path.to_path_buf())
    } else {
        Ok(lane.join(path))
    }
}

fn lane_relative_or_display(lane: &Path, path: &Path) -> String {
    path.strip_prefix(lane)
        .map(|relative| normalized_path_string(&relative.display().to_string()))
        .unwrap_or_else(|_| normalized_path_string(&path.display().to_string()))
}

fn update_native_visible_authorization_checks(
    plan: &mut Value,
    bench_clear_evidence: &str,
    ffb_mode_evidence: &str,
    preserved_path: &Path,
) {
    let Some(checks) = plan
        .get_mut("required_before_next_output")
        .and_then(Value::as_array_mut)
    else {
        return;
    };
    for check in checks {
        match json_string(check, "check") {
            Some("bench_clearance") => {
                check["status"] = serde_json::json!("passed");
                check["evidence"] = serde_json::json!(bench_clear_evidence);
            }
            Some("wheelbase_ffb_mode_and_vendor_state") => {
                check["status"] = serde_json::json!("passed");
                check["evidence"] = serde_json::json!(ffb_mode_evidence);
            }
            Some("failed_receipt_preserved_before_replacement") => {
                check["status"] = serde_json::json!("passed");
                check["evidence"] = serde_json::json!(format!(
                    "Preserved current response-only receipt at {} before authorizing replacement.",
                    preserved_path.display()
                ));
            }
            Some("fresh_operator_bench_clear_for_exact_next_output_command") => {
                check["status"] = serde_json::json!("passed");
                check["evidence"] = serde_json::json!(bench_clear_evidence);
            }
            _ => {}
        }
    }
}

fn require_lane_artifact_path(
    lane: &Path,
    path: &Path,
    relative_path: &str,
    label: &str,
) -> Result<()> {
    if path_value_matches(&lane.join(relative_path), Some(&path.display().to_string())) {
        Ok(())
    } else {
        Err(anyhow!(
            "{label} '{}' must resolve to same-lane artifact '{}'",
            path.display(),
            lane.join(relative_path).display()
        ))
    }
}

fn require_one_of_lane_artifact_paths(
    lane: &Path,
    path: &Path,
    relative_paths: &[&'static str],
    label: &str,
) -> Result<&'static str> {
    for relative_path in relative_paths {
        if path_value_matches(&lane.join(relative_path), Some(&path.display().to_string())) {
            return Ok(relative_path);
        }
    }
    let allowed = relative_paths
        .iter()
        .map(|relative_path| lane.join(relative_path).display().to_string())
        .collect::<Vec<_>>()
        .join(", ");
    Err(anyhow!(
        "{label} '{}' must resolve to one of these same-lane artifacts: {allowed}",
        path.display()
    ))
}

fn native_visible_output_relative_path(
    lane: &Path,
    output: &Path,
    label: &str,
) -> Result<&'static str> {
    require_one_of_lane_artifact_paths(lane, output, NATIVE_VISIBLE_OUTPUT_FILES, label)
}

fn validate_post_authority_pidff_smoke_context(lane: &Path) -> Result<()> {
    let attempt_path = lane.join(VENDOR_AUTHORITY_ATTEMPT_FILE);
    let attempt = read_json_value(lane, VENDOR_AUTHORITY_ATTEMPT_FILE).with_context(|| {
        format!(
            "post-authority PIDFF smoke requires consumed vendor-authority attempt receipt '{}'",
            attempt_path.display()
        )
    })?;
    validate_vendor_authority_attempt_schema(&attempt)?;
    validate_vendor_authority_attempt_gates(&attempt)?;

    let baseline_path = lane.join(NATIVE_ACTUATOR_VISIBLE_RESPONSE_ONLY_FILE);
    let baseline =
        read_json_value(lane, NATIVE_ACTUATOR_VISIBLE_RESPONSE_ONLY_FILE).with_context(|| {
            format!(
                "post-authority PIDFF smoke requires preserved baseline response receipt '{}'",
                baseline_path.display()
            )
        })?;
    native_pidff_response_summary(&baseline_path, &baseline, "baseline")?;
    Ok(())
}

fn controlled_angle_authorization_relative_path(
    lane: &Path,
    authorization_proof: Option<&Path>,
) -> Result<&'static str> {
    match authorization_proof {
        Some(path) => require_one_of_lane_artifact_paths(
            lane,
            path,
            NATIVE_CONTROLLED_ANGLE_AUTHORIZATION_FILES,
            "--authorization-proof",
        ),
        None => Ok(NATIVE_CONTROLLED_ANGLE_AUTHORIZATION_FILE),
    }
}

fn controlled_angle_output_relative_path(
    lane: &Path,
    output: &Path,
    label: &str,
) -> Result<&'static str> {
    require_one_of_lane_artifact_paths(lane, output, NATIVE_CONTROLLED_ANGLE_OUTPUT_FILES, label)
}

fn controlled_angle_preflight_relative_path(
    lane: &Path,
    preflight: Option<&Path>,
) -> Result<&'static str> {
    match preflight {
        Some(path) => require_one_of_lane_artifact_paths(
            lane,
            path,
            NATIVE_CONTROLLED_ANGLE_PREFLIGHT_FILES,
            "--controlled-angle-preflight",
        ),
        None => Ok(NATIVE_CONTROLLED_ANGLE_SMOKE_FILE),
    }
}

fn require_lane_receipt_path(lane: &Path, relative_path: &str) -> Result<()> {
    let receipt = read_json_value(lane, relative_path)?;
    if receipt_path_matches(lane, &receipt, relative_path) {
        Ok(())
    } else {
        Err(anyhow!(
            "{} receipt_path must match the same-lane artifact",
            relative_path
        ))
    }
}

fn validate_zero_output_stage_preflight(
    lane: Option<&Path>,
    json_out: Option<&Path>,
    relative_path: &str,
    strategy: MozaZeroOutputStrategy,
    confirmed: bool,
    confirmation_arg: &'static str,
) -> Result<ZeroOutputStagePreflight> {
    if !confirmed {
        return Err(anyhow!(
            "{confirmation_arg} is required before actual zero-output proof writes"
        ));
    }
    let lane =
        lane.ok_or_else(|| anyhow!("--lane is required before actual zero-output proof writes"))?;
    let json_out = json_out
        .ok_or_else(|| anyhow!("--json-out is required before actual zero-output proof writes"))?;
    require_lane_artifact_path(lane, json_out, relative_path, "--json-out")?;

    let receipt = read_json_value(lane, "pre-output-readiness.json")?;
    let command_ok = json_string(&receipt, "command") == Some("wheelctl moza pre-output-readiness");
    let lane_ok = lane_path_value_matches(lane, json_string(&receipt, "lane"));
    let success = json_bool(&receipt, "success") == Some(true);
    let ready_for_zero_torque = json_bool(&receipt, "ready_for_zero_torque") == Some(true);
    let ready_for_ffb = json_bool(&receipt, "ready_for_ffb") == Some(false);
    let blocking_items_empty = receipt
        .get("blocking_items")
        .and_then(Value::as_array)
        .map(Vec::is_empty)
        == Some(true);
    let status_receipts_ok = receipt
        .get("status_receipts")
        .and_then(Value::as_array)
        .map(|checks| {
            !checks.is_empty()
                && checks
                    .iter()
                    .all(|check| json_string(check, "status") == Some("pass"))
        })
        == Some(true);
    let no_output_receipt = json_bool(&receipt, "no_hid_device_opened") == Some(true)
        && json_bool(&receipt, "no_ffb_writes") == Some(true)
        && json_bool(&receipt, "no_output_reports") == Some(true)
        && json_bool(&receipt, "no_feature_reports") == Some(true)
        && no_out_of_scope_device_commands(&receipt);
    let strategy_metadata = validate_zero_output_strategy_metadata(lane, strategy);
    let strategy_metadata_ok = strategy_metadata.is_ok();

    if command_ok
        && lane_ok
        && success
        && ready_for_zero_torque
        && ready_for_ffb
        && blocking_items_empty
        && status_receipts_ok
        && no_output_receipt
        && strategy_metadata_ok
    {
        Ok(ZeroOutputStagePreflight {
            lane: lane.to_path_buf(),
            lane_display: lane.display().to_string(),
            pre_output_readiness_generated_at: json_string(&receipt, "generated_at_utc")
                .map(str::to_string),
        })
    } else {
        let strategy_metadata_error = strategy_metadata
            .err()
            .map(|error| error.to_string())
            .unwrap_or_else(|| "ok".to_string());
        Err(anyhow!(
            "pre-output readiness receipt '{}' is not ready for zero-output writes with strategy {}: command_ok={command_ok}, lane_ok={lane_ok}, success={success}, ready_for_zero_torque={ready_for_zero_torque}, ready_for_ffb_false={ready_for_ffb}, blocking_items_empty={blocking_items_empty}, status_receipts_ok={status_receipts_ok}, no_output_receipt={no_output_receipt}, strategy_metadata={strategy_metadata_ok}; strategy_metadata_error={strategy_metadata_error}",
            lane.join("pre-output-readiness.json").display(),
            zero_output_strategy_name(strategy)
        ))
    }
}

fn validate_same_lane_zero_proof_for_zero_output(lane: &Path) -> Result<ZeroProofSummary> {
    require_lane_receipt_path(lane, "zero-torque-proof.json")?;
    validate_zero_proof_for_zero_output(&lane.join("zero-torque-proof.json"))
}

fn init_receipt_relative_path(mode: MozaInitMode) -> &'static str {
    match mode {
        MozaInitMode::Off => "init-off.json",
        MozaInitMode::Standard => "init-standard.json",
    }
}

fn validate_init_stage_preflight(
    lane: Option<&Path>,
    json_out: Option<&Path>,
    selector: Option<&str>,
    mode: MozaInitMode,
    confirmed: bool,
) -> Result<InitStagePreflight> {
    if !confirmed {
        return Err(anyhow!(
            "--confirm-init is required before actual init feature-report writes"
        ));
    }
    let lane =
        lane.ok_or_else(|| anyhow!("--lane is required before actual init feature-report writes"))?;
    let json_out = json_out.ok_or_else(|| {
        anyhow!("--json-out is required before actual init feature-report writes")
    })?;
    require_lane_artifact_path(
        lane,
        json_out,
        init_receipt_relative_path(mode),
        "--json-out",
    )?;

    let zero_verification_relative_path = verification_receipt_path(MozaBundleStage::Zero);
    let zero_verification_path = lane.join(zero_verification_relative_path);
    let zero_verification = read_json_value(lane, zero_verification_relative_path).with_context(
        || {
            format!(
                "zero-stage verification receipt '{}' is required before actual init feature-report writes",
                zero_verification_path.display()
            )
        },
    )?;
    let zero_verification_ok =
        lane_path_value_matches(lane, json_string(&zero_verification, "lane"))
            && promotion_verification_summary_ok(Some(&zero_verification), "zero");
    if !zero_verification_ok {
        return Err(anyhow!(
            "zero-stage verification receipt '{}' is not a passing same-lane zero verification",
            zero_verification_path.display()
        ));
    }
    let zero_verification_generated_at = require_valid_generated_at(
        &zero_verification,
        &zero_verification_path,
        "zero-stage verification",
    )?;

    if !stored_lane_audit_receipt_passed(lane, MozaBundleStage::Zero) {
        let zero_audit_path = lane.join(audit_receipt_path(MozaBundleStage::Zero));
        return Err(anyhow!(
            "zero-stage audit receipt '{}' is not a passing same-lane zero audit",
            zero_audit_path.display()
        ));
    }
    let zero_audit_path = lane.join(audit_receipt_path(MozaBundleStage::Zero));
    let zero_audit = read_json_value(lane, audit_receipt_path(MozaBundleStage::Zero))?;
    let zero_audit_generated_at =
        require_valid_generated_at(&zero_audit, &zero_audit_path, "zero-stage audit")?;

    validate_lane_manifest_endpoint_selector(lane, selector, "actual init feature-report writes")?;

    if matches!(mode, MozaInitMode::Standard) {
        let init_off_gate =
            verify_init_receipt_gate(lane, "init_off_handshake", "init-off.json", "off");
        if init_off_gate.status != "pass" {
            return Err(anyhow!(
                "same-lane init-off receipt '{}' must pass before standard init feature-report writes: {}",
                lane.join("init-off.json").display(),
                init_off_gate.details
            ));
        }
    }

    Ok(InitStagePreflight {
        lane_display: lane.display().to_string(),
        zero_verification_generated_at: Some(zero_verification_generated_at),
        zero_audit_generated_at: Some(zero_audit_generated_at),
    })
}

fn validate_lane_manifest_endpoint_selector(
    lane: &Path,
    selector: Option<&str>,
    operation: &str,
) -> Result<String> {
    let expected = lane_manifest_r5_hid_observe_selector(lane).ok_or_else(|| {
        anyhow!("manifest.json must declare an exact R5 wheelbase HID endpoint before {operation}")
    })?;
    let selector = selector.map(str::trim).filter(|selector| !selector.is_empty()).ok_or_else(|| {
        anyhow!(
            "--device must be the lane manifest wheelbase endpoint selector before {operation}: {expected}"
        )
    })?;
    if !selector.eq_ignore_ascii_case(&expected) {
        return Err(anyhow!(
            "--device must match the lane manifest wheelbase endpoint selector before {operation}: expected {expected}, got {selector}"
        ));
    }
    Ok(expected)
}

fn require_valid_generated_at(receipt: &Value, path: &Path, label: &str) -> Result<String> {
    let generated_at = json_string(receipt, "generated_at_utc").ok_or_else(|| {
        anyhow!(
            "{label} receipt '{}' is missing generated_at_utc",
            path.display()
        )
    })?;
    if !utc_timestamp_pair_is_ordered(generated_at, generated_at) {
        return Err(anyhow!(
            "{label} receipt '{}' has invalid generated_at_utc",
            path.display()
        ));
    }
    Ok(generated_at.to_string())
}

fn low_torque_preflight_target_product_id(
    selector: Option<&str>,
    pid_override: Option<&str>,
    lane: &Path,
    zero_proof: &ZeroProofSummary,
    init_proofs: &InitProofSet,
) -> Result<String> {
    let pid = pid_override
        .and_then(parse_hex_selector)
        .or_else(|| selector.and_then(|selector| parse_vid_pid_selector(selector).map(|(_, pid)| pid)))
        .or_else(|| selector.and_then(parse_hex_selector))
        .or_else(|| lane_manifest_r5_pid(lane))
        .or_else(|| zero_proof.product_id.as_deref().and_then(parse_hex_selector))
        .ok_or_else(|| {
            anyhow!("low-torque preflight could not determine target R5 PID from --pid, --device, lane manifest, or zero proof")
        })?;
    if !matches!(pid, product_ids::R5_V1 | product_ids::R5_V2) {
        return Err(anyhow!(
            "low-torque preflight target PID {} is not a Moza R5 wheelbase",
            hex_u16(pid)
        ));
    }
    let target = hex_u16(pid);
    if init_proofs.off.product_id.as_deref() != Some(target.as_str())
        || init_proofs.standard.product_id.as_deref() != Some(target.as_str())
    {
        return Err(anyhow!(
            "init proof PID(s) {:?}/{:?} do not match low-torque preflight target PID {}",
            init_proofs.off.product_id,
            init_proofs.standard.product_id,
            target
        ));
    }
    Ok(target)
}

fn validate_zero_proof_for_torque_test(path: &Path) -> Result<ZeroProofSummary> {
    let summary = validate_zero_proof_for_zero_output(path)?;
    if summary.zero_output_strategy
        != zero_output_strategy_name(MozaZeroOutputStrategy::DirectReport0x20)
    {
        return Err(anyhow!(
            "zero proof '{}' must use direct_report_0x20 before direct low-torque tests",
            path.display()
        ));
    }
    Ok(summary)
}

fn validate_zero_proof_for_low_torque_strategy(
    path: &Path,
    strategy: MozaLowTorqueStrategy,
) -> Result<ZeroProofSummary> {
    match strategy {
        MozaLowTorqueStrategy::DirectReport0x20 => validate_zero_proof_for_torque_test(path),
        MozaLowTorqueStrategy::PidffBoundedEffect => {
            let summary = validate_zero_proof_for_zero_output(path)?;
            if summary.zero_output_strategy
                != zero_output_strategy_name(MozaZeroOutputStrategy::PidffStopAll)
            {
                return Err(anyhow!(
                    "zero proof '{}' must use pidff_device_control_stop_all before PIDFF bounded low-torque tests",
                    path.display()
                ));
            }
            Ok(summary)
        }
    }
}

fn validate_zero_proof_for_zero_output(path: &Path) -> Result<ZeroProofSummary> {
    let receipt = read_json_path(path)?;
    let receipt_crc32 = receipt_file_crc32(path)?;
    let generated_at_utc = json_string(&receipt, "generated_at_utc").map(str::to_string);
    let repeat = json_u64(&receipt, "repeat").unwrap_or(0);
    let dry_run = json_bool(&receipt, "dry_run");
    let no_out_of_scope = no_out_of_scope_device_commands(&receipt);
    let operator_confirmed = json_bool(&receipt, "operator_confirmed");
    let lane_ok = path
        .parent()
        .map(|lane| lane_path_value_matches(lane, json_string(&receipt, "lane")))
        .unwrap_or(false);
    let pre_output_readiness_validated = json_bool(&receipt, "pre_output_readiness_validated");
    let pre_output_readiness_generated_at =
        json_string(&receipt, "pre_output_readiness_generated_at");
    let hz = json_u64(&receipt, "hz").unwrap_or(0);
    let write_attempts = json_u64(&receipt, "write_attempts").unwrap_or(0);
    let writes_ok = json_u64(&receipt, "writes_ok").unwrap_or(0);
    let write_errors = json_u64(&receipt, "write_errors").unwrap_or(u64::MAX);
    let watchdog_faults = json_u64(&receipt, "watchdog_faults").unwrap_or(u64::MAX);
    let writes_ok_exact = repeat.checked_add(1) == Some(writes_ok);
    let zero_output_strategy = json_string(&receipt, "zero_output_strategy").unwrap_or(
        zero_output_strategy_name(MozaZeroOutputStrategy::DirectReport0x20),
    );
    let device = receipt.get("device");
    let product_id = device
        .and_then(|device| json_string(device, "product_id"))
        .map(str::to_string);
    let r5_device = device.map(is_r5_device_value).unwrap_or(false);
    let output_capable =
        device.and_then(|device| json_bool(device, "output_capable")) == Some(true);
    let safe = json_bool(&receipt, "success") == Some(true)
        && dry_run == Some(false)
        && json_bool(&receipt, "no_high_torque") == Some(true)
        && json_bool(&receipt, "no_nonzero_torque") == Some(true)
        && json_bool(&receipt, "no_feature_reports") == Some(true)
        && no_out_of_scope
        && json_bool(&receipt, "no_hid_device_opened") == Some(false)
        && operator_confirmed == Some(true)
        && lane_ok
        && pre_output_readiness_validated == Some(true)
        && pre_output_readiness_generated_at
            .map(|value| {
                generated_at_utc
                    .as_deref()
                    .map(|generated_at| utc_timestamp_pair_is_ordered(value, generated_at))
                    .unwrap_or(false)
            })
            .unwrap_or(false)
        && zero_receipt_payload_is_safe(&receipt)
        && json_bool(&receipt, "final_zero_sent") == Some(true)
        && repeat >= 100
        && hz > 0
        && hz <= 1000
        && write_attempts == repeat
        && writes_ok_exact
        && write_errors == 0
        && watchdog_faults == 0
        && zero_command_log_is_safe(&receipt, repeat)
        && generated_at_utc
            .as_deref()
            .map(|value| utc_timestamp_pair_is_ordered(value, value))
            .unwrap_or(false)
        && product_id.is_some()
        && r5_device
        && output_capable;
    if !safe {
        return Err(anyhow!(
            "zero proof '{}' is not a passing real zero-torque receipt",
            path.display()
        ));
    }

    Ok(ZeroProofSummary {
        path: path.display().to_string(),
        generated_at_utc: generated_at_utc.ok_or_else(|| {
            anyhow!(
                "zero proof '{}' is missing generated_at_utc",
                path.display()
            )
        })?,
        receipt_crc32,
        product_id,
        zero_output_strategy: zero_output_strategy.to_string(),
        repeat,
        writes_ok,
        final_zero_sent: true,
    })
}

fn validate_init_proofs_for_torque_test(
    lane: Option<&Path>,
    init_off: Option<&Path>,
    init_standard: Option<&Path>,
    dry_run: bool,
) -> Result<Option<InitProofSet>> {
    let off_path = init_off
        .map(Path::to_path_buf)
        .or_else(|| lane.map(|path| path.join("init-off.json")));
    let standard_path = init_standard
        .map(Path::to_path_buf)
        .or_else(|| lane.map(|path| path.join("init-standard.json")));

    match (off_path, standard_path) {
        (Some(off_path), Some(standard_path)) => Ok(Some(InitProofSet {
            off: validate_init_proof_for_torque_test(&off_path, "off")?,
            standard: validate_init_proof_for_torque_test(&standard_path, "standard")?,
        })),
        (None, None) if dry_run => Ok(None),
        _ => Err(anyhow!(
            "--lane or both --init-off and --init-standard are required before actual low-torque writes"
        )),
    }
}

fn validate_init_proof_for_torque_test(
    path: &Path,
    expected_mode: &str,
) -> Result<InitProofSummary> {
    let receipt = read_json_path(path)?;
    let receipt_crc32 = receipt_file_crc32(path)?;
    let generated_at_utc = json_string(&receipt, "generated_at_utc").map(str::to_string);
    let device = receipt.get("device");
    let product_id = device
        .and_then(|device| json_string(device, "product_id"))
        .map(str::to_string);
    let feature_report_count = receipt
        .get("feature_reports")
        .and_then(Value::as_array)
        .map(Vec::len)
        .unwrap_or(0);
    let init_state = json_string(&receipt, "init_state").unwrap_or("unknown");
    let ready = json_bool(&receipt, "ready") == Some(true);
    let lane_ok = path
        .parent()
        .map(|lane| lane_path_value_matches(lane, json_string(&receipt, "lane")))
        .unwrap_or(false);
    let selector_matches_lane_endpoint = path
        .parent()
        .map(|lane| receipt_selector_matches_lane_endpoint(lane, &receipt))
        .unwrap_or(false);
    let zero_verification_ordered = json_string(&receipt, "zero_verification_generated_at")
        .and_then(|zero_at| {
            generated_at_utc
                .as_deref()
                .map(|init_at| utc_timestamp_pair_is_ordered(zero_at, init_at))
        })
        .unwrap_or(false);
    let zero_audit_ordered = json_string(&receipt, "zero_audit_generated_at")
        .and_then(|zero_at| {
            generated_at_utc
                .as_deref()
                .map(|init_at| utc_timestamp_pair_is_ordered(zero_at, init_at))
        })
        .unwrap_or(false);
    let safe = json_bool(&receipt, "success") == Some(true)
        && json_string(&receipt, "command") == Some("wheelctl moza init")
        && json_bool(&receipt, "dry_run") == Some(false)
        && json_bool(&receipt, "no_hid_device_opened") == Some(false)
        && json_bool(&receipt, "operator_confirmed") == Some(true)
        && lane_ok
        && json_bool(&receipt, "zero_verification_validated") == Some(true)
        && json_bool(&receipt, "zero_audit_validated") == Some(true)
        && zero_verification_ordered
        && zero_audit_ordered
        && json_bool(&receipt, "no_output_reports") == Some(true)
        && json_bool(&receipt, "no_direct_torque_reports") == Some(true)
        && no_out_of_scope_device_commands(&receipt)
        && json_bool(&receipt, "no_high_torque") == Some(true)
        && json_bool(&receipt, "high_torque") == Some(false)
        && json_string(&receipt, "mode") == Some(expected_mode)
        && init_state == "ready"
        && ready
        && json_u64(&receipt, "feature_write_errors").unwrap_or(u64::MAX) == 0
        && json_u64(&receipt, "output_report_attempts").unwrap_or(u64::MAX) == 0
        && receipt
            .get("feature_reports")
            .map(|reports| {
                init_feature_reports_are_safe_value(
                    reports,
                    expected_mode,
                    false,
                    product_id.as_deref(),
                )
            })
            .unwrap_or(false)
        && generated_at_utc
            .as_deref()
            .map(|value| utc_timestamp_pair_is_ordered(value, value))
            .unwrap_or(false)
        && device.map(is_r5_device_value).unwrap_or(false)
        && device.and_then(|device| json_bool(device, "output_capable")) == Some(true)
        && selector_matches_lane_endpoint
        && product_id.is_some();

    if !safe {
        return Err(anyhow!(
            "init proof '{}' is not a passing real {}-mode handshake receipt",
            path.display(),
            expected_mode
        ));
    }

    Ok(InitProofSummary {
        path: path.display().to_string(),
        generated_at_utc: generated_at_utc.ok_or_else(|| {
            anyhow!(
                "init proof '{}' is missing generated_at_utc",
                path.display()
            )
        })?,
        receipt_crc32,
        product_id,
        mode: expected_mode.to_string(),
        init_state: init_state.to_string(),
        ready,
        feature_report_count,
    })
}

fn validate_direct_mode_gate_for_torque_test(
    descriptor: Option<&Path>,
    selected_product_id: &str,
    explicit_operator_override: bool,
) -> Result<DirectModeGateSummary> {
    if explicit_operator_override {
        return Ok(DirectModeGateSummary::operator_override(
            descriptor.map(Path::to_path_buf),
            selected_product_id,
        ));
    }

    let descriptor_path = descriptor.ok_or_else(|| {
        anyhow!(
            "direct torque report writes require --descriptor with trusted R5 metadata or --explicit-operator-override"
        )
    })?;
    let receipt = read_json_path(descriptor_path)?;
    let Some(devices) = receipt.get("devices").and_then(Value::as_array) else {
        return Err(anyhow!(
            "descriptor receipt '{}' is missing devices[]",
            descriptor_path.display()
        ));
    };

    let trusted = devices.iter().any(|device| {
        is_r5_device_value(device)
            && json_string(device, "product_id") == Some(selected_product_id)
            && r5_descriptor_trusted_for_direct_mode(device)
    });
    if !trusted {
        return Err(anyhow!(
            "descriptor receipt '{}' does not contain descriptor-derived trusted R5 report metadata for PID {}",
            descriptor_path.display(),
            selected_product_id
        ));
    }

    Ok(DirectModeGateSummary::trusted_descriptor(
        descriptor_path,
        selected_product_id,
    ))
}

fn synthetic_moza_device_record(pid: u16) -> MozaDeviceRecord {
    let identity = identify_device(pid);
    let output_capable = is_wheelbase_product(pid);
    MozaDeviceRecord {
        vendor_id: hex_u16(MOZA_VENDOR_ID),
        product_id: hex_u16(pid),
        product_name: identity.name.to_string(),
        product_category: category_label(identity.category).to_string(),
        topology_hint: topology_label(identity.topology_hint).to_string(),
        output_capable,
        r5_wheelbase_pid: matches!(pid, product_ids::R5_V1 | product_ids::R5_V2),
        manufacturer: None,
        product_string: None,
        serial_number_present: false,
        interface_number: None,
        usage_page: None,
        usage: None,
        path: "dry-run".to_string(),
        descriptor_source: "dry_run".to_string(),
        report_descriptor_len: None,
        report_descriptor_crc32: None,
        report_descriptor_hex: None,
        report_metadata_source: "protocol_expected".to_string(),
        input_report_lengths: expected_input_report_lengths(pid),
        output_report_ids: expected_output_report_ids(output_capable),
        output_reports: expected_output_reports(output_capable),
        feature_report_ids: expected_feature_report_ids(pid, output_capable),
        feature_reports: Vec::new(),
    }
}

fn moza_status_receipt(
    devices: Vec<MozaDeviceRecord>,
    selector: Option<&str>,
    lane: Option<&Path>,
) -> Value {
    let lane_status = lane.map(support_bundle_status);
    let device_statuses: Vec<_> = devices
        .into_iter()
        .map(|device| {
            let descriptor_trusted = lane
                .map(|path| lane_descriptor_trusted_for_pid(path, &device.product_id))
                .unwrap_or(false);
            let init_state = if device.output_capable {
                "uninitialized"
            } else {
                "not_applicable"
            };
            serde_json::json!({
                "device": device,
                "init_state": init_state,
                "ffb_ready": false,
                "descriptor_trusted": descriptor_trusted,
                "direct_mode_allowed": false,
                "high_torque_allowed": false,
                "safe_to_send_torque": false,
                "safety_reason": "status is observe-only; run explicit init, zero, and torque-test gates before any output"
            })
        })
        .collect();

    serde_json::json!({
        "success": true,
        "command": "wheelctl moza status",
        "generated_at_utc": now_utc(),
        "selector": selector,
        "device_count": device_statuses.len(),
        "devices": device_statuses,
        "lane": lane.map(|path| path.display().to_string()),
        "lane_status": lane_status,
        "no_hid_device_opened": true,
        "no_ffb_writes": true,
        "no_output_reports": true,
        "no_feature_reports": true,
        "no_serial_config_commands": true,
        "no_firmware_or_dfu_commands": true,
        "notes": [
            "status enumerates Moza HID identity and optional lane receipts only; it sends no feature reports or FFB output",
            "ffb_ready remains false until an explicit staged init receipt proves readiness"
        ]
    })
}

#[derive(Clone, Copy)]
enum SupportBundleValidationMode {
    Fresh,
    ShapeOnly,
}

fn verify_bundle_dir(lane: &Path, stage: MozaBundleStage) -> BundleVerificationReceipt {
    verify_bundle_dir_with_support_validation(lane, stage, SupportBundleValidationMode::Fresh)
}

fn verify_bundle_dir_with_support_validation(
    lane: &Path,
    stage: MozaBundleStage,
    support_validation: SupportBundleValidationMode,
) -> BundleVerificationReceipt {
    let artifact_requirements = bundle_artifact_requirements_for_lane(lane);
    let artifact_checks: Vec<_> = artifact_requirements
        .iter()
        .filter(|requirement| stage_rank(requirement.stage) <= stage_rank(stage))
        .map(|requirement| check_bundle_artifact(lane, requirement))
        .collect();
    // Missing stage artifacts already make the receipt fail; avoid recursively
    // rebuilding fresh support status before writing that diagnostic receipt.
    let support_validation = if matches!(support_validation, SupportBundleValidationMode::Fresh)
        && artifact_checks
            .iter()
            .any(|check| check.status == "missing" || check.status == "invalid")
    {
        SupportBundleValidationMode::ShapeOnly
    } else {
        support_validation
    };

    let mut gates = Vec::new();
    gates.push(if lane.is_dir() {
        BundleGateCheck::pass("lane_directory", format!("found {}", lane.display()))
    } else {
        BundleGateCheck::fail(
            "lane_directory",
            format!("missing lane directory {}", lane.display()),
        )
    });
    gates.push(verify_manifest_gate(lane, stage));
    gates.push(
        verify_manifest_r5_pid_consistency_gate_with_support_validation(
            lane,
            stage,
            support_validation,
        ),
    );
    gates.push(verify_moza_r5_observed_gate(lane));
    gates.push(verify_moza_topology_observed_gate(lane));
    gates.push(verify_topology_required_evidence_supported_gate(lane));
    gates.push(verify_descriptor_metadata_gate(lane));
    gates.push(verify_passive_receipts_success_gate(lane));
    gates.push(verify_passive_no_writes_gate(lane));
    gates.push(verify_passive_capture_parse_gate(lane));
    gates.push(verify_parser_validation_gate(lane));
    gates.push(verify_fixture_promotion_gate(lane));

    if stage_rank(stage) >= stage_rank(MozaBundleStage::Zero) {
        gates.push(verify_zero_torque_gate(lane));
        gates.push(verify_watchdog_proof_gate(lane));
        gates.push(verify_disconnect_proof_gate(lane));
    }

    if stage_rank(stage) >= stage_rank(MozaBundleStage::OpenRacingControlReady) {
        gates.push(verify_init_receipt_gate(
            lane,
            "init_off_handshake",
            "init-off.json",
            "off",
        ));
        gates.push(verify_init_receipt_gate(
            lane,
            "init_standard_handshake",
            "init-standard.json",
            "standard",
        ));
        // Bundle verification already validates the lane's concrete stage
        // receipts below. Rebuilding fresh support-bundle readiness here
        // replays the large capture set again through every stage summary,
        // which makes native-response promotion receipt generation
        // unnecessarily expensive. Keep verify-bundle on stored
        // support-bundle shape/no-output validation; the direct service gate
        // still exercises fresh overclaim checks in its focused tests.
        gates.push(verify_service_status_gate_with_support_validation(
            lane,
            SupportBundleValidationMode::ShapeOnly,
        ));
        gates.push(verify_low_torque_gate(lane));
        gates.push(verify_steering_angle_stream_gate(lane));
        gates.push(verify_native_actuator_profile_smoke_gate(lane));
    }

    if stage_rank(stage) >= stage_rank(MozaBundleStage::NativeResponseReady) {
        gates.push(verify_native_actuator_response_smoke_gate(lane));
    }

    if stage_rank(stage) >= stage_rank(MozaBundleStage::NativeVisibleReady) {
        gates.push(verify_native_actuator_visible_smoke_gate(lane));
    }

    if stage_rank(stage) >= stage_rank(MozaBundleStage::SmokeReady) {
        gates.push(verify_pit_house_coexistence_gate_with_support_validation(
            lane,
            support_validation,
        ));
        gates.push(verify_simulator_telemetry_gate(lane));
        gates.push(verify_simulator_ffb_gate(lane));
    }

    let missing_artifacts = artifact_checks
        .iter()
        .filter(|check| check.status == "missing")
        .count();
    let invalid_artifacts = artifact_checks
        .iter()
        .filter(|check| check.status == "invalid")
        .count();
    let failed_gates = gates.iter().filter(|check| check.status == "fail").count();
    let success = missing_artifacts == 0 && invalid_artifacts == 0 && failed_gates == 0;
    let endpoint_observations = bundle_endpoint_observations(lane);
    let role_evidence = bundle_role_evidence(lane);
    let operator_actions = operator_actions_for_bundle_stage(lane, stage, &gates);
    let next_commands = next_commands_for_bundle_stage(lane, stage, &artifact_checks, &gates);
    let blocked_safe_followups = blocked_safe_followups_for_bundle_stage(lane, stage, &gates);

    BundleVerificationReceipt {
        success,
        command: "wheelctl moza verify-bundle",
        generated_at_utc: now_utc(),
        lane: lane.display().to_string(),
        requested_stage: stage_label(stage).to_string(),
        missing_artifacts,
        invalid_artifacts,
        failed_gates,
        artifacts: artifact_checks,
        gates,
        endpoint_observations,
        role_evidence,
        operator_actions,
        next_commands,
        blocked_safe_followups,
        no_hid_device_opened: true,
        no_ffb_writes: true,
        no_serial_config_commands: true,
        no_firmware_or_dfu_commands: true,
        notes: vec![
            "verify-bundle reads existing receipts only; it opens no HID device and sends no reports"
                .to_string(),
            "a passing bundle is evidence for the requested lane stage only, not release readiness"
                .to_string(),
            "role_evidence is derived from stored capture analysis and does not promote lane receipts"
                .to_string(),
        ],
    }
}

fn bundle_role_evidence(lane: &Path) -> Vec<LaneRoleEvidenceEntry> {
    analyze_lane_captures(lane)
        .map(|analysis| analysis.role_evidence)
        .unwrap_or_default()
}

fn bundle_endpoint_observations(lane: &Path) -> Vec<BundleEndpointObservation> {
    let Ok(manifest) = read_json_value(lane, "manifest.json") else {
        return Vec::new();
    };
    let Some(topology) = manifest.get("topology") else {
        return Vec::new();
    };
    let Some(endpoints) = topology.get("endpoints").and_then(Value::as_array) else {
        return Vec::new();
    };
    let controls = topology
        .get("logical_controls")
        .and_then(Value::as_object)
        .cloned()
        .unwrap_or_default();

    endpoints
        .iter()
        .map(|endpoint| {
            let id = json_string(endpoint, "id").unwrap_or("<missing-id>");
            let required_logical_controls = endpoint_logical_controls(&controls, id, true);
            let optional_logical_controls = endpoint_logical_controls(&controls, id, false);
            let artifacts = [
                "device-list.json",
                "moza-probe.json",
                "hid-list.json",
                "descriptor.json",
            ]
            .into_iter()
            .map(|path| endpoint_artifact_observation(lane, path, endpoint))
            .collect::<Vec<_>>();
            let observed_artifact_count = artifacts
                .iter()
                .filter(|artifact| artifact.vid_pid_count > 0)
                .count();
            let metadata_match_artifact_count = artifacts
                .iter()
                .filter(|artifact| artifact.metadata_match_count > 0)
                .count();

            BundleEndpointObservation {
                id: id.to_string(),
                kind: json_string(endpoint, "kind").map(str::to_string),
                vendor_id: json_string(endpoint, "vendor_id").map(str::to_string),
                product_id: json_string(endpoint, "product_id").map(str::to_string),
                interface_number: json_u64(endpoint, "interface_number"),
                usage_page: json_string(endpoint, "usage_page").map(str::to_string),
                usage: json_string(endpoint, "usage").map(str::to_string),
                output_capable: json_bool(endpoint, "output_capable"),
                required_logical_controls,
                optional_logical_controls,
                observed_artifact_count,
                metadata_match_artifact_count,
                artifacts,
            }
        })
        .collect()
}

fn endpoint_logical_controls(
    controls: &serde_json::Map<String, Value>,
    endpoint_id: &str,
    required: bool,
) -> Vec<String> {
    let mut names = controls
        .iter()
        .filter(|(_, control)| json_string(control, "source_endpoint") == Some(endpoint_id))
        .filter(|(_, control)| json_bool(control, "required").unwrap_or(true) == required)
        .map(|(name, _)| name.to_string())
        .collect::<Vec<_>>();
    names.sort();
    names
}

fn endpoint_artifact_observation(
    lane: &Path,
    path: &str,
    endpoint: &Value,
) -> BundleEndpointArtifactObservation {
    match read_json_value(lane, path) {
        Ok(receipt) => {
            let vid_pid_count = count_topology_endpoint_vid_pid_devices(&receipt, endpoint);
            let metadata_match_count = count_topology_endpoint_metadata_devices(&receipt, endpoint);
            BundleEndpointArtifactObservation {
                path: path.to_string(),
                status: "read".to_string(),
                vid_pid_count,
                metadata_match_count,
            }
        }
        Err(e) => BundleEndpointArtifactObservation {
            path: path.to_string(),
            status: format!("unavailable:{e}"),
            vid_pid_count: 0,
            metadata_match_count: 0,
        },
    }
}

fn count_topology_endpoint_vid_pid_devices(receipt: &Value, endpoint: &Value) -> usize {
    let Some(vendor_id) = json_string(endpoint, "vendor_id").and_then(parse_hex_selector) else {
        return 0;
    };
    let Some(product_id) = json_string(endpoint, "product_id").and_then(parse_hex_selector) else {
        return 0;
    };
    count_vendor_product_devices(receipt, vendor_id, product_id)
}

fn count_topology_endpoint_metadata_devices(receipt: &Value, endpoint: &Value) -> usize {
    receipt
        .get("devices")
        .and_then(Value::as_array)
        .map(|devices| {
            devices
                .iter()
                .filter(|device| topology_endpoint_metadata_matches_device(device, endpoint))
                .count()
        })
        .unwrap_or(0)
}

fn topology_endpoint_metadata_matches_device(device: &Value, endpoint: &Value) -> bool {
    let Some(vendor_id) = json_string(endpoint, "vendor_id").and_then(parse_hex_selector) else {
        return false;
    };
    let Some(product_id) = json_string(endpoint, "product_id").and_then(parse_hex_selector) else {
        return false;
    };
    if !is_vendor_product_device_value(device, vendor_id, product_id) {
        return false;
    }
    if let Some(interface_number) = json_u64(endpoint, "interface_number")
        && json_u64(device, "interface_number") != Some(interface_number)
    {
        return false;
    }
    if let Some(usage_page) = json_string(endpoint, "usage_page")
        && json_string(device, "usage_page") != Some(usage_page)
    {
        return false;
    }
    if let Some(usage) = json_string(endpoint, "usage")
        && json_string(device, "usage") != Some(usage)
    {
        return false;
    }
    true
}

fn operator_actions_for_bundle_stage(
    lane: &Path,
    stage: MozaBundleStage,
    gates: &[BundleGateCheck],
) -> Vec<String> {
    let mut actions = Vec::new();
    if !bundle_gate_check_passed(gates, "descriptor_metadata") {
        actions.push(
            "Export the R5 HID report descriptor byte block into target/moza-r5-report-descriptor.txt or target/moza-r5-report-descriptor.bin, then rerun the descriptor file fallback. A USBTreeView summary that only shows wDescriptorLength or ERROR_INVALID_PARAMETER is not enough, and a Windows HidP KDR collection/preparsed descriptor is not the raw report descriptor; use the actual Report Descriptor hex block, Linux sysfs report_descriptor bytes, or an equivalent descriptor tool. Do not run firmware or DFU flows."
                .to_string(),
        );
    }

    let throttle_missing = gates.iter().any(|gate| {
        gate.name == "passive_captures_parse"
            && gate.status == "fail"
            && gate
                .details
                .contains("captures/r5-throttle-only-sweep.jsonl")
            && gate.details.contains("any_axes_ok=false")
    });
    if throttle_missing {
        let r5_selector =
            lane_manifest_r5_hid_observe_selector(lane).unwrap_or_else(|| "<r5>".to_string());
        let capture_command = format!(
            "wheelctl moza capture-input --device {r5_selector} --duration-ms 60000 --json-out target/moza-gas-check/r5-gas-after-reseat-60s.jsonl --json"
        );
        let analyze_command = "wheelctl moza analyze-capture --capture target/moza-gas-check/r5-gas-after-reseat-60s.jsonl --json-out target/moza-gas-check/r5-gas-after-reseat-analysis.json --json";
        let endpoint_context = if lane_has_single_observed_moza_hid_endpoint(lane) {
            " Stored observe-only HID/PnP receipts already show only the R5 HID game-controller endpoint, so do not chase another Moza HID path; the visible Moza serial/COM interface is diagnostic topology only and must not be probed or configured in the passive lane."
        } else {
            " If Pit House is unavailable, use observe-only HID/PnP inspection to confirm endpoints; a visible Moza serial/COM interface is diagnostic topology only and must not be probed or configured in the passive lane."
        };
        actions.push(format!(
            "Throttle capture parsed but no parser-visible hub-control axis moved; check throttle pedal cable, pedal-set-to-R5 routing, and vendor input state before replacing the lane capture. If Pit House is unavailable, keep the next check target-only: reseat and power-cycle the pedal path, then run `{capture_command}` followed by `{analyze_command}`. Replace the lane capture only if parser-visible hub-control movement appears.{endpoint_context}"
        ));
    }

    let parser_validation_failed = !bundle_gate_check_passed(gates, "parser_fixture_validation");
    let fixture_promotion_failed = !bundle_gate_check_passed(gates, "fixture_promotion");
    if parser_validation_failed && fixture_promotion_failed {
        actions.push(
            "Do not run fixture promotion until validate-captures passes for every manifest-required logical role."
                .to_string(),
        );
    }

    if stage_rank(stage) >= stage_rank(MozaBundleStage::OpenRacingControlReady) {
        push_openracing_control_frontier_operator_action(lane, gates, &mut actions);
    }

    if stage_rank(stage) >= stage_rank(MozaBundleStage::NativeResponseReady)
        && openracing_control_stage_gates_passed(gates)
    {
        push_native_motion_frontier_operator_action(lane, gates, &mut actions);
    }

    if stage == MozaBundleStage::SmokeReady && native_visible_stage_gates_passed(gates) {
        push_external_compat_frontier_operator_action(gates, &mut actions);
    }

    actions
}

fn push_openracing_control_frontier_operator_action(
    lane: &Path,
    gates: &[BundleGateCheck],
    actions: &mut Vec<String>,
) {
    if !zero_stage_gates_passed(gates) {
        return;
    }

    let r5_selector = next_command_r5_selector(lane);
    let init_off_report_text = if lane_manifest_r5_pid(lane) == Some(product_ids::R5_V1) {
        "the bounded Moza init feature report 0x11, with payload 11FF0000"
    } else {
        "the bounded Moza init feature reports 0x03 and 0x11, with 0x11 payload 11FF0000"
    };
    if !bundle_gate_check_passed(gates, "init_off_handshake") {
        actions.push(format!(
            "Current OpenRacing-control frontier: staged init-off. This sends only {init_off_report_text}, and still sends no output reports or torque. Before running it, confirm the operator is at the bench, the wheel is clear, power cutoff is understood, no game/sim FFB source is active, and vendor firmware/update flows are closed or not installed. Run only the lane-bound `wheelctl moza init --device {r5_selector} --mode off --confirm-init ...` command; do not run standard init, low torque, simulator FFB, direct mode, serial config, firmware, or DFU until this receipt passes."
        ));
        return;
    }

    let init_standard_report_text = if lane_manifest_r5_pid(lane) == Some(product_ids::R5_V1) {
        "the bounded Moza init feature report 0x11, with payload 11000000"
    } else {
        "the bounded Moza init feature reports 0x03 and 0x11, with 0x11 payload 11000000"
    };
    if !bundle_gate_check_passed(gates, "init_standard_handshake") {
        actions.push(format!(
            "Current OpenRacing-control frontier: staged init-standard. This sends only {init_standard_report_text}, after the same-lane init-off receipt has passed; it still must not send output reports or torque. Confirm the operator is at the bench, the wheel is clear, power cutoff is understood, and no game/sim FFB source or firmware/update flow is active. Run only the lane-bound `wheelctl moza init --device {r5_selector} --mode standard --confirm-init ...` command; do not run low torque, simulator FFB, direct mode, serial config, firmware, or DFU until this receipt passes."
        ));
        return;
    }

    if !bundle_gate_check_passed(gates, "service_status_receipts") {
        actions.push(
            "Current OpenRacing-control frontier: refresh service/status/support receipts after staged init. These are diagnostic/no-output receipts only; keep safe_to_send_torque=false, ffb_ready=false, high torque disabled, and no feature/output/serial/firmware actions while collecting moza-status.json, device-status.json, and support-bundle.json."
                .to_string(),
        );
        return;
    }

    if !bundle_gate_check_passed(gates, "low_torque_bounded") {
        let blockers = low_torque_frontier_blockers(lane);
        if blockers.is_empty() {
            actions.push(
                "Current OpenRacing-control frontier: bounded low-torque proof. This is the first nonzero torque step; run it only with explicit operator confirmation, wheel clear, power cutoff understood, no game/sim FFB source active, no vendor firmware/update flow active, trusted direct report 0x20 metadata, a same-lane direct-report zero proof, and same-lane zero/off/standard init receipts passing. Keep the cap and duration bounded, and do not proceed to simulator FFB, direct-mode expansion, serial config, firmware, or DFU until low-torque-proof.json passes."
                    .to_string(),
            );
        } else {
            let pidff_blockers = pidff_low_torque_frontier_blockers(lane);
            if pidff_blockers.is_empty() {
                actions.push(
                    "Current OpenRacing-control frontier: bounded PIDFF low-torque proof. This is the first nonzero torque step for the live R5 V1 lane; run it only with explicit operator confirmation, wheel clear, power cutoff understood, no game/sim FFB source active, no vendor firmware/update flow active, same-lane PIDFF Stop All zero proof, same-lane off/standard init receipts, and descriptor-proven PIDFF output reports. Keep the cap at 1% and duration at 150 ms for the first receipt, require final PIDFF Stop All cleanup, and do not proceed to simulator FFB, direct-mode expansion, serial config, firmware, or DFU until low-torque-proof.json passes."
                        .to_string(),
                );
            } else {
                actions.push(format!(
                    "Current OpenRacing-control frontier: bounded low-torque proof is blocked before any write because direct path blockers are [{}] and PIDFF path blockers are [{}]. Resolve the PIDFF bounded-effect software/receipt path or prove the direct report 0x20 path before running `wheelctl moza torque-test`; generated guidance must not add `--explicit-operator-override`. No low torque, simulator FFB, direct-mode expansion, serial config, firmware, or DFU until low-torque-proof.json passes.",
                    blockers.join("; "),
                    pidff_blockers.join("; ")
                ));
            }
        }
        return;
    }

    if !bundle_gate_check_passed(gates, "steering_angle_stream_proof") {
        actions.push(
            "Current OpenRacing-control frontier: native steering angle stream proof. Record same-endpoint steering feedback with no output reports, no FFB writes, no feature reports, no serial config, and no firmware/DFU before any native movement-control claim."
                .to_string(),
        );
        return;
    }

    if !bundle_gate_check_passed(gates, "native_actuator_profile_smoke") {
        actions.push(
            "Current OpenRacing-control frontier: native PIDFF actuator-profile smoke. Run only after steering feedback is proven, keep the force profile bounded, require final PIDFF Stop All cleanup, and keep SimHub and Pit House out of this native-control claim."
                .to_string(),
        );
    }
}

fn push_native_motion_frontier_operator_action(
    lane: &Path,
    gates: &[BundleGateCheck],
    actions: &mut Vec<String>,
) {
    if !bundle_gate_check_passed(gates, "native_actuator_response_smoke") {
        actions.push(
            "Current native-response frontier: bounded native PIDFF actuator-response smoke. The receipt may record a sub-degree response; it must still prove successful PIDFF writes, same-lane steering samples, measured angle delta above the response noise floor, final Stop All cleanup, no direct report 0x20, no high torque, no feature reports, no serial config, and no firmware/DFU commands. Pit House, SimHub, and simulators are not prerequisites for this native OpenRacing path."
                .to_string(),
        );
        return;
    }

    if !bundle_gate_check_passed(gates, "native_actuator_visible_smoke") {
        if let Some(action) = native_visible_smoke_failed_real_receipt_action(lane) {
            actions.push(action);
            return;
        }
        actions.push(
            "Current native-visible frontier: native actuator visible-motion proof. Run an intentionally reviewed bounded PIDFF visible-motion stage only after the actuator-response smoke passes; it must prove operator-visible steering delta, final Stop All cleanup, no direct report 0x20, no high torque, no feature reports, no serial config, and no firmware/DFU commands. Pit House, SimHub, and simulators remain external compatibility work."
                .to_string(),
        );
    }
}

fn push_external_compat_frontier_operator_action(
    gates: &[BundleGateCheck],
    actions: &mut Vec<String>,
) {
    if !bundle_gate_check_passed(gates, "simulator_telemetry") {
        actions.push(
            "Current external-compatibility frontier: simulator telemetry proof. Capture one real simulator telemetry path only; this step must not send Moza output reports, feature reports, torque, serial config, firmware, or DFU commands."
                .to_string(),
        );
        return;
    }

    if !bundle_gate_check_passed(gates, "simulator_ffb_bounded") {
        actions.push(
            "Current external-compatibility frontier: bounded simulator FFB smoke. Run it only after telemetry passes, with the operator at the bench, wheel clear, power cutoff understood, watchdog enabled, descriptor trusted, low-torque proof passing, and no vendor firmware/update flow active. Keep duration and force bounded, record stop/pause/game-exit final-zero behavior, and do not claim Pit House coexistence until the later Pit House mode-change proof links to this receipt."
                .to_string(),
        );
        return;
    }

    if !bundle_gate_check_passed(gates, "pit_house_coexistence") {
        actions.push(
            "Current external-compatibility frontier: Pit House coexistence proof. If Pit House is not installed or we choose not to use it, leave smoke-ready blocked instead of fabricating coexistence evidence. If it is used, collect the closed, open-standard, direct-blocked, mode-change, and firmware/update-page observations as lane artifacts; firmware/update pages must be refused, and the mode-change case must prove output cleared and final zero was attempted after simulator FFB smoke."
                .to_string(),
        );
    }
}

fn native_visible_smoke_failed_real_receipt_action(lane: &Path) -> Option<String> {
    let receipt = failed_real_native_visible_smoke_receipt(lane)?;
    let movement_observed = optional_bool_text(json_bool(&receipt, "movement_observed"));
    let delta = optional_f64_text(json_f64(&receipt, "angle_delta_degrees"));
    let threshold = optional_f64_text(json_f64(&receipt, "movement_threshold_degrees"));
    let stop_all_sent = optional_bool_text(json_bool(&receipt, "final_stop_all_sent"));
    let no_direct = optional_bool_text(json_bool(&receipt, "no_direct_torque_reports"));
    let no_high_torque = optional_bool_text(json_bool(&receipt, "no_high_torque"));
    if let Some(plan) = native_visible_follow_up_plan(lane) {
        let review_decision =
            json_string(&plan, "review_decision").unwrap_or("missing_review_decision");
        let output_authorized = optional_bool_text(json_bool(&plan, "hardware_output_authorized"));
        let force_escalation_authorized =
            optional_bool_text(json_bool(&plan, "force_escalation_authorized"));
        let profile_design_status = plan
            .get("intentional_profile_design")
            .and_then(|design| json_string(design, "status"))
            .unwrap_or("missing_profile_design");
        let profile_plan_summary = native_visible_planned_profile_summary(&plan)
            .unwrap_or_else(|| "planned_profile_details=missing".to_string());
        let controlled_angle_artifact_summary = native_controlled_angle_plan_artifact_summary(lane);
        let controlled_angle_preflight_summary =
            native_controlled_angle_smoke_artifact_summary(lane);
        let controlled_angle_retry_summary =
            native_controlled_angle_retry_smoke_artifact_summary(lane);
        let authorization_guidance = native_visible_authorization_guidance(lane);
        return Some(format!(
            "Current native-visible frontier: native actuator response is recorded, but visible-motion remains unclaimed: movement_observed={movement_observed}, angle_delta_degrees={delta}, movement_threshold_degrees={threshold}. Final Stop All sent={stop_all_sent}, no direct report 0x20={no_direct}, no high torque={no_high_torque}. Follow-up plan exists at {NATIVE_VISIBLE_FOLLOW_UP_PLAN_FILE}: review_decision={review_decision}, profile_design_status={profile_design_status}, {profile_plan_summary}, {controlled_angle_artifact_summary}, {controlled_angle_preflight_summary}, {controlled_angle_retry_summary}, hardware_output_authorized={output_authorized}, force_escalation_authorized={force_escalation_authorized}. {authorization_guidance} Pit House, SimHub, and simulators are not required for this native diagnosis."
        ));
    }
    Some(format!(
        "Current native-visible frontier: native actuator response is recorded, but visible-motion remains unclaimed: movement_observed={movement_observed}, angle_delta_degrees={delta}, movement_threshold_degrees={threshold}. Final Stop All sent={stop_all_sent}, no direct report 0x20={no_direct}, no high torque={no_high_torque}. Do not rerun, raise force, or replace native-actuator-visible-smoke.json from generated guidance; inspect the bench/setup/FFB mode and record a deliberate follow-up plan in {NATIVE_VISIBLE_FOLLOW_UP_PLAN_FILE} before another hardware-output attempt. Pit House, SimHub, and simulators are not required for this native diagnosis."
    ))
}

fn native_visible_authorization_guidance(lane: &Path) -> String {
    if native_controlled_angle_closed_loop_smoke_is_real_output_attempt(lane) {
        let receipt = read_json_value(lane, NATIVE_CONTROLLED_ANGLE_CLOSED_LOOP_SMOKE_FILE).ok();
        let delta = receipt
            .as_ref()
            .map(|receipt| optional_f64_text(json_f64(receipt, "angle_delta_degrees")))
            .unwrap_or("missing".to_string());
        let target_reached = receipt
            .as_ref()
            .map(|receipt| optional_bool_text(json_bool(receipt, "target_reached")))
            .unwrap_or("missing".to_string());
        let timeout_reached = receipt
            .as_ref()
            .map(|receipt| optional_bool_text(json_bool(receipt, "timeout_reached")))
            .unwrap_or("missing".to_string());
        let abort_reason = receipt
            .as_ref()
            .and_then(|receipt| json_string(receipt, "abort_reason"))
            .unwrap_or("missing");
        let writes_ok = receipt
            .as_ref()
            .map(|receipt| optional_u64_text(json_u64(receipt, "writes_ok")))
            .unwrap_or("missing".to_string());
        let write_errors = receipt
            .as_ref()
            .map(|receipt| optional_u64_text(json_u64(receipt, "write_errors")))
            .unwrap_or("missing".to_string());
        let final_stop_all_sent = receipt
            .as_ref()
            .map(|receipt| optional_bool_text(json_bool(receipt, "final_stop_all_sent")))
            .unwrap_or("missing".to_string());
        let final_zero_sent = receipt
            .as_ref()
            .map(|receipt| optional_bool_text(json_bool(receipt, "final_zero_sent")))
            .unwrap_or("missing".to_string());
        let next_analysis = if lane
            .join(NATIVE_CONTROLLED_ANGLE_CLOSED_LOOP_FAILURE_ANALYSIS_FILE)
            .is_file()
        {
            format!(
                "The no-output closed-loop failure analysis is recorded at {NATIVE_CONTROLLED_ANGLE_CLOSED_LOOP_FAILURE_ANALYSIS_FILE}; next required work is no-output Moza vendor-specific protocol evidence before any future output plan."
            )
        } else {
            "Create a no-output closed-loop failure analysis and require new protocol evidence before any future output plan.".to_string()
        };
        return format!(
            "A real closed-loop controlled-angle attempt is already recorded at {NATIVE_CONTROLLED_ANGLE_CLOSED_LOOP_SMOKE_FILE}; preserve {NATIVE_CONTROLLED_ANGLE_CLOSED_LOOP_PREFLIGHT_FILE}, {NATIVE_CONTROLLED_ANGLE_CLOSED_LOOP_AUTHORIZATION_FILE}, and {NATIVE_CONTROLLED_ANGLE_CLOSED_LOOP_SMOKE_FILE}. Closed-loop result: target_reached={target_reached}, timeout_reached={timeout_reached}, abort_reason={abort_reason}, angle_delta_degrees={delta}, writes_ok={writes_ok}, write_errors={write_errors}, final_stop_all_sent={final_stop_all_sent}, final_zero_sent={final_zero_sent}. This is safe undertravel evidence, not native-visible readiness. Do not generate another preflight, authorization, or output command from verifier guidance; {next_analysis} Do not extend dwell, raise force, attempt 3/5/30/90 degrees, use direct report 0x20, high torque, serial config, firmware, DFU, Pit House, SimHub, or a simulator as a native-control prerequisite."
        );
    }

    if native_controlled_angle_attempt_03_smoke_is_real_output_attempt(lane) {
        let attempt = read_json_value(lane, NATIVE_CONTROLLED_ANGLE_ATTEMPT_03_SMOKE_FILE).ok();
        let delta = attempt
            .as_ref()
            .map(|receipt| optional_f64_text(json_f64(receipt, "angle_delta_degrees")))
            .unwrap_or("missing".to_string());
        let target_reached = attempt
            .as_ref()
            .map(|receipt| optional_bool_text(json_bool(receipt, "target_reached")))
            .unwrap_or("missing".to_string());
        let timeout_reached = attempt
            .as_ref()
            .map(|receipt| optional_bool_text(json_bool(receipt, "timeout_reached")))
            .unwrap_or("missing".to_string());
        let writes_ok = attempt
            .as_ref()
            .map(|receipt| optional_u64_text(json_u64(receipt, "writes_ok")))
            .unwrap_or("missing".to_string());
        let write_errors = attempt
            .as_ref()
            .map(|receipt| optional_u64_text(json_u64(receipt, "write_errors")))
            .unwrap_or("missing".to_string());
        let final_stop_all_sent = attempt
            .as_ref()
            .map(|receipt| optional_bool_text(json_bool(receipt, "final_stop_all_sent")))
            .unwrap_or("missing".to_string());
        let next_guidance =
            native_visible_standard_pidff_diagnosis_guidance(lane).unwrap_or_else(|| {
                "Do not generate another preflight, authorization, or output command from verifier guidance; classify the attempt with a no-output analysis before any future profile plan. Do not extend dwell, raise force, attempt 30/90 degrees, use direct report 0x20, or use the visible-output authorizer.".to_string()
            });
        return format!(
            "A real controlled-angle attempt 03 is already recorded at {NATIVE_CONTROLLED_ANGLE_ATTEMPT_03_SMOKE_FILE}; preserve {NATIVE_CONTROLLED_ANGLE_SMOKE_FILE}, {NATIVE_CONTROLLED_ANGLE_RETRY_SMOKE_FILE}, {NATIVE_CONTROLLED_ANGLE_ATTEMPT_03_PREFLIGHT_FILE}, {NATIVE_CONTROLLED_ANGLE_ATTEMPT_03_AUTHORIZATION_FILE}, and {NATIVE_CONTROLLED_ANGLE_ATTEMPT_03_SMOKE_FILE}. Attempt 03 result: target_reached={target_reached}, timeout_reached={timeout_reached}, angle_delta_degrees={delta}, writes_ok={writes_ok}, write_errors={write_errors}, final_stop_all_sent={final_stop_all_sent}. {next_guidance}"
        );
    }
    if native_controlled_angle_attempt_03_preflight_is_no_output_preflight(lane) {
        return format!(
            "The no-output controlled-angle attempt 03 preflight is recorded at {NATIVE_CONTROLLED_ANGLE_ATTEMPT_03_PREFLIGHT_FILE} for profile bounded-pidff-effect-lifecycle-v1; preserve {NATIVE_CONTROLLED_ANGLE_SMOKE_FILE}, {NATIVE_CONTROLLED_ANGLE_RETRY_SMOKE_FILE}, and {NATIVE_CONTROLLED_ANGLE_ATTEMPT_03_PREFLIGHT_FILE}. This preflight opens no HID device, sends no writes, proves no motion, and does not authorize output. Any attempt 03 output still requires fresh command-bound bench-clear plus an exact wheelctl moza authorize-controlled-angle-output receipt at {NATIVE_CONTROLLED_ANGLE_ATTEMPT_03_AUTHORIZATION_FILE}, and the authorized command must write {NATIVE_CONTROLLED_ANGLE_ATTEMPT_03_SMOKE_FILE}. Do not generate authorization or output from verifier guidance; do not extend dwell, raise force, attempt 30/90 degrees, use direct report 0x20, or use the visible-output authorizer."
        );
    }
    if native_controlled_angle_retry_smoke_is_real_output_attempt(lane) {
        let retry = read_json_value(lane, NATIVE_CONTROLLED_ANGLE_RETRY_SMOKE_FILE).ok();
        let delta = retry
            .as_ref()
            .map(|receipt| optional_f64_text(json_f64(receipt, "angle_delta_degrees")))
            .unwrap_or("missing".to_string());
        let target_reached = retry
            .as_ref()
            .map(|receipt| optional_bool_text(json_bool(receipt, "target_reached")))
            .unwrap_or("missing".to_string());
        let timeout_reached = retry
            .as_ref()
            .map(|receipt| optional_bool_text(json_bool(receipt, "timeout_reached")))
            .unwrap_or("missing".to_string());
        let writes_ok = retry
            .as_ref()
            .map(|receipt| optional_u64_text(json_u64(receipt, "writes_ok")))
            .unwrap_or("missing".to_string());
        let write_errors = retry
            .as_ref()
            .map(|receipt| optional_u64_text(json_u64(receipt, "write_errors")))
            .unwrap_or("missing".to_string());
        let final_stop_all_sent = retry
            .as_ref()
            .map(|receipt| optional_bool_text(json_bool(receipt, "final_stop_all_sent")))
            .unwrap_or("missing".to_string());
        let analysis_status =
            read_json_value(lane, NATIVE_CONTROLLED_ANGLE_RETRY_FAILURE_ANALYSIS_FILE)
                .ok()
                .and_then(|analysis| json_string(&analysis, "classification").map(str::to_string))
                .unwrap_or_else(|| "missing_retry_failure_analysis".to_string());
        let semantics_diagnosis = native_pidff_semantics_diagnosis_artifact_summary(lane);
        let next_step = if semantics_diagnosis.contains("present_no_output") {
            "The no-output PIDFF semantics/profile diagnosis is recorded; do not authorize output from it. The next work is a separate software-only reviewed profile/lifecycle plan that names what PIDFF operation-order or effect-lifecycle change will be tested before any later exact authorization."
        } else {
            "Create a new no-output PIDFF semantics/profile diagnosis before any later exact authorization."
        };
        return format!(
            "A real controlled-angle retry is already recorded at {NATIVE_CONTROLLED_ANGLE_RETRY_SMOKE_FILE}; preserve {NATIVE_CONTROLLED_ANGLE_SMOKE_FILE}, {NATIVE_CONTROLLED_ANGLE_RETRY_PREFLIGHT_FILE}, {NATIVE_CONTROLLED_ANGLE_RETRY_AUTHORIZATION_FILE}, and {NATIVE_CONTROLLED_ANGLE_RETRY_SMOKE_FILE}. The retry did not prove visible motion: target_reached={target_reached}, timeout_reached={timeout_reached}, angle_delta_degrees={delta}, writes_ok={writes_ok}, write_errors={write_errors}, final_stop_all_sent={final_stop_all_sent}, retry_failure_classification={analysis_status}. {semantics_diagnosis}. Do not generate a third preflight, authorization, or output command from verifier guidance; {next_step} Do not extend dwell, raise force, attempt 30/90 degrees, use direct report 0x20, or use the visible-output authorizer."
        );
    }
    if native_controlled_angle_smoke_is_real_output_attempt(lane) {
        if read_json_value(lane, NATIVE_CONTROLLED_ANGLE_PLAN_FILE)
            .is_ok_and(|plan| native_controlled_angle_plan_retry_profile_ok(&plan))
        {
            return format!(
                "A real controlled-angle attempt is already recorded and the reviewed retry profile is present in {NATIVE_CONTROLLED_ANGLE_PLAN_FILE}; preserve {NATIVE_CONTROLLED_ANGLE_SMOKE_FILE}, generate a no-output retry preflight at {NATIVE_CONTROLLED_ANGLE_RETRY_PREFLIGHT_FILE}, and use the bounded-pidff-micro-step-v2 profile/feedback loop only after a separate fresh command-bound bench-clear plus an exact wheelctl moza authorize-controlled-angle-output receipt at {NATIVE_CONTROLLED_ANGLE_RETRY_AUTHORIZATION_FILE}. The retry output must write {NATIVE_CONTROLLED_ANGLE_RETRY_SMOKE_FILE}. Do not use the visible-output authorizer, extend dwell, raise force, or rerun from verifier guidance."
            );
        }
        format!(
            "A real controlled-angle attempt is already recorded; preserve {NATIVE_CONTROLLED_ANGLE_SMOKE_FILE} and diagnose the profile/feedback loop before any new output plan. Update {NATIVE_CONTROLLED_ANGLE_PLAN_FILE} with the reason the 1 degree target was not reached, then use wheelctl moza authorize-controlled-angle-output only after a separate reviewed exact command and fresh bench-clear; do not use the visible-output authorizer, extend dwell, raise force, or rerun from verifier guidance."
        )
    } else if native_controlled_angle_smoke_is_no_output_preflight(lane) {
        format!(
            "Do not run output until fresh bench-clear is recorded for the exact 1 degree controlled-angle command via wheelctl moza authorize-controlled-angle-output, producing {NATIVE_CONTROLLED_ANGLE_AUTHORIZATION_FILE}; no visible-output authorizer is required for this controlled-angle path."
        )
    } else {
        "Do not run output until the follow-up requirements are complete and a fresh bench-clear is recorded for the exact next output command via wheelctl moza authorize-visible-output.".to_string()
    }
}

fn native_visible_standard_pidff_diagnosis_guidance(lane: &Path) -> Option<String> {
    if !lane
        .join(NATIVE_PIDFF_STANDARD_PATH_DIAGNOSIS_FILE)
        .is_file()
    {
        return None;
    }

    if native_controlled_angle_closed_loop_smoke_is_real_output_attempt(lane) {
        let receipt = read_json_value(lane, NATIVE_CONTROLLED_ANGLE_CLOSED_LOOP_SMOKE_FILE).ok();
        let delta = receipt
            .as_ref()
            .map(|receipt| optional_f64_text(json_f64(receipt, "angle_delta_degrees")))
            .unwrap_or("missing".to_string());
        let target_reached = receipt
            .as_ref()
            .map(|receipt| optional_bool_text(json_bool(receipt, "target_reached")))
            .unwrap_or("missing".to_string());
        let timeout_reached = receipt
            .as_ref()
            .map(|receipt| optional_bool_text(json_bool(receipt, "timeout_reached")))
            .unwrap_or("missing".to_string());
        let final_zero_sent = receipt
            .as_ref()
            .map(|receipt| optional_bool_text(json_bool(receipt, "final_zero_sent")))
            .unwrap_or("missing".to_string());
        return Some(format!(
            "The standard PIDFF path diagnosis is recorded at {NATIVE_PIDFF_STANDARD_PATH_DIAGNOSIS_FILE}, and the follow-up closed-loop output receipt is recorded at {NATIVE_CONTROLLED_ANGLE_CLOSED_LOOP_SMOKE_FILE}. Closed-loop native visible motion is still unproven: target_reached={target_reached}, timeout_reached={timeout_reached}, angle_delta_degrees={delta}, final_zero_sent={final_zero_sent}. Preserve the receipt and write no-output analysis before any future protocol plan; no further output is authorized by verifier guidance."
        ));
    }

    if lane
        .join(NATIVE_CONTROLLED_ANGLE_CLOSED_LOOP_PREFLIGHT_FILE)
        .is_file()
    {
        return Some(format!(
            "The standard PIDFF path diagnosis is recorded at {NATIVE_PIDFF_STANDARD_PATH_DIAGNOSIS_FILE}; no further fixed standard-PIDFF output is authorized. A no-output closed-loop controller preflight is recorded at {NATIVE_CONTROLLED_ANGLE_CLOSED_LOOP_PREFLIGHT_FILE}; any real output still requires fresh command-bound bench-clear plus an exact authorization at {NATIVE_CONTROLLED_ANGLE_CLOSED_LOOP_AUTHORIZATION_FILE}, and the output receipt must be {NATIVE_CONTROLLED_ANGLE_CLOSED_LOOP_SMOKE_FILE}. Pit House, SimHub, and simulators remain coexistence or telemetry evidence, not native-control prerequisites. Do not extend dwell, raise force, attempt 3/5/30/90 degrees, use direct report 0x20, high torque, serial config, firmware, or DFU."
        ));
    }

    Some(format!(
        "The standard PIDFF path diagnosis is recorded at {NATIVE_PIDFF_STANDARD_PATH_DIAGNOSIS_FILE}; no further fixed standard-PIDFF output is authorized. Next native-control evidence is a no-output closed-loop controller preflight at {NATIVE_CONTROLLED_ANGLE_CLOSED_LOOP_PREFLIGHT_FILE} using --profile {}. Pit House, SimHub, and simulators remain coexistence or telemetry evidence, not native-control prerequisites. Do not extend dwell, raise force, attempt 3/5/30/90 degrees, use direct report 0x20, high torque, serial config, firmware, or DFU.",
        controlled_angle_profile_cli_name(MozaControlledAngleProfile::ClosedLoopPidffAngleV1)
    ))
}

fn native_controlled_angle_plan_artifact_summary(lane: &Path) -> String {
    let Ok(plan) = read_json_value(lane, NATIVE_CONTROLLED_ANGLE_PLAN_FILE) else {
        return "controlled_angle_plan_artifact=missing".to_string();
    };

    let command_ok = json_string(&plan, "command") == Some("wheelctl moza receipt-template");
    let no_output_ok = native_controlled_angle_plan_no_output_ok(&plan);
    let ladder_ok = native_controlled_angle_plan_ladder_ok(&plan);
    let retry_profile_ok = native_controlled_angle_plan_retry_profile_ok(&plan);
    let artifact_status = if command_ok && no_output_ok && ladder_ok && retry_profile_ok {
        "present_no_output"
    } else {
        "present_needs_review"
    };

    format!(
        "controlled_angle_plan_artifact={artifact_status}, controlled_angle_ladder=1/3/5/10/30/90, controlled_angle_command_ok={command_ok}, controlled_angle_no_output_ok={no_output_ok}, controlled_angle_ladder_ok={ladder_ok}, controlled_angle_retry_profile_ok={retry_profile_ok}"
    )
}

fn native_controlled_angle_smoke_artifact_summary(lane: &Path) -> String {
    let Ok(receipt) = read_json_value(lane, NATIVE_CONTROLLED_ANGLE_SMOKE_FILE) else {
        return "controlled_angle_preflight_artifact=missing".to_string();
    };
    let command_ok =
        json_string(&receipt, "command") == Some("wheelctl moza controlled-angle-smoke");
    let target = optional_f64_text(json_f64(&receipt, "target_degrees"));
    if json_bool(&receipt, "dry_run") == Some(false) {
        let actual_gate = verify_native_controlled_angle_smoke_gate(lane);
        let motion_proven = json_bool(&receipt, "controlled_angle_motion_proven") == Some(true);
        let target_reached = json_bool(&receipt, "target_reached") == Some(true);
        let returned = json_bool(&receipt, "return_to_start_proven") == Some(true);
        let delta = optional_f64_text(json_f64(&receipt, "angle_delta_degrees"));
        let abort_reason = json_string(&receipt, "abort_reason").unwrap_or("missing");
        let timeout_reached = optional_bool_text(json_bool(&receipt, "timeout_reached"));
        let overshoot = optional_bool_text(json_bool(&receipt, "overshoot_detected"));
        let no_steering_samples = optional_bool_text(json_bool(&receipt, "no_steering_samples"));
        let write_errors = optional_u64_text(json_u64(&receipt, "write_errors"));
        let stop_all = optional_bool_text(json_bool(&receipt, "final_stop_all_sent"));
        let no_direct = optional_bool_text(json_bool(&receipt, "no_direct_torque_reports"));
        return format!(
            "controlled_angle_receipt_artifact={}, controlled_angle_target_degrees={target}, controlled_angle_delta_degrees={delta}, controlled_angle_motion_proven={motion_proven}, controlled_angle_target_reached={target_reached}, controlled_angle_return_to_start={returned}, controlled_angle_abort_reason={abort_reason}, controlled_angle_timeout_reached={timeout_reached}, controlled_angle_overshoot_detected={overshoot}, controlled_angle_no_steering_samples={no_steering_samples}, controlled_angle_write_errors={write_errors}, controlled_angle_final_stop_all_sent={stop_all}, controlled_angle_no_direct_report_0x20={no_direct}",
            actual_gate.status
        );
    }
    let no_output_ok = json_bool(&receipt, "hardware_output_enabled") == Some(false)
        && json_bool(&receipt, "dry_run") == Some(true)
        && json_bool(&receipt, "no_hid_device_opened") == Some(true)
        && json_bool(&receipt, "no_ffb_writes") == Some(true)
        && json_bool(&receipt, "no_output_reports") == Some(true)
        && json_bool(&receipt, "no_feature_reports") == Some(true)
        && no_out_of_scope_device_commands(&receipt);
    let motion_unclaimed = json_bool(&receipt, "controlled_angle_motion_proven") == Some(false)
        && json_bool(&receipt, "actual_hardware_writes_supported") == Some(false)
        && json_bool(&receipt, "planned_next_output_allowed") == Some(false);
    let status = if command_ok && no_output_ok && motion_unclaimed {
        "present_no_output"
    } else {
        "present_needs_review"
    };
    format!(
        "controlled_angle_preflight_artifact={status}, controlled_angle_preflight_target_degrees={target}, controlled_angle_preflight_command_ok={command_ok}, controlled_angle_preflight_no_output_ok={no_output_ok}, controlled_angle_motion_unclaimed={motion_unclaimed}"
    )
}

