fn native_controlled_angle_ladder_degrees() -> [f64; 6] {
    [1.0, 3.0, 5.0, 10.0, 30.0, 90.0]
}

fn native_controlled_angle_plan_no_output_ok(plan: &Value) -> bool {
    json_bool(plan, "hardware_output_authorized") == Some(false)
        && plan
            .get("planned_next_output")
            .and_then(|planned| json_bool(planned, "allowed"))
            == Some(false)
        && json_bool(plan, "no_hid_device_opened") == Some(true)
        && json_bool(plan, "no_ffb_writes") == Some(true)
        && json_bool(plan, "no_output_reports") == Some(true)
        && json_bool(plan, "no_feature_reports") == Some(true)
        && no_out_of_scope_device_commands(plan)
}

fn native_controlled_angle_plan_ladder_ok(plan: &Value) -> bool {
    let Some(ladder) = plan
        .get("controlled_angle_profile_plan")
        .and_then(|profile| profile.get("target_ladder_degrees"))
        .and_then(Value::as_array)
    else {
        return false;
    };
    let observed = ladder.iter().filter_map(Value::as_u64).collect::<Vec<_>>();
    observed == [1, 3, 5, 10, 30, 90]
}

fn native_controlled_angle_plan_retry_profile_ok(plan: &Value) -> bool {
    let Some(profile) = plan
        .get("controlled_angle_profile_plan")
        .and_then(|profile| profile.get("reviewed_retry_profile"))
    else {
        return false;
    };
    json_string(profile, "profile")
        == Some(controlled_angle_profile_name(
            MozaControlledAngleProfile::BoundedPidffMicroStepV2,
        ))
        && json_string(profile, "profile_cli")
            == Some(controlled_angle_profile_cli_name(
                MozaControlledAngleProfile::BoundedPidffMicroStepV2,
            ))
        && json_string(profile, "status") == Some("implemented_no_output_authorized")
        && json_bool(profile, "hardware_output_authorized") == Some(false)
        && json_f64(profile, "target_degrees") == Some(NATIVE_CONTROLLED_ANGLE_FIRST_TARGET_DEGREES)
        && json_f64(profile, "max_percent")
            == Some(f64::from(NATIVE_CONTROLLED_ANGLE_FIRST_MAX_PERCENT))
        && json_u64(profile, "timeout_ms") == Some(NATIVE_CONTROLLED_ANGLE_FIRST_MAX_DURATION_MS)
}

fn native_pidff_effect_lifecycle_plan_no_output_ok(plan: &Value) -> bool {
    json_string(plan, "artifact_kind") == Some("native_pidff_effect_lifecycle_plan")
        && json_bool(plan, "hardware_output_authorized") == Some(false)
        && json_bool(plan, "planned_next_output_allowed") == Some(false)
        && json_bool(plan, "native_visible_claimed") == Some(false)
        && json_bool(plan, "openracing_hardware_output") == Some(false)
        && json_bool(plan, "no_hid_device_opened") == Some(true)
        && json_bool(plan, "no_output_reports") == Some(true)
        && json_bool(plan, "no_ffb_writes") == Some(true)
        && json_bool(plan, "no_feature_reports") == Some(true)
        && no_out_of_scope_device_commands(plan)
        && plan
            .get("planned_next_output")
            .and_then(|planned| json_bool(planned, "allowed"))
            == Some(false)
}

fn native_pidff_effect_lifecycle_plan_profile_ok(plan: &Value) -> bool {
    let Some(profile) = plan.get("profile") else {
        return false;
    };
    json_string(profile, "name")
        == Some(controlled_angle_profile_name(
            MozaControlledAngleProfile::BoundedPidffEffectLifecycleV1,
        ))
        && json_string(profile, "cli_name")
            == Some(controlled_angle_profile_cli_name(
                MozaControlledAngleProfile::BoundedPidffEffectLifecycleV1,
            ))
        && json_string(profile, "implementation_status")
            == Some("implemented_no_output_preflight_supported")
        && json_bool(profile, "hardware_output_authorized") == Some(false)
        && profile
            .get("unchanged_caps")
            .and_then(|caps| json_f64(caps, "target_degrees"))
            == Some(NATIVE_CONTROLLED_ANGLE_FIRST_TARGET_DEGREES)
        && profile
            .get("unchanged_caps")
            .and_then(|caps| json_f64(caps, "max_percent"))
            == Some(f64::from(NATIVE_CONTROLLED_ANGLE_FIRST_MAX_PERCENT))
        && profile
            .get("unchanged_caps")
            .and_then(|caps| json_u64(caps, "timeout_ms"))
            == Some(NATIVE_CONTROLLED_ANGLE_FIRST_MAX_DURATION_MS)
        && profile
            .get("unchanged_caps")
            .and_then(|caps| json_string(caps, "strategy"))
            == Some(low_torque_strategy_cli_name(
                MozaLowTorqueStrategy::PidffBoundedEffect,
            ))
}

fn validate_native_pidff_effect_lifecycle_plan_artifact(lane: &Path) -> Result<Value> {
    let plan =
        read_json_value(lane, NATIVE_PIDFF_EFFECT_LIFECYCLE_PLAN_FILE).with_context(|| {
            format!(
                "bounded-pidff-effect-lifecycle-v1 preflight requires {} in the lane",
                NATIVE_PIDFF_EFFECT_LIFECYCLE_PLAN_FILE
            )
        })?;
    let no_output_ok = native_pidff_effect_lifecycle_plan_no_output_ok(&plan);
    let profile_ok = native_pidff_effect_lifecycle_plan_profile_ok(&plan);
    if no_output_ok && profile_ok {
        Ok(plan)
    } else {
        Err(anyhow!(
            "{} is not a safe implemented no-output PIDFF effect lifecycle plan: no_output_ok={no_output_ok}, profile_ok={profile_ok}",
            NATIVE_PIDFF_EFFECT_LIFECYCLE_PLAN_FILE
        ))
    }
}

fn native_pidff_effect_lifecycle_plan_summary(plan: &Value) -> Value {
    serde_json::json!({
        "path": NATIVE_PIDFF_EFFECT_LIFECYCLE_PLAN_FILE,
        "artifact_kind": json_string(plan, "artifact_kind"),
        "no_output_ok": native_pidff_effect_lifecycle_plan_no_output_ok(plan),
        "profile_ok": native_pidff_effect_lifecycle_plan_profile_ok(plan),
        "classification": json_string(plan, "classification"),
        "implementation_status": plan
            .get("profile")
            .and_then(|profile| json_string(profile, "implementation_status")),
        "hardware_output_authorized": json_bool(plan, "hardware_output_authorized"),
        "planned_next_output_allowed": json_bool(plan, "planned_next_output_allowed"),
        "native_visible_claimed": json_bool(plan, "native_visible_claimed"),
        "generated_at_utc": json_string(plan, "generated_at_utc")
    })
}

fn validate_native_controlled_angle_plan_artifact(lane: &Path) -> Result<Value> {
    let plan = read_json_value(lane, NATIVE_CONTROLLED_ANGLE_PLAN_FILE).with_context(|| {
        format!(
            "native controlled-angle preflight requires {} in the lane; generate it with `wheelctl moza receipt-template --kind controlled-angle-plan`",
            NATIVE_CONTROLLED_ANGLE_PLAN_FILE
        )
    })?;
    let command_ok = json_string(&plan, "command") == Some("wheelctl moza receipt-template");
    let no_output_ok = native_controlled_angle_plan_no_output_ok(&plan);
    let ladder_ok = native_controlled_angle_plan_ladder_ok(&plan);
    let retry_profile_ok = native_controlled_angle_plan_retry_profile_ok(&plan);
    if command_ok && no_output_ok && ladder_ok && retry_profile_ok {
        Ok(plan)
    } else {
        Err(anyhow!(
            "{} is not a safe no-output controlled-angle plan artifact: command_ok={command_ok}, no_output_ok={no_output_ok}, ladder_ok={ladder_ok}, retry_profile_ok={retry_profile_ok}",
            NATIVE_CONTROLLED_ANGLE_PLAN_FILE
        ))
    }
}

fn validate_native_controlled_angle_dry_run_preflight(
    lane: &Path,
    preflight_file: &str,
    selector: &str,
    target_degrees: f64,
    profile: MozaControlledAngleProfile,
    strategy: MozaLowTorqueStrategy,
    max_percent: f32,
) -> Result<Value> {
    let receipt = read_json_value(lane, preflight_file).with_context(|| {
        format!(
            "native controlled-angle authorization requires a no-output dry-run preflight at {}",
            lane.join(preflight_file).display()
        )
    })?;
    let command_ok =
        json_string(&receipt, "command") == Some("wheelctl moza controlled-angle-smoke");
    let receipt_path_ok = receipt_path_matches(lane, &receipt, preflight_file);
    let selector_ok = json_string(&receipt, "selector") == Some(selector);
    let success = json_bool(&receipt, "success") == Some(true);
    let dry_run = json_bool(&receipt, "dry_run") == Some(true);
    let preflight_only = json_bool(&receipt, "preflight_only") == Some(true);
    let hardware_output_enabled = json_bool(&receipt, "hardware_output_enabled") == Some(false);
    let actual_hardware_writes_supported =
        json_bool(&receipt, "actual_hardware_writes_supported") == Some(false);
    let no_hid_device_opened = json_bool(&receipt, "no_hid_device_opened") == Some(true);
    let no_feature_reports = json_bool(&receipt, "no_feature_reports") == Some(true);
    let no_output_reports = json_bool(&receipt, "no_output_reports") == Some(true);
    let no_ffb_writes = json_bool(&receipt, "no_ffb_writes") == Some(true);
    let no_direct_torque_reports = json_bool(&receipt, "no_direct_torque_reports") == Some(true);
    let no_high_torque = json_bool(&receipt, "no_high_torque") == Some(true);
    let high_torque = json_bool(&receipt, "high_torque") == Some(false);
    let no_serial_config_commands = json_bool(&receipt, "no_serial_config_commands") == Some(true);
    let no_firmware_or_dfu_commands =
        json_bool(&receipt, "no_firmware_or_dfu_commands") == Some(true);
    let target_ok = json_f64(&receipt, "target_degrees")
        .map(|value| (value - target_degrees).abs() <= f64::EPSILON)
        .unwrap_or(false);
    let profile_ok =
        json_string(&receipt, "profile") == Some(controlled_angle_profile_name(profile));
    let effect_lifecycle_plan_ok =
        if controlled_angle_profile_requires_effect_lifecycle_plan(profile) {
            receipt
                .get("pidff_effect_lifecycle_plan_artifact")
                .map(|artifact| {
                    json_string(artifact, "path") == Some(NATIVE_PIDFF_EFFECT_LIFECYCLE_PLAN_FILE)
                        && json_bool(artifact, "no_output_ok") == Some(true)
                        && json_bool(artifact, "profile_ok") == Some(true)
                        && json_string(artifact, "implementation_status")
                            == Some("implemented_no_output_preflight_supported")
                        && json_bool(artifact, "hardware_output_authorized") == Some(false)
                        && json_bool(artifact, "planned_next_output_allowed") == Some(false)
                        && json_bool(artifact, "native_visible_claimed") == Some(false)
                })
                .unwrap_or(false)
        } else {
            true
        };
    let max_percent_ok = json_f64(&receipt, "max_percent")
        .map(|value| (value - f64::from(max_percent)).abs() <= f64::EPSILON)
        .unwrap_or(false);
    let strategy_ok =
        json_string(&receipt, "output_strategy") == Some(low_torque_strategy_name(strategy));
    let motion_unclaimed = json_bool(&receipt, "controlled_angle_motion_proven") == Some(false);
    let no_out_of_scope = no_out_of_scope_device_commands(&receipt);

    if command_ok
        && receipt_path_ok
        && selector_ok
        && success
        && dry_run
        && preflight_only
        && hardware_output_enabled
        && actual_hardware_writes_supported
        && no_hid_device_opened
        && no_feature_reports
        && no_output_reports
        && no_ffb_writes
        && no_direct_torque_reports
        && no_high_torque
        && high_torque
        && no_serial_config_commands
        && no_firmware_or_dfu_commands
        && target_ok
        && profile_ok
        && effect_lifecycle_plan_ok
        && max_percent_ok
        && strategy_ok
        && motion_unclaimed
        && no_out_of_scope
    {
        Ok(receipt)
    } else {
        Err(anyhow!(
            "{} is not a matching no-output controlled-angle dry-run preflight: command_ok={command_ok}, receipt_path_ok={receipt_path_ok}, selector_ok={selector_ok}, success={success}, dry_run={dry_run}, preflight_only={preflight_only}, hardware_output_enabled_false={hardware_output_enabled}, actual_hardware_writes_supported_false={actual_hardware_writes_supported}, no_hid_device_opened={no_hid_device_opened}, no_feature_reports={no_feature_reports}, no_output_reports={no_output_reports}, no_ffb_writes={no_ffb_writes}, no_direct_torque_reports={no_direct_torque_reports}, no_high_torque={no_high_torque}, high_torque_false={high_torque}, no_serial_config_commands={no_serial_config_commands}, no_firmware_or_dfu_commands={no_firmware_or_dfu_commands}, target_ok={target_ok}, profile_ok={profile_ok}, effect_lifecycle_plan_ok={effect_lifecycle_plan_ok}, max_percent_ok={max_percent_ok}, strategy_ok={strategy_ok}, motion_unclaimed={motion_unclaimed}, no_out_of_scope={no_out_of_scope}",
            preflight_file
        ))
    }
}

fn failed_real_native_visible_smoke_receipt(lane: &Path) -> Option<Value> {
    let receipt = read_json_value(lane, "native-actuator-visible-smoke.json").ok()?;
    let real_failed_visible_receipt = json_string(&receipt, "command")
        == Some("wheelctl moza actuator-visible-smoke")
        && json_bool(&receipt, "success") == Some(false)
        && json_bool(&receipt, "dry_run") != Some(true)
        && json_bool(&receipt, "hardware_output_enabled") == Some(true);
    if real_failed_visible_receipt {
        Some(receipt)
    } else {
        None
    }
}

fn native_visible_follow_up_plan(lane: &Path) -> Option<Value> {
    read_json_value(lane, NATIVE_VISIBLE_FOLLOW_UP_PLAN_FILE).ok()
}

fn native_visible_planned_profile_summary(plan: &Value) -> Option<String> {
    let design = plan.get("intentional_profile_design")?;
    let selected = design.get("selected_next_profile")?;
    let status = json_string(selected, "status")?;
    let family = json_string(selected, "family")?;
    let cli_support = json_string(selected, "current_cli_support").unwrap_or("missing");
    let envelope = selected.get("expected_small_angle_envelope_degrees")?;
    let min = json_f64(envelope, "min")?;
    let max = json_f64(envelope, "max")?;
    let exact_output_authorized = plan
        .get("planned_next_output")
        .and_then(|planned| json_bool(planned, "allowed"))
        .unwrap_or(false);

    Some(format!(
        "planned_profile_status={status}, planned_profile_family={family}, planned_profile_cli_support={cli_support}, expected_small_angle_envelope_degrees={min:.3}..{max:.3}, exact_output_command_authorized={exact_output_authorized}"
    ))
}

fn optional_bool_text(value: Option<bool>) -> String {
    value
        .map(|value| value.to_string())
        .unwrap_or_else(|| "missing".to_string())
}

fn optional_f64_text(value: Option<f64>) -> String {
    value
        .filter(|value| value.is_finite())
        .map(|value| format!("{value:.3}"))
        .unwrap_or_else(|| "missing".to_string())
}

fn optional_u64_text(value: Option<u64>) -> String {
    value
        .map(|value| value.to_string())
        .unwrap_or_else(|| "missing".to_string())
}

fn audit_lane_dir(lane: &Path, stage: MozaBundleStage) -> LaneAuditReceipt {
    let live_verification = verify_bundle_dir(lane, stage);
    let mut receipt_checks = Vec::new();
    for audited_stage in audit_stages_through(stage) {
        receipt_checks.push(audit_stored_verification_receipt(lane, audited_stage));
        receipt_checks.push(audit_manifest_promotion_receipt(lane, audited_stage));
    }

    let missing_receipts = receipt_checks
        .iter()
        .filter(|check| check.status == "missing")
        .count();
    let invalid_receipts = receipt_checks
        .iter()
        .filter(|check| check.status == "invalid")
        .count();
    let success = live_verification.success && missing_receipts == 0 && invalid_receipts == 0;

    LaneAuditReceipt {
        success,
        command: "wheelctl moza audit-lane",
        generated_at_utc: now_utc(),
        lane: lane.display().to_string(),
        requested_stage: stage_label(stage).to_string(),
        live_verification_success: live_verification.success,
        live_verification: bundle_verification_summary_value(&live_verification),
        missing_receipts,
        invalid_receipts,
        receipt_checks,
        no_hid_device_opened: true,
        no_ffb_writes: true,
        no_serial_config_commands: true,
        no_firmware_or_dfu_commands: true,
        notes: vec![
            "audit-lane reads existing verification and promotion receipts only; it opens no HID device and sends no reports".to_string(),
            "audit-lane is a post-promotion completeness audit, not a release-readiness claim".to_string(),
        ],
    }
}

fn pre_output_readiness_dir(lane: &Path) -> PreOutputReadinessReceipt {
    let passive = pre_output_stored_verification_receipt(lane, MozaBundleStage::Passive);
    let zero = pre_output_stored_verification_receipt(lane, MozaBundleStage::Zero);
    let openracing_control =
        pre_output_stored_verification_receipt(lane, MozaBundleStage::OpenRacingControlReady);
    let smoke_ready = pre_output_stored_verification_receipt(lane, MozaBundleStage::SmokeReady);
    let passive_audit_passed = stored_lane_audit_receipt_passed(lane, MozaBundleStage::Passive);
    let zero_audit_passed = stored_lane_audit_receipt_passed(lane, MozaBundleStage::Zero);
    let openracing_control_audit_passed =
        stored_lane_audit_receipt_passed(lane, MozaBundleStage::OpenRacingControlReady);
    let smoke_ready_audit_passed =
        stored_lane_audit_receipt_passed(lane, MozaBundleStage::SmokeReady);
    let status_receipts = pre_output_status_receipt_checks(lane);
    let status_receipts_no_output = status_receipts.iter().all(|check| check.status == "pass");

    let role_evidence_complete = required_role_evidence_complete(&passive);
    let input_role_semantics = moza_input_role_semantics_summary(lane);
    let pit_house_compatibility = moza_pit_house_compatibility_summary(lane);
    let simulator_compatibility = moza_simulator_compatibility_summary(lane);
    let input_semantic_mapping_complete = json_string(&input_role_semantics, "semantic_status")
        == Some("all_required_roles_semantically_proven");
    let native_actuator_response_gate = verify_native_actuator_response_smoke_gate(lane);
    let native_visible_motion_gate = verify_native_actuator_visible_smoke_gate(lane);
    let native_actuator_response_proven = native_actuator_response_gate.status == "pass";
    let native_visible_motion_proven = native_visible_motion_gate.status == "pass";
    let direct_zero_report_metadata = zero_output_direct_report_metadata_trusted(lane);
    let zero_output_strategies = zero_output_strategy_candidates(lane, direct_zero_report_metadata);
    let zero_output_strategy_ready = zero_output_strategies.iter().any(|strategy| strategy.ready);
    let ready_for_zero_torque = passive.success
        && passive_audit_passed
        && status_receipts_no_output
        && zero_output_strategy_ready;
    let ready_for_ffb = ready_for_zero_torque
        && zero.success
        && zero_audit_passed
        && pre_output_bounded_ffb_prerequisite_gates_passed(&smoke_ready);
    let native_control_blocking_items = pre_output_native_control_blocking_items(
        &zero,
        &openracing_control,
        zero_audit_passed,
        openracing_control_audit_passed,
    );
    let ready_for_native_control = native_control_blocking_items.is_empty();
    let external_compatibility_blocking_items =
        pre_output_external_compatibility_blocking_items(&smoke_ready, smoke_ready_audit_passed);
    let ready_for_external_compatibility = external_compatibility_blocking_items.is_empty();

    let blocking_items = pre_output_zero_blocking_items(
        &passive,
        passive_audit_passed,
        status_receipts_no_output,
        zero_output_strategy_ready,
    );
    let ffb_blocking_items = pre_output_ffb_blocking_items(&zero, &smoke_ready, zero_audit_passed);
    let passed_items = pre_output_passed_items(
        &passive,
        PreOutputPassedItemState {
            role_evidence_complete,
            passive_audit_passed,
            status_receipts_no_output,
            zero_output_strategy_ready,
            ready_for_zero_torque,
            ready_for_ffb,
            ready_for_native_control,
            ready_for_external_compatibility,
            native_actuator_response_proven,
            native_visible_motion_proven,
        },
    );

    PreOutputReadinessReceipt {
        success: ready_for_zero_torque,
        command: "wheelctl moza pre-output-readiness",
        generated_at_utc: now_utc(),
        lane: lane.display().to_string(),
        stage: "pre_output_readiness",
        ready_for_zero_torque,
        ready_for_ffb,
        ready_for_native_control,
        ready_for_external_compatibility,
        native_actuator_response_proven,
        native_visible_motion_proven,
        input_semantic_mapping_complete,
        input_role_semantics,
        pit_house_compatibility,
        simulator_compatibility,
        blocking_items,
        ffb_blocking_items,
        native_control_blocking_items,
        external_compatibility_blocking_items,
        native_actuator_response_gate,
        native_visible_motion_gate,
        zero_output_strategies,
        passed_items,
        status_receipts,
        passive_verification: pre_output_verification_summary(&passive),
        zero_verification: pre_output_verification_summary(&zero),
        openracing_control_verification: pre_output_verification_summary(&openracing_control),
        smoke_ready_verification: pre_output_verification_summary(&smoke_ready),
        passive_audit_passed,
        zero_audit_passed,
        openracing_control_audit_passed,
        smoke_ready_audit_passed,
        no_hid_device_opened: true,
        no_ffb_writes: true,
        no_output_reports: true,
        no_feature_reports: true,
        no_serial_config_commands: true,
        no_firmware_or_dfu_commands: true,
        hard_forbidden_until_ready: vec![
            "ffb",
            "direct_mode",
            "nonzero_torque",
            "output_reports",
            "feature_reports",
            "serial_config",
            "firmware_dfu",
        ],
        notes: vec![
            "pre-output-readiness reads existing lane receipts only; it opens no HID device and sends no reports".to_string(),
            "ready_for_zero_torque is the first output-adjacent gate and still does not permit nonzero torque or FFB".to_string(),
            "ready_for_native_control is the OpenRacing-owned movement path and does not require SimHub, Pit House, or direct report 0x20".to_string(),
            "native_actuator_response_proven means bounded native PIDFF writes produced measured steering response above the response noise floor; it does not claim operator-visible motion".to_string(),
            "native_visible_motion_proven remains a stricter native claim and is false until an intentionally reviewed visible-motion profile passes".to_string(),
            "ready_for_external_compatibility tracks optional adapter/vendor-app surfaces such as simulator telemetry bridges and Pit House coexistence; it is not required for native control".to_string(),
            "ready_for_ffb is the legacy bounded simulator FFB preflight; keep it separate from native-control and release-readiness claims".to_string(),
            "input_role_semantics is diagnostic topology context; generic_aux mappings remain valid passive evidence but are not full role-specific semantic proof".to_string(),
        ],
    }
}

struct PreOutputPassedItemState {
    role_evidence_complete: bool,
    passive_audit_passed: bool,
    status_receipts_no_output: bool,
    zero_output_strategy_ready: bool,
    ready_for_zero_torque: bool,
    ready_for_ffb: bool,
    ready_for_native_control: bool,
    ready_for_external_compatibility: bool,
    native_actuator_response_proven: bool,
    native_visible_motion_proven: bool,
}

fn pre_output_passed_items(
    passive: &PreOutputVerificationReceipt,
    state: PreOutputPassedItemState,
) -> Vec<String> {
    let mut passed = Vec::new();
    if pre_output_gate_passed(passive, "moza_r5_observed") {
        passed.push("r5_endpoint_observed".to_string());
    }
    if pre_output_gate_passed(passive, "moza_topology_observed") {
        passed.push("topology_endpoint_observed".to_string());
    }
    if state.role_evidence_complete {
        passed.push("role_evidence_complete".to_string());
    }
    if pre_output_gate_passed(passive, "passive_captures_parse") {
        passed.push("passive_captures_parse".to_string());
    }
    if pre_output_gate_passed(passive, "parser_fixture_validation") {
        passed.push("parser_fixture_validation".to_string());
    }
    if pre_output_gate_passed(passive, "descriptor_metadata") {
        passed.push("descriptor_metadata".to_string());
    }
    if pre_output_gate_passed(passive, "fixture_promotion") {
        passed.push("fixture_promotion".to_string());
    }
    if state.status_receipts_no_output {
        passed.push("status_receipts_no_output".to_string());
        passed.push("support_bundle_no_output".to_string());
    }
    if state.zero_output_strategy_ready {
        passed.push("zero_output_strategy_ready".to_string());
    }
    if passive.success {
        passed.push("passive_verification".to_string());
    }
    if state.passive_audit_passed {
        passed.push("passive_audit".to_string());
    }
    if state.ready_for_zero_torque {
        passed.push("ready_for_zero_torque".to_string());
    }
    if state.ready_for_ffb {
        passed.push("ready_for_ffb".to_string());
    }
    if state.ready_for_native_control {
        passed.push("ready_for_native_control".to_string());
    }
    if state.native_actuator_response_proven {
        passed.push("native_actuator_response_proven".to_string());
    }
    if state.native_visible_motion_proven {
        passed.push("native_visible_motion_proven".to_string());
    }
    if state.ready_for_external_compatibility {
        passed.push("ready_for_external_compatibility".to_string());
    }
    passed
}

fn pre_output_zero_blocking_items(
    passive: &PreOutputVerificationReceipt,
    passive_audit_passed: bool,
    status_receipts_no_output: bool,
    zero_output_strategy_ready: bool,
) -> Vec<String> {
    let mut blockers = Vec::new();
    append_verification_blocking_items(&mut blockers, passive);
    if !passive_audit_passed {
        blockers.push("passive_audit".to_string());
    }
    if !status_receipts_no_output {
        blockers.push("status_receipts_no_output".to_string());
    }
    if !zero_output_strategy_ready {
        blockers.push("zero_output_strategy_ready".to_string());
    }
    blockers.sort();
    blockers.dedup();
    blockers
}

fn zero_output_direct_report_metadata_trusted(lane: &Path) -> bool {
    validate_zero_output_direct_report_metadata(lane).is_ok()
}

fn validate_zero_output_strategy_metadata(
    lane: &Path,
    strategy: MozaZeroOutputStrategy,
) -> Result<()> {
    match strategy {
        MozaZeroOutputStrategy::DirectReport0x20 => {
            validate_zero_output_direct_report_metadata(lane)
        }
        MozaZeroOutputStrategy::PidffStopAll => {
            validate_zero_output_pidff_stop_all_report_metadata(lane)
        }
    }
}

fn validate_zero_output_direct_report_metadata(lane: &Path) -> Result<()> {
    let pid = lane_manifest_r5_pid(lane).ok_or_else(|| {
        anyhow!("zero-output writes require a lane manifest with a supported R5 wheelbase PID")
    })?;
    let target_product_id = hex_u16(pid);
    let descriptor_path = lane.join("descriptor.json");
    validate_direct_mode_gate_for_torque_test(Some(&descriptor_path), &target_product_id, false)
        .map(|_| ())
        .with_context(|| {
            format!(
                "zero-output writes require trusted descriptor-derived direct output report metadata for PID {} in '{}'",
                target_product_id,
                descriptor_path.display()
            )
        })
}

fn validate_zero_output_pidff_stop_all_report_metadata(lane: &Path) -> Result<()> {
    let pid = lane_manifest_r5_pid(lane).ok_or_else(|| {
        anyhow!("PIDFF stop-all zero-output writes require a lane manifest with a supported R5 wheelbase PID")
    })?;
    let target_product_id = hex_u16(pid);
    let descriptor_path = lane.join("descriptor.json");
    let receipt = read_json_path(&descriptor_path)?;
    let Some(devices) = receipt.get("devices").and_then(Value::as_array) else {
        return Err(anyhow!(
            "descriptor receipt '{}' is missing devices[]",
            descriptor_path.display()
        ));
    };

    if devices.iter().any(|device| {
        is_r5_device_value(device)
            && json_string(device, "product_id") == Some(target_product_id.as_str())
            && r5_descriptor_metadata_trusted(device)
            && json_report_record_contains(
                device,
                "output_reports",
                PIDFF_DEVICE_CONTROL_REPORT_ID,
                PIDFF_DEVICE_CONTROL_REPORT_LEN,
            )
    }) {
        Ok(())
    } else {
        Err(anyhow!(
            "PIDFF stop-all zero-output writes require trusted descriptor-derived Device Control output report metadata for PID {} in '{}'",
            target_product_id,
            descriptor_path.display()
        ))
    }
}

fn zero_output_strategy_candidates(
    lane: &Path,
    direct_zero_report_metadata: bool,
) -> Vec<ZeroOutputStrategyCandidate> {
    let descriptor_metadata_trusted =
        zero_output_r5_descriptor_metadata_trusted(lane).unwrap_or(false);
    let direct_report_observed = zero_output_direct_report_observed(lane).unwrap_or(false);
    let pidff_stop_all_report_observed =
        zero_output_pidff_stop_all_report_observed(lane).unwrap_or(false);

    vec![
        zero_output_direct_strategy_candidate(
            direct_report_observed,
            descriptor_metadata_trusted,
            direct_zero_report_metadata,
        ),
        zero_output_pidff_stop_all_strategy_candidate(
            pidff_stop_all_report_observed,
            descriptor_metadata_trusted,
        ),
    ]
}

fn zero_output_direct_strategy_candidate(
    descriptor_report_observed: bool,
    descriptor_metadata_trusted: bool,
    ready: bool,
) -> ZeroOutputStrategyCandidate {
    let mut blocking_items = Vec::new();
    if !descriptor_metadata_trusted {
        blocking_items.push("direct_zero_descriptor_trust");
    }
    if !descriptor_report_observed {
        blocking_items.push("direct_zero_report_metadata");
    }

    ZeroOutputStrategyCandidate {
        name: "direct_report_0x20",
        description: "Moza proprietary direct zero-torque report",
        implemented: true,
        descriptor_report_observed,
        descriptor_metadata_trusted,
        ready,
        required_output_reports: vec![HidReportRecord {
            report_id: DIRECT_TORQUE_REPORT_ID.to_string(),
            report_len: REPORT_LEN,
        }],
        blocking_items,
        notes: vec![
            "implemented by wheelctl moza zero".to_string(),
            "requires descriptor-derived output report 0x20 with the expected 8-byte shape"
                .to_string(),
        ],
    }
}

fn zero_output_pidff_stop_all_strategy_candidate(
    descriptor_report_observed: bool,
    descriptor_metadata_trusted: bool,
) -> ZeroOutputStrategyCandidate {
    let mut blocking_items = Vec::new();
    if !descriptor_report_observed {
        blocking_items.push("pidff_device_control_report_metadata");
    }
    if !descriptor_metadata_trusted {
        blocking_items.push("pidff_device_control_descriptor_trust");
    }
    let ready = descriptor_report_observed && descriptor_metadata_trusted;

    ZeroOutputStrategyCandidate {
        name: "pidff_device_control_stop_all",
        description: "standard HID PIDFF Device Control Stop All Effects zero-output candidate",
        implemented: true,
        descriptor_report_observed,
        descriptor_metadata_trusted,
        ready,
        required_output_reports: vec![HidReportRecord {
            report_id: PIDFF_DEVICE_CONTROL_REPORT_ID.to_string(),
            report_len: PIDFF_DEVICE_CONTROL_REPORT_LEN,
        }],
        blocking_items,
        notes: vec![
            "implemented by wheelctl moza zero --strategy pidff-stop-all".to_string(),
            "the candidate report carries a stop-all-effects command, not a force magnitude"
                .to_string(),
        ],
    }
}

