fn pre_output_ffb_blocking_items(
    zero: &PreOutputVerificationReceipt,
    smoke_ready: &PreOutputVerificationReceipt,
    zero_audit_passed: bool,
) -> Vec<String> {
    let mut blockers = Vec::new();
    append_verification_blocking_items(&mut blockers, zero);
    if !zero.success || !zero_audit_passed {
        if !zero_audit_passed {
            blockers.push("zero_audit".to_string());
        }
        blockers.sort();
        blockers.dedup();
        return blockers;
    }
    if smoke_ready.gates.is_empty() {
        append_verification_blocking_items(&mut blockers, smoke_ready);
        blockers.sort();
        blockers.dedup();
        return blockers;
    }
    for gate in [
        "init_off_handshake",
        "init_standard_handshake",
        "service_status_receipts",
        "low_torque_bounded",
        "native_actuator_visible_smoke",
        "simulator_telemetry",
    ] {
        if !pre_output_gate_passed(smoke_ready, gate) {
            blockers.push(gate.to_string());
        }
    }
    blockers.sort();
    blockers.dedup();
    blockers
}

fn pre_output_native_control_blocking_items(
    zero: &PreOutputVerificationReceipt,
    openracing_control: &PreOutputVerificationReceipt,
    zero_audit_passed: bool,
    openracing_control_audit_passed: bool,
) -> Vec<String> {
    let mut blockers = Vec::new();
    append_verification_blocking_items(&mut blockers, zero);
    if !zero.success || !zero_audit_passed {
        if !zero_audit_passed {
            blockers.push("zero_audit".to_string());
        }
        blockers.sort();
        blockers.dedup();
        return blockers;
    }
    if openracing_control.gates.is_empty() {
        append_verification_blocking_items(&mut blockers, openracing_control);
        blockers.sort();
        blockers.dedup();
        return blockers;
    }
    for gate in [
        "init_off_handshake",
        "init_standard_handshake",
        "service_status_receipts",
        "low_torque_bounded",
        "steering_angle_stream_proof",
        "native_actuator_profile_smoke",
    ] {
        if !pre_output_gate_passed(openracing_control, gate) {
            blockers.push(gate.to_string());
        }
    }
    if blockers.is_empty() && !openracing_control.success {
        append_verification_blocking_items(&mut blockers, openracing_control);
    }
    if blockers.is_empty() && !openracing_control_audit_passed {
        blockers.push("openracing_control_audit".to_string());
    }
    blockers.sort();
    blockers.dedup();
    blockers
}

fn pre_output_external_compatibility_blocking_items(
    smoke_ready: &PreOutputVerificationReceipt,
    smoke_ready_audit_passed: bool,
) -> Vec<String> {
    let mut blockers = Vec::new();
    if smoke_ready.gates.is_empty() {
        append_verification_blocking_items(&mut blockers, smoke_ready);
        blockers.sort();
        blockers.dedup();
        return blockers;
    }
    for gate in [
        "simulator_telemetry",
        "simulator_ffb_bounded",
        "pit_house_coexistence",
    ] {
        if !pre_output_gate_passed(smoke_ready, gate) {
            blockers.push(gate.to_string());
        }
    }
    if blockers.is_empty() && !smoke_ready_audit_passed {
        blockers.push("smoke_ready_audit".to_string());
    }
    blockers.sort();
    blockers.dedup();
    blockers
}

fn append_verification_blocking_items(
    blockers: &mut Vec<String>,
    receipt: &PreOutputVerificationReceipt,
) {
    blockers.extend(
        receipt
            .artifacts
            .iter()
            .filter(|artifact| artifact.status != "pass")
            .map(|artifact| artifact.path.clone()),
    );
    blockers.extend(
        receipt
            .gates
            .iter()
            .filter(|gate| gate.status == "fail")
            .map(|gate| gate.name.to_string()),
    );
}

fn pre_output_bounded_ffb_prerequisite_gates_passed(
    receipt: &PreOutputVerificationReceipt,
) -> bool {
    pre_output_zero_stage_gates_passed(receipt)
        && pre_output_gate_checks_passed(
            receipt,
            &[
                "init_off_handshake",
                "init_standard_handshake",
                "service_status_receipts",
                "low_torque_bounded",
                "native_actuator_visible_smoke",
                "simulator_telemetry",
            ],
        )
}

fn pre_output_zero_stage_gates_passed(receipt: &PreOutputVerificationReceipt) -> bool {
    pre_output_passive_stage_gates_passed(receipt)
        && pre_output_gate_checks_passed(
            receipt,
            &[
                "zero_torque_real_hardware",
                "watchdog_zero_output",
                "disconnect_final_zero",
            ],
        )
}

fn pre_output_passive_stage_gates_passed(receipt: &PreOutputVerificationReceipt) -> bool {
    pre_output_gate_checks_passed(
        receipt,
        &[
            "lane_directory",
            "manifest_no_overclaim",
            "manifest_r5_pid_consistency",
            "moza_r5_observed",
            "moza_topology_observed",
            "descriptor_metadata",
            "passive_receipts_successful",
            "passive_receipts_no_ffb_writes",
            "passive_captures_parse",
            "parser_fixture_validation",
            "fixture_promotion",
        ],
    )
}

fn pre_output_gate_checks_passed(receipt: &PreOutputVerificationReceipt, names: &[&str]) -> bool {
    names
        .iter()
        .all(|name| pre_output_gate_passed(receipt, name))
}

fn pre_output_gate_passed(receipt: &PreOutputVerificationReceipt, name: &str) -> bool {
    receipt
        .gates
        .iter()
        .any(|gate| gate.name == name && gate.status == "pass")
}

fn required_role_evidence_complete(receipt: &PreOutputVerificationReceipt) -> bool {
    !receipt.role_evidence.is_empty()
        && receipt
            .role_evidence
            .iter()
            .filter(|role| role.required)
            .all(|role| role.parser_visible && role.missing_requirements.is_empty())
}

fn pre_output_stored_verification_receipt(
    lane: &Path,
    stage: MozaBundleStage,
) -> PreOutputVerificationReceipt {
    let relative_path = verification_receipt_path(stage);
    let receipt = match read_json_value(lane, relative_path) {
        Ok(receipt) => receipt,
        Err(e) => {
            return PreOutputVerificationReceipt::missing(
                stage,
                relative_path,
                format!("failed to read {relative_path}: {e}"),
            );
        }
    };

    if !stored_verification_identity_safe(lane, stage, &receipt) {
        return PreOutputVerificationReceipt::invalid(
            stage,
            relative_path,
            format!("{relative_path} is not a trusted observe-only verify-bundle receipt"),
        );
    }

    PreOutputVerificationReceipt {
        success: json_bool(&receipt, "success") == Some(true)
            && json_u64(&receipt, "missing_artifacts") == Some(0)
            && json_u64(&receipt, "invalid_artifacts") == Some(0)
            && json_u64(&receipt, "failed_gates") == Some(0),
        requested_stage: json_string(&receipt, "requested_stage")
            .unwrap_or(stage_label(stage))
            .to_string(),
        missing_artifacts: json_u64(&receipt, "missing_artifacts")
            .map(|value| value as usize)
            .unwrap_or_else(|| pre_output_artifact_status_count(&receipt, "missing")),
        invalid_artifacts: json_u64(&receipt, "invalid_artifacts")
            .map(|value| value as usize)
            .unwrap_or_else(|| pre_output_artifact_status_count(&receipt, "invalid")),
        failed_gates: json_u64(&receipt, "failed_gates")
            .map(|value| value as usize)
            .unwrap_or_else(|| pre_output_gate_status_count(&receipt, "fail")),
        artifacts: pre_output_artifacts_from_receipt(&receipt),
        gates: pre_output_gates_from_receipt(&receipt),
        role_evidence: pre_output_role_evidence_from_receipt(&receipt),
    }
}

fn pre_output_artifact_status_count(receipt: &Value, status: &str) -> usize {
    receipt
        .get("artifacts")
        .and_then(Value::as_array)
        .map(|artifacts| {
            artifacts
                .iter()
                .filter(|artifact| json_string(artifact, "status") == Some(status))
                .count()
        })
        .unwrap_or_default()
}

fn pre_output_gate_status_count(receipt: &Value, status: &str) -> usize {
    receipt
        .get("gates")
        .and_then(Value::as_array)
        .map(|gates| {
            gates
                .iter()
                .filter(|gate| json_string(gate, "status") == Some(status))
                .count()
        })
        .unwrap_or_default()
}

fn pre_output_artifacts_from_receipt(receipt: &Value) -> Vec<PreOutputVerificationArtifact> {
    receipt
        .get("artifacts")
        .and_then(Value::as_array)
        .map(|artifacts| {
            artifacts
                .iter()
                .map(|artifact| PreOutputVerificationArtifact {
                    path: json_string(artifact, "path")
                        .unwrap_or("<missing-path>")
                        .to_string(),
                    status: json_string(artifact, "status")
                        .unwrap_or("invalid")
                        .to_string(),
                })
                .collect()
        })
        .unwrap_or_default()
}

fn pre_output_gates_from_receipt(receipt: &Value) -> Vec<PreOutputVerificationGate> {
    receipt
        .get("gates")
        .and_then(Value::as_array)
        .map(|gates| {
            gates
                .iter()
                .map(|gate| PreOutputVerificationGate {
                    name: json_string(gate, "name")
                        .unwrap_or("<missing-name>")
                        .to_string(),
                    status: json_string(gate, "status").unwrap_or("fail").to_string(),
                })
                .collect()
        })
        .unwrap_or_default()
}

fn pre_output_role_evidence_from_receipt(receipt: &Value) -> Vec<PreOutputRoleEvidence> {
    receipt
        .get("role_evidence")
        .and_then(Value::as_array)
        .map(|roles| {
            roles
                .iter()
                .map(|role| PreOutputRoleEvidence {
                    required: json_bool(role, "required").unwrap_or(false),
                    parser_visible: json_bool(role, "parser_visible").unwrap_or(false),
                    missing_requirements: role
                        .get("missing_requirements")
                        .and_then(Value::as_array)
                        .map(|requirements| {
                            requirements
                                .iter()
                                .filter_map(Value::as_str)
                                .map(str::to_string)
                                .collect()
                        })
                        .unwrap_or_default(),
                })
                .collect()
        })
        .unwrap_or_default()
}

fn pre_output_verification_summary(receipt: &PreOutputVerificationReceipt) -> Value {
    let missing_artifacts: Vec<_> = receipt
        .artifacts
        .iter()
        .filter(|artifact| artifact.status == "missing")
        .map(|artifact| artifact.path.clone())
        .collect();
    let invalid_artifacts: Vec<_> = receipt
        .artifacts
        .iter()
        .filter(|artifact| artifact.status == "invalid")
        .map(|artifact| artifact.path.clone())
        .collect();
    let failed_gates: Vec<_> = receipt
        .gates
        .iter()
        .filter(|gate| gate.status == "fail")
        .map(|gate| gate.name.clone())
        .collect();

    serde_json::json!({
        "success": receipt.success,
        "requested_stage": receipt.requested_stage,
        "missing_artifacts": receipt.missing_artifacts,
        "invalid_artifacts": receipt.invalid_artifacts,
        "failed_gates": receipt.failed_gates,
        "missing_artifact_paths": missing_artifacts,
        "invalid_artifact_paths": invalid_artifacts,
        "failed_gate_names": failed_gates
    })
}

fn pre_output_status_receipt_checks(lane: &Path) -> Vec<PreOutputReadinessCheck> {
    [
        ("moza_status", "moza-status.json", "wheelctl moza status"),
        (
            "device_status",
            "device-status.json",
            "wheelctl device status",
        ),
        (
            "support_bundle",
            "support-bundle.json",
            "wheelctl support-bundle",
        ),
    ]
    .into_iter()
    .map(|(name, path, command)| pre_output_status_receipt_check(lane, name, path, command))
    .collect()
}

fn pre_output_status_receipt_check(
    lane: &Path,
    name: &'static str,
    path: &'static str,
    command: &'static str,
) -> PreOutputReadinessCheck {
    let receipt = match read_json_value(lane, path) {
        Ok(value) => value,
        Err(e) => {
            return PreOutputReadinessCheck::fail(name, format!("{path}: {e}"));
        }
    };

    let command_ok = json_string(&receipt, "command") == Some(command);
    let no_output = receipt_observe_only_no_output_flags_ok(&receipt);
    let lane_ok = match path {
        "moza-status.json" => lane_path_value_matches(lane, json_string(&receipt, "lane")),
        "device-status.json" => lane_path_value_matches(lane, json_string(&receipt, "moza_lane")),
        "support-bundle.json" => receipt
            .get("moza_lane")
            .map(|status| lane_path_value_matches(lane, json_string(status, "lane")))
            .unwrap_or(false),
        _ => false,
    };
    if command_ok && lane_ok && no_output {
        PreOutputReadinessCheck::pass(
            name,
            format!("{path} is observe-only and bound to {}", lane.display()),
        )
    } else {
        PreOutputReadinessCheck::fail(
            name,
            format!("command_ok={command_ok}, lane_ok={lane_ok}, no_output={no_output}"),
        )
    }
}

fn receipt_observe_only_no_output_flags_ok(receipt: &Value) -> bool {
    json_bool(receipt, "success") == Some(true)
        && json_bool(receipt, "no_hid_device_opened") == Some(true)
        && json_bool(receipt, "no_ffb_writes") == Some(true)
        && json_bool(receipt, "no_output_reports") == Some(true)
        && json_bool(receipt, "no_feature_reports") == Some(true)
        && no_out_of_scope_device_commands(receipt)
}

fn next_commands_for_bundle_stage(
    lane: &Path,
    stage: MozaBundleStage,
    artifact_checks: &[BundleArtifactCheck],
    gates: &[BundleGateCheck],
) -> Vec<String> {
    let has_blockers = artifact_checks.iter().any(|check| check.status != "pass")
        || gates.iter().any(|gate| gate.status == "fail");
    if !has_blockers {
        return Vec::new();
    }

    let lane = next_command_lane(lane);
    let wheelbase_pid = lane_manifest_r5_pid(&lane)
        .map(hex_u16)
        .unwrap_or_else(|| "0x0014".to_string());
    let mut commands = Vec::new();
    push_passive_next_commands(&lane, &wheelbase_pid, artifact_checks, gates, &mut commands);

    let passive_ready = passive_stage_gates_passed(gates);
    let zero_ready = zero_stage_gates_passed(gates);

    if stage_rank(stage) >= stage_rank(MozaBundleStage::Zero) && passive_ready && !zero_ready {
        push_zero_next_commands(&lane, gates, &mut commands);
    }

    let openracing_control_ready = openracing_control_stage_gates_passed(gates);

    if stage_rank(stage) >= stage_rank(MozaBundleStage::OpenRacingControlReady)
        && zero_ready
        && !openracing_control_ready
    {
        push_openracing_control_next_commands(&lane, gates, &mut commands);
    }

    let native_response_ready = native_response_stage_gates_passed(gates);
    if stage_rank(stage) >= stage_rank(MozaBundleStage::NativeResponseReady)
        && openracing_control_ready
        && !native_response_ready
    {
        push_native_response_next_commands(&lane, gates, &mut commands);
    }

    let native_visible_ready = native_visible_stage_gates_passed(gates);
    if stage_rank(stage) >= stage_rank(MozaBundleStage::NativeVisibleReady)
        && native_response_ready
        && !native_visible_ready
    {
        push_native_visible_next_commands(&lane, gates, &mut commands);
    }

    if stage_rank(stage) >= stage_rank(MozaBundleStage::SmokeReady) && native_visible_ready {
        push_external_smoke_ready_next_commands(&lane, gates, &mut commands);
    }

    commands
}

fn blocked_safe_followups_for_bundle_stage(
    lane: &Path,
    stage: MozaBundleStage,
    gates: &[BundleGateCheck],
) -> Vec<BundleBlockedSafeFollowup> {
    if stage != MozaBundleStage::SmokeReady
        || bundle_gate_check_passed(gates, "native_actuator_visible_smoke")
        || failed_real_native_visible_smoke_receipt(lane).is_none()
    {
        return Vec::new();
    }

    let mut followups = Vec::new();
    match pit_house_availability_state(lane) {
        PitHouseAvailabilityState::MissingOrInvalid => {
            let mut commands = Vec::new();
            push_pit_house_availability_next_command(lane, &mut commands, false);
            followups.push(BundleBlockedSafeFollowup {
                name: "pit_house_availability_check",
                reason: "Visible-motion remains blocked, and Pit House open-state evidence should start with a no-output install/process availability receipt before generating case-specific observations.".to_string(),
                hardware_output_enabled: false,
                no_hid_device_opened: true,
                no_ffb_writes: true,
                commands,
                notes: vec![
                    "This availability receipt is not Pit House coexistence proof.".to_string(),
                    "If Pit House is absent, leave smoke-ready blocked instead of fabricating open-state observations.".to_string(),
                    "If Pit House is available, rerun verify-bundle and follow the generated case-specific observation commands.".to_string(),
                ],
            });
        }
        PitHouseAvailabilityState::Unavailable => {
            let mut commands = Vec::new();
            push_pit_house_availability_next_command(lane, &mut commands, true);
            followups.push(BundleBlockedSafeFollowup {
                name: "pit_house_unavailable_recorded",
                reason: "Visible-motion remains blocked, and the lane records that Pit House is not installed or running on this host. Smoke-ready remains blocked rather than fabricating coexistence evidence.".to_string(),
                hardware_output_enabled: false,
                no_hid_device_opened: true,
                no_ffb_writes: true,
                commands,
                notes: vec![
                    "Refresh this availability receipt after installing or launching Pit House.".to_string(),
                    "Do not run pit-house-observation open-state cases until the availability receipt shows Pit House is present.".to_string(),
                    "Do not run pit-house-proof or claim full coexistence from an unavailable receipt.".to_string(),
                ],
            });
        }
        PitHouseAvailabilityState::Available => {
            let mut pit_house_commands = Vec::new();
            push_pit_house_pre_mode_change_safe_commands(lane, &mut pit_house_commands);
            if !pit_house_commands.is_empty() {
                followups.push(BundleBlockedSafeFollowup {
                    name: "pit_house_pre_mode_change_evidence",
                    reason: "Visible-motion remains blocked, but Pit House closed/open-standard/open-direct/firmware-page observations and case receipts are no-output evidence work. Mode-change and parent coexistence proof remain deferred until simulator FFB exists.".to_string(),
                    hardware_output_enabled: false,
                    no_hid_device_opened: true,
                    no_ffb_writes: true,
                    commands: pit_house_commands,
                    notes: vec![
                        "Run pit-house-evidence first when the matching process/window snapshot artifact is missing; generated commands use --require-match so an unavailable Pit House app fails without writing stale open-case evidence.".to_string(),
                        "pit-house-observation rejects wheelctl-generated snapshots that do not match the requested Pit House case.".to_string(),
                        "Do not run pit-house-proof or claim full coexistence from these subcases alone.".to_string(),
                    ],
                });
            }
        }
    }

    if !bundle_gate_check_passed(gates, "simulator_telemetry") {
        let lane_arg = command_arg(&lane.display().to_string());
        let session_id = simulator_telemetry_session_id(lane);
        followups.push(BundleBlockedSafeFollowup {
            name: "simulator_telemetry_only",
            reason: "Visible-motion remains blocked, but simulator telemetry recording is no-output evidence and can be prepared when a real SimHub/simulator source is available.".to_string(),
            hardware_output_enabled: false,
            no_hid_device_opened: true,
            no_ffb_writes: true,
            commands: vec![
                format!(
                    "wheelctl telemetry record --game simhub-bridge --telemetry-source simhub_bridge --live-simhub --port 5555 --out {} --session-id {} --duration-ms 30000",
                    lane_path_arg(lane, "simulator-telemetry-recording.jsonl"),
                    command_arg(&session_id)
                ),
                format!(
                    "wheelctl moza simulator-telemetry-proof --lane {lane_arg} --game simhub-bridge --telemetry-source simhub_bridge --recorder-artifact simulator-telemetry-recording.jsonl --duration-ms 30000 --json-out {}",
                    lane_path_arg(lane, "simulator-telemetry-proof.json")
                ),
            ],
            notes: vec![
                "Use only with a real simulator or SimHub bridge source; fixtures and placeholders do not satisfy the gate.".to_string(),
                "Do not start wheeld or simulator-ffb-smoke from this blocked follow-up.".to_string(),
            ],
        });
    }

    followups
}

enum PitHouseAvailabilityState {
    MissingOrInvalid,
    Unavailable,
    Available,
}

fn pit_house_availability_state(lane: &Path) -> PitHouseAvailabilityState {
    let Ok(receipt) = read_json_value(lane, "pit-house-availability.json") else {
        return PitHouseAvailabilityState::MissingOrInvalid;
    };
    if !pit_house_availability_receipt_is_safe(&receipt) {
        return PitHouseAvailabilityState::MissingOrInvalid;
    }
    if json_bool(&receipt, "pit_house_available") == Some(true) {
        PitHouseAvailabilityState::Available
    } else {
        PitHouseAvailabilityState::Unavailable
    }
}

fn pit_house_availability_receipt_is_safe(receipt: &Value) -> bool {
    json_bool(receipt, "success") == Some(true)
        && json_string(receipt, "command") == Some("wheelctl moza pit-house-availability")
        && json_string(receipt, "evidence_status") == Some("non_claiming_external_app_availability")
        && json_bool(receipt, "pit_house_coexistence_proven") == Some(false)
        && json_bool(receipt, "satisfies_pit_house_coexistence") == Some(false)
        && json_bool(receipt, "no_hid_device_opened") == Some(true)
        && json_bool(receipt, "no_ffb_writes") == Some(true)
        && no_out_of_scope_device_commands(receipt)
}

fn push_pit_house_availability_next_command(
    lane: &Path,
    commands: &mut Vec<String>,
    overwrite: bool,
) {
    let mut command = format!(
        "wheelctl moza pit-house-availability --operator Steven --evidence {} --json-out {}",
        command_arg("Pit House install/process/window availability snapshot."),
        lane_path_arg(lane, "pit-house-availability.json")
    );
    if overwrite {
        command.push_str(" --overwrite");
    }
    commands.push(command);
}

fn push_pit_house_pre_mode_change_safe_commands(lane: &Path, commands: &mut Vec<String>) {
    for (case, case_id, evidence_artifact, artifact, evidence) in [
        (
            "closed",
            "pit_house_closed",
            "pit-house-evidence-closed.json",
            "pit-house-observation-closed.json",
            "Pit House closed; OpenRacing staged handshake observed",
        ),
        (
            "open-standard",
            "pit_house_open_idle_standard",
            "pit-house-evidence-open-standard.json",
            "pit-house-observation-open-standard.json",
            "Pit House open and idle; standard mode observed",
        ),
        (
            "open-direct",
            "pit_house_open_direct",
            "pit-house-evidence-open-direct.json",
            "pit-house-observation-open-direct.json",
            "Pit House open during direct request; OpenRacing warned or blocked",
        ),
        (
            "firmware-page",
            "pit_house_firmware_update_page_open",
            "pit-house-evidence-firmware-page.json",
            "pit-house-observation-firmware-page.json",
            "Pit House firmware/update page open; high-risk tests refused",
        ),
    ] {
        if pit_house_observation_receipt_is_safe(lane, artifact, case_id) {
            continue;
        }
        push_pit_house_observation_next_command(
            lane,
            commands,
            case,
            evidence_artifact,
            artifact,
            evidence,
        );
    }

    for (case, case_id, observation, artifact, evidence) in [
        (
            "closed",
            "pit_house_closed",
            "pit-house-observation-closed.json",
            "pit-house-closed.json",
            "Pit House closed case observed",
        ),
        (
            "open-standard",
            "pit_house_open_idle_standard",
            "pit-house-observation-open-standard.json",
            "pit-house-open-standard.json",
            "Pit House open standard case observed",
        ),
        (
            "open-direct",
            "pit_house_open_direct",
            "pit-house-observation-open-direct.json",
            "pit-house-direct-blocked.json",
            "Pit House open direct request warned or blocked",
        ),
        (
            "firmware-page",
            "pit_house_firmware_update_page_open",
            "pit-house-observation-firmware-page.json",
            "pit-house-firmware-page.json",
            "Pit House firmware/update page refusal observed",
        ),
    ] {
        if pit_house_case_receipt_is_safe(lane, artifact, case_id) {
            continue;
        }
        push_pit_house_case_next_command(lane, commands, case, observation, artifact, evidence);
    }
}

fn next_command_lane(lane: &Path) -> PathBuf {
    if is_moza_lane_root(lane) {
        lane.join("YYYY-MM-DD")
    } else {
        lane.to_path_buf()
    }
}

fn is_moza_lane_root(lane: &Path) -> bool {
    lane.file_name()
        .and_then(|name| name.to_str())
        .is_some_and(|name| name.eq_ignore_ascii_case("moza-r5"))
        && lane.join("README.md").is_file()
        && lane.join("manifest.schema.json").is_file()
        && !lane.join("manifest.json").is_file()
}

fn push_passive_next_commands(
    lane: &Path,
    wheelbase_pid: &str,
    artifact_checks: &[BundleArtifactCheck],
    gates: &[BundleGateCheck],
    commands: &mut Vec<String>,
) {
    let lane_arg = command_arg(&lane.display().to_string());
    let fixture_dir = Path::new("crates/hid-moza-protocol/fixtures").join(format!(
        "moza-r5-{}",
        lane.file_name()
            .and_then(|name| name.to_str())
            .filter(|name| !name.is_empty())
            .unwrap_or("YYYY-MM-DD")
    ));
    let fixture_dir_arg = command_arg(&fixture_dir.display().to_string());
    let r5_selector = lane_manifest_r5_hid_observe_selector(lane)
        .unwrap_or_else(|| format!("0x346E:{wheelbase_pid}"));

    if bundle_artifact_needs_regeneration(artifact_checks, "manifest.json")
        || !bundle_gate_check_passed(gates, "manifest_no_overclaim")
    {
        commands.push(format!(
            "wheelctl moza init-lane --lane {lane_arg} --wheelbase-pid {wheelbase_pid} --operator Steven"
        ));
    }
    if bundle_artifacts_need_regeneration(
        artifact_checks,
        &["device-list.json", "moza-probe.json", "hid-list.json"],
    ) || !bundle_gate_check_passed(gates, "moza_r5_observed")
        || !bundle_gate_check_passed(gates, "moza_topology_observed")
    {
        commands.push(format!(
            "wheelctl device list --hid-observe-only --json-out {}",
            lane_path_arg(lane, "device-list.json")
        ));
        commands.push(format!(
            "wheelctl moza probe --json-out {}",
            lane_path_arg(lane, "moza-probe.json")
        ));
        commands.push(format!(
            "hid-capture list --vendor 0x346E --json-out {}",
            lane_path_arg(lane, "hid-list.json")
        ));
    }
    if bundle_artifact_needs_regeneration(artifact_checks, "hardware-doctor.json") {
        commands.push(format!(
            "wheelctl hardware doctor --json-out {}",
            lane_path_arg(lane, "hardware-doctor.json")
        ));
    }
    if bundle_artifact_needs_regeneration(artifact_checks, "descriptor.json")
        || !bundle_gate_check_passed(gates, "descriptor_metadata")
    {
        commands.push(format!(
            "wheelctl moza descriptor --json-out {}",
            lane_path_arg(lane, "descriptor.json")
        ));
        if usbpcap_descriptor_extractor_next_command_allowed(lane) {
            commands.push(
                "powershell -ExecutionPolicy Bypass -File scripts/extract_usbpcap_report_descriptor.ps1 -InputPcapng target/moza-r5-usbpcap-enumeration.pcapng -Output target/moza-r5-report-descriptor.txt -InterfaceNumber 2".to_string()
            );
        }
        commands.push(format!(
            "wheelctl moza descriptor --device {r5_selector} --report-descriptor-hex-file target/moza-r5-report-descriptor.txt --json-out {}",
            lane_path_arg(lane, "descriptor.json")
        ));
        commands.push(format!(
            "wheelctl moza descriptor --device {r5_selector} --report-descriptor-bin-file target/moza-r5-report-descriptor.bin --json-out {}",
            lane_path_arg(lane, "descriptor.json")
        ));
    }

    for requirement in passive_capture_requirements_for_lane(lane) {
        if bundle_artifact_needs_regeneration(artifact_checks, requirement.relative_path) {
            let (device, duration_ms) =
                passive_capture_next_command_hint(requirement.relative_path);
            commands.push(format!(
                "wheelctl moza capture-input --device {device} --duration-ms {duration_ms} --json-out {}",
                lane_path_arg(lane, requirement.relative_path)
            ));
        }
    }

    if bundle_artifact_needs_regeneration(artifact_checks, "parser-fixture-validation.json")
        || !bundle_gate_check_passed(gates, "passive_captures_parse")
        || !bundle_gate_check_passed(gates, "parser_fixture_validation")
    {
        commands.push(format!(
            "wheelctl moza analyze-lane --lane {lane_arg} --json-out target/moza-lane-analysis.json"
        ));
        commands.push(format!(
            "wheelctl moza sync-role-status --lane {lane_arg} --json-out target/moza-role-status-sync.json"
        ));
        commands.push(format!(
            "wheelctl moza sync-role-status --lane {lane_arg} --check --json-out target/moza-role-status-check.json"
        ));
        commands.push(format!(
            "wheelctl moza validate-captures --lane {lane_arg} --json-out {}",
            lane_path_arg(lane, "parser-fixture-validation.json")
        ));
    }
    if bundle_gate_check_passed(gates, "passive_captures_parse")
        && bundle_gate_check_passed(gates, "parser_fixture_validation")
        && bundle_gate_check_passed(gates, "descriptor_metadata")
        && !bundle_gate_check_passed(gates, "fixture_promotion")
    {
        commands.push(format!(
            "wheelctl moza promote-fixtures --lane {lane_arg} --fixture-dir {fixture_dir_arg} --json-out {}",
            lane_path_arg(lane, "fixture-promotion.json")
        ));
        commands.push(
            "cargo test -p racing-wheel-hid-moza-protocol promoted_capture_fixtures_replay_through_moza_parser"
                .to_string(),
        );
    }
    if !stored_verification_receipt_success(lane, MozaBundleStage::Passive) {
        commands.push(format!(
            "wheelctl moza verify-bundle --lane {lane_arg} --stage passive --json-out {}",
            lane_path_arg(lane, verification_receipt_path(MozaBundleStage::Passive))
        ));
    }
    if bundle_gate_checks_passed(
        gates,
        &[
            "lane_directory",
            "manifest_no_overclaim",
            "manifest_r5_pid_consistency",
            "moza_r5_observed",
            "moza_topology_observed",
            "descriptor_metadata",
            "passive_receipts_no_ffb_writes",
            "passive_captures_parse",
            "parser_fixture_validation",
            "fixture_promotion",
        ],
    ) {
        if !stored_manifest_promotion_receipt_success(lane, MozaBundleStage::Passive) {
            commands.push(format!(
                "wheelctl moza promote-manifest --lane {lane_arg} --stage passive --json-out {}",
                lane_path_arg(lane, promotion_receipt_path(MozaBundleStage::Passive))
            ));
        }
        if !stored_lane_audit_receipt_success(lane, MozaBundleStage::Passive) {
            commands.push(format!(
                "wheelctl moza audit-lane --lane {lane_arg} --stage passive --json-out {}",
                lane_path_arg(lane, audit_receipt_path(MozaBundleStage::Passive))
            ));
        }
    }
}

fn usbpcap_descriptor_extractor_next_command_allowed(lane: &Path) -> bool {
    let Ok(receipt) = read_json_path(&lane.join("hardware-doctor.json")) else {
        return true;
    };
    receipt
        .get("tools")
        .and_then(|tools| tools.get("usbpcap_descriptor_capture"))
        .and_then(|capture| capture.get("ready_for_usbpcap_descriptor_capture"))
        .and_then(Value::as_bool)
        != Some(false)
}

fn bundle_gate_check_passed(gates: &[BundleGateCheck], name: &str) -> bool {
    gates
        .iter()
        .any(|gate| gate.name == name && gate.status == "pass")
}

fn bundle_gate_checks_passed(gates: &[BundleGateCheck], names: &[&str]) -> bool {
    names
        .iter()
        .all(|name| bundle_gate_check_passed(gates, name))
}

fn stored_verification_receipt_success(lane: &Path, stage: MozaBundleStage) -> bool {
    let Ok(receipt) = read_json_value(lane, verification_receipt_path(stage)) else {
        return false;
    };

    json_bool(&receipt, "success") == Some(true)
        && json_string(&receipt, "command") == Some("wheelctl moza verify-bundle")
        && json_string(&receipt, "requested_stage") == Some(stage_label(stage))
        && json_u64(&receipt, "missing_artifacts") == Some(0)
        && json_u64(&receipt, "invalid_artifacts") == Some(0)
        && json_u64(&receipt, "failed_gates") == Some(0)
        && json_bool(&receipt, "no_hid_device_opened") == Some(true)
        && json_bool(&receipt, "no_ffb_writes") == Some(true)
        && no_out_of_scope_device_commands(&receipt)
}

fn stored_manifest_promotion_receipt_success(lane: &Path, stage: MozaBundleStage) -> bool {
    let Ok(receipt) = read_json_value(lane, promotion_receipt_path(stage)) else {
        return false;
    };

    let (completion_state, hardware_validated, simulator_validated) =
        manifest_promotion_values(stage);
    json_bool(&receipt, "success") == Some(true)
        && json_string(&receipt, "command") == Some("wheelctl moza promote-manifest")
        && json_string(&receipt, "stage") == Some(stage_label(stage))
        && json_string(&receipt, "completion_state") == Some(completion_state)
        && json_bool(&receipt, "hardware_validated") == Some(hardware_validated)
        && json_bool(&receipt, "simulator_validated") == Some(simulator_validated)
        && json_bool(&receipt, "high_torque_validated") == Some(false)
        && json_bool(&receipt, "release_ready") == Some(false)
        && json_bool(&receipt, "no_hid_device_opened") == Some(true)
        && json_bool(&receipt, "no_ffb_writes") == Some(true)
        && no_out_of_scope_device_commands(&receipt)
        && promotion_verification_summary_ok(receipt.get("verification_before"), stage_label(stage))
        && promotion_verification_summary_ok(receipt.get("verification_after"), stage_label(stage))
}

fn stored_lane_audit_receipt_success(lane: &Path, stage: MozaBundleStage) -> bool {
    let Ok(receipt) = read_json_value(lane, audit_receipt_path(stage)) else {
        return false;
    };

    let receipt_checks_ok = receipt
        .get("receipt_checks")
        .and_then(Value::as_array)
        .map(|checks| {
            let expected_check_count = audit_stages_through(stage).len() * 2;
            checks.len() == expected_check_count
                && checks
                    .iter()
                    .all(|check| json_string(check, "status") == Some("pass"))
        })
        .unwrap_or(false);

    json_bool(&receipt, "success") == Some(true)
        && json_string(&receipt, "command") == Some("wheelctl moza audit-lane")
        && json_string(&receipt, "requested_stage") == Some(stage_label(stage))
        && json_bool(&receipt, "live_verification_success") == Some(true)
        && json_u64(&receipt, "missing_receipts") == Some(0)
        && json_u64(&receipt, "invalid_receipts") == Some(0)
        && receipt_checks_ok
        && json_bool(&receipt, "no_hid_device_opened") == Some(true)
        && json_bool(&receipt, "no_ffb_writes") == Some(true)
        && no_out_of_scope_device_commands(&receipt)
}

fn passive_stage_gates_passed(gates: &[BundleGateCheck]) -> bool {
    bundle_gate_checks_passed(
        gates,
        &[
            "lane_directory",
            "manifest_no_overclaim",
            "manifest_r5_pid_consistency",
            "moza_r5_observed",
            "moza_topology_observed",
            "descriptor_metadata",
            "passive_receipts_successful",
            "passive_receipts_no_ffb_writes",
            "passive_captures_parse",
            "parser_fixture_validation",
            "fixture_promotion",
        ],
    )
}

fn zero_stage_gates_passed(gates: &[BundleGateCheck]) -> bool {
    passive_stage_gates_passed(gates)
        && bundle_gate_checks_passed(
            gates,
            &[
                "zero_torque_real_hardware",
                "watchdog_zero_output",
                "disconnect_final_zero",
            ],
        )
}

fn openracing_control_stage_gates_passed(gates: &[BundleGateCheck]) -> bool {
    zero_stage_gates_passed(gates)
        && bundle_gate_checks_passed(
            gates,
            &[
                "init_off_handshake",
                "init_standard_handshake",
                "service_status_receipts",
                "low_torque_bounded",
                "steering_angle_stream_proof",
                "native_actuator_profile_smoke",
            ],
        )
}

fn smoke_ready_stage_gates_passed(gates: &[BundleGateCheck]) -> bool {
    native_visible_stage_gates_passed(gates)
        && bundle_gate_checks_passed(
            gates,
            &[
                "pit_house_coexistence",
                "simulator_telemetry",
                "simulator_ffb_bounded",
            ],
        )
}

fn native_response_stage_gates_passed(gates: &[BundleGateCheck]) -> bool {
    openracing_control_stage_gates_passed(gates)
        && bundle_gate_check_passed(gates, "native_actuator_response_smoke")
}

fn native_visible_stage_gates_passed(gates: &[BundleGateCheck]) -> bool {
    native_response_stage_gates_passed(gates)
        && bundle_gate_check_passed(gates, "native_actuator_visible_smoke")
}

fn bundle_artifact_needs_regeneration(
    artifact_checks: &[BundleArtifactCheck],
    relative_path: &str,
) -> bool {
    artifact_checks
        .iter()
        .find(|check| check.path == relative_path)
        .is_none_or(|check| check.status != "pass")
}

fn bundle_artifacts_need_regeneration(
    artifact_checks: &[BundleArtifactCheck],
    relative_paths: &[&str],
) -> bool {
    relative_paths
        .iter()
        .any(|path| bundle_artifact_needs_regeneration(artifact_checks, path))
}

fn passive_capture_next_command_hint(relative_path: &str) -> (&'static str, u64) {
    match relative_path {
        "captures/r5-idle.jsonl" | "captures/r5-aggregated-idle-after-controls.jsonl" => {
            ("<r5>", 5000)
        }
        "captures/r5-throttle-only-sweep.jsonl"
        | "captures/r5-brake-only-sweep.jsonl"
        | "captures/r5-clutch-only-sweep.jsonl"
        | "captures/r5-handbrake-only-sweep.jsonl" => ("<r5>", 15000),
        "captures/srp-standalone-sweep.jsonl" => ("<srp>", 10000),
        "captures/hbp-standalone-sweep.jsonl" => ("<hbp>", 10000),
        _ => ("<r5>", 10000),
    }
}

fn push_zero_next_commands(lane: &Path, gates: &[BundleGateCheck], commands: &mut Vec<String>) {
    let lane_arg = command_arg(&lane.display().to_string());
    let r5_selector = next_command_r5_selector(lane);
    let strategy = zero_next_command_strategy(lane);
    let strategy_arg = zero_output_strategy_command_arg(strategy);
    if !bundle_gate_check_passed(gates, "zero_torque_real_hardware") {
        commands.push(format!(
            "wheelctl moza zero --device {r5_selector} --lane {lane_arg} --strategy {strategy_arg} --confirm-zero-torque --repeat 100 --hz 1000 --json-out {}",
            lane_path_arg(lane, "zero-torque-proof.json")
        ));
    }
    if !bundle_gate_check_passed(gates, "watchdog_zero_output") {
        commands.push(format!(
            "wheelctl moza watchdog-proof --device {r5_selector} --lane {lane_arg} --strategy {strategy_arg} --confirm-watchdog-test --pre-zero-count 3 --watchdog-timeout-ms 100 --json-out {}",
            lane_path_arg(lane, "watchdog-proof.json")
        ));
    }
    if !bundle_gate_check_passed(gates, "disconnect_final_zero") {
        commands.push(format!(
            "wheelctl moza disconnect-proof --device {r5_selector} --lane {lane_arg} --strategy {strategy_arg} --confirm-disconnect-test --max-duration-ms 10000 --json-out {}",
            lane_path_arg(lane, "disconnect-proof.json")
        ));
    }
    commands.push(format!(
        "wheelctl moza verify-bundle --lane {lane_arg} --stage zero --json-out {}",
        lane_path_arg(lane, verification_receipt_path(MozaBundleStage::Zero))
    ));
    if zero_stage_gates_passed(gates) {
        commands.push(format!(
            "wheelctl moza promote-manifest --lane {lane_arg} --stage zero --json-out {}",
            lane_path_arg(lane, promotion_receipt_path(MozaBundleStage::Zero))
        ));
        commands.push(format!(
            "wheelctl moza audit-lane --lane {lane_arg} --stage zero --json-out {}",
            lane_path_arg(lane, audit_receipt_path(MozaBundleStage::Zero))
        ));
    }
}

fn zero_next_command_strategy(lane: &Path) -> MozaZeroOutputStrategy {
    if let Ok(summary) = validate_zero_proof_for_zero_output(&lane.join("zero-torque-proof.json")) {
        match summary.zero_output_strategy.as_str() {
            "pidff_device_control_stop_all" => {
                return MozaZeroOutputStrategy::PidffStopAll;
            }
            "direct_report_0x20" => {
                return MozaZeroOutputStrategy::DirectReport0x20;
            }
            _ => {}
        }
    }

    if validate_zero_output_strategy_metadata(lane, MozaZeroOutputStrategy::DirectReport0x20)
        .is_ok()
    {
        MozaZeroOutputStrategy::DirectReport0x20
    } else if validate_zero_output_strategy_metadata(lane, MozaZeroOutputStrategy::PidffStopAll)
        .is_ok()
    {
        MozaZeroOutputStrategy::PidffStopAll
    } else {
        MozaZeroOutputStrategy::DirectReport0x20
    }
}

fn zero_output_strategy_command_arg(strategy: MozaZeroOutputStrategy) -> &'static str {
    match strategy {
        MozaZeroOutputStrategy::DirectReport0x20 => "direct-report0x20",
        MozaZeroOutputStrategy::PidffStopAll => "pidff-stop-all",
    }
}

fn next_command_r5_selector(lane: &Path) -> String {
    lane_manifest_r5_hid_observe_selector(lane).unwrap_or_else(|| "<r5>".to_string())
}

fn low_torque_frontier_blockers(lane: &Path) -> Vec<&'static str> {
    let mut blockers = Vec::new();
    if !zero_output_direct_report_metadata_trusted(lane) {
        blockers.push("descriptor.json does not prove trusted direct report 0x20 metadata");
    }
    if !low_torque_direct_zero_proof_ready(lane) {
        blockers.push("zero-torque-proof.json is not a same-lane direct_report_0x20 proof accepted by torque-test");
    }
    blockers
}

fn pidff_low_torque_frontier_blockers(lane: &Path) -> Vec<&'static str> {
    let mut blockers = Vec::new();
    if validate_zero_output_pidff_stop_all_report_metadata(lane).is_err() {
        blockers.push(
            "descriptor.json does not prove trusted PIDFF Device Control report 0x0C metadata",
        );
    }
    if !low_torque_pidff_zero_proof_ready(lane) {
        blockers
            .push("zero-torque-proof.json is not a same-lane pidff_device_control_stop_all proof");
    }
    blockers.extend(pidff_bounded_effect_descriptor_blockers(lane));
    blockers
}

fn pidff_bounded_effect_descriptor_blockers(lane: &Path) -> Vec<&'static str> {
    let mut blockers = Vec::new();
    if !lane_descriptor_has_output_report(
        lane,
        PIDFF_SET_CONSTANT_FORCE_REPORT_ID,
        PIDFF_SET_CONSTANT_FORCE_REPORT_LEN,
    ) {
        blockers
            .push("descriptor.json does not prove PIDFF Set Constant Force report 0x05 metadata");
    }
    if !lane_descriptor_has_output_report(
        lane,
        PIDFF_EFFECT_OPERATION_REPORT_ID,
        PIDFF_EFFECT_OPERATION_REPORT_LEN,
    ) {
        blockers.push("descriptor.json does not prove PIDFF Effect Operation report 0x0A metadata");
    }
    if !lane_descriptor_has_output_report(
        lane,
        PIDFF_BLOCK_FREE_REPORT_ID,
        PIDFF_BLOCK_FREE_REPORT_LEN,
    ) {
        blockers.push("descriptor.json does not prove PIDFF Block Free report 0x0B metadata");
    }
    if !lane_descriptor_has_pidff_set_effect_encoder(lane) {
        blockers.push("descriptor.json does not prove a descriptor-compatible PIDFF Set Effect encoder; expected generic report 0x01 len 14 or live R5 V1 report 0x01 len 22 metadata");
    }
    for (report_id, label) in [
        (
            PIDFF_CREATE_NEW_EFFECT_FEATURE_REPORT_ID,
            "PIDFF Create New Effect feature report 0x11 length metadata",
        ),
        (
            PIDFF_BLOCK_LOAD_FEATURE_REPORT_ID,
            "PIDFF Block Load feature report 0x12 length metadata",
        ),
        (
            PIDFF_PID_POOL_FEATURE_REPORT_ID,
            "PIDFF PID Pool feature report 0x13 length metadata",
        ),
    ] {
        if !lane_descriptor_has_feature_report_metadata(lane, report_id) {
            blockers.push(match report_id {
                PIDFF_CREATE_NEW_EFFECT_FEATURE_REPORT_ID => {
                    "descriptor.json does not include PIDFF Create New Effect feature report 0x11 length metadata"
                }
                PIDFF_BLOCK_LOAD_FEATURE_REPORT_ID => {
                    "descriptor.json does not include PIDFF Block Load feature report 0x12 length metadata"
                }
                PIDFF_PID_POOL_FEATURE_REPORT_ID => {
                    "descriptor.json does not include PIDFF PID Pool feature report 0x13 length metadata"
                }
                _ => label,
            });
        }
    }
    blockers
}

fn simulator_ffb_smoke_strategy_arg(lane: &Path) -> &'static str {
    if lane_low_torque_strategy_is_pidff(lane) {
        " --strategy pidff-bounded-effect"
    } else {
        ""
    }
}

fn lane_low_torque_strategy_is_pidff(lane: &Path) -> bool {
    let Ok(receipt) = read_json_value(lane, "low-torque-proof.json") else {
        return false;
    };
    json_string(&receipt, "low_torque_strategy")
        == Some(low_torque_strategy_name(
            MozaLowTorqueStrategy::PidffBoundedEffect,
        ))
}

fn low_torque_direct_zero_proof_ready(lane: &Path) -> bool {
    let proof_path = lane.join("zero-torque-proof.json");
    read_json_path(&proof_path)
        .map(|receipt| receipt_path_matches(lane, &receipt, "zero-torque-proof.json"))
        .unwrap_or(false)
        && validate_zero_proof_for_torque_test(&proof_path).is_ok()
}

fn low_torque_pidff_zero_proof_ready(lane: &Path) -> bool {
    let proof_path = lane.join("zero-torque-proof.json");
    read_json_path(&proof_path)
        .map(|receipt| receipt_path_matches(lane, &receipt, "zero-torque-proof.json"))
        .unwrap_or(false)
        && validate_zero_proof_for_low_torque_strategy(
            &proof_path,
            MozaLowTorqueStrategy::PidffBoundedEffect,
        )
        .is_ok()
}

fn push_openracing_control_next_commands(
    lane: &Path,
    gates: &[BundleGateCheck],
    commands: &mut Vec<String>,
) {
    let lane_arg = command_arg(&lane.display().to_string());
    let r5_selector = next_command_r5_selector(lane);

    if !bundle_gate_check_passed(gates, "init_off_handshake") {
        commands.push(format!(
            "wheelctl moza init --device {r5_selector} --lane {lane_arg} --mode off --confirm-init --json-out {}",
            lane_path_arg(lane, "init-off.json")
        ));
        return;
    }

    if !bundle_gate_check_passed(gates, "init_standard_handshake") {
        commands.push(format!(
            "wheelctl moza init --device {r5_selector} --lane {lane_arg} --mode standard --confirm-init --json-out {}",
            lane_path_arg(lane, "init-standard.json")
        ));
        return;
    }

    if !bundle_gate_check_passed(gates, "service_status_receipts") {
        commands.push(format!("wheeld --hardware-lane {lane_arg}"));
        commands.push(format!(
            "wheelctl moza status --device {r5_selector} --lane {lane_arg} --json-out {}",
            lane_path_arg(lane, "moza-status.json")
        ));
        commands.push(format!(
            "wheelctl device status {r5_selector} --moza-lane {lane_arg} --json-out {} --json",
            lane_path_arg(lane, "device-status.json")
        ));
        commands.push(format!(
            "wheelctl --json support-bundle --device {r5_selector} --moza-lane {lane_arg} --output {}",
            lane_path_arg(lane, "support-bundle.json")
        ));
        return;
    }

    if !bundle_gate_check_passed(gates, "low_torque_bounded") {
        if low_torque_frontier_blockers(lane).is_empty() {
            commands.push(format!(
                "wheelctl moza torque-test --device {r5_selector} --lane {lane_arg} --zero-proof {} --descriptor {} --max-percent 2 --duration-ms 250 --confirm-low-torque --json-out {}",
                lane_path_arg(lane, "zero-torque-proof.json"),
                lane_path_arg(lane, "descriptor.json"),
                lane_path_arg(lane, "low-torque-proof.json")
            ));
        } else if pidff_low_torque_frontier_blockers(lane).is_empty() {
            commands.push(format!(
                "wheelctl moza torque-test --device {r5_selector} --lane {lane_arg} --strategy pidff-bounded-effect --zero-proof {} --init-off {} --init-standard {} --max-percent 1 --duration-ms 150 --confirm-low-torque --json-out {} --json",
                lane_path_arg(lane, "zero-torque-proof.json"),
                lane_path_arg(lane, "init-off.json"),
                lane_path_arg(lane, "init-standard.json"),
                lane_path_arg(lane, "low-torque-proof.json")
            ));
        } else {
            commands.push(format!(
                "wheelctl moza pre-output-readiness --lane {lane_arg} --json-out {} --json",
                lane_path_arg(lane, "pre-output-readiness.json")
            ));
        }
        return;
    }

    if !bundle_gate_check_passed(gates, "steering_angle_stream_proof") {
        commands.push(format!(
            "wheelctl moza pre-output-readiness --lane {lane_arg} --json-out {} --json",
            lane_path_arg(lane, "pre-output-readiness.json")
        ));
        return;
    }

    if !bundle_gate_check_passed(gates, "native_actuator_profile_smoke") {
        if lane_low_torque_strategy_is_pidff(lane) {
            commands.push(format!(
                "wheelctl moza actuator-profile-smoke --device {r5_selector} --lane {lane_arg} --low-torque-proof {} --steering-proof {} --profile constant-low-force --strategy pidff-bounded-effect --max-percent 1 --duration-ms 2000 --confirm-actuator-profile --json-out {} --json",
                lane_path_arg(lane, "low-torque-proof.json"),
                lane_path_arg(lane, "steering-angle-stream-proof.json"),
                lane_path_arg(lane, "native-actuator-profile-smoke.json")
            ));
        } else {
            commands.push(format!(
                "wheelctl moza pre-output-readiness --lane {lane_arg} --json-out {} --json",
                lane_path_arg(lane, "pre-output-readiness.json")
            ));
        }
        return;
    }

    commands.push(format!(
        "wheelctl moza verify-bundle --lane {lane_arg} --stage openracing-control-ready --json-out {}",
        lane_path_arg(
            lane,
            verification_receipt_path(MozaBundleStage::OpenRacingControlReady)
        )
    ));
    if openracing_control_stage_gates_passed(gates) {
        commands.push(format!(
            "wheelctl moza promote-manifest --lane {lane_arg} --stage openracing-control-ready --json-out {}",
            lane_path_arg(
                lane,
                promotion_receipt_path(MozaBundleStage::OpenRacingControlReady)
            )
        ));
        commands.push(format!(
            "wheelctl moza audit-lane --lane {lane_arg} --stage openracing-control-ready --json-out {}",
            lane_path_arg(
                lane,
                audit_receipt_path(MozaBundleStage::OpenRacingControlReady)
            )
        ));
    }
}

fn push_native_response_next_commands(
    lane: &Path,
    gates: &[BundleGateCheck],
    commands: &mut Vec<String>,
) {
    push_native_visible_next_commands(lane, gates, commands);
}

fn push_native_visible_next_commands(
    lane: &Path,
    gates: &[BundleGateCheck],
    commands: &mut Vec<String>,
) {
    let lane_arg = command_arg(&lane.display().to_string());
    let r5_selector = next_command_r5_selector(lane);

    if !bundle_gate_check_passed(gates, "native_actuator_visible_smoke") {
        if failed_real_native_visible_smoke_receipt(lane).is_some() {
            if !lane.join(NATIVE_VISIBLE_FOLLOW_UP_PLAN_FILE).exists() {
                commands.push(format!(
                    "wheelctl moza receipt-template --kind visible-motion-follow-up --json-out {} --json",
                    lane_path_arg(lane, NATIVE_VISIBLE_FOLLOW_UP_PLAN_FILE)
                ));
            }
            let controlled_angle_plan_ready =
                validate_native_controlled_angle_plan_artifact(lane).is_ok();
            if !controlled_angle_plan_ready {
                commands.push(format!(
                    "wheelctl moza receipt-template --kind controlled-angle-plan --json-out {} --json",
                    lane_path_arg(lane, NATIVE_CONTROLLED_ANGLE_PLAN_FILE)
                ));
            }
            if native_controlled_angle_real_attempt_recorded(lane) {
                return;
            }
            let controlled_angle_dry_run_ready =
                native_controlled_angle_first_rung_dry_run_ready(lane, &r5_selector);
            if controlled_angle_plan_ready && !controlled_angle_dry_run_ready {
                let target_degrees = compact_f64(NATIVE_CONTROLLED_ANGLE_FIRST_TARGET_DEGREES);
                let max_percent = compact_f32(NATIVE_CONTROLLED_ANGLE_FIRST_MAX_PERCENT);
                let timeout_ms = NATIVE_CONTROLLED_ANGLE_FIRST_MAX_DURATION_MS;
                let profile = controlled_angle_profile_cli_name(
                    MozaControlledAngleProfile::BoundedPidffMicroStepV2,
                );
                commands.push(format!(
                    "wheelctl moza controlled-angle-smoke --device {r5_selector} --lane {lane_arg} --prior-actuator-proof {} --steering-proof {} --target-degrees {target_degrees} --profile {profile} --max-percent {max_percent} --timeout-ms {timeout_ms} --strategy pidff-bounded-effect --dry-run --json-out {} --json",
                    lane_path_arg(lane, "native-actuator-profile-smoke.json"),
                    lane_path_arg(lane, "steering-angle-stream-proof.json"),
                    lane_path_arg(lane, NATIVE_CONTROLLED_ANGLE_SMOKE_FILE)
                ));
            }
            if !pre_output_readiness_receipt_is_no_output_snapshot(lane) {
                commands.push(format!(
                    "wheelctl moza pre-output-readiness --lane {lane_arg} --json-out {} --json",
                    lane_path_arg(lane, "pre-output-readiness.json")
                ));
            }
            return;
        }
        commands.push(format!(
            "wheelctl moza actuator-visible-smoke --device {r5_selector} --lane {lane_arg} --prior-actuator-proof {} --steering-proof {} --profile constant-low-force --strategy pidff-bounded-effect --max-percent 5 --duration-ms 2000 --confirm-actuator-visible --json-out {} --json",
            lane_path_arg(lane, "native-actuator-profile-smoke.json"),
            lane_path_arg(lane, "steering-angle-stream-proof.json"),
            lane_path_arg(lane, "native-actuator-visible-smoke.json")
        ));
        return;
    }

    commands.push(format!(
        "wheelctl moza verify-bundle --lane {lane_arg} --stage native-visible-ready --json-out {}",
        lane_path_arg(
            lane,
            verification_receipt_path(MozaBundleStage::NativeVisibleReady)
        )
    ));
    if native_visible_stage_gates_passed(gates) {
        commands.push(format!(
            "wheelctl moza promote-manifest --lane {lane_arg} --stage native-visible-ready --json-out {}",
            lane_path_arg(lane, promotion_receipt_path(MozaBundleStage::NativeVisibleReady))
        ));
        commands.push(format!(
            "wheelctl moza audit-lane --lane {lane_arg} --stage native-visible-ready --json-out {}",
            lane_path_arg(
                lane,
                audit_receipt_path(MozaBundleStage::NativeVisibleReady)
            )
        ));
    }
}

fn native_controlled_angle_real_attempt_recorded(lane: &Path) -> bool {
    native_controlled_angle_smoke_is_real_output_attempt(lane)
        || native_controlled_angle_retry_smoke_is_real_output_attempt(lane)
        || native_controlled_angle_attempt_03_smoke_is_real_output_attempt(lane)
        || native_controlled_angle_closed_loop_smoke_is_real_output_attempt(lane)
}

fn native_controlled_angle_first_rung_dry_run_ready(lane: &Path, selector: &str) -> bool {
    validate_native_controlled_angle_dry_run_preflight(
        lane,
        NATIVE_CONTROLLED_ANGLE_SMOKE_FILE,
        selector,
        NATIVE_CONTROLLED_ANGLE_FIRST_TARGET_DEGREES,
        MozaControlledAngleProfile::BoundedPidffMicroStepV2,
        MozaLowTorqueStrategy::PidffBoundedEffect,
        NATIVE_CONTROLLED_ANGLE_FIRST_MAX_PERCENT,
    )
    .is_ok()
}

fn push_external_smoke_ready_next_commands(
    lane: &Path,
    gates: &[BundleGateCheck],
    commands: &mut Vec<String>,
) {
    let lane_arg = command_arg(&lane.display().to_string());

    if !bundle_gate_check_passed(gates, "simulator_telemetry") {
        let session_id = simulator_telemetry_session_id(lane);
        commands.push(format!(
            "wheelctl telemetry record --game simhub-bridge --telemetry-source simhub_bridge --live-simhub --port 5555 --out {} --session-id {} --duration-ms 30000",
            lane_path_arg(lane, "simulator-telemetry-recording.jsonl"),
            command_arg(&session_id)
        ));
        commands.push(format!(
            "wheelctl moza simulator-telemetry-proof --lane {lane_arg} --game simhub-bridge --telemetry-source simhub_bridge --recorder-artifact simulator-telemetry-recording.jsonl --duration-ms 30000 --json-out {}",
            lane_path_arg(lane, "simulator-telemetry-proof.json")
        ));
        return;
    }

    if !bundle_gate_check_passed(gates, "simulator_ffb_bounded") {
        let strategy_arg = simulator_ffb_smoke_strategy_arg(lane);
        commands.push(format!("wheeld --hardware-lane {lane_arg}"));
        commands.push(format!(
            "wheelctl moza simulator-ffb-smoke --lane {lane_arg} --game <sim> --telemetry-source real_game --output-log-artifact simulator-ffb-output.jsonl{strategy_arg} --descriptor-trusted --watchdog-timeout-ms 100 --stop-cleared-output --pause-cleared-output --game-exit-cleared-output --json-out {}",
            lane_path_arg(lane, "simulator-ffb-smoke.json")
        ));
        return;
    }

    if bundle_gate_check_passed(gates, "pit_house_coexistence") {
        commands.push(format!(
            "wheelctl moza verify-bundle --lane {lane_arg} --stage smoke-ready --json-out {}",
            lane_path_arg(lane, verification_receipt_path(MozaBundleStage::SmokeReady))
        ));
        if smoke_ready_stage_gates_passed(gates) {
            commands.push(format!(
                "wheelctl moza promote-manifest --lane {lane_arg} --stage smoke-ready --json-out {}",
                lane_path_arg(lane, promotion_receipt_path(MozaBundleStage::SmokeReady))
            ));
            commands.push(format!(
                "wheelctl moza audit-lane --lane {lane_arg} --stage smoke-ready --json-out {}",
                lane_path_arg(lane, audit_receipt_path(MozaBundleStage::SmokeReady))
            ));
        }
        return;
    }

    match pit_house_availability_state(lane) {
        PitHouseAvailabilityState::MissingOrInvalid => {
            push_pit_house_availability_next_command(lane, commands, false);
            return;
        }
        PitHouseAvailabilityState::Unavailable => {
            push_pit_house_availability_next_command(lane, commands, true);
            return;
        }
        PitHouseAvailabilityState::Available => {}
    }

    for (case, case_id, evidence_artifact, artifact, evidence) in [
        (
            "closed",
            "pit_house_closed",
            "pit-house-evidence-closed.json",
            "pit-house-observation-closed.json",
            "Pit House closed; OpenRacing staged handshake observed",
        ),
        (
            "open-standard",
            "pit_house_open_idle_standard",
            "pit-house-evidence-open-standard.json",
            "pit-house-observation-open-standard.json",
            "Pit House open and idle; standard mode observed",
        ),
        (
            "open-direct",
            "pit_house_open_direct",
            "pit-house-evidence-open-direct.json",
            "pit-house-observation-open-direct.json",
            "Pit House open during direct request; OpenRacing warned or blocked",
        ),
        (
            "firmware-page",
            "pit_house_firmware_update_page_open",
            "pit-house-evidence-firmware-page.json",
            "pit-house-observation-firmware-page.json",
            "Pit House firmware/update page open; high-risk tests refused",
        ),
    ] {
        if pit_house_observation_receipt_is_safe(lane, artifact, case_id) {
            continue;
        }
        push_pit_house_observation_next_command(
            lane,
            commands,
            case,
            evidence_artifact,
            artifact,
            evidence,
        );
    }

    for (case, case_id, observation, artifact, evidence) in [
        (
            "closed",
            "pit_house_closed",
            "pit-house-observation-closed.json",
            "pit-house-closed.json",
            "Pit House closed case observed",
        ),
        (
            "open-standard",
            "pit_house_open_idle_standard",
            "pit-house-observation-open-standard.json",
            "pit-house-open-standard.json",
            "Pit House open standard case observed",
        ),
        (
            "open-direct",
            "pit_house_open_direct",
            "pit-house-observation-open-direct.json",
            "pit-house-direct-blocked.json",
            "Pit House open direct request warned or blocked",
        ),
        (
            "firmware-page",
            "pit_house_firmware_update_page_open",
            "pit-house-observation-firmware-page.json",
            "pit-house-firmware-page.json",
            "Pit House firmware/update page refusal observed",
        ),
    ] {
        if pit_house_case_receipt_is_safe(lane, artifact, case_id) {
            continue;
        }
        push_pit_house_case_next_command(lane, commands, case, observation, artifact, evidence);
    }
    if !pit_house_observation_receipt_is_safe(
        lane,
        "pit-house-observation-mode-change.json",
        "pit_house_mode_change_during_run",
    ) {
        push_pit_house_observation_next_command(
            lane,
            commands,
            "mode-change",
            "pit-house-evidence-mode-change.json",
            "pit-house-observation-mode-change.json",
            "Pit House mode change observed during bounded run; output cleared",
        );
    }
    if !pit_house_case_receipt_is_safe(
        lane,
        "pit-house-mode-change.json",
        "pit_house_mode_change_during_run",
    ) {
        push_pit_house_case_next_command(
            lane,
            commands,
            "mode-change",
            "pit-house-observation-mode-change.json",
            "pit-house-mode-change.json",
            "Pit House mode change fail-safe observed",
        );
    }
    commands.push(format!(
        "wheelctl moza pit-house-proof --lane {lane_arg} --closed-artifact pit-house-closed.json --open-standard-artifact pit-house-open-standard.json --direct-artifact pit-house-direct-blocked.json --mode-change-artifact pit-house-mode-change.json --firmware-page-artifact pit-house-firmware-page.json --shared-control-risk warned --json-out {}",
        lane_path_arg(lane, "pit-house-coexistence.json")
    ));
    commands.push(format!(
        "wheelctl moza verify-bundle --lane {lane_arg} --stage smoke-ready --json-out {}",
        lane_path_arg(lane, verification_receipt_path(MozaBundleStage::SmokeReady))
    ));
}

fn pre_output_readiness_receipt_is_no_output_snapshot(lane: &Path) -> bool {
    let Ok(receipt) = read_json_value(lane, "pre-output-readiness.json") else {
        return false;
    };
    json_string(&receipt, "command") == Some("wheelctl moza pre-output-readiness")
        && json_string(&receipt, "stage") == Some("pre_output_readiness")
        && lane_path_value_matches(lane, json_string(&receipt, "lane"))
        && json_bool(&receipt, "no_hid_device_opened") == Some(true)
        && json_bool(&receipt, "no_ffb_writes") == Some(true)
        && json_bool(&receipt, "no_output_reports") == Some(true)
        && json_bool(&receipt, "no_feature_reports") == Some(true)
        && no_out_of_scope_device_commands(&receipt)
}

fn simulator_telemetry_session_id(lane: &Path) -> String {
    let suffix = lane
        .file_name()
        .and_then(|name| name.to_str())
        .filter(|name| !name.trim().is_empty())
        .map(sanitize_session_id_component)
        .filter(|name| !name.is_empty())
        .unwrap_or_else(|| "manual".to_string());
    format!("simhub-bridge-{suffix}")
}

fn sanitize_session_id_component(value: &str) -> String {
    value
        .chars()
        .map(|ch| {
            if ch.is_ascii_alphanumeric() || ch == '-' || ch == '_' {
                ch
            } else {
                '-'
            }
        })
        .collect()
}

fn pit_house_observation_receipt_is_safe(
    lane: &Path,
    observation_artifact: &str,
    case_id: &str,
) -> bool {
    let artifact = serde_json::json!({
        "pit_house_observation_artifact": observation_artifact
    });
    pit_house_case_observation_is_safe(lane, &artifact, case_id)
}

fn pit_house_case_receipt_is_safe(lane: &Path, artifact_path: &str, case_id: &str) -> bool {
    let Some(path) = resolve_receipt_path(lane, artifact_path) else {
        return false;
    };
    let Ok(artifact) = read_json_path(&path) else {
        return false;
    };
    let result = json_string(&artifact, "result");
    pit_house_case_artifact_is_safe(
        lane,
        artifact_path,
        case_id,
        result,
        SupportBundleValidationMode::Fresh,
    )
}

fn push_pit_house_observation_next_command(
    lane: &Path,
    commands: &mut Vec<String>,
    case: &str,
    evidence_artifact: &str,
    output_artifact: &str,
    evidence: &str,
) {
    if pit_house_evidence_artifact_needs_refresh(lane, evidence_artifact, case) {
        push_pit_house_evidence_next_command(lane, commands, case, evidence_artifact, evidence);
    }
    commands.push(format!(
        "wheelctl moza pit-house-observation --case {case} --evidence-kind process-window-snapshot --evidence-artifact {evidence_artifact} --operator Steven --evidence {} --json-out {}",
        command_arg(evidence),
        lane_path_arg(lane, output_artifact)
    ));
}

fn pit_house_evidence_artifact_needs_refresh(
    lane: &Path,
    evidence_artifact: &str,
    case: &str,
) -> bool {
    let path = lane.join(evidence_artifact);
    if !path.is_file() {
        return true;
    }
    let Some(case_id) = pit_house_observation_case_arg_id(case) else {
        return false;
    };
    read_json_path(&path)
        .map(|snapshot| !pit_house_process_window_snapshot_matches_case(&snapshot, case_id))
        .unwrap_or(false)
}

fn pit_house_observation_case_arg_id(case: &str) -> Option<&'static str> {
    match case {
        "closed" => Some("pit_house_closed"),
        "open-standard" => Some("pit_house_open_idle_standard"),
        "open-direct" => Some("pit_house_open_direct"),
        "mode-change" => Some("pit_house_mode_change_during_run"),
        "firmware-page" => Some("pit_house_firmware_update_page_open"),
        _ => None,
    }
}

fn push_pit_house_evidence_next_command(
    lane: &Path,
    commands: &mut Vec<String>,
    case: &str,
    evidence_artifact: &str,
    evidence: &str,
) {
    commands.push(format!(
        "wheelctl moza pit-house-evidence --case {case} --operator Steven --evidence {} --require-match --json-out {}",
        command_arg(evidence),
        lane_path_arg(lane, evidence_artifact)
    ));
}

fn push_pit_house_case_next_command(
    lane: &Path,
    commands: &mut Vec<String>,
    case: &str,
    observation_artifact: &str,
    output_artifact: &str,
    evidence: &str,
) {
    let lane_arg = command_arg(&lane.display().to_string());
    commands.push(format!(
        "wheelctl moza pit-house-case --lane {lane_arg} --case {case} --observation-artifact {observation_artifact} --evidence {} --json-out {}",
        command_arg(evidence),
        lane_path_arg(lane, output_artifact)
    ));
}

fn lane_path_arg(lane: &Path, relative_path: &str) -> String {
    command_arg(&lane.join(relative_path).display().to_string())
}

fn command_arg(value: &str) -> String {
    let needs_quotes = value.is_empty()
        || value.chars().any(|ch| {
            ch.is_whitespace()
                || matches!(
                    ch,
                    '\'' | '"' | '&' | '(' | ')' | '[' | ']' | '{' | '}' | ';' | '<' | '>'
                )
        });
    if needs_quotes {
        format!("'{}'", value.replace('\'', "''"))
    } else {
        value.to_string()
    }
}

fn audit_stages_through(stage: MozaBundleStage) -> Vec<MozaBundleStage> {
    match stage {
        MozaBundleStage::Passive => vec![MozaBundleStage::Passive],
        MozaBundleStage::Zero => vec![MozaBundleStage::Passive, MozaBundleStage::Zero],
        MozaBundleStage::OpenRacingControlReady => vec![
            MozaBundleStage::Passive,
            MozaBundleStage::Zero,
            MozaBundleStage::OpenRacingControlReady,
        ],
        MozaBundleStage::NativeResponseReady => vec![
            MozaBundleStage::Passive,
            MozaBundleStage::Zero,
            MozaBundleStage::OpenRacingControlReady,
            MozaBundleStage::NativeResponseReady,
        ],
        MozaBundleStage::NativeVisibleReady => vec![
            MozaBundleStage::Passive,
            MozaBundleStage::Zero,
            MozaBundleStage::OpenRacingControlReady,
            MozaBundleStage::NativeResponseReady,
            MozaBundleStage::NativeVisibleReady,
        ],
        MozaBundleStage::SmokeReady => vec![
            MozaBundleStage::Passive,
            MozaBundleStage::Zero,
            MozaBundleStage::OpenRacingControlReady,
            MozaBundleStage::NativeResponseReady,
            MozaBundleStage::NativeVisibleReady,
            MozaBundleStage::SmokeReady,
        ],
    }
}

fn audit_stored_verification_receipt(lane: &Path, stage: MozaBundleStage) -> LaneAuditCheck {
    let path = verification_receipt_path(stage);
    let stage_label = stage_label(stage);
    let receipt = match read_json_value(lane, path) {
        Ok(value) => value,
        Err(e) => {
            return LaneAuditCheck::missing(stage_label, "verification", path, e.to_string());
        }
    };

    let success = json_bool(&receipt, "success") == Some(true);
    let command_ok = json_string(&receipt, "command") == Some("wheelctl moza verify-bundle");
    let lane_ok = lane_path_value_matches(lane, json_string(&receipt, "lane"));
    let stage_ok = json_string(&receipt, "requested_stage") == Some(stage_label);
    let missing_artifacts = json_u64(&receipt, "missing_artifacts").unwrap_or(u64::MAX);
    let invalid_artifacts = json_u64(&receipt, "invalid_artifacts").unwrap_or(u64::MAX);
    let failed_gates = json_u64(&receipt, "failed_gates").unwrap_or(u64::MAX);
    let no_hid_device_opened = json_bool(&receipt, "no_hid_device_opened") == Some(true);
    let no_ffb_writes = json_bool(&receipt, "no_ffb_writes") == Some(true);
    let no_out_of_scope = no_out_of_scope_device_commands(&receipt);
    let safe = success
        && command_ok
        && lane_ok
        && stage_ok
        && missing_artifacts == 0
        && invalid_artifacts == 0
        && failed_gates == 0
        && no_hid_device_opened
        && no_ffb_writes
        && no_out_of_scope;

    if safe {
        LaneAuditCheck::pass(
            stage_label,
            "verification",
            path,
            "stored verify-bundle receipt passed with no missing artifacts, invalid artifacts, failed gates, HID opens, FFB writes, serial config, firmware, or DFU commands".to_string(),
        )
    } else {
        LaneAuditCheck::invalid(
            stage_label,
            "verification",
            path,
            format!(
                "success={success}, command_ok={command_ok}, lane_ok={lane_ok}, stage_ok={stage_ok}, missing_artifacts={missing_artifacts}, invalid_artifacts={invalid_artifacts}, failed_gates={failed_gates}, no_hid_device_opened={no_hid_device_opened}, no_ffb_writes={no_ffb_writes}, no_out_of_scope={no_out_of_scope}"
            ),
        )
    }
}

fn audit_manifest_promotion_receipt(lane: &Path, stage: MozaBundleStage) -> LaneAuditCheck {
    let path = promotion_receipt_path(stage);
    let stage_label = stage_label(stage);
    let receipt = match read_json_value(lane, path) {
        Ok(value) => value,
        Err(e) => {
            return LaneAuditCheck::missing(stage_label, "promotion", path, e.to_string());
        }
    };

    let (completion_state, hardware_validated, simulator_validated) =
        manifest_promotion_values(stage);
    let success = json_bool(&receipt, "success") == Some(true);
    let command_ok = json_string(&receipt, "command") == Some("wheelctl moza promote-manifest");
    let lane_ok = lane_path_value_matches(lane, json_string(&receipt, "lane"));
    let manifest_ok = artifact_path_value_matches(
        &lane.join("manifest.json"),
        json_string(&receipt, "manifest"),
    );
    let stage_ok = json_string(&receipt, "stage") == Some(stage_label);
    let completion_ok = json_string(&receipt, "completion_state") == Some(completion_state);
    let hardware_ok = json_bool(&receipt, "hardware_validated") == Some(hardware_validated);
    let simulator_ok = json_bool(&receipt, "simulator_validated") == Some(simulator_validated);
    let no_overclaim = json_bool(&receipt, "high_torque_validated") == Some(false)
        && json_bool(&receipt, "release_ready") == Some(false);
    let no_hid_device_opened = json_bool(&receipt, "no_hid_device_opened") == Some(true);
    let no_ffb_writes = json_bool(&receipt, "no_ffb_writes") == Some(true);
    let no_out_of_scope = no_out_of_scope_device_commands(&receipt);
    let verification_before_ok =
        promotion_verification_summary_ok(receipt.get("verification_before"), stage_label);
    let verification_after_ok =
        promotion_verification_summary_ok(receipt.get("verification_after"), stage_label);
    let safe = success
        && command_ok
        && lane_ok
        && manifest_ok
        && stage_ok
        && completion_ok
        && hardware_ok
        && simulator_ok
        && no_overclaim
        && no_hid_device_opened
        && no_ffb_writes
        && no_out_of_scope
        && verification_before_ok
        && verification_after_ok;

    if safe {
        LaneAuditCheck::pass(
            stage_label,
            "promotion",
            path,
            "stored promote-manifest receipt passed, records before/after live verification, and declares no HID opens, FFB writes, serial config, firmware, or DFU commands".to_string(),
        )
    } else {
        LaneAuditCheck::invalid(
            stage_label,
            "promotion",
            path,
            format!(
                "success={success}, command_ok={command_ok}, lane_ok={lane_ok}, manifest_ok={manifest_ok}, stage_ok={stage_ok}, completion_ok={completion_ok}, hardware_ok={hardware_ok}, simulator_ok={simulator_ok}, no_overclaim={no_overclaim}, no_hid_device_opened={no_hid_device_opened}, no_ffb_writes={no_ffb_writes}, no_out_of_scope={no_out_of_scope}, verification_before_ok={verification_before_ok}, verification_after_ok={verification_after_ok}"
            ),
        )
    }
}

fn path_value_matches(expected: &Path, recorded: Option<&str>) -> bool {
    let Some(recorded) = recorded.map(str::trim).filter(|value| !value.is_empty()) else {
        return false;
    };
    if recorded == expected.display().to_string() {
        return true;
    }
    if normalized_path_string(recorded) == normalized_path_string(&expected.display().to_string()) {
        return true;
    }

    let recorded_path = Path::new(recorded);
    let recorded_canonical = fs::canonicalize(recorded_path).or_else(|_| {
        std::env::current_dir().and_then(|cwd| fs::canonicalize(cwd.join(recorded_path)))
    });
    match (fs::canonicalize(expected), recorded_canonical) {
        (Ok(expected), Ok(recorded)) => expected == recorded,
        _ => false,
    }
}

fn lane_path_value_matches(expected: &Path, recorded: Option<&str>) -> bool {
    let Some(recorded) = recorded.map(str::trim).filter(|value| !value.is_empty()) else {
        return false;
    };
    if path_value_matches(expected, Some(recorded)) {
        return true;
    }

    relative_path_value_matches(expected, recorded)
}

fn artifact_path_value_matches(expected: &Path, recorded: Option<&str>) -> bool {
    let Some(recorded) = recorded.map(str::trim).filter(|value| !value.is_empty()) else {
        return false;
    };
    path_value_matches(expected, Some(recorded)) || relative_path_value_matches(expected, recorded)
}

fn relative_path_value_matches(expected: &Path, recorded: &str) -> bool {
    let recorded_path = Path::new(recorded);
    if recorded_path.is_absolute() || recorded.contains(':') {
        return false;
    }

    let expected = normalized_path_string(&expected.display().to_string());
    let recorded = normalized_path_string(recorded);
    expected == recorded || expected.ends_with(&format!("/{recorded}"))
}

fn normalized_path_string(path: &str) -> String {
    path.replace('\\', "/").trim_end_matches('/').to_string()
}

fn receipt_path_matches(lane: &Path, receipt: &Value, relative_path: &str) -> bool {
    let expected = lane.join(relative_path);
    let Some(recorded) = json_string(receipt, "receipt_path") else {
        return false;
    };
    artifact_path_value_matches(&expected, Some(recorded))
}

fn verification_receipt_path(stage: MozaBundleStage) -> &'static str {
    match stage {
        MozaBundleStage::Passive => "passive-verification.json",
        MozaBundleStage::Zero => "zero-verification.json",
        MozaBundleStage::OpenRacingControlReady => "openracing-control-verification.json",
        MozaBundleStage::NativeResponseReady => "native-response-verification.json",
        MozaBundleStage::NativeVisibleReady => "native-visible-verification.json",
        MozaBundleStage::SmokeReady => "smoke-ready-verification.json",
    }
}

fn promotion_verification_summary_ok(summary: Option<&Value>, expected_stage: &str) -> bool {
    let Some(summary) = summary else {
        return false;
    };

    json_bool(summary, "success") == Some(true)
        && json_string(summary, "requested_stage") == Some(expected_stage)
        && json_u64(summary, "missing_artifacts") == Some(0)
        && json_u64(summary, "invalid_artifacts") == Some(0)
        && json_u64(summary, "failed_gates") == Some(0)
        && json_bool(summary, "no_hid_device_opened") == Some(true)
        && json_bool(summary, "no_ffb_writes") == Some(true)
        && json_bool(summary, "no_serial_config_commands") == Some(true)
        && json_bool(summary, "no_firmware_or_dfu_commands") == Some(true)
}

fn promotion_receipt_path(stage: MozaBundleStage) -> &'static str {
    match stage {
        MozaBundleStage::Passive => "manifest-promotion-passive.json",
        MozaBundleStage::Zero => "manifest-promotion-zero.json",
        MozaBundleStage::OpenRacingControlReady => "manifest-promotion-openracing-control.json",
        MozaBundleStage::NativeResponseReady => "manifest-promotion-native-response.json",
        MozaBundleStage::NativeVisibleReady => "manifest-promotion-native-visible.json",
        MozaBundleStage::SmokeReady => "manifest-promotion-smoke-ready.json",
    }
}

fn audit_receipt_path(stage: MozaBundleStage) -> &'static str {
    match stage {
        MozaBundleStage::Passive => "lane-audit-passive.json",
        MozaBundleStage::Zero => "lane-audit-zero.json",
        MozaBundleStage::OpenRacingControlReady => "lane-audit-openracing-control.json",
        MozaBundleStage::NativeResponseReady => "lane-audit-native-response.json",
        MozaBundleStage::NativeVisibleReady => "lane-audit-native-visible.json",
        MozaBundleStage::SmokeReady => "lane-audit-smoke-ready.json",
    }
}

pub(crate) fn support_bundle_status(lane: &Path) -> Value {
    support_bundle_status_with_support_validation(lane, SupportBundleValidationMode::ShapeOnly)
}

fn artifact_navigation_status(lane: &Path) -> Value {
    let passive = pre_output_stored_verification_receipt(lane, MozaBundleStage::Passive);
    let zero = pre_output_stored_verification_receipt(lane, MozaBundleStage::Zero);
    let openracing_control =
        pre_output_stored_verification_receipt(lane, MozaBundleStage::OpenRacingControlReady);
    let native_response =
        pre_output_stored_verification_receipt(lane, MozaBundleStage::NativeResponseReady);
    let native_visible =
        pre_output_stored_verification_receipt(lane, MozaBundleStage::NativeVisibleReady);
    let smoke_ready = pre_output_stored_verification_receipt(lane, MozaBundleStage::SmokeReady);
    let passive_audit_passed = stored_lane_audit_receipt_passed(lane, MozaBundleStage::Passive);
    let zero_audit_passed = stored_lane_audit_receipt_passed(lane, MozaBundleStage::Zero);
    let openracing_control_audit_passed =
        stored_lane_audit_receipt_passed(lane, MozaBundleStage::OpenRacingControlReady);
    let native_response_audit_passed =
        stored_lane_audit_receipt_passed(lane, MozaBundleStage::NativeResponseReady);
    let native_visible_audit_passed =
        stored_lane_audit_receipt_passed(lane, MozaBundleStage::NativeVisibleReady);
    let smoke_ready_audit_passed =
        stored_lane_audit_receipt_passed(lane, MozaBundleStage::SmokeReady);
    let init_handshakes_pass = pre_output_gate_passed(&openracing_control, "init_off_handshake")
        && pre_output_gate_passed(&openracing_control, "init_standard_handshake");
    let native_control_blocking_items = pre_output_native_control_blocking_items(
        &zero,
        &openracing_control,
        zero_audit_passed,
        openracing_control_audit_passed,
    );
    let external_compatibility_blocking_items =
        pre_output_external_compatibility_blocking_items(&smoke_ready, smoke_ready_audit_passed);
    let highest_passing_stage = stored_highest_passing_stage(lane);
    let first_blocking_stage = if !passive.success {
        pre_output_verification_summary(&passive)
    } else if !zero.success {
        pre_output_verification_summary(&zero)
    } else if !openracing_control.success {
        pre_output_verification_summary(&openracing_control)
    } else if !native_response.success {
        pre_output_verification_summary(&native_response)
    } else if !native_visible.success {
        pre_output_verification_summary(&native_visible)
    } else if !smoke_ready.success {
        pre_output_verification_summary(&smoke_ready)
    } else {
        Value::Null
    };
    let artifact_index: Vec<_> = artifact_navigation_requirements()
        .map(|requirement| check_bundle_artifact(lane, &requirement))
        .collect();

    serde_json::json!({
        "artifact_index": artifact_index,
        "readiness": {
            "highest_passing_stage": highest_passing_stage,
            "next_required_stage": next_stage_after(highest_passing_stage),
            "ready_for_zero_torque": passive.success && passive_audit_passed,
            "ready_for_low_torque": support_ready_for_low_torque(
                lane,
                zero.success,
                zero_audit_passed,
                init_handshakes_pass,
            ),
            "ready_for_native_control": native_control_blocking_items.is_empty(),
            "native_control_blocking_items": native_control_blocking_items,
            "native_actuator_response_proven": pre_output_gate_passed(
                &native_response,
                "native_actuator_response_smoke",
            ),
            "native_visible_motion_proven": pre_output_gate_passed(
                &native_visible,
                "native_actuator_visible_smoke",
            ),
            "ready_for_external_compatibility": external_compatibility_blocking_items.is_empty(),
            "external_compatibility_blocking_items": external_compatibility_blocking_items,
            "ready_for_real_hardware_smoke": smoke_ready.success && smoke_ready_audit_passed,
            "passive_lane_audit_passed": passive_audit_passed,
            "zero_lane_audit_passed": zero_audit_passed,
            "openracing_control_lane_audit_passed": openracing_control_audit_passed,
            "native_response_lane_audit_passed": native_response_audit_passed,
            "native_visible_lane_audit_passed": native_visible_audit_passed,
            "smoke_ready_lane_audit_passed": smoke_ready_audit_passed,
            "release_ready": false,
            "first_blocking_stage": first_blocking_stage,
            "claim_scope": "diagnostic_context_only",
            "source": "stored_verification_receipts"
        },
        "notes": [
            "artifact navigation status reads stored lane receipts only; it does not rebuild full support-bundle verification",
            "artifact navigation status is diagnostic context, not readiness promotion"
        ]
    })
}

fn artifact_index_readiness_summary(lane: &Path, support_status: &Value) -> Value {
    let mut readiness = support_status
        .get("readiness")
        .filter(|value| value.is_object())
        .cloned()
        .unwrap_or_else(|| serde_json::json!({}));
    let highest = stored_highest_passing_stage(lane);
    if let Some(object) = readiness.as_object_mut() {
        object.insert(
            "highest_passing_stage".to_string(),
            Value::String(highest.to_string()),
        );
        object.insert(
            "next_required_stage".to_string(),
            match next_stage_after(highest) {
                Some(stage) => Value::String(stage.to_string()),
                None => Value::Null,
            },
        );
        object.insert(
            "native_actuator_response_proven".to_string(),
            Value::Bool(stored_verification_gate_passed(
                lane,
                MozaBundleStage::NativeResponseReady,
                "native_actuator_response_smoke",
            )),
        );
        object.insert(
            "native_visible_motion_proven".to_string(),
            Value::Bool(stored_verification_gate_passed(
                lane,
                MozaBundleStage::NativeVisibleReady,
                "native_actuator_visible_smoke",
            )),
        );
        object.insert("release_ready".to_string(), Value::Bool(false));
        object.insert(
            "claim_scope".to_string(),
            Value::String("diagnostic_context_only".to_string()),
        );
        object.insert(
            "source".to_string(),
            Value::String("stored_verification_receipts".to_string()),
        );
    }
    readiness
}

fn moza_input_role_semantics_summary(lane: &Path) -> Value {
    let source_stage_order = [
        MozaBundleStage::NativeVisibleReady,
        MozaBundleStage::NativeResponseReady,
        MozaBundleStage::OpenRacingControlReady,
        MozaBundleStage::Zero,
        MozaBundleStage::Passive,
    ];
    let mut selected_stage = None;
    let mut selected_path = None;
    let mut selected_roles: Vec<Value> = Vec::new();

    for stage in source_stage_order {
        let path = verification_receipt_path(stage);
        let Ok(receipt) = read_json_value(lane, path) else {
            continue;
        };
        let Some(roles) = receipt.get("role_evidence").and_then(Value::as_array) else {
            continue;
        };
        if roles.is_empty() {
            continue;
        }
        selected_stage = Some(stage_label(stage));
        selected_path = Some(path);
        selected_roles = roles.clone();
        break;
    }

    let mut status_counts: BTreeMap<String, usize> = BTreeMap::new();
    let mut roles = Vec::new();
    let mut generic_aux_roles = Vec::new();
    let mut incomplete_roles = Vec::new();
    let mut required_role_count = 0usize;
    let mut required_parser_visible_count = 0usize;
    let mut semantic_candidate_count = 0usize;
    let mut ambiguous_semantic_candidate_count = 0usize;
    let axis_controls = candidate_axis_controls_for_role_values(&selected_roles);

    for role in selected_roles {
        let required = json_bool(&role, "required").unwrap_or(false);
        let parser_visible = json_bool(&role, "parser_visible").unwrap_or(false);
        let semantic_status = json_string(&role, "semantic_status")
            .unwrap_or("unknown")
            .to_string();
        let control = json_string(&role, "control")
            .unwrap_or("unknown")
            .to_string();
        let role_name = json_string(&role, "role").unwrap_or("unknown").to_string();
        let evidence_capture = json_string(&role, "evidence_capture").map(str::to_string);
        let missing_requirements = role
            .get("missing_requirements")
            .and_then(Value::as_array)
            .map(|requirements| {
                requirements
                    .iter()
                    .filter_map(Value::as_str)
                    .map(str::to_string)
                    .collect::<Vec<_>>()
            })
            .unwrap_or_default();
        let moving_required_axes = role
            .get("moving_required_axes")
            .and_then(Value::as_array)
            .map(|axes| {
                axes.iter()
                    .filter_map(Value::as_str)
                    .map(str::to_string)
                    .collect::<Vec<_>>()
            })
            .unwrap_or_default();
        let notes = role
            .get("notes")
            .and_then(Value::as_array)
            .map(|notes| {
                notes
                    .iter()
                    .filter_map(Value::as_str)
                    .map(str::to_string)
                    .collect::<Vec<_>>()
            })
            .unwrap_or_default();

        *status_counts.entry(semantic_status.clone()).or_default() += 1;
        if required {
            required_role_count += 1;
            if parser_visible && missing_requirements.is_empty() {
                required_parser_visible_count += 1;
            }
        }
        let semantic_candidates = role
            .get("semantic_candidates")
            .and_then(Value::as_array)
            .cloned()
            .unwrap_or_else(|| {
                semantic_candidate_values_for_role(
                    &control,
                    &role_name,
                    evidence_capture.as_deref(),
                    &moving_required_axes,
                    &axis_controls,
                )
            });
        semantic_candidate_count += semantic_candidates.len();
        ambiguous_semantic_candidate_count += semantic_candidates
            .iter()
            .filter(|candidate| json_string(candidate, "confidence") == Some("ambiguous_candidate"))
            .count();

        let entry = serde_json::json!({
            "control": control,
            "role": role_name,
            "required": required,
            "semantic_status": semantic_status,
            "parser_visible": parser_visible,
            "evidence_capture": evidence_capture,
            "moving_required_axes": moving_required_axes,
            "missing_requirements": missing_requirements,
            "semantic_candidates": semantic_candidates,
            "notes": notes
        });

        if required && json_string(&entry, "semantic_status") == Some("generic_aux") {
            generic_aux_roles.push(entry.clone());
        }
        if required
            && matches!(
                json_string(&entry, "semantic_status"),
                Some("missing" | "unavailable" | "unknown")
            )
        {
            incomplete_roles.push(entry.clone());
        }
        roles.push(entry);
    }

    let semantic_status = if selected_stage.is_none() {
        "unavailable"
    } else if !incomplete_roles.is_empty() {
        "incomplete_role_mapping"
    } else if !generic_aux_roles.is_empty() {
        "partial_generic_aux_mapping"
    } else {
        "all_required_roles_semantically_proven"
    };
    let semantic_mapping_complete = semantic_status == "all_required_roles_semantically_proven";
    let unproven_required_role_count = generic_aux_roles.len() + incomplete_roles.len();

    serde_json::json!({
        "source_stage": selected_stage,
        "source_artifact": selected_path,
        "semantic_status": semantic_status,
        "semantic_mapping_complete": semantic_mapping_complete,
        "required_role_count": required_role_count,
        "required_parser_visible_count": required_parser_visible_count,
        "generic_aux_role_count": generic_aux_roles.len(),
        "incomplete_role_count": incomplete_roles.len(),
        "unproven_required_role_count": unproven_required_role_count,
        "semantic_candidate_count": semantic_candidate_count,
        "ambiguous_semantic_candidate_count": ambiguous_semantic_candidate_count,
        "status_counts": status_counts,
        "generic_aux_roles": generic_aux_roles,
        "incomplete_roles": incomplete_roles,
        "roles": roles,
        "passive_artifacts_remain_valid": true,
        "blocks_native_control": false,
        "blocks_native_visible": false,
        "blocks_smoke_ready": false,
        "readiness_claim": false,
        "notes": [
            "input role semantics are diagnostic navigation only; they do not open HID or send output",
            "generic_aux means the capture showed parser-visible R5 extended-field movement, but the role-specific semantic mapping remains unproven",
            "semantic_candidates name observed R5 V1 extended slots from isolated captures only; they are not readiness claims",
            "generic_aux evidence can keep passive artifacts valid while still marking input topology semantics as incomplete for product-quality follow-up"
        ]
    })
}

fn stored_highest_passing_stage(lane: &Path) -> &'static str {
    [
        (MozaBundleStage::SmokeReady, "smoke_ready"),
        (MozaBundleStage::NativeVisibleReady, "native_visible_ready"),
        (
            MozaBundleStage::NativeResponseReady,
            "native_response_ready",
        ),
        (
            MozaBundleStage::OpenRacingControlReady,
            "openracing_control_ready",
        ),
        (MozaBundleStage::Zero, "zero"),
        (MozaBundleStage::Passive, "passive"),
    ]
    .into_iter()
    .find_map(|(stage, label)| stored_verification_success(lane, stage).then_some(label))
    .unwrap_or("none")
}

fn next_stage_after(stage: &str) -> Option<&'static str> {
    match stage {
        "none" => Some("passive"),
        "passive" => Some("zero"),
        "zero" => Some("openracing_control_ready"),
        "openracing_control_ready" => Some("native_response_ready"),
        "native_response_ready" => Some("native_visible_ready"),
        "native_visible_ready" => Some("smoke_ready"),
        "smoke_ready" => None,
        _ => Some("passive"),
    }
}

fn stored_verification_success(lane: &Path, stage: MozaBundleStage) -> bool {
    read_json_value(lane, verification_receipt_path(stage))
        .ok()
        .and_then(|receipt| json_bool(&receipt, "success"))
        == Some(true)
}

fn stored_verification_gate_passed(lane: &Path, stage: MozaBundleStage, gate_name: &str) -> bool {
    let Ok(receipt) = read_json_value(lane, verification_receipt_path(stage)) else {
        return false;
    };
    receipt
        .get("gates")
        .and_then(Value::as_array)
        .map(|gates| {
            gates.iter().any(|gate| {
                json_string(gate, "name") == Some(gate_name)
                    && json_string(gate, "status") == Some("pass")
            })
        })
        .unwrap_or(false)
}

fn discover_lane_artifacts(lane: &Path) -> Result<Vec<Value>> {
    let mut paths = Vec::new();
    collect_lane_artifact_paths(lane, &mut paths)?;
    paths.sort_by(|left, right| {
        let left = lane_relative_or_display(lane, left);
        let right = lane_relative_or_display(lane, right);
        left.cmp(&right)
    });

    Ok(paths
        .into_iter()
        .filter_map(|path| lane_artifact_index_entry(lane, &path))
        .collect())
}

fn collect_lane_artifact_paths(directory: &Path, paths: &mut Vec<PathBuf>) -> Result<()> {
    for entry in fs::read_dir(directory)
        .with_context(|| format!("failed to read '{}'", directory.display()))?
    {
        let entry =
            entry.with_context(|| format!("failed to read entry in '{}'", directory.display()))?;
        let path = entry.path();
        if path.is_dir() {
            collect_lane_artifact_paths(&path, paths)?;
        } else if lane_artifact_file_kind(&path).is_some() {
            paths.push(path);
        }
    }
    Ok(())
}

fn lane_artifact_index_entry(lane: &Path, path: &Path) -> Option<Value> {
    let kind = lane_artifact_file_kind(path)?;
    let relative_path = lane_relative_or_display(lane, path);
    let category = lane_artifact_category(&relative_path);
    let metadata = fs::metadata(path).ok();
    Some(serde_json::json!({
        "path": relative_path,
        "kind": kind,
        "category": category,
        "exists": true,
        "size_bytes": metadata.as_ref().map(fs::Metadata::len),
        "readiness_evidence": lane_artifact_readiness_evidence(&relative_path),
    }))
}

fn lane_artifact_file_kind(path: &Path) -> Option<&'static str> {
    match path
        .extension()
        .and_then(|extension| extension.to_str())
        .map(|extension| extension.to_ascii_lowercase())
        .as_deref()
    {
        Some("json") => Some("json"),
        Some("jsonl") => Some("jsonl"),
        Some("md") => Some("markdown"),
        _ => None,
    }
}

fn lane_artifact_category(relative_path: &str) -> &'static str {
    if relative_path == "index.md" || relative_path.contains("pre-output-readiness") {
        return "support";
    }
    if relative_path.starts_with("captures/") {
        return "passive";
    }
    if relative_path.starts_with("sniff/") || relative_path.contains("sniff") {
        return "sniff";
    }
    if relative_path.contains("vendor-protocol-evidence-review") {
        return "sniff";
    }
    if relative_path.contains("pit-house") {
        return "pit_house";
    }
    if relative_path.contains("simulator") {
        return "simulator";
    }
    if relative_path.contains("controlled-angle")
        || relative_path.contains("pidff")
        || relative_path.contains("visible")
    {
        return "native_visible";
    }
    if relative_path.contains("native-response") {
        return "native_response";
    }
    if relative_path.contains("zero")
        || relative_path.contains("watchdog")
        || relative_path.contains("disconnect")
    {
        return "zero_safety";
    }
    if matches!(
        relative_path,
        "init-off.json"
            | "init-standard.json"
            | "low-torque-proof.json"
            | "steering-angle-stream-proof.json"
            | "steering-angle-stream.jsonl"
            | "native-actuator-profile-smoke.json"
    ) {
        return "openracing_control";
    }
    if relative_path.contains("support-bundle")
        || relative_path.contains("moza-status")
        || relative_path.contains("device-status")
    {
        return "support";
    }
    if relative_path.contains("smoke-ready") {
        return "smoke";
    }
    "passive"
}

fn lane_artifact_readiness_evidence(relative_path: &str) -> &'static str {
    match lane_artifact_category(relative_path) {
        "passive" => "passive_input_or_descriptor_evidence",
        "zero_safety" => "zero_torque_safety_evidence",
        "openracing_control" => "native_control_foundation_evidence",
        "native_response" => "native_response_evidence",
        "native_visible" => "native_visible_or_pidff_diagnosis_evidence",
        "pit_house" => "external_compatibility_evidence",
        "simulator" => "external_simulator_evidence",
        "smoke" => "smoke_readiness_evidence",
        "support" => "diagnostic_support_evidence",
        "sniff" => "passive_protocol_research_evidence",
        _ => "diagnostic_evidence",
    }
}

fn moza_lane_frontier_label(lane: &Path, support_status: &Value) -> String {
    if native_controlled_angle_closed_loop_smoke_is_real_output_attempt(lane) {
        "closed_loop_undertravel_recorded".to_string()
    } else if lane
        .join(NATIVE_CONTROLLED_ANGLE_ATTEMPT_03_SMOKE_FILE)
        .is_file()
    {
        "controlled_angle_attempt_03_recorded".to_string()
    } else if lane
        .join(NATIVE_CONTROLLED_ANGLE_ATTEMPT_03_PREFLIGHT_FILE)
        .is_file()
    {
        "repeated_safe_undertravel_attempt_03_preflight_recorded".to_string()
    } else if lane.join(NATIVE_PIDFF_EFFECT_LIFECYCLE_PLAN_FILE).is_file() {
        "pidff_effect_lifecycle_profile_planned".to_string()
    } else if lane.join(NATIVE_PIDFF_SEMANTICS_DIAGNOSIS_FILE).is_file() {
        "repeated_safe_undertravel".to_string()
    } else {
        support_status
            .pointer("/readiness/highest_passing_stage")
            .and_then(Value::as_str)
            .unwrap_or("unknown")
            .to_string()
    }
}

fn support_bundle_status_for_receipt_validation(lane: &Path) -> Value {
    support_bundle_status_with_support_validation(lane, SupportBundleValidationMode::ShapeOnly)
}

fn support_bundle_status_with_support_validation(
    lane: &Path,
    support_validation: SupportBundleValidationMode,
) -> Value {
    let manifest_path = lane.join("manifest.json");
    let manifest = match read_json_path(&manifest_path) {
        Ok(value) => serde_json::json!({
            "present": true,
            "completion_state": json_string(&value, "completion_state"),
            "hardware_validated": json_bool(&value, "hardware_validated"),
            "simulator_validated": json_bool(&value, "simulator_validated"),
            "high_torque_validated": json_bool(&value, "high_torque_validated"),
            "release_ready": json_bool(&value, "release_ready")
        }),
        Err(error) => serde_json::json!({
            "present": manifest_path.exists(),
            "error": error.to_string()
        }),
    };

    let passive = verify_bundle_dir_with_support_validation(
        lane,
        MozaBundleStage::Passive,
        support_validation,
    );
    let zero =
        verify_bundle_dir_with_support_validation(lane, MozaBundleStage::Zero, support_validation);
    let openracing_control = verify_bundle_dir_with_support_validation(
        lane,
        MozaBundleStage::OpenRacingControlReady,
        support_validation,
    );
    let native_response = verify_bundle_dir_with_support_validation(
        lane,
        MozaBundleStage::NativeResponseReady,
        support_validation,
    );
    let native_visible = verify_bundle_dir_with_support_validation(
        lane,
        MozaBundleStage::NativeVisibleReady,
        support_validation,
    );
    let smoke_ready = verify_bundle_dir_with_support_validation(
        lane,
        MozaBundleStage::SmokeReady,
        support_validation,
    );
    let passive_audit_passed = stored_lane_audit_receipt_passed(lane, MozaBundleStage::Passive);
    let zero_audit_passed = stored_lane_audit_receipt_passed(lane, MozaBundleStage::Zero);
    let openracing_control_audit_passed =
        stored_lane_audit_receipt_passed(lane, MozaBundleStage::OpenRacingControlReady);
    let native_response_audit_passed =
        stored_lane_audit_receipt_passed(lane, MozaBundleStage::NativeResponseReady);
    let native_visible_audit_passed =
        stored_lane_audit_receipt_passed(lane, MozaBundleStage::NativeVisibleReady);
    let smoke_ready_audit_passed =
        stored_lane_audit_receipt_passed(lane, MozaBundleStage::SmokeReady);
    let readiness = support_readiness_summary(SupportReadinessInputs {
        lane,
        passive: &passive,
        zero: &zero,
        openracing_control: &openracing_control,
        native_response: &native_response,
        native_visible: &native_visible,
        smoke_ready: &smoke_ready,
        audits: SupportReadinessAudits {
            passive: passive_audit_passed,
            zero: zero_audit_passed,
            openracing_control: openracing_control_audit_passed,
            native_response: native_response_audit_passed,
            native_visible: native_visible_audit_passed,
            smoke_ready: smoke_ready_audit_passed,
        },
    });
    let artifact_index: Vec<_> = lane_artifact_index_requirements()
        .map(|requirement| check_bundle_artifact(lane, &requirement))
        .collect();

    serde_json::json!({
        "lane": lane.display().to_string(),
        "lane_directory_present": lane.is_dir(),
        "generated_at_utc": now_utc(),
        "manifest": manifest,
        "artifact_index": artifact_index,
        "readiness": readiness,
        "verifications": {
            "passive": support_verification_summary(&passive),
            "zero": support_verification_summary(&zero),
            "openracing_control_ready": support_verification_summary(&openracing_control),
            "native_response_ready": support_verification_summary(&native_response),
            "native_visible_ready": support_verification_summary(&native_visible),
            "smoke_ready": support_verification_summary(&smoke_ready)
        },
        "notes": [
            "support bundle status reads Moza lane receipts only; it opens no HID device and sends no reports",
            "support bundle status is diagnostic context, not a readiness promotion or release claim"
        ]
    })
}

struct SupportReadinessAudits {
    passive: bool,
    zero: bool,
    openracing_control: bool,
    native_response: bool,
    native_visible: bool,
    smoke_ready: bool,
}

struct SupportReadinessInputs<'a> {
    lane: &'a Path,
    passive: &'a BundleVerificationReceipt,
    zero: &'a BundleVerificationReceipt,
    openracing_control: &'a BundleVerificationReceipt,
    native_response: &'a BundleVerificationReceipt,
    native_visible: &'a BundleVerificationReceipt,
    smoke_ready: &'a BundleVerificationReceipt,
    audits: SupportReadinessAudits,
}

fn support_readiness_summary(inputs: SupportReadinessInputs<'_>) -> Value {
    let SupportReadinessInputs {
        lane,
        passive,
        zero,
        openracing_control,
        native_response,
        native_visible,
        smoke_ready,
        audits,
    } = inputs;
    let init_handshakes_pass = bundle_gate_passed(openracing_control, "init_off_handshake")
        && bundle_gate_passed(openracing_control, "init_standard_handshake");
    let (highest_passing_stage, next_required_stage) = if smoke_ready.success {
        ("smoke_ready", Value::Null)
    } else if native_visible.success {
        (
            "native_visible_ready",
            Value::String("smoke_ready".to_string()),
        )
    } else if native_response.success {
        (
            "native_response_ready",
            Value::String("native_visible_ready".to_string()),
        )
    } else if openracing_control.success {
        (
            "openracing_control_ready",
            Value::String("native_response_ready".to_string()),
        )
    } else if zero.success {
        (
            "zero",
            Value::String("openracing_control_ready".to_string()),
        )
    } else if passive.success {
        ("passive", Value::String("zero".to_string()))
    } else {
        ("none", Value::String("passive".to_string()))
    };

    let first_blocking = if !passive.success {
        support_verification_summary(passive)
    } else if !zero.success {
        support_verification_summary(zero)
    } else if !openracing_control.success {
        support_verification_summary(openracing_control)
    } else if !native_response.success {
        support_verification_summary(native_response)
    } else if !native_visible.success {
        support_verification_summary(native_visible)
    } else if !smoke_ready.success {
        support_verification_summary(smoke_ready)
    } else {
        Value::Null
    };
    let native_control_blocking_items = support_native_control_blocking_items(
        zero.success,
        audits.zero,
        openracing_control,
        audits.openracing_control,
    );
    let ready_for_native_control = native_control_blocking_items.is_empty();
    let native_actuator_response_proven =
        bundle_gate_passed(native_response, "native_actuator_response_smoke");
    let native_visible_motion_proven =
        bundle_gate_passed(native_visible, "native_actuator_visible_smoke");
    let external_compatibility_blocking_items =
        support_external_compatibility_blocking_items(smoke_ready, audits.smoke_ready);
    let ready_for_external_compatibility = external_compatibility_blocking_items.is_empty();

    serde_json::json!({
        "highest_passing_stage": highest_passing_stage,
        "next_required_stage": next_required_stage,
        "ready_for_zero_torque": passive.success && audits.passive,
        "ready_for_low_torque": support_ready_for_low_torque(lane, zero.success, audits.zero, init_handshakes_pass),
        "ready_for_native_control": ready_for_native_control,
        "native_control_blocking_items": native_control_blocking_items,
        "native_actuator_response_proven": native_actuator_response_proven,
        "native_visible_motion_proven": native_visible_motion_proven,
        "ready_for_external_compatibility": ready_for_external_compatibility,
        "external_compatibility_blocking_items": external_compatibility_blocking_items,
        "ready_for_real_hardware_smoke": smoke_ready.success && audits.smoke_ready,
        "passive_lane_audit_passed": audits.passive,
        "zero_lane_audit_passed": audits.zero,
        "openracing_control_lane_audit_passed": audits.openracing_control,
        "native_response_lane_audit_passed": audits.native_response,
        "native_visible_lane_audit_passed": audits.native_visible,
        "smoke_ready_lane_audit_passed": audits.smoke_ready,
        "release_ready": false,
        "first_blocking_stage": first_blocking,
        "claim_scope": "diagnostic_context_only"
    })
}

fn support_native_control_blocking_items(
    zero_success: bool,
    zero_audit_passed: bool,
    openracing_control: &BundleVerificationReceipt,
    openracing_control_audit_passed: bool,
) -> Vec<String> {
    let zero = PreOutputVerificationReceipt {
        success: zero_success,
        requested_stage: "zero".to_string(),
        missing_artifacts: 0,
        invalid_artifacts: 0,
        failed_gates: if zero_success { 0 } else { 1 },
        artifacts: Vec::new(),
        gates: Vec::new(),
        role_evidence: Vec::new(),
    };
    let native = pre_output_receipt_from_bundle(openracing_control);
    pre_output_native_control_blocking_items(
        &zero,
        &native,
        zero_audit_passed,
        openracing_control_audit_passed,
    )
}

fn support_external_compatibility_blocking_items(
    smoke_ready: &BundleVerificationReceipt,
    smoke_ready_audit_passed: bool,
) -> Vec<String> {
    let smoke = pre_output_receipt_from_bundle(smoke_ready);
    pre_output_external_compatibility_blocking_items(&smoke, smoke_ready_audit_passed)
}

fn pre_output_receipt_from_bundle(
    receipt: &BundleVerificationReceipt,
) -> PreOutputVerificationReceipt {
    PreOutputVerificationReceipt {
        success: receipt.success,
        requested_stage: receipt.requested_stage.clone(),
        missing_artifacts: receipt.missing_artifacts,
        invalid_artifacts: receipt.invalid_artifacts,
        failed_gates: receipt.failed_gates,
        artifacts: receipt
            .artifacts
            .iter()
            .map(|artifact| PreOutputVerificationArtifact {
                path: artifact.path.clone(),
                status: artifact.status.clone(),
            })
            .collect(),
        gates: receipt
            .gates
            .iter()
            .map(|gate| PreOutputVerificationGate {
                name: gate.name.to_string(),
                status: gate.status.to_string(),
            })
            .collect(),
        role_evidence: receipt
            .role_evidence
            .iter()
            .map(|role| PreOutputRoleEvidence {
                required: role.required,
                parser_visible: role.parser_visible,
                missing_requirements: role.missing_requirements.clone(),
            })
            .collect(),
    }
}

fn support_ready_for_low_torque(
    lane: &Path,
    zero_success: bool,
    zero_audit_passed: bool,
    init_handshakes_pass: bool,
) -> bool {
    zero_success
        && zero_audit_passed
        && init_handshakes_pass
        && (low_torque_frontier_blockers(lane).is_empty()
            || pidff_low_torque_frontier_blockers(lane).is_empty())
}

fn stored_lane_audit_receipt_passed(lane: &Path, stage: MozaBundleStage) -> bool {
    let path = audit_receipt_path(stage);
    let Ok(receipt) = read_json_value(lane, path) else {
        return false;
    };

    let receipt_checks_ok = receipt
        .get("receipt_checks")
        .and_then(Value::as_array)
        .map(|checks| {
            let expected_check_count = audit_stages_through(stage).len() * 2;
            checks.len() == expected_check_count
                && checks
                    .iter()
                    .all(|check| json_string(check, "status") == Some("pass"))
        })
        .unwrap_or(false);

    json_bool(&receipt, "success") == Some(true)
        && json_string(&receipt, "command") == Some("wheelctl moza audit-lane")
        && path_value_matches(lane, json_string(&receipt, "lane"))
        && json_string(&receipt, "requested_stage") == Some(stage_label(stage))
        && json_bool(&receipt, "live_verification_success") == Some(true)
        && json_u64(&receipt, "missing_receipts") == Some(0)
        && json_u64(&receipt, "invalid_receipts") == Some(0)
        && receipt_checks_ok
        && json_bool(&receipt, "no_hid_device_opened") == Some(true)
        && json_bool(&receipt, "no_ffb_writes") == Some(true)
        && no_out_of_scope_device_commands(&receipt)
}

fn bundle_gate_passed(receipt: &BundleVerificationReceipt, name: &str) -> bool {
    receipt
        .gates
        .iter()
        .any(|gate| gate.name == name && gate.status == "pass")
}

fn support_verification_summary(receipt: &BundleVerificationReceipt) -> Value {
    let missing_artifacts: Vec<_> = receipt
        .artifacts
        .iter()
        .filter(|artifact| artifact.status == "missing")
        .map(|artifact| artifact.path.clone())
        .collect();
    let invalid_artifacts: Vec<_> = receipt
        .artifacts
        .iter()
        .filter(|artifact| artifact.status == "invalid")
        .map(|artifact| artifact.path.clone())
        .collect();
    let failed_gates: Vec<_> = receipt
        .gates
        .iter()
        .filter(|gate| gate.status == "fail")
        .map(|gate| gate.name)
        .collect();

    serde_json::json!({
        "success": receipt.success,
        "requested_stage": receipt.requested_stage,
        "missing_artifacts": receipt.missing_artifacts,
        "invalid_artifacts": receipt.invalid_artifacts,
        "failed_gates": receipt.failed_gates,
        "missing_artifact_paths": missing_artifacts,
        "invalid_artifact_paths": invalid_artifacts,
        "failed_gate_names": failed_gates
    })
}

fn build_capture_fixture(
    capture: &Path,
    fixture_id: &str,
    pid_override: Option<u16>,
    max_reports: usize,
) -> Result<MozaCaptureFixture> {
    if fixture_id.trim().is_empty() {
        return Err(anyhow!("--fixture-id must not be empty"));
    }
    if max_reports == 0 || max_reports > 10_000 {
        return Err(anyhow!("--max-reports must be in 1..=10000"));
    }

    let file =
        File::open(capture).with_context(|| format!("failed to open '{}'", capture.display()))?;
    let reader = BufReader::new(file);
    let mut summary = CaptureValidationSummary::default();
    let mut product_ids = BTreeMap::new();
    let mut reports = Vec::new();

    for (idx, line) in reader.lines().enumerate() {
        let line_no = idx + 1;
        let line = line.with_context(|| format!("failed to read line {line_no}"))?;

        if line.trim().is_empty() {
            continue;
        }

        summary.total_reports += 1;

        let parsed_line: CapturedInputReportLine = serde_json::from_str(&line)
            .with_context(|| format!("invalid JSON capture line {line_no}"))?;

        let pid = pid_override
            .or_else(|| {
                parsed_line
                    .product_id
                    .as_deref()
                    .and_then(parse_hex_selector)
            })
            .ok_or_else(|| {
                anyhow!("line {line_no} is missing product_id; pass --pid to override")
            })?;

        let data = parsed_line
            .decode_data()
            .map_err(|e| anyhow!("line {line_no}: {e}"))?;
        if let Some(expected_len) = parsed_line.report_len
            && expected_len != data.len()
        {
            return Err(anyhow!(
                "line {line_no}: report_len mismatch: declared {expected_len}, decoded {}",
                data.len()
            ));
        }

        let report_id = data.first().copied().unwrap_or(0);
        increment_count(&mut summary.report_ids, hex_u8(report_id));
        increment_count(&mut summary.report_lengths, data.len().to_string());
        increment_count(&mut product_ids, hex_u16(pid));

        let protocol = MozaProtocol::new_with_config(pid, FfbMode::Off, false);
        let state = protocol
            .parse_input_state(&data)
            .ok_or_else(|| anyhow!("line {line_no}: Moza parser rejected report"))?;
        summary.record_parsed(pid, &state, &data);

        if reports.len() < max_reports {
            let identity = identify_device(pid);
            reports.push(MozaFixtureReport {
                source_line: line_no,
                product_id: hex_u16(pid),
                product_category: category_label(identity.category).to_string(),
                report_id: hex_u8(report_id),
                report_len: data.len(),
                data_hex: bytes_hex_compact(&data),
                parsed: MozaFixtureParsedState::from_input_state(&state),
            });
        }
    }

    if summary.total_reports == 0 {
        return Err(anyhow!("capture contains no non-empty report lines"));
    }

    Ok(MozaCaptureFixture {
        schema_version: 1,
        fixture_id: fixture_id.to_string(),
        generated_at_utc: now_utc(),
        source_capture: capture.display().to_string(),
        pid_override: pid_override.map(hex_u16),
        no_ffb_writes: true,
        total_reports: summary.total_reports,
        included_reports: reports.len(),
        fixture_truncated: summary.total_reports > reports.len(),
        product_ids,
        parsed_by_category: summary.parsed_by_category,
        report_ids: summary.report_ids,
        report_lengths: summary.report_lengths,
        axis_ranges: summary.axis_ranges,
        reports,
        notes: vec![
            "fixture was generated offline from capture JSONL and parser replay".to_string(),
            "fixture omits HID path, manufacturer, product string, and raw device identity data"
                .to_string(),
        ],
    })
}

