fn vendor_status_timing_correlation_review_receipt(
    semantic_review_path: &Path,
    semantic_review: &Value,
    capture_provenance_input: VendorStatusTimingCorrelationCaptureProvenanceInput<'_>,
    summary_path: &Path,
    summary: &Value,
    operator_notes_path: &Path,
    operator_notes: &str,
) -> Result<Value> {
    validate_vendor_status_timing_correlation_plan_source(semantic_review_path, semantic_review)?;
    validate_vendor_status_timing_correlation_review_summary(summary_path, summary)?;
    let capture_provenance =
        vendor_status_timing_correlation_capture_provenance(summary, capture_provenance_input)?;
    let capture_provenance_verified =
        json_bool(&capture_provenance, "capture_provenance_verified") == Some(true);

    let required_markers = vendor_status_timing_correlation_required_markers();
    let present_markers = required_markers
        .iter()
        .copied()
        .filter(|marker| operator_notes.contains(marker))
        .map(str::to_string)
        .collect::<Vec<_>>();
    let missing_markers = required_markers
        .iter()
        .copied()
        .filter(|marker| !operator_notes.contains(marker))
        .map(str::to_string)
        .collect::<Vec<_>>();
    let event_marker_notes_complete = missing_markers.is_empty();
    let marker_times =
        vendor_status_timing_correlation_marker_times(operator_notes, &required_markers);
    let marker_times_present = marker_times.keys().cloned().collect::<Vec<_>>();
    let marker_times_missing = required_markers
        .iter()
        .copied()
        .filter(|marker| !marker_times.contains_key(*marker))
        .map(str::to_string)
        .collect::<Vec<_>>();
    let event_marker_timestamps_complete = marker_times_missing.is_empty();
    let event_marker_order_violations =
        vendor_status_timing_correlation_event_marker_order_violations(&marker_times);
    let operator_event_marker_order_valid =
        event_marker_timestamps_complete && event_marker_order_violations.is_empty();
    let capture_receipt_window =
        vendor_status_timing_correlation_capture_receipt_window_marker_status(
            &capture_provenance,
            &marker_times,
            event_marker_timestamps_complete,
            operator_event_marker_order_valid,
        );
    let capture_receipt_window_verified =
        json_bool(&capture_receipt_window, "capture_receipt_window_verified") == Some(true);
    let correlation_marker_ids = vendor_status_timing_correlation_semantic_event_markers();
    let administrative_marker_ids = vendor_status_timing_correlation_administrative_event_markers();
    let correlation_marker_times = marker_times
        .iter()
        .filter(|(marker, _)| correlation_marker_ids.contains(&marker.as_str()))
        .map(|(marker, epoch_seconds)| (marker.clone(), *epoch_seconds))
        .collect::<BTreeMap<_, _>>();

    let target_tuple_ids = vendor_status_timing_correlation_target_tuple_ids();
    let semantic_samples = semantic_review
        .get("reviewed_payload_source_samples")
        .and_then(Value::as_array)
        .ok_or_else(|| {
            anyhow!(
                "payload-source semantic review '{}' is missing reviewed_payload_source_samples",
                semantic_review_path.display()
            )
        })?;
    let semantic_payload_by_tuple = semantic_samples
        .iter()
        .filter_map(|sample| {
            let tuple_id = json_string(sample, "tuple_id")?;
            let payload_hex = json_string(sample, "payload_hex")?;
            Some((tuple_id.to_string(), payload_hex.to_string()))
        })
        .collect::<BTreeMap<_, _>>();

    let summary_serial_frames =
        device_to_host_serial_frame_summary_from_observed_reports(summary, "reviewed_summary");
    let mut summary_payloads_by_tuple = BTreeMap::<String, BTreeSet<String>>::new();
    let mut summary_samples_by_tuple = BTreeMap::<String, Vec<Value>>::new();
    for sample in &summary_serial_frames.tuple_samples {
        if !target_tuple_ids.contains(&sample.tuple_id.as_str()) {
            continue;
        }
        summary_payloads_by_tuple
            .entry(sample.tuple_id.clone())
            .or_default()
            .insert(sample.payload_hex.clone());
        summary_samples_by_tuple
            .entry(sample.tuple_id.clone())
            .or_default()
            .push(vendor_status_timing_correlation_sample_json(sample));
    }

    let summary_has_packet_timestamp_samples =
        summary_samples_by_tuple.values().flatten().any(|sample| {
            sample.get("frame_time_epoch").is_some()
                || sample.get("frame_time").is_some()
                || sample.get("packet_time_epoch").is_some()
                || sample.get("packet_timestamp_epoch").is_some()
        });
    let (
        target_sample_timestamp_count,
        target_samples_outside_capture_window,
        target_samples_within_capture_window,
    ) = vendor_status_timing_correlation_capture_window_sample_status(
        &summary_samples_by_tuple,
        &marker_times,
        operator_event_marker_order_valid,
    );
    let mut any_target_samples_observed = false;
    let mut same_tuple_payload_variation_observed = false;
    let mut operator_event_marker_correlation_observed = false;
    let mut same_tuple_payload_variation_with_event_markers_observed = false;
    let mut tuple_reviews = Vec::new();
    for tuple_id in &target_tuple_ids {
        let observed_payloads = summary_payloads_by_tuple
            .get(*tuple_id)
            .map(|payloads| payloads.iter().cloned().collect::<Vec<_>>())
            .unwrap_or_default();
        let observed_samples = summary_samples_by_tuple
            .get(*tuple_id)
            .cloned()
            .unwrap_or_default();
        let sample_count = observed_samples.len();
        any_target_samples_observed |= sample_count > 0;
        let tuple_varied = observed_payloads.len() > 1;
        same_tuple_payload_variation_observed |= tuple_varied;
        let mut correlated_event_markers = BTreeSet::<String>::new();
        let mut correlated_payloads = BTreeSet::<String>::new();
        let mut correlated_samples = Vec::new();
        for sample in &observed_samples {
            let Some(sample_epoch_seconds) = vendor_status_sample_epoch_seconds(sample) else {
                continue;
            };
            let nearest_marker = correlation_marker_times
                .iter()
                .map(|(marker, marker_epoch_seconds)| {
                    let delta_seconds = sample_epoch_seconds - marker_epoch_seconds;
                    (
                        marker,
                        marker_epoch_seconds,
                        delta_seconds,
                        delta_seconds.abs(),
                    )
                })
                .min_by(|left, right| left.3.total_cmp(&right.3));
            if let Some((marker, marker_epoch_seconds, delta_seconds, abs_delta_seconds)) =
                nearest_marker
                && abs_delta_seconds <= VENDOR_STATUS_TIMING_CORRELATION_WINDOW_SECONDS
            {
                correlated_event_markers.insert(marker.clone());
                if let Some(payload_hex) = json_string(sample, "payload_hex") {
                    correlated_payloads.insert(payload_hex.to_string());
                }
                correlated_samples.push(serde_json::json!({
                    "event_marker": marker,
                    "delta_seconds": delta_seconds,
                    "abs_delta_seconds": abs_delta_seconds,
                    "sample_epoch_seconds": sample_epoch_seconds,
                    "marker_epoch_seconds": marker_epoch_seconds,
                    "packet_ordinal": json_u64(sample, "packet_ordinal").unwrap_or(0),
                    "frame_number": sample.get("frame_number").cloned().unwrap_or(Value::Null),
                    "payload_hex": json_string(sample, "payload_hex").unwrap_or("unknown"),
                    "hardware_output_authorized": false,
                    "output_sendability_claim": false,
                    "read_only_probe_allowed": false
                }));
            }
        }
        let tuple_event_correlated = !correlated_event_markers.is_empty();
        operator_event_marker_correlation_observed |= tuple_event_correlated;
        let tuple_varied_near_event_markers = correlated_payloads.len() > 1;
        same_tuple_payload_variation_with_event_markers_observed |= tuple_varied_near_event_markers;
        tuple_reviews.push(serde_json::json!({
            "tuple_id": tuple_id,
            "semantic_review_payload_hex": semantic_payload_by_tuple
                .get(*tuple_id)
                .cloned()
                .unwrap_or_else(|| "unknown".to_string()),
            "summary_observed_sample_count": sample_count,
            "summary_observed_payload_hex_values": observed_payloads,
            "same_tuple_payload_variation_observed": tuple_varied,
            "operator_event_marker_correlation_observed": tuple_event_correlated,
            "same_tuple_payload_variation_with_event_markers_observed": tuple_varied_near_event_markers,
            "correlated_sample_count": correlated_samples.len(),
            "correlated_operator_event_markers": correlated_event_markers.into_iter().collect::<Vec<_>>(),
            "correlated_payload_hex_values": correlated_payloads.into_iter().collect::<Vec<_>>(),
            "correlated_samples": correlated_samples,
            "timing_correlation_status": if sample_count == 0 {
                "missing_from_summary"
            } else if tuple_varied_near_event_markers {
                "candidate_payload_variation_near_operator_events"
            } else if tuple_event_correlated {
                "event_marker_correlated_static_or_single_payload"
            } else if tuple_varied {
                "payload_varies_but_timing_not_proven"
            } else {
                "static_or_single_sample"
            },
            "summary_samples": observed_samples,
            "risk_class": "unknown_do_not_send",
            "semantic_decode_claim": false,
            "registry_promotion_claim": false,
            "output_sendability_claim": false,
            "read_only_probe_allowed": false,
            "hardware_output_authorized": false,
            "native_control_evidence": false
        }));
    }

    let timing_correlation_candidate_without_capture_provenance = event_marker_notes_complete
        && event_marker_timestamps_complete
        && operator_event_marker_order_valid
        && summary_has_packet_timestamp_samples
        && target_samples_within_capture_window
        && same_tuple_payload_variation_with_event_markers_observed;
    let timing_correlation_candidate_observed =
        timing_correlation_candidate_without_capture_provenance
            && capture_provenance_verified
            && capture_receipt_window_verified;
    let timing_correlation_proven = false;
    let timing_correlation_verdict = if !any_target_samples_observed {
        "insufficient_no_target_0x8e_samples"
    } else if timing_correlation_candidate_observed {
        "candidate_payload_variation_correlated_to_operator_events"
    } else if timing_correlation_candidate_without_capture_provenance
        && !capture_provenance_verified
    {
        "insufficient_capture_provenance_missing_or_unverified"
    } else if timing_correlation_candidate_without_capture_provenance
        && capture_provenance_verified
        && !capture_receipt_window_verified
    {
        "insufficient_capture_receipt_window_mismatch"
    } else if !summary_has_packet_timestamp_samples || target_sample_timestamp_count == 0 {
        "insufficient_missing_packet_timestamps"
    } else if !event_marker_notes_complete || !event_marker_timestamps_complete {
        "insufficient_missing_event_markers"
    } else if event_marker_timestamps_complete && !operator_event_marker_order_valid {
        "insufficient_event_marker_order_invalid"
    } else if summary_has_packet_timestamp_samples && !target_samples_within_capture_window {
        "insufficient_target_samples_outside_capture_window"
    } else if operator_event_marker_correlation_observed {
        "insufficient_event_correlated_static_or_single_payload"
    } else if !same_tuple_payload_variation_observed {
        "insufficient_static_or_single_sample_0x8e_payloads"
    } else if same_tuple_payload_variation_observed {
        "payload_varies_but_event_timing_not_proven"
    } else {
        "insufficient_no_timing_correlation_candidate"
    };

    let mut receipt = serde_json::Map::new();
    macro_rules! insert_json {
        ($key:literal, $value:expr) => {
            receipt.insert($key.to_string(), serde_json::json!($value));
        };
    }

    insert_json!("success", true);
    insert_json!("schema_version", 1);
    insert_json!(
        "artifact_kind",
        "moza_vendor_status_timing_correlation_review"
    );
    insert_json!("claim_scope", "no_output_0x8e_timing_correlation_review");
    insert_json!(
        "command",
        "wheelctl moza vendor-status-timing-correlation-review"
    );
    insert_json!("generated_at_utc", now_utc());
    insert_json!(
        "semantic_review_receipt",
        semantic_review_path.display().to_string()
    );
    insert_json!("sniff_summary", summary_path.display().to_string());
    insert_json!("operator_notes", operator_notes_path.display().to_string());
    insert_json!(
        "capture_provenance_inputs_provided",
        json_bool(&capture_provenance, "capture_provenance_inputs_provided").unwrap_or(false)
    );
    insert_json!("capture_provenance_verified", capture_provenance_verified);
    insert_json!("capture_provenance_required_for_candidate", true);
    insert_json!(
        "capture_provenance_status",
        json_string(&capture_provenance, "capture_provenance_status").unwrap_or("unknown")
    );
    receipt.insert("capture_provenance".to_string(), capture_provenance.clone());
    insert_json!("capture_receipt_window_required_for_candidate", true);
    insert_json!(
        "capture_receipt_window_verified",
        capture_receipt_window_verified
    );
    insert_json!(
        "capture_receipt_window_status",
        json_string(&capture_receipt_window, "capture_receipt_window_status").unwrap_or("unknown")
    );
    insert_json!(
        "operator_event_markers_inside_capture_receipt_window",
        json_bool(
            &capture_receipt_window,
            "operator_event_markers_inside_capture_receipt_window"
        )
        .unwrap_or(false)
    );
    receipt.insert(
        "capture_receipt_window".to_string(),
        capture_receipt_window.clone(),
    );
    insert_json!(
        "summary_command",
        json_string(summary, "command").unwrap_or("unknown")
    );
    insert_json!(
        "summary_pcapng_sha256",
        json_string(summary, "pcapng_sha256").unwrap_or("unknown")
    );
    insert_json!(
        "summary_matched_packets",
        json_u64(summary, "matched_packets").unwrap_or(0)
    );
    insert_json!(
        "target_group_id",
        PAYLOAD_BEARING_STATUS_SOURCE_RESPONSE_GROUP_ID
    );
    insert_json!(
        "target_tuple_ids",
        target_tuple_ids
            .iter()
            .copied()
            .map(str::to_string)
            .collect::<Vec<_>>()
    );
    insert_json!(
        "device_to_host_serial_frame_count",
        summary_serial_frames.parsed_frame_count
    );
    insert_json!(
        "device_to_host_serial_frame_checksum_valid_count",
        summary_serial_frames.checksum_valid_frame_count
    );
    insert_json!(
        "device_to_host_serial_frame_shape_decode_gap",
        summary_serial_frames.frame_shape_decode_gap
    );
    insert_json!(
        "target_tuple_sample_count",
        tuple_reviews
            .iter()
            .filter_map(|review| json_u64(review, "summary_observed_sample_count"))
            .sum::<u64>()
    );
    receipt.insert(
        "target_tuple_reviews".to_string(),
        Value::Array(tuple_reviews),
    );
    insert_json!(
        "operator_event_markers_required",
        required_markers
            .iter()
            .copied()
            .map(str::to_string)
            .collect::<Vec<_>>()
    );
    insert_json!("operator_event_marker_count", present_markers.len());
    insert_json!("operator_event_markers_present", present_markers);
    insert_json!("operator_event_markers_missing", missing_markers);
    insert_json!(
        "operator_event_marker_notes_complete",
        event_marker_notes_complete
    );
    insert_json!(
        "operator_event_marker_timestamps_present",
        marker_times_present
    );
    insert_json!(
        "operator_event_marker_timestamps_missing",
        marker_times_missing
    );
    insert_json!(
        "operator_event_marker_timestamps_complete",
        event_marker_timestamps_complete
    );
    insert_json!(
        "operator_event_marker_order_valid",
        operator_event_marker_order_valid
    );
    receipt.insert(
        "operator_event_marker_order_violations".to_string(),
        Value::Array(event_marker_order_violations),
    );
    insert_json!(
        "operator_event_marker_correlation_scope",
        "semantic_operator_events_only"
    );
    insert_json!(
        "operator_event_marker_correlation_markers_allowed",
        correlation_marker_ids
            .iter()
            .copied()
            .map(str::to_string)
            .collect::<Vec<_>>()
    );
    insert_json!(
        "operator_event_marker_correlation_markers_ignored",
        administrative_marker_ids
            .iter()
            .copied()
            .map(str::to_string)
            .collect::<Vec<_>>()
    );
    insert_json!(
        "event_correlation_window_seconds",
        VENDOR_STATUS_TIMING_CORRELATION_WINDOW_SECONDS
    );
    insert_json!(
        "summary_has_packet_timestamp_samples",
        summary_has_packet_timestamp_samples
    );
    insert_json!(
        "target_sample_timestamp_count",
        target_sample_timestamp_count
    );
    insert_json!(
        "target_samples_within_capture_window",
        target_samples_within_capture_window
    );
    receipt.insert(
        "target_samples_outside_capture_window".to_string(),
        Value::Array(target_samples_outside_capture_window),
    );
    insert_json!("any_target_samples_observed", any_target_samples_observed);
    insert_json!(
        "same_tuple_payload_variation_observed",
        same_tuple_payload_variation_observed
    );
    insert_json!(
        "operator_event_marker_correlation_observed",
        operator_event_marker_correlation_observed
    );
    insert_json!(
        "same_tuple_payload_variation_with_event_markers_observed",
        same_tuple_payload_variation_with_event_markers_observed
    );
    insert_json!(
        "timing_correlation_candidate_observed",
        timing_correlation_candidate_observed
    );
    insert_json!(
        "timing_correlation_candidate_without_capture_provenance",
        timing_correlation_candidate_without_capture_provenance
    );
    insert_json!("timing_correlation_proven", timing_correlation_proven);
    insert_json!("timing_correlation_verdict", timing_correlation_verdict);
    insert_json!("payload_bearing_authority_state_source_found", false);
    insert_json!("reviewed_equivalent_status_source_found", false);
    insert_json!("corrected_read_only_probe_ready", false);
    insert_json!("live_read_only_probe_allowed", false);
    insert_json!("authorization_plan_allowed", false);
    insert_json!("motion_attempt_allowed", false);
    insert_json!("native_control_evidence", false);
    insert_json!("hardware_output_authorized", false);
    insert_json!("native_visible_ready", false);
    insert_json!("smoke_ready", false);
    insert_json!("release_ready", false);
    insert_json!("registry_promotion_claim", false);
    insert_json!("output_sendability_claim", false);
    insert_json!("semantic_decode_claim", false);
    insert_json!("wheel_moved_under_openracing", false);
    insert_json!("visible_motion_verified", false);
    insert_json!("output_was_sent", false);
    insert_json!("authority_state", "blocked");
    insert_json!("no_hid_device_opened", true);
    insert_json!("opened_serial_device", false);
    insert_json!("sent_read_only_query_commands", false);
    insert_json!("sent_output_writes", false);
    insert_json!("sent_configuration_writes", false);
    insert_json!("sent_firmware_or_dfu_commands", false);
    insert_json!("high_torque_enabled", false);
    insert_json!("mode_enable_candidates_sendable", false);
    insert_json!("planned_next_output_allowed", false);
    insert_json!("unknown_safety_or_mode_state_blocks_authority", true);
    insert_json!(
        "exact_next_blocker",
        vendor_status_timing_correlation_exact_next_blocker(timing_correlation_verdict)
    );
    insert_json!(
        "next_allowed_action",
        "If this review is insufficient, run the staged passive Pit House 0x8E event-marker capture with complete operator notes and review the derived summary again. If it finds meaningful variation, create a separate reviewed read-only/status plan; do not authorize output from this receipt."
    );
    insert_json!(
        "blocked_actions",
        [
            "live read-only probe based on 0x8E candidates",
            "mode enable write",
            "authority write",
            "output write",
            "configuration write",
            "PIDFF rerun",
            "authorization receipt",
            "hardware writes",
            "high torque",
            "native-control claim",
            "native-visible claim",
            "smoke-ready claim",
            "release-ready claim",
            "firmware or DFU command",
            "unknown host-to-device command"
        ]
    );
    insert_json!(
        "required_artifacts",
        [
            semantic_review_path.display().to_string(),
            summary_path.display().to_string(),
            operator_notes_path.display().to_string(),
            "schemas/moza-vendor-status-timing-correlation-review.schema.json".to_string()
        ]
    );
    insert_json!(
        "notes",
        [
            "This receipt reads stored JSON and Markdown only; it opens no HID or serial device and sends no traffic.",
            "The reviewed 0x8E samples remain unknown_do_not_send status-source questions.",
            "Timing correlation is not semantic decode, registry promotion, read-only probe eligibility, output sendability, authorization input, or motion authorization.",
            "Native visible motion remains blocked; no wheel movement is claimed."
        ]
    );

    Ok(Value::Object(receipt))
}

fn vendor_status_timing_correlation_capture_provenance(
    summary: &Value,
    input: VendorStatusTimingCorrelationCaptureProvenanceInput<'_>,
) -> Result<Value> {
    if input.sniff_capture_receipt_path.is_some() != input.sniff_capture_receipt.is_some()
        || input.sniff_receipt_path.is_some() != input.sniff_receipt.is_some()
        || input.sniff_capture_receipt_path.is_some() != input.sniff_receipt_path.is_some()
    {
        return Err(anyhow!(
            "timing-correlation capture provenance must include both receipt paths and both receipt JSON values"
        ));
    }

    let mut provenance = serde_json::Map::new();
    macro_rules! insert_json {
        ($key:literal, $value:expr) => {
            provenance.insert($key.to_string(), serde_json::json!($value));
        };
    }

    insert_json!("capture_provenance_required_for_candidate", true);

    let (
        Some(sniff_capture_receipt_path),
        Some(sniff_capture_receipt),
        Some(sniff_receipt_path),
        Some(sniff_receipt),
    ) = (
        input.sniff_capture_receipt_path,
        input.sniff_capture_receipt,
        input.sniff_receipt_path,
        input.sniff_receipt,
    )
    else {
        insert_json!("capture_provenance_inputs_provided", false);
        insert_json!("capture_provenance_verified", false);
        insert_json!("capture_provenance_status", "not_provided");
        insert_json!(
            "notes",
            [
                "No capture provenance receipts were supplied; this legacy review can remain blocked, but it cannot surface a candidate timing correlation."
            ]
        );
        return Ok(Value::Object(provenance));
    };

    let capture_path = sniff_capture_receipt_path.display().to_string();
    let receipt_path = sniff_receipt_path.display().to_string();
    insert_json!("capture_provenance_inputs_provided", true);
    insert_json!("sniff_capture_receipt", capture_path);
    insert_json!("sniff_receipt", receipt_path);

    if json_string(sniff_capture_receipt, "command") != Some("wheelctl hardware sniff-capture") {
        return Err(anyhow!(
            "timing-correlation capture receipt '{}' must come from `wheelctl hardware sniff-capture`",
            sniff_capture_receipt_path.display()
        ));
    }
    if json_bool(sniff_capture_receipt, "success") != Some(true) {
        return Err(anyhow!(
            "timing-correlation capture receipt '{}' must have success=true",
            sniff_capture_receipt_path.display()
        ));
    }
    if json_bool(sniff_capture_receipt, "openracing_hardware_output") != Some(false) {
        return Err(anyhow!(
            "timing-correlation capture receipt '{}' must keep openracing_hardware_output=false",
            sniff_capture_receipt_path.display()
        ));
    }
    for field in [
        "native_control_evidence",
        "openracing_hid_device_opened",
        "openracing_ffb_writes",
        "openracing_output_reports",
        "openracing_feature_reports",
        "openracing_serial_config_commands",
        "openracing_firmware_or_dfu_commands",
        "satisfies_native_visible_ready",
        "satisfies_smoke_ready",
        "satisfies_release_ready",
    ] {
        if json_bool(sniff_capture_receipt, field) != Some(false) {
            return Err(anyhow!(
                "timing-correlation capture receipt '{}' must keep {field}=false",
                sniff_capture_receipt_path.display()
            ));
        }
    }
    if json_bool(sniff_capture_receipt, "pcapng_finalization_succeeded") != Some(true) {
        return Err(anyhow!(
            "timing-correlation capture receipt '{}' must have pcapng_finalization_succeeded=true",
            sniff_capture_receipt_path.display()
        ));
    }
    if json_u64(sniff_capture_receipt, "pcapng_size_bytes").unwrap_or(0) == 0 {
        return Err(anyhow!(
            "timing-correlation capture receipt '{}' must record a non-empty pcapng",
            sniff_capture_receipt_path.display()
        ));
    }
    let selector_verification = sniff_capture_receipt
        .get("selector_verification")
        .ok_or_else(|| {
            anyhow!(
                "timing-correlation capture receipt '{}' is missing selector_verification",
                sniff_capture_receipt_path.display()
            )
        })?;
    if json_bool(selector_verification, "verified_moza_selector") != Some(true) {
        return Err(anyhow!(
            "timing-correlation capture receipt '{}' must verify the Moza USBPcap selector",
            sniff_capture_receipt_path.display()
        ));
    }
    if json_bool(selector_verification, "accepted_moza_protocol_evidence") != Some(true) {
        return Err(anyhow!(
            "timing-correlation capture receipt '{}' must have accepted_moza_protocol_evidence=true",
            sniff_capture_receipt_path.display()
        ));
    }
    let capture_hardware_doctor_freshness =
        vendor_status_timing_correlation_capture_hardware_doctor_freshness(
            sniff_capture_receipt_path,
            selector_verification,
        )?;
    let capture_receipt_window = vendor_status_timing_correlation_capture_receipt_window(
        sniff_capture_receipt_path,
        sniff_capture_receipt,
    )?;

    if json_string(sniff_receipt, "command") != Some("wheelctl hardware sniff-receipt") {
        return Err(anyhow!(
            "timing-correlation sniff receipt '{}' must come from `wheelctl hardware sniff-receipt`",
            sniff_receipt_path.display()
        ));
    }
    if json_bool(sniff_receipt, "success") != Some(true) {
        return Err(anyhow!(
            "timing-correlation sniff receipt '{}' must have success=true",
            sniff_receipt_path.display()
        ));
    }
    if json_string(sniff_receipt, "scenario") != Some("pit-house-0x8e-timing-correlation") {
        return Err(anyhow!(
            "timing-correlation sniff receipt '{}' must use scenario pit-house-0x8e-timing-correlation",
            sniff_receipt_path.display()
        ));
    }
    for field in [
        "native_control_evidence",
        "openracing_hardware_output",
        "openracing_hid_device_opened",
        "openracing_ffb_writes",
        "openracing_output_reports",
        "openracing_feature_reports",
        "openracing_serial_config_commands",
        "openracing_firmware_or_dfu_commands",
        "satisfies_native_visible_ready",
        "satisfies_smoke_ready",
        "satisfies_release_ready",
    ] {
        if json_bool(sniff_receipt, field) != Some(false) {
            return Err(anyhow!(
                "timing-correlation sniff receipt '{}' must keep {field}=false",
                sniff_receipt_path.display()
            ));
        }
    }

    let summary_sha = json_string(summary, "pcapng_sha256").unwrap_or("");
    let capture_sha = json_string(sniff_capture_receipt, "pcapng_sha256").unwrap_or("");
    let receipt_sha = json_string(sniff_receipt, "pcapng_sha256").unwrap_or("");
    if summary_sha.is_empty() || summary_sha != capture_sha || summary_sha != receipt_sha {
        return Err(anyhow!(
            "timing-correlation summary/capture/sniff receipt pcapng hashes must match"
        ));
    }
    let capture_out_path = json_string(sniff_capture_receipt, "out_path").unwrap_or("");
    let receipt_pcap_path = json_string(sniff_receipt, "pcapng_path").unwrap_or("");
    if !capture_out_path.is_empty()
        && !receipt_pcap_path.is_empty()
        && capture_out_path != receipt_pcap_path
    {
        return Err(anyhow!(
            "timing-correlation capture out_path '{}' must match sniff receipt pcapng_path '{}'",
            capture_out_path,
            receipt_pcap_path
        ));
    }

    insert_json!("capture_provenance_verified", true);
    insert_json!("capture_provenance_status", "verified");
    insert_json!("summary_pcapng_sha256", summary_sha);
    insert_json!("capture_pcapng_sha256", capture_sha);
    insert_json!("sniff_receipt_pcapng_sha256", receipt_sha);
    insert_json!("capture_out_path", capture_out_path);
    insert_json!("sniff_receipt_pcapng_path", receipt_pcap_path);
    insert_json!(
        "capture_selector_status",
        json_string(selector_verification, "status").unwrap_or("unknown")
    );
    insert_json!(
        "capture_requested_usbpcap_interface",
        json_string(selector_verification, "requested_usbpcap_interface").unwrap_or("unknown")
    );
    insert_json!(
        "capture_requested_devices",
        json_string(selector_verification, "requested_devices").unwrap_or("unknown")
    );
    insert_json!(
        "capture_hardware_doctor_generated_at_utc",
        capture_hardware_doctor_freshness.generated_at_utc
    );
    insert_json!(
        "capture_hardware_doctor_age_seconds",
        capture_hardware_doctor_freshness.age_seconds
    );
    insert_json!(
        "capture_hardware_doctor_freshness_max_age_minutes",
        capture_hardware_doctor_freshness.max_age_minutes
    );
    insert_json!(
        "sniff_capture_started_at_utc",
        capture_receipt_window.started_at_utc
    );
    insert_json!(
        "sniff_capture_expected_stop_at_utc",
        capture_receipt_window.expected_stop_at_utc
    );
    insert_json!(
        "sniff_capture_window_start_epoch_seconds",
        capture_receipt_window.start_epoch_seconds
    );
    insert_json!(
        "sniff_capture_window_stop_epoch_seconds",
        capture_receipt_window.stop_epoch_seconds
    );
    insert_json!(
        "sniff_capture_duration_ms",
        capture_receipt_window.duration_ms
    );
    insert_json!(
        "sniff_capture_window_tolerance_seconds",
        capture_receipt_window.tolerance_seconds
    );
    insert_json!(
        "sniff_receipt_scenario",
        json_string(sniff_receipt, "scenario").unwrap_or("unknown")
    );
    insert_json!("hardware_output_authorized", false);
    insert_json!("native_control_evidence", false);
    insert_json!("native_visible_ready", false);
    insert_json!("output_was_sent", false);
    insert_json!(
        "notes",
        [
            "Capture provenance is derived-only and non-claiming.",
            "Verified provenance is required before a timing-correlation candidate can be surfaced.",
            "The reviewed 0x8E tuples remain unknown_do_not_send."
        ]
    );

    Ok(Value::Object(provenance))
}

#[derive(Debug)]
struct VendorStatusTimingCorrelationCaptureHardwareDoctorFreshness {
    generated_at_utc: String,
    age_seconds: u64,
    max_age_minutes: u64,
}

#[derive(Debug)]
struct VendorStatusTimingCorrelationCaptureReceiptWindow {
    started_at_utc: String,
    expected_stop_at_utc: String,
    start_epoch_seconds: f64,
    stop_epoch_seconds: f64,
    duration_ms: u64,
    tolerance_seconds: f64,
}

fn vendor_status_timing_correlation_capture_hardware_doctor_freshness(
    sniff_capture_receipt_path: &Path,
    selector_verification: &Value,
) -> Result<VendorStatusTimingCorrelationCaptureHardwareDoctorFreshness> {
    let generated_at_utc = json_string(selector_verification, "hardware_doctor_generated_at_utc")
        .ok_or_else(|| {
            anyhow!(
                "timing-correlation capture receipt '{}' must include selector_verification.hardware_doctor_generated_at_utc from a fresh hardware doctor",
                sniff_capture_receipt_path.display()
            )
        })?;
    chrono::DateTime::parse_from_rfc3339(generated_at_utc).with_context(|| {
        format!(
            "timing-correlation capture receipt '{}' has invalid selector_verification.hardware_doctor_generated_at_utc `{generated_at_utc}`",
            sniff_capture_receipt_path.display()
        )
    })?;
    let age_seconds = json_u64(selector_verification, "hardware_doctor_age_seconds").ok_or_else(
        || {
            anyhow!(
                "timing-correlation capture receipt '{}' must include selector_verification.hardware_doctor_age_seconds from sniff-capture --hardware-doctor freshness validation",
                sniff_capture_receipt_path.display()
            )
        },
    )?;
    let max_age_minutes = json_u64(
        selector_verification,
        "hardware_doctor_freshness_max_age_minutes",
    )
    .ok_or_else(|| {
        anyhow!(
            "timing-correlation capture receipt '{}' must include selector_verification.hardware_doctor_freshness_max_age_minutes from sniff-capture --hardware-doctor freshness validation",
            sniff_capture_receipt_path.display()
        )
    })?;
    let expected_max_age = PIT_HOUSE_0X8E_CAPTURE_PREP_MAX_AGE_MINUTES as u64;
    if max_age_minutes != expected_max_age {
        return Err(anyhow!(
            "timing-correlation capture receipt '{}' must use the {expected_max_age}-minute hardware doctor freshness window; got {max_age_minutes}",
            sniff_capture_receipt_path.display()
        ));
    }
    let max_age_seconds = max_age_minutes.checked_mul(60).ok_or_else(|| {
        anyhow!(
            "timing-correlation capture receipt '{}' has an overflowing hardware doctor freshness window",
            sniff_capture_receipt_path.display()
        )
    })?;
    if age_seconds > max_age_seconds {
        return Err(anyhow!(
            "timing-correlation capture receipt '{}' used a stale hardware doctor aged {age_seconds}s, exceeding {max_age_seconds}s; rerun observe-only hardware doctor before capture",
            sniff_capture_receipt_path.display()
        ));
    }

    Ok(
        VendorStatusTimingCorrelationCaptureHardwareDoctorFreshness {
            generated_at_utc: generated_at_utc.to_string(),
            age_seconds,
            max_age_minutes,
        },
    )
}

fn vendor_status_timing_correlation_capture_receipt_window(
    sniff_capture_receipt_path: &Path,
    sniff_capture_receipt: &Value,
) -> Result<VendorStatusTimingCorrelationCaptureReceiptWindow> {
    let started_at_utc = json_string(sniff_capture_receipt, "started_at_utc").ok_or_else(|| {
        anyhow!(
            "timing-correlation capture receipt '{}' must include started_at_utc so review markers can be bound to the bounded capture window",
            sniff_capture_receipt_path.display()
        )
    })?;
    let started_at = chrono::DateTime::parse_from_rfc3339(started_at_utc).with_context(|| {
        format!(
            "timing-correlation capture receipt '{}' has invalid started_at_utc `{started_at_utc}`",
            sniff_capture_receipt_path.display()
        )
    })?;
    let started_at = started_at.with_timezone(&chrono::Utc);
    let duration_ms = json_u64(sniff_capture_receipt, "duration_ms").ok_or_else(|| {
        anyhow!(
            "timing-correlation capture receipt '{}' must include duration_ms so review markers can be bound to the bounded capture window",
            sniff_capture_receipt_path.display()
        )
    })?;
    if duration_ms == 0 {
        return Err(anyhow!(
            "timing-correlation capture receipt '{}' must have nonzero duration_ms",
            sniff_capture_receipt_path.display()
        ));
    }
    let duration_i64 = i64::try_from(duration_ms).with_context(|| {
        format!(
            "timing-correlation capture receipt '{}' duration_ms does not fit in a bounded signed duration",
            sniff_capture_receipt_path.display()
        )
    })?;
    if json_bool(sniff_capture_receipt, "terminated_after_duration") != Some(true) {
        return Err(anyhow!(
            "timing-correlation capture receipt '{}' must have terminated_after_duration=true so the capture window is bounded",
            sniff_capture_receipt_path.display()
        ));
    }

    let expected_stop_at = started_at + chrono::Duration::milliseconds(duration_i64);
    let start_epoch_seconds = started_at.timestamp() as f64
        + f64::from(started_at.timestamp_subsec_nanos()) / 1_000_000_000.0;
    let stop_epoch_seconds = expected_stop_at.timestamp() as f64
        + f64::from(expected_stop_at.timestamp_subsec_nanos()) / 1_000_000_000.0;

    Ok(VendorStatusTimingCorrelationCaptureReceiptWindow {
        started_at_utc: started_at.to_rfc3339_opts(chrono::SecondsFormat::Millis, true),
        expected_stop_at_utc: expected_stop_at.to_rfc3339_opts(chrono::SecondsFormat::Millis, true),
        start_epoch_seconds,
        stop_epoch_seconds,
        duration_ms,
        tolerance_seconds: VENDOR_STATUS_TIMING_CORRELATION_CAPTURE_WINDOW_TOLERANCE_SECONDS,
    })
}

fn vendor_status_timing_correlation_capture_receipt_window_marker_status(
    capture_provenance: &Value,
    marker_times: &BTreeMap<String, f64>,
    event_marker_timestamps_complete: bool,
    operator_event_marker_order_valid: bool,
) -> Value {
    let capture_provenance_verified =
        json_bool(capture_provenance, "capture_provenance_verified") == Some(true);
    let mut status = serde_json::json!({
        "capture_receipt_window_required_for_candidate": true,
        "capture_receipt_window_verified": false,
        "capture_receipt_window_status": "not_applicable_capture_provenance_unverified",
        "operator_event_markers_inside_capture_receipt_window": false,
        "operator_event_markers_outside_capture_receipt_window": [],
        "hardware_output_authorized": false,
        "native_control_evidence": false,
        "native_visible_ready": false,
        "output_was_sent": false
    });

    if !capture_provenance_verified {
        return status;
    }

    let Some(start_epoch_seconds) = json_f64(
        capture_provenance,
        "sniff_capture_window_start_epoch_seconds",
    ) else {
        status["capture_receipt_window_status"] =
            Value::String("missing_sniff_capture_receipt_window".to_string());
        return status;
    };
    let Some(stop_epoch_seconds) = json_f64(
        capture_provenance,
        "sniff_capture_window_stop_epoch_seconds",
    ) else {
        status["capture_receipt_window_status"] =
            Value::String("missing_sniff_capture_receipt_window".to_string());
        return status;
    };
    let Some(tolerance_seconds) =
        json_f64(capture_provenance, "sniff_capture_window_tolerance_seconds")
    else {
        status["capture_receipt_window_status"] =
            Value::String("missing_sniff_capture_receipt_window".to_string());
        return status;
    };

    status["sniff_capture_started_at_utc"] = serde_json::json!(
        json_string(capture_provenance, "sniff_capture_started_at_utc").unwrap_or("unknown")
    );
    status["sniff_capture_expected_stop_at_utc"] = serde_json::json!(
        json_string(capture_provenance, "sniff_capture_expected_stop_at_utc").unwrap_or("unknown")
    );
    status["sniff_capture_window_start_epoch_seconds"] = serde_json::json!(start_epoch_seconds);
    status["sniff_capture_window_stop_epoch_seconds"] = serde_json::json!(stop_epoch_seconds);
    status["sniff_capture_window_tolerance_seconds"] = serde_json::json!(tolerance_seconds);

    if !event_marker_timestamps_complete {
        status["capture_receipt_window_status"] =
            Value::String("missing_event_marker_timestamps".to_string());
        return status;
    }

    if !operator_event_marker_order_valid {
        status["capture_receipt_window_status"] =
            Value::String("event_marker_order_invalid".to_string());
        return status;
    }

    let allowed_start = start_epoch_seconds - tolerance_seconds;
    let allowed_stop = stop_epoch_seconds + tolerance_seconds;
    let mut outside_window = Vec::new();
    for marker in vendor_status_timing_correlation_event_marker_order() {
        let Some(marker_epoch_seconds) = marker_times.get(marker).copied() else {
            continue;
        };
        if marker_epoch_seconds < allowed_start || marker_epoch_seconds > allowed_stop {
            outside_window.push(serde_json::json!({
                "marker": marker,
                "marker_epoch_seconds": marker_epoch_seconds,
                "sniff_capture_window_start_epoch_seconds": start_epoch_seconds,
                "sniff_capture_window_stop_epoch_seconds": stop_epoch_seconds,
                "sniff_capture_window_tolerance_seconds": tolerance_seconds,
                "allowed_start_epoch_seconds": allowed_start,
                "allowed_stop_epoch_seconds": allowed_stop,
                "hardware_output_authorized": false,
                "native_control_evidence": false,
                "output_sendability_claim": false,
                "read_only_probe_allowed": false
            }));
        }
    }

    status["operator_event_markers_outside_capture_receipt_window"] =
        serde_json::json!(outside_window);
    if status
        .get("operator_event_markers_outside_capture_receipt_window")
        .and_then(Value::as_array)
        .is_some_and(Vec::is_empty)
    {
        status["capture_receipt_window_verified"] = Value::Bool(true);
        status["capture_receipt_window_status"] = Value::String("verified".to_string());
        status["operator_event_markers_inside_capture_receipt_window"] = Value::Bool(true);
    } else {
        status["capture_receipt_window_status"] =
            Value::String("operator_markers_outside_sniff_capture_window".to_string());
    }

    status
}

fn validate_vendor_status_timing_correlation_review_summary(
    path: &Path,
    summary: &Value,
) -> Result<()> {
    if json_string(summary, "command") != Some("wheelctl hardware sniff-summary") {
        return Err(anyhow!(
            "timing-correlation summary '{}' must be produced by `wheelctl hardware sniff-summary`",
            path.display()
        ));
    }
    if json_bool(summary, "native_control_evidence") != Some(false) {
        return Err(anyhow!(
            "timing-correlation summary '{}' must keep native_control_evidence=false",
            path.display()
        ));
    }
    if json_bool(summary, "openracing_hardware_output") != Some(false) {
        return Err(anyhow!(
            "timing-correlation summary '{}' must keep openracing_hardware_output=false",
            path.display()
        ));
    }
    if json_bool(summary, "satisfies_native_visible_ready") != Some(false) {
        return Err(anyhow!(
            "timing-correlation summary '{}' must keep satisfies_native_visible_ready=false",
            path.display()
        ));
    }
    if json_bool(summary, "satisfies_smoke_ready") != Some(false) {
        return Err(anyhow!(
            "timing-correlation summary '{}' must keep satisfies_smoke_ready=false",
            path.display()
        ));
    }
    if json_bool(summary, "satisfies_release_ready") != Some(false) {
        return Err(anyhow!(
            "timing-correlation summary '{}' must keep satisfies_release_ready=false",
            path.display()
        ));
    }
    Ok(())
}

