fn validate_vendor_authority_smoke_gates(smoke_dry_run: &Value) -> Result<()> {
    for (path, expected) in [
        ("/success", true),
        ("/authorization_receipt_validated", true),
        ("/authorization_consumed", false),
        ("/exact_authorization", true),
        ("/single_use_authorization", true),
        ("/native_control_evidence", false),
        ("/hardware_output_authorized", false),
        ("/native_visible_ready", false),
        ("/no_hid_device_opened", true),
        ("/no_serial_device_opened", true),
        ("/no_serial_query_sent", true),
        ("/sent_output_writes", false),
        ("/sent_configuration_writes", false),
        ("/sent_firmware_or_dfu_commands", false),
        ("/planned_next_output/allowed", false),
    ] {
        let actual = json_pointer_bool(smoke_dry_run, path)?;
        if actual != expected {
            return Err(anyhow!(
                "smoke dry-run receipt gate `{path}` expected {expected}, got {actual}"
            ));
        }
    }
    for (path, expected) in [
        ("/artifact_kind", "moza_vendor_authority_smoke"),
        ("/claim_scope", "software_vendor_authority_smoke_dry_run"),
        ("/transport_kind", "dry_run_only"),
        ("/codec_status", "fixture_decode_verified_exact_frame"),
    ] {
        let actual = json_pointer_string(smoke_dry_run, path)?;
        if actual != expected {
            return Err(anyhow!(
                "smoke dry-run receipt field `{path}` expected `{expected}`, got `{actual}`"
            ));
        }
    }
    let commands_sent = smoke_dry_run
        .pointer("/commands_sent")
        .and_then(Value::as_array)
        .ok_or_else(|| anyhow!("missing or non-array JSON field `/commands_sent`"))?;
    if !commands_sent.is_empty() {
        return Err(anyhow!(
            "smoke dry-run receipt must not include sent commands"
        ));
    }
    Ok(())
}

fn validate_vendor_authority_smoke_matches_authorization(
    smoke_dry_run: &Value,
    command_id: &str,
    command_name: &str,
    family: &str,
    risk_class: &str,
    frame_sha256: &str,
    payload_sha256: &str,
) -> Result<()> {
    for (path, expected) in [
        ("/planned_next_output/command_id", command_id),
        ("/planned_next_output/command_name", command_name),
        ("/planned_next_output/family", family),
        ("/planned_next_output/risk_class", risk_class),
        ("/planned_next_output/frame_sha256", frame_sha256),
        ("/planned_next_output/payload_sha256", payload_sha256),
    ] {
        let actual = json_pointer_string(smoke_dry_run, path)?;
        if actual != expected {
            return Err(anyhow!(
                "smoke dry-run receipt field `{path}` expected `{expected}`, got `{actual}`"
            ));
        }
    }
    Ok(())
}

fn validate_vendor_authority_authorization_gates(authorization: &Value) -> Result<()> {
    for (path, expected) in [
        ("/success", true),
        ("/native_control_evidence", false),
        ("/hardware_output_authorized", true),
        ("/native_visible_ready", false),
        ("/authorization_consumed", false),
        ("/exact_authorization", true),
        ("/single_use", true),
        ("/no_hid_device_opened", true),
        ("/no_serial_device_opened", true),
        ("/no_serial_query_sent", true),
        ("/sent_output_writes", false),
        ("/sent_configuration_writes", false),
        ("/sent_firmware_or_dfu_commands", false),
    ] {
        let actual = json_pointer_bool(authorization, path)?;
        if actual != expected {
            return Err(anyhow!(
                "authorization receipt gate `{path}` expected {expected}, got {actual}"
            ));
        }
    }
    for (path, expected) in [
        ("/artifact_kind", "moza_vendor_authority_authorization"),
        (
            "/claim_scope",
            "single_use_exact_vendor_authority_authorization",
        ),
        ("/transport_kind", "authorization_receipt_only"),
        ("/codec_status", "fixture_decode_verified_exact_frame"),
    ] {
        let actual = json_pointer_string(authorization, path)?;
        if actual != expected {
            return Err(anyhow!(
                "authorization receipt field `{path}` expected `{expected}`, got `{actual}`"
            ));
        }
    }
    Ok(())
}

fn validate_authorization_not_expired(authorization: &Value) -> Result<()> {
    let expires_at = json_pointer_string(authorization, "/expires_at_utc")?;
    let expires_at = chrono::DateTime::parse_from_rfc3339(expires_at)
        .with_context(|| format!("invalid authorization expires_at_utc `{expires_at}`"))?
        .with_timezone(&chrono::Utc);
    if expires_at <= chrono::Utc::now() {
        return Err(anyhow!(
            "authorization receipt expired at {}",
            expires_at.to_rfc3339_opts(chrono::SecondsFormat::Secs, true)
        ));
    }
    Ok(())
}

fn json_pointer_string<'a>(value: &'a Value, path: &str) -> Result<&'a str> {
    value
        .pointer(path)
        .and_then(Value::as_str)
        .ok_or_else(|| anyhow!("missing or non-string JSON field `{path}`"))
}

fn json_pointer_string_array(value: &Value, path: &str) -> Result<Vec<String>> {
    let array = value
        .pointer(path)
        .and_then(Value::as_array)
        .ok_or_else(|| anyhow!("missing or non-array JSON field `{path}`"))?;
    let mut strings = Vec::with_capacity(array.len());
    for item in array {
        let Some(text) = item.as_str() else {
            return Err(anyhow!("non-string item in JSON field `{path}`"));
        };
        strings.push(text.to_string());
    }
    Ok(strings)
}

fn json_pointer_bool(value: &Value, path: &str) -> Result<bool> {
    value
        .pointer(path)
        .and_then(Value::as_bool)
        .ok_or_else(|| anyhow!("missing or non-bool JSON field `{path}`"))
}

fn json_pointer_utc(value: &Value, path: &str) -> Result<chrono::DateTime<chrono::Utc>> {
    let raw = json_pointer_string(value, path)?;
    chrono::DateTime::parse_from_rfc3339(raw)
        .with_context(|| format!("invalid UTC timestamp `{raw}` at `{path}`"))
        .map(|timestamp| timestamp.with_timezone(&chrono::Utc))
}

fn vendor_command_by_id(command_id: &str) -> Result<&'static MozaVendorCommand> {
    REQUIRED_VENDOR_COMMANDS
        .iter()
        .find(|candidate| candidate.id == command_id)
        .ok_or_else(|| anyhow!("unknown Moza vendor command `{command_id}`"))
}

fn ensure_vendor_authority_exact_authorization_candidate(
    command: &MozaVendorCommand,
) -> Result<()> {
    match command.risk_class {
        MozaRiskClass::VendorControlCandidate
        | MozaRiskClass::VendorOutputCandidate
        | MozaRiskClass::ConfigurationCandidate => Ok(()),
        MozaRiskClass::FirmwareOrDfuForbidden | MozaRiskClass::UnknownDoNotSend => Err(anyhow!(
            "command `{}` is {:?} and must never be authorized",
            command.id,
            command.risk_class
        )),
        _ => Err(anyhow!(
            "command `{}` is {:?} and does not require exact vendor-authority authorization",
            command.id,
            command.risk_class
        )),
    }
}

fn vendor_authority_attempt_write_flags(risk_class: MozaRiskClass) -> (bool, bool) {
    match risk_class {
        MozaRiskClass::VendorOutputCandidate => (true, false),
        MozaRiskClass::ConfigurationCandidate => (false, true),
        MozaRiskClass::VendorControlCandidate => (false, false),
        _ => (false, false),
    }
}

fn validate_vendor_authority_bench_clear_evidence(evidence: &str, command_id: &str) -> Result<()> {
    let lower = evidence.to_ascii_lowercase();
    for required in [
        "bench clear",
        "exact",
        command_id,
        "r5 stable",
        "hands clear",
        "wheel clear",
    ] {
        if !lower.contains(&required.to_ascii_lowercase()) {
            return Err(anyhow!(
                "bench-clear evidence must include `{required}` for the exact vendor-authority command"
            ));
        }
    }
    Ok(())
}

fn authorization_expiration_utc(expires_after_minutes: u64) -> Result<String> {
    let expires_at = chrono::Utc::now()
        .checked_add_signed(chrono::Duration::minutes(
            i64::try_from(expires_after_minutes).context("expiration minutes out of range")?,
        ))
        .ok_or_else(|| anyhow!("failed to compute authorization expiration"))?;
    Ok(expires_at.to_rfc3339_opts(chrono::SecondsFormat::Secs, true))
}

fn sha256_hex(bytes: &[u8]) -> String {
    let digest = Sha256::digest(bytes);
    digest.iter().map(|byte| format!("{byte:02x}")).collect()
}

fn moza_serial_port_identity(serial_port: &str) -> Result<VendorStatusProbePortIdentity> {
    let requested = normalize_serial_port_name(serial_port);
    let ports = serialport::available_ports()
        .context("failed to enumerate serial ports before Moza serial command")?;

    let port_info = ports
        .into_iter()
        .find(|port| normalize_serial_port_name(&port.port_name) == requested)
        .ok_or_else(|| anyhow!("serial port `{serial_port}` was not found"))?;

    match port_info.port_type {
        serialport::SerialPortType::UsbPort(info)
            if info.vid == MOZA_VENDOR_ID && info.pid == product_ids::R5_V1 =>
        {
            Ok(VendorStatusProbePortIdentity {
                port_name: port_info.port_name,
                port_type: "usb".to_string(),
                vendor_id: Some(hex_u16(info.vid)),
                product_id: Some(hex_u16(info.pid)),
                manufacturer: info.manufacturer,
                product: info.product,
                serial_number_present: info.serial_number.is_some(),
            })
        }
        serialport::SerialPortType::UsbPort(info) => Err(anyhow!(
            "serial port `{}` is USB {:04X}:{:04X}, expected MOZA R5 {:04X}:{:04X}",
            port_info.port_name,
            info.vid,
            info.pid,
            MOZA_VENDOR_ID,
            product_ids::R5_V1
        )),
        _ => Err(anyhow!(
            "serial port `{}` is not a USB serial port with MOZA R5 identity",
            port_info.port_name
        )),
    }
}

fn normalize_serial_port_name(serial_port: &str) -> String {
    serial_port
        .trim()
        .trim_start_matches(r"\\.\")
        .to_ascii_lowercase()
}

fn vendor_fake_transport_cli_receipt() -> Result<VendorFakeTransportCliReceipt> {
    let codec_fixture: Value = serde_json::from_str(MOZA_VENDOR_SERIAL_CODEC_FIXTURES_JSON)
        .context("failed to parse checked-in Moza serial codec fixture")?;
    let transport_fixture: Value = serde_json::from_str(MOZA_VENDOR_FAKE_SERIAL_TRANSPORT_JSON)
        .context("failed to parse checked-in Moza fake transport fixture")?;
    let protocol_evidence_review: Value =
        serde_json::from_str(MOZA_VENDOR_PROTOCOL_EVIDENCE_REVIEW_JSON)
            .context("failed to parse checked-in Moza vendor protocol evidence review")?;
    let authority_status_endpoint_candidates: Value =
        serde_json::from_str(MOZA_VENDOR_STATUS_ENDPOINT_CANDIDATES_FROM_PAYLOAD_RERUN_JSON)
            .context(
                "failed to parse checked-in Moza authority-status endpoint candidate receipt",
            )?;
    let fixtures = vendor_serial_fixtures_by_id(&codec_fixture)?;
    let accepted_fixture_ids = json_string_array_field(&transport_fixture, "accepted_fixture_ids")?;
    let blocked_fixture_ids = json_string_array_field(&transport_fixture, "blocked_fixture_ids")?;
    let mut transport = MozaFakeSerialTransport::new();
    let mut accepted_exchanges = Vec::new();

    for fixture_id in &accepted_fixture_ids {
        let fixture = fixtures
            .get(fixture_id.as_str())
            .ok_or_else(|| anyhow!("accepted fixture `{fixture_id}` is missing"))?;
        let frame = fixture_frame_bytes(fixture)?;
        let exchange = transport
            .submit_read_only_fixture_frame(&frame)
            .with_context(|| format!("accepted fixture `{fixture_id}` failed fake transport"))?;
        accepted_exchanges.push(VendorFakeTransportAcceptedExchange {
            fixture_id: fixture_id.clone(),
            command_name: exchange.command_name.to_string(),
            group: exchange.group,
            device_id: exchange.device_id,
            command: exchange.command,
            risk_class: exchange.risk_class.as_registry_str().to_string(),
            synthetic_response_payload_hex: bytes_hex_compact(&exchange.synthetic_response_payload),
        });
    }

    let mut blocked_exchanges = Vec::new();
    for fixture_id in &blocked_fixture_ids {
        let fixture = fixtures
            .get(fixture_id.as_str())
            .ok_or_else(|| anyhow!("blocked fixture `{fixture_id}` is missing"))?;
        let frame = fixture_frame_bytes(fixture)?;
        match transport.submit_read_only_fixture_frame(&frame) {
            Err(MozaFakeSerialTransportError::AuthorizationRequired {
                command_id,
                risk_class,
            }) => {
                blocked_exchanges.push(VendorFakeTransportBlockedExchange {
                    fixture_id: command_id.to_string(),
                    reason: "requires_exact_authorization".to_string(),
                    risk_class: risk_class.as_registry_str().to_string(),
                });
            }
            Err(error) => {
                return Err(error).with_context(|| {
                    format!("blocked fixture `{fixture_id}` failed unexpectedly")
                });
            }
            Ok(exchange) => {
                return Err(anyhow!(
                    "write-like fixture `{}` unexpectedly passed fake transport",
                    exchange.command_id
                ));
            }
        }
    }

    let mut bad_checksum = parse_hex_bytes("7E01281302C9").map_err(anyhow::Error::msg)?;
    let checksum_index = bad_checksum
        .len()
        .checked_sub(1)
        .ok_or_else(|| anyhow!("bad checksum fixture is empty"))?;
    bad_checksum[checksum_index] ^= 1;
    let malformed_frame_rejected = matches!(
        transport.submit_read_only_fixture_frame(&bad_checksum),
        Err(MozaFakeSerialTransportError::Frame(_))
    );
    let unknown_command_rejected = matches!(
        transport.submit_read_only_fixture_frame(
            &parse_hex_bytes("7E01FF13019F").map_err(anyhow::Error::msg)?
        ),
        Err(MozaFakeSerialTransportError::Frame(_))
    );

    let mode_enable_candidate_observations =
        vendor_fake_transport_mode_enable_observations(&mut transport, &protocol_evidence_review)
            .context("failed to observe mode/enable candidates in fake transport")?;
    let mode_enable_candidate_group_count = mode_enable_candidate_observations.len();
    let mode_enable_candidate_frame_count = mode_enable_candidate_observations
        .iter()
        .map(|observation| observation.observed_frame_count)
        .sum();
    let mode_enable_candidate_send_path_rejected_count = mode_enable_candidate_observations
        .iter()
        .map(|observation| observation.send_path_rejected_count)
        .sum();
    let authority_status_endpoint_candidate_observations =
        vendor_fake_transport_authority_status_endpoint_observations(
            &mut transport,
            &protocol_evidence_review,
            &authority_status_endpoint_candidates,
        )
        .context("failed to contain authority-status endpoint candidates in fake transport")?;
    let authority_status_endpoint_candidate_group_count =
        authority_status_endpoint_candidate_observations.len();
    let authority_status_endpoint_candidate_frame_count =
        authority_status_endpoint_candidate_observations
            .iter()
            .map(|observation| observation.observed_frame_count)
            .sum();
    let authority_status_endpoint_candidate_send_path_rejected_count =
        authority_status_endpoint_candidate_observations
            .iter()
            .map(|observation| observation.send_path_rejected_count)
            .sum();
    let authority_command_id_0x07_analog_observations =
        vendor_fake_transport_authority_command_id_0x07_analog_observations(
            &mut transport,
            &authority_status_endpoint_candidates,
        )
        .context("failed to contain authority command-id 0x07 analogs in fake transport")?;
    let authority_command_id_0x07_analog_count =
        authority_command_id_0x07_analog_observations.len();
    let authority_command_id_0x07_analog_frame_count =
        authority_command_id_0x07_analog_observations
            .iter()
            .map(|observation| observation.observed_frame_count)
            .sum();
    let authority_command_id_0x07_analog_send_path_rejected_count =
        authority_command_id_0x07_analog_observations
            .iter()
            .map(|observation| observation.send_path_rejected_count)
            .sum();

    Ok(VendorFakeTransportCliReceipt {
        success: true,
        schema_version: 1,
        artifact_kind: "moza_vendor_no_output_cli",
        claim_scope: "software_cli_fake_transport_only",
        command: "wheelctl moza vendor-fake-transport",
        generated_at_utc: now_utc(),
        native_control_evidence: false,
        hardware_output_authorized: false,
        native_visible_ready: false,
        smoke_ready: false,
        release_ready: false,
        registry_promotion_claim: false,
        output_sendability_claim: false,
        next_allowed_action: "Use this fake-only endpoint-candidate containment proof to identify a payload-bearing authority-state status endpoint before any live probe, output, authorization, registry promotion, or hardware write.",
        blocked_actions: vec![
            "serial device open",
            "read-only hardware probe",
            "serial query send",
            "output write",
            "configuration write",
            "authorization receipt",
            "hardware writes",
            "high torque",
            "native-visible claim",
            "smoke-ready claim",
            "release-ready claim",
            "firmware or DFU command",
            "unknown host-to-device command",
        ],
        required_artifacts: vec![
            "docs/specs/OR-SPEC-0002-moza-r5-vendor-authority-test-lane.md",
            "docs/hardware/moza-r5-vendor-authority-test-plan.md",
            "fixtures/moza/r5/vendor-command-registry.json",
            "fixtures/moza/r5/vendor-serial-codec-fixtures.json",
            "fixtures/moza/r5/vendor-fake-serial-transport.json",
            "ci/hardware/moza-r5/2026-05-13/vendor-protocol-evidence-review.json",
            "ci/hardware/moza-r5/2026-05-13/vendor-status-endpoint-candidates-from-payload-rerun.json",
            "crates/hid-moza-protocol/src/serial/fake_transport.rs",
            "crates/cli/src/commands/moza.rs",
        ],
        no_hid_device_opened: true,
        opened_serial_device: false,
        no_ffb_writes: true,
        no_output_reports: true,
        no_feature_reports: true,
        no_serial_config_commands: true,
        no_firmware_or_dfu_commands: true,
        sent_read_only_query_commands: false,
        sent_output_writes: false,
        sent_configuration_writes: false,
        sent_firmware_or_dfu_commands: false,
        high_torque_enabled: false,
        real_hardware_validated: false,
        transport_kind: "fake_only",
        fake_transport_verified: true,
        codec_status: moza_serial_codec_status_name(FAKE_TRANSPORT_CODEC_STATUS),
        hardware_write_eligible: FAKE_TRANSPORT_CODEC_STATUS.allows_hardware_writes(),
        fixture_source: "fixtures/moza/r5/vendor-serial-codec-fixtures.json",
        fake_transport_fixture: "fixtures/moza/r5/vendor-fake-serial-transport.json",
        accepted_fixture_count: accepted_exchanges.len(),
        blocked_fixture_count: blocked_exchanges.len(),
        accepted_exchanges,
        blocked_exchanges,
        malformed_frame_rejected,
        unknown_command_rejected,
        mode_enable_candidate_fixture_source: "ci/hardware/moza-r5/2026-05-13/vendor-protocol-evidence-review.json",
        mode_enable_candidate_group_count,
        mode_enable_candidate_frame_count,
        mode_enable_candidate_send_path_rejected_count,
        mode_enable_candidates_unknown_do_not_send: true,
        mode_enable_candidate_observations,
        authority_status_endpoint_candidate_fixture_source: "ci/hardware/moza-r5/2026-05-13/vendor-status-endpoint-candidates-from-payload-rerun.json",
        authority_status_endpoint_candidate_group_count,
        authority_status_endpoint_candidate_frame_count,
        authority_status_endpoint_candidate_send_path_rejected_count,
        authority_status_endpoint_candidates_unknown_do_not_send: true,
        authority_status_endpoint_candidates_match_payload_status: false,
        corrected_read_only_probe_ready: false,
        authority_status_endpoint_candidate_observations,
        authority_command_id_0x07_analog_fixture_source: "ci/hardware/moza-r5/2026-05-13/vendor-status-endpoint-candidates-from-payload-rerun.json",
        authority_command_id_0x07_analog_count,
        authority_command_id_0x07_analog_frame_count,
        authority_command_id_0x07_analog_send_path_rejected_count,
        authority_command_id_0x07_analogs_unknown_do_not_send: true,
        authority_command_id_0x07_analogs_match_payload_status: false,
        authority_command_id_0x07_analogs_read_only_probe_allowed: false,
        authority_command_id_0x07_analogs_sendable: false,
        authority_command_id_0x07_analog_observations,
        notes: vec![
            "This command replays checked-in synthetic fixture bytes only.",
            "It does not open HID or serial devices and sends no host-to-device traffic.",
            "Write-like vendor output/configuration candidates remain blocked until a later exact authorization stage.",
            "Mode/enable candidate frames from passive evidence are observed in fake transport as unknown_do_not_send and are rejected by the command send path.",
            "Authority-status endpoint candidates from the payload rerun remain fake-only, do not match payload-bearing status responses, and are rejected by the command send path.",
            "Authority command-id 0x07 analogs are observed in fake transport as unknown_do_not_send endpoint-search fixtures and remain rejected by the command send path.",
        ],
    })
}

fn vendor_serial_fixtures_by_id(codec_fixture: &Value) -> Result<BTreeMap<&str, &Value>> {
    let mut fixtures = BTreeMap::new();
    let entries = codec_fixture
        .get("fixtures")
        .and_then(Value::as_array)
        .ok_or_else(|| anyhow!("codec fixture is missing `fixtures` array"))?;
    for fixture in entries {
        let id = json_string(fixture, "id")
            .ok_or_else(|| anyhow!("codec fixture entry is missing string `id`"))?;
        if fixtures.insert(id, fixture).is_some() {
            return Err(anyhow!("duplicate codec fixture `{id}`"));
        }
    }
    Ok(fixtures)
}

fn json_string_array_field(value: &Value, field: &str) -> Result<Vec<String>> {
    let array = value
        .get(field)
        .and_then(Value::as_array)
        .ok_or_else(|| anyhow!("missing `{field}` array"))?;
    array
        .iter()
        .map(|entry| {
            entry
                .as_str()
                .map(str::to_string)
                .ok_or_else(|| anyhow!("`{field}` must contain strings"))
        })
        .collect()
}

fn fixture_frame_bytes(fixture: &Value) -> Result<Vec<u8>> {
    let raw_frame_hex = json_string(fixture, "raw_frame_hex")
        .ok_or_else(|| anyhow!("fixture is missing string `raw_frame_hex`"))?;
    parse_hex_bytes(raw_frame_hex).map_err(anyhow::Error::msg)
}

fn vendor_fake_transport_mode_enable_observations(
    transport: &mut MozaFakeSerialTransport,
    review: &Value,
) -> Result<Vec<VendorFakeTransportModeEnableCandidateObservation>> {
    let candidates = review
        .pointer("/passive_tuple_registry_coverage/decode_candidate_mode_enable_review/candidates")
        .and_then(Value::as_array)
        .ok_or_else(|| {
            anyhow!("vendor protocol evidence review is missing mode/enable candidates")
        })?;
    let mut observations = Vec::new();

    for candidate in candidates {
        let candidate_id = json_string(candidate, "candidate_id")
            .ok_or_else(|| anyhow!("mode/enable candidate is missing `candidate_id`"))?;
        let semantic_hypothesis =
            json_string(candidate, "semantic_hypothesis").ok_or_else(|| {
                anyhow!("mode/enable candidate `{candidate_id}` is missing `semantic_hypothesis`")
            })?;
        let risk_class = json_string(candidate, "risk_class").ok_or_else(|| {
            anyhow!("mode/enable candidate `{candidate_id}` is missing `risk_class`")
        })?;
        if risk_class != "unknown_do_not_send" {
            return Err(anyhow!(
                "mode/enable candidate `{candidate_id}` has unexpected risk class `{risk_class}`"
            ));
        }
        for claim_field in [
            "semantic_decode_claim",
            "registry_promotion_claim",
            "hardware_output_authorized",
            "native_control_evidence",
            "output_sendability_claim",
        ] {
            if json_bool(candidate, claim_field) != Some(false) {
                return Err(anyhow!(
                    "mode/enable candidate `{candidate_id}` must keep `{claim_field}` false"
                ));
            }
        }

        let candidate_semantics = json_string_array_field(candidate, "candidate_semantics")?;
        let tuple_ids = json_string_array_field(candidate, "tuple_ids")?;
        let representative_frame_hexes =
            json_string_array_field(candidate, "representative_frame_hexes")?;
        let mut observed_frame_count = 0usize;
        let mut send_path_rejected_count = 0usize;

        for frame_hex in &representative_frame_hexes {
            let frame = parse_hex_bytes(frame_hex).map_err(anyhow::Error::msg)?;
            {
                let observation = transport
                    .observe_mode_enable_candidate_fixture_frame(&frame)
                    .with_context(|| {
                        format!(
                            "mode/enable candidate `{candidate_id}` frame `{frame_hex}` was not observable"
                        )
                    })?;
                if observation.candidate_id != candidate_id {
                    return Err(anyhow!(
                        "mode/enable candidate frame `{frame_hex}` routed to `{}`, expected `{candidate_id}`",
                        observation.candidate_id
                    ));
                }
                if observation.semantic_hypothesis != semantic_hypothesis {
                    return Err(anyhow!(
                        "mode/enable candidate frame `{frame_hex}` semantic hypothesis `{}` did not match `{semantic_hypothesis}`",
                        observation.semantic_hypothesis
                    ));
                }
                if observation.risk_class != MozaRiskClass::UnknownDoNotSend {
                    return Err(anyhow!(
                        "mode/enable candidate frame `{frame_hex}` was not fenced unknown_do_not_send"
                    ));
                }
                if observation.semantic_decode_claim
                    || observation.registry_promotion_claim
                    || observation.hardware_output_authorized
                    || observation.native_control_evidence
                    || observation.output_sendability_claim
                {
                    return Err(anyhow!(
                        "mode/enable candidate frame `{frame_hex}` created a forbidden claim"
                    ));
                }
            }
            observed_frame_count = observed_frame_count.saturating_add(1);

            match transport.submit_read_only_fixture_frame(&frame) {
                Err(MozaFakeSerialTransportError::Frame(
                    MozaSerialFrameError::UnknownCommand { .. },
                )) => {
                    send_path_rejected_count = send_path_rejected_count.saturating_add(1);
                }
                Err(error) => {
                    return Err(error).with_context(|| {
                        format!(
                            "mode/enable candidate `{candidate_id}` frame `{frame_hex}` send-path rejection used an unexpected error"
                        )
                    });
                }
                Ok(exchange) => {
                    return Err(anyhow!(
                        "mode/enable candidate frame `{frame_hex}` unexpectedly entered fake command path as `{}`",
                        exchange.command_id
                    ));
                }
            }
        }

        observations.push(VendorFakeTransportModeEnableCandidateObservation {
            candidate_id: candidate_id.to_string(),
            semantic_hypothesis: semantic_hypothesis.to_string(),
            candidate_semantics,
            tuple_ids,
            representative_frame_hexes,
            observed_frame_count,
            send_path_rejected_count,
            risk_class: risk_class.to_string(),
            semantic_decode_claim: false,
            registry_promotion_claim: false,
            hardware_output_authorized: false,
            native_control_evidence: false,
            output_sendability_claim: false,
        });
    }

    Ok(observations)
}

fn vendor_fake_transport_authority_status_endpoint_observations(
    transport: &mut MozaFakeSerialTransport,
    protocol_review: &Value,
    endpoint_candidates: &Value,
) -> Result<Vec<VendorFakeTransportAuthorityStatusEndpointCandidateObservation>> {
    if json_string(endpoint_candidates, "source_diagnosis_classification")
        != Some("authority_status_endpoint_specific_debug_telemetry_without_payload")
    {
        return Err(anyhow!(
            "authority-status endpoint fixture must come from the debug-telemetry-only payload rerun"
        ));
    }
    if json_bool(endpoint_candidates, "corrected_read_only_probe_ready") != Some(false) {
        return Err(anyhow!(
            "authority-status endpoint fixture must keep corrected_read_only_probe_ready false"
        ));
    }
    for claim_field in [
        "native_control_evidence",
        "hardware_output_authorized",
        "native_visible_ready",
        "smoke_ready",
        "release_ready",
        "registry_promotion_claim",
        "output_sendability_claim",
        "semantic_decode_claim",
    ] {
        if json_bool(endpoint_candidates, claim_field) != Some(false) {
            return Err(anyhow!(
                "authority-status endpoint fixture must keep `{claim_field}` false"
            ));
        }
    }

    let mode_enable_candidates = protocol_review
        .pointer("/passive_tuple_registry_coverage/decode_candidate_mode_enable_review/candidates")
        .and_then(Value::as_array)
        .ok_or_else(|| {
            anyhow!("vendor protocol evidence review is missing mode/enable candidates")
        })?;
    let mut mode_enable_by_id = BTreeMap::new();
    for candidate in mode_enable_candidates {
        let candidate_id = json_string(candidate, "candidate_id")
            .ok_or_else(|| anyhow!("mode/enable candidate is missing `candidate_id`"))?;
        if mode_enable_by_id.insert(candidate_id, candidate).is_some() {
            return Err(anyhow!("duplicate mode/enable candidate `{candidate_id}`"));
        }
    }

    let candidates = endpoint_candidates
        .get("passive_tuple_candidates")
        .and_then(Value::as_array)
        .ok_or_else(|| {
            anyhow!("authority-status endpoint fixture is missing passive tuple candidates")
        })?;
    let mut observations = Vec::new();

    for candidate in candidates {
        let candidate_id = json_string(candidate, "candidate_id").ok_or_else(|| {
            anyhow!("authority-status endpoint candidate is missing `candidate_id`")
        })?;
        let passive_hypothesis = json_string(candidate, "passive_hypothesis").ok_or_else(|| {
            anyhow!(
                "authority-status endpoint candidate `{candidate_id}` is missing `passive_hypothesis`"
            )
        })?;
        let risk_class = json_string(candidate, "risk_class").ok_or_else(|| {
            anyhow!("authority-status endpoint candidate `{candidate_id}` is missing `risk_class`")
        })?;
        if risk_class != "unknown_do_not_send" {
            return Err(anyhow!(
                "authority-status endpoint candidate `{candidate_id}` has unexpected risk class `{risk_class}`"
            ));
        }
        if json_bool(candidate, "read_only_probe_allowed") != Some(false) {
            return Err(anyhow!(
                "authority-status endpoint candidate `{candidate_id}` must not be read-only probe allowed"
            ));
        }
        for claim_field in [
            "semantic_decode_claim",
            "registry_promotion_claim",
            "output_sendability_claim",
        ] {
            if json_bool(candidate, claim_field) != Some(false) {
                return Err(anyhow!(
                    "authority-status endpoint candidate `{candidate_id}` must keep `{claim_field}` false"
                ));
            }
        }

        let mode_enable_candidate = mode_enable_by_id
            .get(passive_hypothesis)
            .ok_or_else(|| {
                anyhow!(
                    "authority-status endpoint candidate `{candidate_id}` references missing passive hypothesis `{passive_hypothesis}`"
                )
            })?;
        let candidate_semantics = json_string_array_field(candidate, "question_scope")?;
        let tuple_ids = json_string_array_field(candidate, "tuple_ids")?;
        let mode_enable_tuple_ids = json_string_array_field(mode_enable_candidate, "tuple_ids")?;
        if mode_enable_tuple_ids != tuple_ids {
            return Err(anyhow!(
                "authority-status endpoint candidate `{candidate_id}` tuple ids do not match passive review candidate `{passive_hypothesis}`"
            ));
        }
        let representative_frame_hexes =
            json_string_array_field(mode_enable_candidate, "representative_frame_hexes")?;
        let mut observed_frame_count = 0usize;
        let mut send_path_rejected_count = 0usize;

        for frame_hex in &representative_frame_hexes {
            let frame = parse_hex_bytes(frame_hex).map_err(anyhow::Error::msg)?;
            {
                let observation = transport
                    .observe_authority_status_endpoint_candidate_fixture_frame(&frame)
                    .with_context(|| {
                        format!(
                            "authority-status endpoint candidate `{candidate_id}` frame `{frame_hex}` was not observable"
                        )
                    })?;
                if observation.candidate_id != passive_hypothesis {
                    return Err(anyhow!(
                        "authority-status endpoint candidate frame `{frame_hex}` routed to `{}`, expected `{passive_hypothesis}`",
                        observation.candidate_id
                    ));
                }
                if observation.semantic_hypothesis != passive_hypothesis {
                    return Err(anyhow!(
                        "authority-status endpoint candidate frame `{frame_hex}` semantic hypothesis `{}` did not match `{passive_hypothesis}`",
                        observation.semantic_hypothesis
                    ));
                }
                if observation.risk_class != MozaRiskClass::UnknownDoNotSend {
                    return Err(anyhow!(
                        "authority-status endpoint candidate frame `{frame_hex}` was not fenced unknown_do_not_send"
                    ));
                }
                if observation.matches_payload_authority_status_response
                    || observation.corrected_read_only_probe_ready
                    || observation.semantic_decode_claim
                    || observation.registry_promotion_claim
                    || observation.hardware_output_authorized
                    || observation.native_control_evidence
                    || observation.output_sendability_claim
                {
                    return Err(anyhow!(
                        "authority-status endpoint candidate frame `{frame_hex}` created a forbidden claim"
                    ));
                }
            }
            observed_frame_count = observed_frame_count.saturating_add(1);

            match transport.submit_read_only_fixture_frame(&frame) {
                Err(MozaFakeSerialTransportError::Frame(
                    MozaSerialFrameError::UnknownCommand { .. },
                )) => {
                    send_path_rejected_count = send_path_rejected_count.saturating_add(1);
                }
                Err(error) => {
                    return Err(error).with_context(|| {
                        format!(
                            "authority-status endpoint candidate `{candidate_id}` frame `{frame_hex}` send-path rejection used an unexpected error"
                        )
                    });
                }
                Ok(exchange) => {
                    return Err(anyhow!(
                        "authority-status endpoint candidate frame `{frame_hex}` unexpectedly entered fake command path as `{}`",
                        exchange.command_id
                    ));
                }
            }
        }

        observations.push(
            VendorFakeTransportAuthorityStatusEndpointCandidateObservation {
                candidate_id: candidate_id.to_string(),
                passive_hypothesis: passive_hypothesis.to_string(),
                candidate_semantics,
                tuple_ids,
                representative_frame_hexes,
                observed_frame_count,
                send_path_rejected_count,
                risk_class: risk_class.to_string(),
                matches_payload_authority_status_response: false,
                corrected_read_only_probe_ready: false,
                semantic_decode_claim: false,
                registry_promotion_claim: false,
                hardware_output_authorized: false,
                native_control_evidence: false,
                output_sendability_claim: false,
            },
        );
    }

    Ok(observations)
}

fn vendor_fake_transport_authority_command_id_0x07_analog_observations(
    transport: &mut MozaFakeSerialTransport,
    endpoint_candidates: &Value,
) -> Result<Vec<VendorFakeTransportAuthorityCommandId0x07AnalogObservation>> {
    if json_bool(
        endpoint_candidates,
        "passive_command_id_0x07_analogs_match_payload_status",
    ) != Some(false)
    {
        return Err(anyhow!(
            "authority command-id 0x07 analogs must not match payload status"
        ));
    }
    if json_bool(
        endpoint_candidates,
        "passive_command_id_0x07_analogs_read_only_probe_allowed",
    ) != Some(false)
    {
        return Err(anyhow!(
            "authority command-id 0x07 analogs must not be read-only probe allowed"
        ));
    }
    if json_bool(
        endpoint_candidates,
        "passive_command_id_0x07_analogs_sendable",
    ) != Some(false)
    {
        return Err(anyhow!(
            "authority command-id 0x07 analogs must not be sendable"
        ));
    }

    let analogs = endpoint_candidates
        .get("passive_command_id_0x07_analogs")
        .and_then(Value::as_array)
        .ok_or_else(|| {
            anyhow!("authority-status endpoint fixture is missing command-id 0x07 analogs")
        })?;
    let mut observations = Vec::new();

    for analog in analogs {
        let tuple_id = json_string(analog, "tuple_id")
            .ok_or_else(|| anyhow!("command-id 0x07 analog is missing `tuple_id`"))?;
        if json_string(analog, "registry_status") != Some("unknown_commanded") {
            return Err(anyhow!(
                "command-id 0x07 analog `{tuple_id}` must remain unknown_commanded"
            ));
        }
        if json_string(analog, "risk_class") != Some("unknown_do_not_send") {
            return Err(anyhow!(
                "command-id 0x07 analog `{tuple_id}` must remain unknown_do_not_send"
            ));
        }
        if json_bool(analog, "command_id_matches_expected_source") != Some(true) {
            return Err(anyhow!(
                "command-id 0x07 analog `{tuple_id}` must preserve command-id match context"
            ));
        }
        if json_bool(analog, "response_shape_matches_expected_authority_status") != Some(false) {
            return Err(anyhow!(
                "command-id 0x07 analog `{tuple_id}` must not match payload authority status"
            ));
        }
        if json_bool(analog, "read_only_probe_allowed") != Some(false) {
            return Err(anyhow!(
                "command-id 0x07 analog `{tuple_id}` must not be read-only probe allowed"
            ));
        }
        for claim_field in [
            "semantic_decode_claim",
            "registry_promotion_claim",
            "output_sendability_claim",
        ] {
            if json_bool(analog, claim_field) != Some(false) {
                return Err(anyhow!(
                    "command-id 0x07 analog `{tuple_id}` must keep `{claim_field}` false"
                ));
            }
        }

        let payload_len_min = json_u64(analog, "payload_len_min")
            .ok_or_else(|| anyhow!("command-id 0x07 analog `{tuple_id}` missing payload_len_min"))?
            as usize;
        let payload_len_max = json_u64(analog, "payload_len_max")
            .ok_or_else(|| anyhow!("command-id 0x07 analog `{tuple_id}` missing payload_len_max"))?
            as usize;
        if payload_len_min != payload_len_max {
            return Err(anyhow!(
                "command-id 0x07 analog `{tuple_id}` must have a stable payload length for representative fake containment"
            ));
        }

        let representative_frame_hex =
            representative_unknown_tuple_frame_hex(tuple_id, payload_len_min).with_context(
                || format!("failed to build representative frame for `{tuple_id}`"),
            )?;
        let frame = parse_hex_bytes(&representative_frame_hex).map_err(anyhow::Error::msg)?;
        {
            let observation = transport
                .observe_authority_command_id_0x07_analog_fixture_frame(&frame)
                .with_context(|| {
                    format!(
                        "command-id 0x07 analog `{tuple_id}` frame `{representative_frame_hex}` was not observable"
                    )
                })?;
            if observation.tuple_id != tuple_id {
                return Err(anyhow!(
                    "command-id 0x07 analog frame `{representative_frame_hex}` routed to `{}`, expected `{tuple_id}`",
                    observation.tuple_id
                ));
            }
            if observation.risk_class != MozaRiskClass::UnknownDoNotSend {
                return Err(anyhow!(
                    "command-id 0x07 analog frame `{representative_frame_hex}` was not fenced unknown_do_not_send"
                ));
            }
            if observation.matches_payload_authority_status_response
                || observation.corrected_read_only_probe_ready
                || observation.read_only_probe_allowed
                || observation.semantic_decode_claim
                || observation.registry_promotion_claim
                || observation.hardware_output_authorized
                || observation.native_control_evidence
                || observation.output_sendability_claim
            {
                return Err(anyhow!(
                    "command-id 0x07 analog frame `{representative_frame_hex}` created a forbidden claim"
                ));
            }
        }

        let mut send_path_rejected_count = 0usize;
        match transport.submit_read_only_fixture_frame(&frame) {
            Err(MozaFakeSerialTransportError::Frame(MozaSerialFrameError::UnknownCommand {
                ..
            })) => {
                send_path_rejected_count = send_path_rejected_count.saturating_add(1);
            }
            Err(error) => {
                return Err(error).with_context(|| {
                    format!(
                        "command-id 0x07 analog `{tuple_id}` frame `{representative_frame_hex}` send-path rejection used an unexpected error"
                    )
                });
            }
            Ok(exchange) => {
                return Err(anyhow!(
                    "command-id 0x07 analog frame `{representative_frame_hex}` unexpectedly entered fake command path as `{}`",
                    exchange.command_id
                ));
            }
        }

        observations.push(VendorFakeTransportAuthorityCommandId0x07AnalogObservation {
            candidate_id: "authority_command_id_0x07_analog".to_string(),
            candidate_semantics: vec![
                "authority_state_status_endpoint_question".to_string(),
                "payload_bearing_read_only_status_question".to_string(),
                "command_id_0x07_analog".to_string(),
            ],
            tuple_id: tuple_id.to_string(),
            scenarios: json_string_array_field(analog, "scenarios")?,
            total_count: json_u64(analog, "total_count")
                .ok_or_else(|| anyhow!("command-id 0x07 analog `{tuple_id}` missing total_count"))?
                as usize,
            payload_len_min,
            payload_len_max,
            representative_frame_hexes: vec![representative_frame_hex],
            observed_frame_count: 1,
            send_path_rejected_count,
            command_id_matches_expected_source: true,
            risk_class: "unknown_do_not_send".to_string(),
            matches_payload_authority_status_response: false,
            corrected_read_only_probe_ready: false,
            read_only_probe_allowed: false,
            semantic_decode_claim: false,
            registry_promotion_claim: false,
            hardware_output_authorized: false,
            native_control_evidence: false,
            output_sendability_claim: false,
        });
    }

    Ok(observations)
}

fn representative_unknown_tuple_frame_hex(tuple_id: &str, payload_len: usize) -> Result<String> {
    let (group, device_id, command) = parse_tuple_id_bytes(tuple_id)?;
    let declared_len = payload_len
        .checked_add(1)
        .ok_or_else(|| anyhow!("representative payload length overflow"))?;
    let declared_len = u8::try_from(declared_len)
        .with_context(|| format!("representative payload for `{tuple_id}` is too long"))?;
    let mut frame = vec![MESSAGE_START, declared_len, group, device_id, command];
    frame.resize(frame.len() + payload_len, 0);
    let checksum = serial_checksum(&frame);
    frame.push(checksum);
    Ok(bytes_hex_compact(&frame))
}

fn parse_tuple_id_bytes(tuple_id: &str) -> Result<(u8, u8, u8)> {
    let mut parts = tuple_id.split('/');
    let group = parse_tuple_id_byte(tuple_id, "group", parts.next())?;
    let device_id = parse_tuple_id_byte(tuple_id, "device_id", parts.next())?;
    let command = parse_tuple_id_byte(tuple_id, "command", parts.next())?;
    if parts.next().is_some() {
        return Err(anyhow!("tuple id `{tuple_id}` has more than three parts"));
    }
    Ok((group, device_id, command))
}

fn parse_tuple_id_byte(tuple_id: &str, label: &str, part: Option<&str>) -> Result<u8> {
    let part = part.ok_or_else(|| anyhow!("tuple id `{tuple_id}` is missing {label}"))?;
    parse_hex_u8_token(part)
        .map_err(anyhow::Error::msg)
        .with_context(|| format!("tuple id `{tuple_id}` has invalid {label} byte `{part}`"))
}

#[derive(Default)]
struct CaptureValidationSummary {
    total_reports: usize,
    parsed_reports: usize,
    rejected_reports: usize,
    capture_input_format_reports: usize,
    product_ids: BTreeMap<String, usize>,
    parsed_by_category: BTreeMap<String, usize>,
    report_ids: BTreeMap<String, usize>,
    report_lengths: BTreeMap<String, usize>,
    axis_ranges: BTreeMap<String, AxisRange>,
    line_errors: Vec<CaptureLineError>,
    line_errors_truncated: bool,
}

impl CaptureValidationSummary {
    fn record_parsed(&mut self, pid: u16, state: &MozaInputState, report: &[u8]) {
        self.parsed_reports += 1;
        let identity = identify_device(pid);
        increment_count(
            &mut self.parsed_by_category,
            category_label(identity.category).to_string(),
        );
        self.update_axis("steering_u16", state.steering_u16);
        self.update_axis("throttle_u16", state.throttle_u16);
        self.update_axis("brake_u16", state.brake_u16);
        self.update_axis("clutch_u16", state.clutch_u16);
        self.update_axis("handbrake_u16", state.handbrake_u16);
        self.update_axis("buttons0_u8", u16::from(state.buttons[0]));
        self.update_axis(
            "buttons_any_u8",
            u16::from(
                state
                    .buttons
                    .iter()
                    .copied()
                    .fold(0u8, |acc, value| acc | value),
            ),
        );
        self.update_axis("hat_u8", u16::from(state.hat));
        self.update_axis("funky_u8", u16::from(state.funky));
        self.update_axis("rotary0_u8", u16::from(state.rotary[0]));
        self.update_axis("rotary1_u8", u16::from(state.rotary[1]));
        self.update_axis(
            "ks_buttons_any_u8",
            u16::from(
                state
                    .ks_snapshot
                    .buttons
                    .iter()
                    .copied()
                    .fold(0u8, |acc, value| acc | value),
            ),
        );
        self.update_axis("ks_hat_u8", u16::from(state.ks_snapshot.hat));
        if looks_like_live_r5_v1_extended_report(report) {
            self.update_report_axis(
                "r5_v1_extended_ks_axis0_u16",
                report,
                input_report::R5_V1_EXTENDED_KS_AXIS0_START,
            );
            self.update_report_axis(
                "r5_v1_extended_axis0_u16",
                report,
                input_report::R5_V1_EXTENDED_AXIS0_START,
            );
            self.update_report_axis(
                "r5_v1_extended_axis1_u16",
                report,
                input_report::R5_V1_EXTENDED_AXIS1_START,
            );
            self.update_report_axis(
                "r5_v1_extended_axis2_u16",
                report,
                input_report::R5_V1_EXTENDED_AXIS2_START,
            );
            self.update_report_axis(
                "r5_v1_extended_aux0_u16",
                report,
                input_report::R5_V1_EXTENDED_AUX0_START,
            );
            self.update_report_axis(
                "r5_v1_extended_aux1_u16",
                report,
                input_report::R5_V1_EXTENDED_AUX1_START,
            );
        }
    }

    fn update_axis(&mut self, name: &str, value: u16) {
        self.axis_ranges
            .entry(name.to_string())
            .or_default()
            .update(value);
    }

    fn update_report_axis(&mut self, name: &str, report: &[u8], start: usize) {
        if let Some(value) = parse_axis(report, start) {
            self.update_axis(name, value);
        }
    }

    fn record_rejection(&mut self, line: usize, error: String) {
        self.rejected_reports += 1;
        self.record_line_error(line, error);
    }

    fn record_line_error(&mut self, line: usize, error: String) {
        const MAX_LINE_ERRORS: usize = 16;
        if self.line_errors.len() < MAX_LINE_ERRORS {
            self.line_errors.push(CaptureLineError { line, error });
        } else {
            self.line_errors_truncated = true;
        }
    }
}

#[derive(Debug, Default, Serialize)]
struct AxisRange {
    min: Option<u16>,
    max: Option<u16>,
}

impl AxisRange {
    fn update(&mut self, value: u16) {
        self.min = Some(self.min.map_or(value, |min| min.min(value)));
        self.max = Some(self.max.map_or(value, |max| max.max(value)));
    }
}

