fn selector_matches(device: &MozaDeviceRecord, selector: Option<&str>) -> bool {
    let Some(selector) = selector else {
        return true;
    };

    let selector = selector.trim();
    if selector.is_empty() {
        return true;
    }

    if let Some(identity) = parse_hid_observe_selector(selector) {
        return hid_observe_selector_matches(device, &identity);
    }

    if let Some((vid, pid)) = parse_vid_pid_selector(selector) {
        return device.vendor_id.eq_ignore_ascii_case(&hex_u16(vid))
            && device.product_id.eq_ignore_ascii_case(&hex_u16(pid));
    }

    if let Some(pid) = parse_hex_selector(selector) {
        return device.product_id.eq_ignore_ascii_case(&hex_u16(pid));
    }

    let selector_lc = selector.to_ascii_lowercase();
    device.path.to_ascii_lowercase().contains(&selector_lc)
        || device
            .product_name
            .to_ascii_lowercase()
            .contains(&selector_lc)
        || device
            .product_string
            .as_deref()
            .map(|s| s.to_ascii_lowercase().contains(&selector_lc))
            .unwrap_or(false)
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct HidObserveSelector {
    vendor_id: u16,
    product_id: u16,
    interface_number: i32,
    usage_page: u16,
    usage: u16,
}

fn parse_hid_observe_selector(selector: &str) -> Option<HidObserveSelector> {
    let rest = selector.strip_prefix("hid-")?;
    let mut parts = rest.split('-');
    let vendor_id = parse_hex_selector(parts.next()?)?;
    let product_id = parse_hex_selector(parts.next()?)?;
    let interface_number = parts.next()?.strip_prefix("if")?.parse::<i32>().ok()?;
    let usage_page = parse_hex_selector(parts.next()?)?;
    let usage = parse_hex_selector(parts.next()?)?;
    parts.next().is_none().then_some(HidObserveSelector {
        vendor_id,
        product_id,
        interface_number,
        usage_page,
        usage,
    })
}

fn hid_observe_selector_matches(device: &MozaDeviceRecord, selector: &HidObserveSelector) -> bool {
    device
        .vendor_id
        .eq_ignore_ascii_case(&hex_u16(selector.vendor_id))
        && device
            .product_id
            .eq_ignore_ascii_case(&hex_u16(selector.product_id))
        && device.interface_number == Some(selector.interface_number)
        && device.usage_page.as_deref().is_some_and(|usage_page| {
            usage_page.eq_ignore_ascii_case(&hex_u16(selector.usage_page))
        })
        && device
            .usage
            .as_deref()
            .is_some_and(|usage| usage.eq_ignore_ascii_case(&hex_u16(selector.usage)))
}

fn parse_vid_pid_selector(selector: &str) -> Option<(u16, u16)> {
    let (vid, pid) = selector.split_once(':')?;
    Some((parse_hex_selector(vid)?, parse_hex_selector(pid)?))
}

fn parse_hex_selector(selector: &str) -> Option<u16> {
    let value = selector
        .strip_prefix("0x")
        .or_else(|| selector.strip_prefix("0X"))
        .unwrap_or(selector);
    u16::from_str_radix(value, 16).ok()
}

fn parse_required_hex_u16(value: &str) -> Result<u16> {
    parse_hex_selector(value).ok_or_else(|| anyhow!("expected hex u16, got '{value}'"))
}

fn category_label(category: MozaDeviceCategory) -> &'static str {
    match category {
        MozaDeviceCategory::Wheelbase => "wheelbase",
        MozaDeviceCategory::Pedals => "pedals",
        MozaDeviceCategory::Shifter => "shifter",
        MozaDeviceCategory::Handbrake => "handbrake",
        MozaDeviceCategory::Unknown => "unknown",
    }
}

fn topology_label(topology: MozaTopologyHint) -> &'static str {
    match topology {
        MozaTopologyHint::WheelbaseAggregated => "wheelbase_aggregated",
        MozaTopologyHint::StandaloneUsb => "standalone_usb",
        MozaTopologyHint::Unknown => "unknown",
    }
}

fn write_json_receipt<T: Serialize>(path: Option<&Path>, value: &T) -> Result<()> {
    let Some(path) = path else {
        return Ok(());
    };
    write_json_file(path, value)
}

fn write_json_file<T: Serialize>(path: &Path, value: &T) -> Result<()> {
    if let Some(parent) = path.parent().filter(|p| !p.as_os_str().is_empty()) {
        fs::create_dir_all(parent)
            .with_context(|| format!("failed to create '{}'", parent.display()))?;
    }

    let json = serde_json::to_string_pretty(value).context("failed to serialize JSON receipt")?;
    fs::write(path, json).with_context(|| format!("failed to write '{}'", path.display()))?;
    Ok(())
}

fn write_text_file(path: &Path, contents: &str) -> Result<()> {
    if let Some(parent) = path.parent().filter(|p| !p.as_os_str().is_empty()) {
        fs::create_dir_all(parent)
            .with_context(|| format!("failed to create '{}'", parent.display()))?;
    }
    fs::write(path, contents).with_context(|| format!("failed to write '{}'", path.display()))?;
    Ok(())
}

fn print_probe_receipt(json: bool, json_out: Option<&Path>, receipt: &ProbeReceipt) -> Result<()> {
    if json {
        println!("{}", serde_json::to_string_pretty(receipt)?);
    } else {
        println!(
            "Moza probe found {} HID device(s); no FFB writes sent.",
            receipt.devices.len()
        );
        if let Some(path) = json_out {
            println!("Receipt: {}", path.display());
        }
    }
    Ok(())
}

fn print_status_receipt(json: bool, json_out: Option<&Path>, receipt: &Value) -> Result<()> {
    if json {
        println!("{}", serde_json::to_string_pretty(receipt)?);
    } else {
        let device_count = json_u64(receipt, "device_count").unwrap_or(0);
        let lane = json_string(receipt, "lane");
        println!("Moza status found {device_count} HID device(s); no FFB writes sent.");
        if let Some(lane) = lane {
            println!("Lane: {lane}");
        }
        if let Some(path) = json_out {
            println!("Receipt: {}", path.display());
        }
    }
    Ok(())
}

fn print_artifact_index_receipt(
    json: bool,
    json_out: Option<&Path>,
    md_out: Option<&Path>,
    receipt: &Value,
) -> Result<()> {
    if json {
        println!("{}", serde_json::to_string_pretty(receipt)?);
    } else {
        let count = receipt
            .get("lane_artifacts")
            .and_then(Value::as_array)
            .map_or(0, Vec::len);
        let frontier = json_string(receipt, "frontier").unwrap_or("unknown");
        println!(
            "Moza artifact index rendered {count} lane artifact(s); frontier={frontier}; no hardware output sent."
        );
        if let Some(path) = json_out {
            println!("Receipt: {}", path.display());
        }
        if let Some(path) = md_out {
            println!("Markdown: {}", path.display());
        }
    }
    Ok(())
}

fn print_bench_wizard_receipt(
    json: bool,
    json_out: Option<&Path>,
    md_out: Option<&Path>,
    receipt: &Value,
) -> Result<()> {
    if json {
        println!("{}", serde_json::to_string_pretty(receipt)?);
    } else {
        let frontier = json_string(receipt, "frontier").unwrap_or("unknown");
        let next = receipt
            .get("next_operator_step")
            .and_then(|step| step.get("kind"))
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        println!(
            "Moza bench wizard rendered frontier={frontier}; next={next}; no hardware output authorized."
        );
        if let Some(path) = json_out {
            println!("Receipt: {}", path.display());
        }
        if let Some(path) = md_out {
            println!("Markdown: {}", path.display());
        }
    }
    Ok(())
}

fn render_moza_lane_artifact_index_markdown(receipt: &Value) -> String {
    let lane = json_string(receipt, "lane").unwrap_or("unknown");
    let frontier = json_string(receipt, "frontier").unwrap_or("unknown");
    let readiness = receipt.get("readiness").unwrap_or(&Value::Null);
    let highest = readiness
        .get("highest_passing_stage")
        .and_then(Value::as_str)
        .unwrap_or("unknown");
    let next = readiness
        .get("next_required_stage")
        .and_then(Value::as_str)
        .unwrap_or("none");
    let native_response = readiness
        .get("native_actuator_response_proven")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let native_visible = readiness
        .get("native_visible_motion_proven")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let release_ready = readiness
        .get("release_ready")
        .and_then(Value::as_bool)
        .unwrap_or(false);

    let mut out = String::new();
    out.push_str("# Moza Lane Artifact Index\n\n");
    out.push_str("This index is diagnostic navigation only. It reads stored lane files, opens no HID device, sends no output or feature reports, and does not authorize hardware output or promote readiness.\n\n");
    out.push_str(&format!("- Lane: `{}`\n", markdown_escape(lane)));
    out.push_str(&format!("- Frontier: `{}`\n", markdown_escape(frontier)));
    out.push_str(&format!(
        "- Highest passing stage: `{}`\n",
        markdown_escape(highest)
    ));
    out.push_str(&format!(
        "- Next required stage: `{}`\n",
        markdown_escape(next)
    ));
    out.push_str(&format!(
        "- Native actuator response proven: `{native_response}`\n"
    ));
    out.push_str(&format!(
        "- Native visible motion proven: `{native_visible}`\n"
    ));
    out.push_str(&format!("- Release ready: `{release_ready}`\n\n"));

    push_input_role_semantics_markdown(&mut out, receipt);
    push_vendor_authority_navigation_markdown(&mut out, receipt);
    push_pit_house_compatibility_markdown(&mut out, receipt);
    push_simulator_compatibility_markdown(&mut out, receipt);
    push_passive_sniff_navigation_markdown(&mut out, receipt);

    let mut grouped: BTreeMap<&str, Vec<&Value>> = BTreeMap::new();
    if let Some(artifacts) = receipt.get("lane_artifacts").and_then(Value::as_array) {
        for artifact in artifacts {
            let category = json_string(artifact, "category").unwrap_or("diagnostic");
            grouped.entry(category).or_default().push(artifact);
        }
    }

    let category_order = [
        ("passive", "Passive Enumeration And Input"),
        ("zero_safety", "Zero, Watchdog, Disconnect"),
        ("openracing_control", "OpenRacing Native Control Foundation"),
        ("native_response", "Native Response"),
        ("native_visible", "Native Visible And PIDFF Diagnosis"),
        ("pit_house", "Pit House External Compatibility"),
        ("simulator", "Simulator And FFB Smoke"),
        ("smoke", "Smoke Promotion"),
        ("support", "Support And Service Diagnostics"),
        ("sniff", "Passive USB Sniffing"),
    ];

    for (category, title) in category_order.iter().copied() {
        if let Some(artifacts) = grouped.get(category) {
            push_artifact_markdown_table(&mut out, title, artifacts);
        }
    }
    let remaining: Vec<_> = grouped
        .iter()
        .filter(|(category, _)| {
            !category_order
                .iter()
                .any(|(known_category, _)| known_category == *category)
        })
        .flat_map(|(_, artifacts)| artifacts.iter().copied())
        .collect();
    if !remaining.is_empty() {
        push_artifact_markdown_table(&mut out, "Other Lane Artifacts", &remaining);
    }

    out.push_str("## Required Support-Bundle Artifact Index\n\n");
    out.push_str("| Path | Required Stage | Artifact Status | Claim Status |\n");
    out.push_str("| --- | --- | --- | --- |\n");
    if let Some(artifacts) = receipt
        .get("required_artifact_index")
        .and_then(Value::as_array)
    {
        for artifact in artifacts {
            let path = json_string(artifact, "path").unwrap_or("unknown");
            let stage = json_string(artifact, "required_stage").unwrap_or("unknown");
            let status = json_string(artifact, "status").unwrap_or("unknown");
            let claim_status = json_string(artifact, "claim_status").unwrap_or("artifact_only");
            out.push_str(&format!(
                "| `{}` | `{}` | `{}` | `{}` |\n",
                markdown_escape(path),
                markdown_escape(stage),
                markdown_escape(status),
                markdown_escape(claim_status)
            ));
        }
    }
    out
}

fn render_moza_bench_wizard_markdown(receipt: &Value) -> String {
    let lane = json_string(receipt, "lane").unwrap_or("unknown");
    let frontier = json_string(receipt, "frontier").unwrap_or("unknown");
    let readiness = receipt.get("readiness").unwrap_or(&Value::Null);
    let highest = readiness
        .get("highest_passing_stage")
        .and_then(Value::as_str)
        .unwrap_or("unknown");
    let next_stage = readiness
        .get("next_required_stage")
        .and_then(Value::as_str)
        .unwrap_or("none");
    let step = receipt.get("next_operator_step").unwrap_or(&Value::Null);
    let step_kind = step
        .get("kind")
        .and_then(Value::as_str)
        .unwrap_or("unknown");
    let step_summary = step
        .get("summary")
        .and_then(Value::as_str)
        .unwrap_or("No next step summary recorded.");

    let mut out = String::new();
    out.push_str("# Moza Bench Wizard\n\n");
    out.push_str("This wizard is read-only operator navigation. It reads stored lane artifacts, opens no HID device, sends no output or feature reports, creates no authorization receipt, and does not promote readiness.\n\n");
    out.push_str(&format!("- Lane: `{}`\n", markdown_escape(lane)));
    out.push_str(&format!("- Frontier: `{}`\n", markdown_escape(frontier)));
    out.push_str(&format!(
        "- Highest passing stage: `{}`\n",
        markdown_escape(highest)
    ));
    out.push_str(&format!(
        "- Next required stage: `{}`\n",
        markdown_escape(next_stage)
    ));
    out.push_str(&format!(
        "- Next operator step: `{}` - {}\n\n",
        markdown_escape(step_kind),
        markdown_escape(step_summary)
    ));
    push_native_motion_status_markdown(&mut out, receipt);
    push_next_concrete_command_markdown(&mut out, receipt);
    push_next_operator_step_capture_checklist_markdown(&mut out, step);
    push_next_operator_step_external_capture_commands_markdown(&mut out, step);
    push_next_operator_step_commands_markdown(&mut out, step);

    push_input_role_semantics_markdown(&mut out, receipt);
    push_vendor_authority_navigation_markdown(&mut out, receipt);
    push_pit_house_compatibility_markdown(&mut out, receipt);
    push_simulator_compatibility_markdown(&mut out, receipt);
    push_passive_sniff_navigation_markdown(&mut out, receipt);

    out.push_str("## Safe No-Output Commands\n\n");
    out.push_str("| Name | Command |\n");
    out.push_str("| --- | --- |\n");
    if let Some(commands) = receipt
        .get("safe_no_output_commands")
        .and_then(Value::as_array)
    {
        for command in commands {
            let name = json_string(command, "name").unwrap_or("unknown");
            let command_text = json_string(command, "command").unwrap_or("");
            out.push_str(&format!(
                "| `{}` | `{}` |\n",
                markdown_escape(name),
                markdown_escape(command_text)
            ));
        }
    }
    out.push('\n');

    out.push_str("## Active Blockers\n\n");
    out.push_str("| Name | Scope | Stage | Status |\n");
    out.push_str("| --- | --- | --- | --- |\n");
    if let Some(blockers) = receipt.get("active_blockers").and_then(Value::as_array) {
        for blocker in blockers {
            let name = json_string(blocker, "name").unwrap_or("unknown");
            let scope = json_string(blocker, "scope").unwrap_or("unknown");
            let stage = json_string(blocker, "blocking_stage").unwrap_or("unknown");
            let status = json_string(blocker, "status").unwrap_or("unknown");
            out.push_str(&format!(
                "| `{}` | `{}` | `{}` | `{}` |\n",
                markdown_escape(name),
                markdown_escape(scope),
                markdown_escape(stage),
                markdown_escape(status)
            ));
        }
    }
    out.push('\n');

    out.push_str("## Output Boundary\n\n");
    out.push_str("Output is not authorized by this wizard. Any real controlled-angle or vendor-authority attempt needs a separate fresh command-bound bench-clear plus exact authorization receipt. Do not use this wizard as permission to rerun, raise force, extend dwell, run 30/90 degrees, use direct report 0x20, high torque, serial config, firmware, or DFU.\n\n");
    if let Some(evidence) = step
        .get("required_bench_clear_evidence")
        .and_then(Value::as_str)
    {
        out.push_str(
            "Required bench-clear evidence for the next separately authorized attempt:\n\n",
        );
        out.push_str(&format!("```text\n{}\n```\n\n", markdown_escape(evidence)));
    }
    if let Some(authorization) = step.get("authorization_receipt").and_then(Value::as_str) {
        out.push_str(&format!(
            "- Recorded authorization receipt: `{}`\n",
            markdown_escape(authorization)
        ));
    }
    if let Some(planned_output) = step.get("planned_output_receipt").and_then(Value::as_str) {
        out.push_str(&format!(
            "- Planned output receipt: `{}`\n",
            markdown_escape(planned_output)
        ));
    }
    if let Some(smoke) = step.get("smoke_dry_run_receipt").and_then(Value::as_str) {
        out.push_str(&format!(
            "- Smoke dry-run receipt: `{}`\n",
            markdown_escape(smoke)
        ));
    }
    if let Some(emitted) = step
        .get("hardware_attempt_command_emitted")
        .and_then(Value::as_bool)
    {
        out.push_str(&format!(
            "- Hardware attempt command emitted by wizard: `{emitted}`\n"
        ));
    }
    if step.get("authorization_receipt").is_some() || step.get("planned_output_receipt").is_some() {
        out.push('\n');
    }
    out
}

fn push_native_motion_status_markdown(out: &mut String, receipt: &Value) {
    let Some(status) = receipt.get("native_motion_status") else {
        return;
    };
    if status.is_null() {
        return;
    }

    let wheel_moved = json_bool(status, "wheel_moved_under_openracing").unwrap_or(false);
    let visible_motion = json_bool(status, "visible_motion_verified").unwrap_or(false);
    let output_sent = json_bool(status, "output_was_sent").unwrap_or(false);
    let authority_state = json_string(status, "authority_state").unwrap_or("blocked");
    let motion_allowed = json_bool(status, "motion_attempt_allowed").unwrap_or(false);
    let read_only_allowed = json_bool(status, "live_read_only_probe_allowed").unwrap_or(false);
    let zero_response_diagnosed =
        json_bool(status, "zero_response_original_probe_diagnosed").unwrap_or(false);
    let timing_source_missing =
        json_bool(status, "timing_correlated_payload_source_missing").unwrap_or(false);
    let endpoint_mismatch =
        json_bool(status, "authority_status_endpoint_or_command_mismatch").unwrap_or(false);
    let corrected_probe_ready =
        json_bool(status, "corrected_read_only_probe_ready").unwrap_or(false);
    let fresh_bench_clear =
        json_bool(status, "fresh_command_bound_bench_clear_present").unwrap_or(false);
    let exact_blocker =
        json_string(status, "exact_blocker").unwrap_or("native visible motion remains blocked");
    let next_action =
        json_string(status, "next_action").unwrap_or("continue no-output diagnosis before motion");
    let read_only_reason = json_string(status, "reason_read_only_rerun_not_allowed")
        .unwrap_or("read-only rerun remains blocked");
    let motion_reason =
        json_string(status, "reason_motion_not_allowed").unwrap_or("motion remains blocked");

    out.push_str("## Native Motion State\n\n");
    out.push_str("This is the current native OpenRacing movement state, not a prerequisite-completion summary.\n\n");
    out.push_str(&format!(
        "- wheel_moved_under_openracing: `{wheel_moved}`\n"
    ));
    out.push_str(&format!("- visible_motion_verified: `{visible_motion}`\n"));
    out.push_str(&format!("- output_was_sent: `{output_sent}`\n"));
    out.push_str(&format!(
        "- authority_state: `{}`\n",
        markdown_escape(authority_state)
    ));
    out.push_str(&format!("- motion_attempt_allowed: `{motion_allowed}`\n"));
    out.push_str(&format!(
        "- live_read_only_probe_allowed: `{read_only_allowed}`\n"
    ));
    out.push_str(&format!(
        "- zero_response_original_probe_diagnosed: `{zero_response_diagnosed}`\n"
    ));
    out.push_str(&format!(
        "- authority_status_endpoint_or_command_mismatch: `{endpoint_mismatch}`\n"
    ));
    out.push_str(&format!(
        "- timing_correlated_payload_source_missing: `{timing_source_missing}`\n"
    ));
    out.push_str(&format!(
        "- corrected_read_only_probe_ready: `{corrected_probe_ready}`\n"
    ));
    out.push_str(&format!(
        "- fresh_command_bound_bench_clear_present: `{fresh_bench_clear}`\n"
    ));
    out.push_str(&format!(
        "- Read-only rerun blocker: {}\n",
        markdown_escape(read_only_reason)
    ));
    out.push_str(&format!(
        "- Motion blocker: {}\n",
        markdown_escape(motion_reason)
    ));
    out.push_str(&format!(
        "- Exact blocker: {}\n",
        markdown_escape(exact_blocker)
    ));
    out.push_str(&format!(
        "- Next concrete action: {}\n\n",
        markdown_escape(next_action)
    ));
}

fn push_next_concrete_command_markdown(out: &mut String, receipt: &Value) {
    let Some(command) = receipt.get("next_concrete_command") else {
        return;
    };
    if command.is_null() {
        return;
    }
    let command_text = json_string(command, "command").unwrap_or("");
    if command_text.is_empty() {
        return;
    }

    let name = json_string(command, "name").unwrap_or("unknown");
    let sequence_count = receipt
        .get("next_concrete_command_count")
        .and_then(Value::as_u64)
        .unwrap_or(0);
    let output_enabled = json_bool(command, "output_enabled").unwrap_or(false);
    let openracing_output = json_bool(command, "openracing_hardware_output").unwrap_or(false);
    let openracing_hid = json_bool(command, "openracing_hid_open").unwrap_or(false);
    let openracing_feature_reports =
        json_bool(command, "openracing_feature_reports").unwrap_or(false);
    let openracing_serial_config =
        json_bool(command, "openracing_serial_config_commands").unwrap_or(false);
    let openracing_firmware_or_dfu =
        json_bool(command, "openracing_firmware_or_dfu_commands").unwrap_or(false);

    out.push_str("## Next Concrete Command\n\n");
    out.push_str("This is the next immediately runnable no-output command from the current movement blocker. It is not authorization, it does not move the wheel, and it does not promote readiness.\n\n");
    out.push_str(&format!("- Name: `{}`\n", markdown_escape(name)));
    out.push_str(&format!(
        "- Runnable next-command sequence length: `{sequence_count}`\n"
    ));
    out.push_str(&format!("- output_enabled: `{output_enabled}`\n"));
    out.push_str(&format!(
        "- openracing_hardware_output: `{openracing_output}`\n"
    ));
    out.push_str(&format!("- openracing_hid_open: `{openracing_hid}`\n"));
    out.push_str(&format!(
        "- openracing_feature_reports: `{openracing_feature_reports}`\n"
    ));
    out.push_str(&format!(
        "- openracing_serial_config_commands: `{openracing_serial_config}`\n"
    ));
    out.push_str(&format!(
        "- openracing_firmware_or_dfu_commands: `{openracing_firmware_or_dfu}`\n"
    ));
    out.push_str("\n```powershell\n");
    out.push_str(command_text);
    out.push_str("\n```\n\n");
}

fn push_artifact_markdown_table(out: &mut String, title: &str, artifacts: &[&Value]) {
    out.push_str(&format!("## {title}\n\n"));
    out.push_str("| Path | Kind | Evidence Role |\n");
    out.push_str("| --- | --- | --- |\n");
    for artifact in artifacts {
        let path = json_string(artifact, "path").unwrap_or("unknown");
        let kind = json_string(artifact, "kind").unwrap_or("unknown");
        let evidence = json_string(artifact, "readiness_evidence").unwrap_or("diagnostic");
        out.push_str(&format!(
            "| `{}` | `{}` | `{}` |\n",
            markdown_escape(path),
            markdown_escape(kind),
            markdown_escape(evidence)
        ));
    }
    out.push('\n');
}

fn push_input_role_semantics_markdown(out: &mut String, receipt: &Value) {
    let Some(summary) = receipt.get("input_role_semantics") else {
        return;
    };
    if summary.is_null() {
        return;
    }

    let semantic_status = json_string(summary, "semantic_status").unwrap_or("unknown");
    let source_artifact = json_string(summary, "source_artifact").unwrap_or("none");
    let required_role_count = json_u64(summary, "required_role_count").unwrap_or(0);
    let required_parser_visible_count =
        json_u64(summary, "required_parser_visible_count").unwrap_or(0);
    let generic_aux_role_count = json_u64(summary, "generic_aux_role_count").unwrap_or(0);
    let semantic_mapping_complete =
        json_bool(summary, "semantic_mapping_complete").unwrap_or(false);
    let unproven_required_role_count =
        json_u64(summary, "unproven_required_role_count").unwrap_or(generic_aux_role_count);
    let semantic_candidate_count = json_u64(summary, "semantic_candidate_count").unwrap_or(0);

    out.push_str("## Input Role Semantics\n\n");
    out.push_str("This section is diagnostic navigation only. `generic_aux` roles are valid parser-visible passive evidence, but they are not fully role-specific semantic mappings.\n\n");
    out.push_str(&format!(
        "- Source artifact: `{}`\n",
        markdown_escape(source_artifact)
    ));
    out.push_str(&format!(
        "- Semantic status: `{}`\n",
        markdown_escape(semantic_status)
    ));
    out.push_str(&format!("- Required roles: `{required_role_count}`\n"));
    out.push_str(&format!(
        "- Required parser-visible roles: `{required_parser_visible_count}`\n"
    ));
    out.push_str(&format!(
        "- Role-specific semantic mapping complete: `{semantic_mapping_complete}`\n"
    ));
    out.push_str(&format!(
        "- Unproven required role semantics: `{unproven_required_role_count}`\n"
    ));
    out.push_str(&format!(
        "- Generic auxiliary roles: `{generic_aux_role_count}`\n\n"
    ));
    out.push_str(&format!(
        "- Candidate-only extended slots: `{semantic_candidate_count}`\n\n"
    ));

    if let Some(roles) = summary.get("generic_aux_roles").and_then(Value::as_array)
        && !roles.is_empty()
    {
        out.push_str("| Control | Role | Evidence Capture | Semantic Status | Candidate Slots |\n");
        out.push_str("| --- | --- | --- | --- | --- |\n");
        for role in roles {
            let control = json_string(role, "control").unwrap_or("unknown");
            let role_name = json_string(role, "role").unwrap_or("unknown");
            let evidence = json_string(role, "evidence_capture").unwrap_or("unknown");
            let status = json_string(role, "semantic_status").unwrap_or("unknown");
            let candidate_slots = role
                .get("semantic_candidates")
                .and_then(Value::as_array)
                .map(|candidates| {
                    candidates
                        .iter()
                        .filter_map(|candidate| json_string(candidate, "axis"))
                        .collect::<Vec<_>>()
                        .join(", ")
                })
                .filter(|slots| !slots.is_empty())
                .unwrap_or_else(|| "none".to_string());
            out.push_str(&format!(
                "| `{}` | `{}` | `{}` | `{}` | `{}` |\n",
                markdown_escape(control),
                markdown_escape(role_name),
                markdown_escape(evidence),
                markdown_escape(status),
                markdown_escape(&candidate_slots)
            ));
        }
        out.push('\n');
    }
}

fn push_vendor_authority_navigation_markdown(out: &mut String, receipt: &Value) {
    let Some(summary) = receipt.get("vendor_authority_navigation") else {
        return;
    };
    if summary.is_null() {
        return;
    }

    let state = json_string(summary, "state").unwrap_or("unknown");
    let next_allowed_action =
        json_string(summary, "next_allowed_action").unwrap_or("review source-of-truth");
    let hardware_output_authorized =
        json_bool(summary, "hardware_output_authorized").unwrap_or(false);
    let native_visible_ready = json_bool(summary, "native_visible_ready").unwrap_or(false);
    let hardware_attempt_command_emitted =
        json_bool(summary, "hardware_attempt_command_emitted").unwrap_or(false);
    let command = summary.get("exact_command").unwrap_or(&Value::Null);
    let command_id = json_string(command, "command_id").unwrap_or("unknown");
    let frame_hex = json_string(command, "frame_hex").unwrap_or("unknown");
    let payload_hex = json_string(command, "payload_hex").unwrap_or("unknown");
    let risk_class = json_string(command, "risk_class").unwrap_or("unknown");

    out.push_str("## Vendor Authority Handoff\n\n");
    out.push_str("This section is native-control research navigation only. It does not open HID, send serial traffic, create authorization, emit the hardware attempt command, or claim native-visible readiness.\n\n");
    out.push_str(&format!("- State: `{}`\n", markdown_escape(state)));
    out.push_str(&format!(
        "- Next allowed action: {}\n",
        markdown_escape(next_allowed_action)
    ));
    out.push_str(&format!(
        "- Hardware output authorized: `{hardware_output_authorized}`\n"
    ));
    out.push_str(&format!(
        "- Native visible ready: `{native_visible_ready}`\n"
    ));
    out.push_str(&format!(
        "- Hardware attempt command emitted: `{hardware_attempt_command_emitted}`\n"
    ));
    out.push_str(&format!(
        "- Exact command: `{}` frame `{}` payload `{}` risk `{}`\n",
        markdown_escape(command_id),
        markdown_escape(frame_hex),
        markdown_escape(payload_hex),
        markdown_escape(risk_class)
    ));
    if let Some(blocker) = summary
        .get("native_motion_blocker")
        .filter(|blocker| !blocker.is_null())
    {
        let exact_next_blocker =
            json_string(blocker, "exact_next_blocker").unwrap_or("not recorded");
        let scenario = json_string(blocker, "scenario").unwrap_or("unknown");
        let live_read_only_probe_allowed =
            json_bool(blocker, "live_read_only_probe_allowed").unwrap_or(false);
        let authorization_plan_allowed =
            json_bool(blocker, "authorization_plan_allowed").unwrap_or(false);
        let motion_attempt_allowed = json_bool(blocker, "motion_attempt_allowed").unwrap_or(false);
        let wheel_moved = json_bool(blocker, "wheel_moved_under_openracing").unwrap_or(false);
        let visible_motion = json_bool(blocker, "visible_motion_verified").unwrap_or(false);
        let output_was_sent = json_bool(blocker, "output_was_sent").unwrap_or(false);
        let authority_state = json_string(blocker, "authority_state").unwrap_or("unknown");
        out.push_str("\n### Native Motion Blocker\n\n");
        out.push_str(&format!(
            "- Exact blocker: {}\n",
            markdown_escape(exact_next_blocker)
        ));
        out.push_str(&format!(
            "- Required passive scenario: `{}`\n",
            markdown_escape(scenario)
        ));
        out.push_str(&format!(
            "- Live read-only probe allowed: `{live_read_only_probe_allowed}`\n"
        ));
        out.push_str(&format!(
            "- Authorization plan allowed: `{authorization_plan_allowed}`\n"
        ));
        out.push_str(&format!(
            "- Motion attempt allowed: `{motion_attempt_allowed}`\n"
        ));
        out.push_str(&format!(
            "- wheel_moved_under_openracing: `{wheel_moved}`\n"
        ));
        out.push_str(&format!("- visible_motion_verified: `{visible_motion}`\n"));
        out.push_str(&format!("- output_was_sent: `{output_was_sent}`\n"));
        out.push_str(&format!(
            "- authority_state: `{}`\n",
            markdown_escape(authority_state)
        ));
        if let Some(tuples) = blocker.get("target_tuple_ids").and_then(Value::as_array)
            && !tuples.is_empty()
        {
            let rendered_tuples = tuples
                .iter()
                .filter_map(Value::as_str)
                .map(markdown_escape)
                .collect::<Vec<_>>()
                .join("`, `");
            out.push_str(&format!("- Target 0x8E tuples: `{rendered_tuples}`\n"));
        }
        out.push('\n');
    }
    if let Some(evidence) = summary
        .get("required_bench_clear_evidence")
        .and_then(Value::as_str)
    {
        out.push_str(&format!(
            "- Required bench-clear evidence: `{}`\n",
            markdown_escape(evidence)
        ));
    }
    if let Some(precondition) = summary.get("serial_precondition") {
        let requires_exclusive =
            json_bool(precondition, "requires_exclusive_r5_serial_cdc_access").unwrap_or(false);
        let pit_house_dependency = json_bool(precondition, "pit_house_dependency").unwrap_or(false);
        let pit_house_owner_risk =
            json_bool(precondition, "pit_house_serial_owner_risk").unwrap_or(false);
        let opens_serial = json_bool(precondition, "opens_serial").unwrap_or(false);
        let sends_output = json_bool(precondition, "sends_output").unwrap_or(false);
        out.push_str(&format!(
            "- Requires exclusive R5 serial/CDC access before separate attempt: `{requires_exclusive}`\n"
        ));
        out.push_str(&format!(
            "- Pit House dependency: `{pit_house_dependency}`; serial-owner risk: `{pit_house_owner_risk}`\n"
        ));
        out.push_str(&format!(
            "- Handoff opens serial: `{opens_serial}`; sends output: `{sends_output}`\n"
        ));
        if let Some(hints) = precondition
            .get("serial_port_hints")
            .and_then(Value::as_array)
            .filter(|hints| !hints.is_empty())
        {
            let rendered_hints = hints
                .iter()
                .filter_map(Value::as_str)
                .map(markdown_escape)
                .collect::<Vec<_>>()
                .join("`, `");
            out.push_str(&format!("- R5 serial port hints: `{rendered_hints}`\n"));
        }
        if let Some(guidance) = json_string(precondition, "guidance") {
            out.push_str(&format!(
                "- Serial precondition guidance: {}\n",
                markdown_escape(guidance)
            ));
        }
        if let Some(command) = json_string(precondition, "live_precondition_command") {
            out.push_str(&format!(
                "- Live precondition refresh command: `{}`\n",
                markdown_escape(command)
            ));
        }
        if let Some(receipt) = json_string(precondition, "live_precondition_receipt") {
            out.push_str(&format!(
                "- Live precondition receipt: `{}`\n",
                markdown_escape(receipt)
            ));
        }
    }
    if let Some(artifacts) = summary.get("artifacts") {
        out.push_str("\n| Artifact | Path |\n");
        out.push_str("| --- | --- |\n");
        for (label, pointer) in [
            ("authorization", "authorization_receipt"),
            ("smoke_dry_run", "smoke_dry_run_receipt"),
            ("attempt", "attempt_receipt"),
            (
                "post_authority_pidff_smoke",
                "post_authority_pidff_smoke_receipt",
            ),
            (
                "post_authority_pidff_response",
                "post_authority_pidff_response_receipt",
            ),
            (
                "vendor_protocol_evidence_review",
                "vendor_protocol_evidence_review_receipt",
            ),
        ] {
            let path = json_string(artifacts, pointer).unwrap_or("unknown");
            out.push_str(&format!(
                "| `{}` | `{}` |\n",
                markdown_escape(label),
                markdown_escape(path)
            ));
        }
    }
    if let Some(priority) = summary
        .get("vendor_protocol_decode_priority")
        .filter(|priority| !priority.is_null())
    {
        let status = json_string(priority, "status").unwrap_or("unknown");
        let source = json_string(priority, "source_receipt").unwrap_or("unknown");
        let risk_class =
            json_string(priority, "unknown_tuple_risk_class").unwrap_or("unknown_do_not_send");
        let output_sendability_claim =
            json_bool(priority, "output_sendability_claim").unwrap_or(false);
        out.push_str("\n### Protocol Decode Priority\n\n");
        out.push_str("Frequency-ranked tuples are decode-priority navigation only. They do not make an unknown tuple sendable.\n\n");
        out.push_str(&format!("- Status: `{}`\n", markdown_escape(status)));
        out.push_str(&format!(
            "- Source receipt: `{}`\n",
            markdown_escape(source)
        ));
        out.push_str(&format!(
            "- Unknown tuple risk class: `{}`\n",
            markdown_escape(risk_class)
        ));
        out.push_str(&format!(
            "- Output sendability claim: `{output_sendability_claim}`\n"
        ));
        let sample_scope =
            json_string(priority, "decode_candidate_sample_scope").unwrap_or("not_recorded");
        let sample_count = json_u64(priority, "decode_candidate_sample_count").unwrap_or(0);
        out.push_str(&format!(
            "- Decode candidate sample scope: `{}`\n",
            markdown_escape(sample_scope)
        ));
        out.push_str(&format!(
            "- Decode candidate sample frames: `{sample_count}`\n"
        ));
        if let Some(shape_summary) = priority
            .get("decode_candidate_payload_shape_summary")
            .filter(|summary| !summary.is_null())
        {
            let all_empty_or_zero =
                json_bool(shape_summary, "all_sample_payloads_empty_or_zero_filled")
                    .unwrap_or(false);
            let shape_count = json_u64(shape_summary, "unique_payload_shape_count").unwrap_or(0);
            out.push_str(&format!(
                "- Decode candidate payload shapes: `{shape_count}`\n"
            ));
            out.push_str(&format!(
                "- Payloads empty or zero-filled in samples: `{all_empty_or_zero}`\n"
            ));
        }
        if let Some(group_summary) = priority
            .get("decode_candidate_packet_group_summary")
            .filter(|summary| !summary.is_null())
        {
            let packet_group_count = json_u64(group_summary, "packet_group_count").unwrap_or(0);
            let pattern_count = json_u64(group_summary, "unique_packet_pattern_count").unwrap_or(0);
            let motif_count =
                json_u64(group_summary, "repeated_contiguous_motif_count").unwrap_or(0);
            out.push_str(&format!(
                "- Decode candidate packet groups: `{packet_group_count}`\n"
            ));
            out.push_str(&format!("- Unique packet patterns: `{pattern_count}`\n"));
            out.push_str(&format!("- Repeated contiguous motifs: `{motif_count}`\n"));
        }
        if let Some(hypothesis_summary) = priority
            .get("decode_candidate_semantic_hypothesis_summary")
            .filter(|summary| !summary.is_null())
        {
            let hypothesis_count = json_u64(hypothesis_summary, "hypothesis_count").unwrap_or(0);
            let semantic_decode_claim =
                json_bool(hypothesis_summary, "semantic_decode_claim").unwrap_or(false);
            let registry_promotion_claim =
                json_bool(hypothesis_summary, "registry_promotion_claim").unwrap_or(false);
            out.push_str(&format!(
                "- Semantic hypothesis count: `{hypothesis_count}`\n"
            ));
            out.push_str(&format!(
                "- Semantic decode claim: `{semantic_decode_claim}`\n"
            ));
            out.push_str(&format!(
                "- Registry promotion claim: `{registry_promotion_claim}`\n"
            ));
        }
        if let Some(correlation_plan) = priority
            .get("decode_candidate_semantic_correlation_plan")
            .filter(|plan| !plan.is_null())
        {
            let target_count = json_u64(correlation_plan, "correlation_target_count").unwrap_or(0);
            let output_sendability_claim =
                json_bool(correlation_plan, "output_sendability_claim").unwrap_or(false);
            let next_allowed_action =
                json_string(correlation_plan, "next_allowed_action").unwrap_or("not recorded");
            out.push_str(&format!(
                "- Semantic correlation target count: `{target_count}`\n"
            ));
            out.push_str(&format!(
                "- Semantic correlation sendability claim: `{output_sendability_claim}`\n"
            ));
            out.push_str(&format!(
                "- Semantic correlation next action: `{}`\n",
                markdown_escape(next_allowed_action)
            ));
            if let Some(targets) = correlation_plan
                .get("targets")
                .and_then(Value::as_array)
                .filter(|targets| !targets.is_empty())
            {
                out.push_str(
                    "\n| Correlation target | Tuples | Observed completed scenarios | Missing scenarios | Next capture | Sendable |\n",
                );
                out.push_str("| --- | --- | --- | --- | --- | --- |\n");
                for target in targets {
                    let semantic_hypothesis =
                        json_string(target, "semantic_hypothesis").unwrap_or("unknown");
                    let tuple_ids = json_string_array_value(target.get("tuple_ids"))
                        .into_iter()
                        .map(|tuple_id| format!("`{}`", markdown_escape(&tuple_id)))
                        .collect::<Vec<_>>()
                        .join(", ");
                    let observed_completed_scenarios =
                        json_string_array_value(target.get("observed_completed_scenarios"))
                            .join(", ");
                    let missing_correlation_scenarios =
                        json_string_array_value(target.get("missing_correlation_scenarios"))
                            .join(", ");
                    let next_capture_priority =
                        json_string(target, "next_capture_priority").unwrap_or("unknown");
                    let output_sendability_claim =
                        json_bool(target, "output_sendability_claim").unwrap_or(false);
                    out.push_str(&format!(
                        "| `{}` | {} | `{}` | `{}` | `{}` | `{}` |\n",
                        markdown_escape(semantic_hypothesis),
                        tuple_ids,
                        markdown_escape(&observed_completed_scenarios),
                        markdown_escape(&missing_correlation_scenarios),
                        markdown_escape(next_capture_priority),
                        output_sendability_claim
                    ));
                }
            }
        }
        if let Some(mode_enable_review) = priority
            .get("decode_candidate_mode_enable_review")
            .filter(|review| !review.is_null())
        {
            let candidate_count = json_u64(mode_enable_review, "candidate_count").unwrap_or(0);
            let output_sendability_claim =
                json_bool(mode_enable_review, "output_sendability_claim").unwrap_or(false);
            let protocol_evidence_sufficient = json_bool(
                mode_enable_review,
                "protocol_evidence_sufficient_for_output_plan",
            )
            .unwrap_or(false);
            out.push_str(&format!(
                "- Mode/enable decode candidate count: `{candidate_count}`\n"
            ));
            out.push_str(&format!(
                "- Mode/enable sendability claim: `{output_sendability_claim}`\n"
            ));
            out.push_str(&format!(
                "- Mode/enable evidence sufficient for output plan: `{protocol_evidence_sufficient}`\n"
            ));
            if let Some(candidates) = mode_enable_review
                .get("candidates")
                .and_then(Value::as_array)
                .filter(|candidates| !candidates.is_empty())
            {
                out.push_str("\n| Mode/enable candidate | Semantic questions | Tuples | Direction | Frame | Risk | Sendable |\n");
                out.push_str("| --- | --- | --- | --- | --- | --- | --- |\n");
                for candidate in candidates {
                    let candidate_id = json_string(candidate, "candidate_id").unwrap_or("unknown");
                    let semantics = candidate
                        .get("candidate_semantics")
                        .and_then(Value::as_array)
                        .map(|items| {
                            items
                                .iter()
                                .filter_map(Value::as_str)
                                .map(markdown_escape)
                                .collect::<Vec<_>>()
                                .join(", ")
                        })
                        .filter(|semantics| !semantics.is_empty())
                        .unwrap_or_else(|| "unknown".to_string());
                    let tuple_ids = json_string_array_value(candidate.get("tuple_ids"))
                        .into_iter()
                        .map(|tuple_id| format!("`{}`", markdown_escape(&tuple_id)))
                        .collect::<Vec<_>>()
                        .join(", ");
                    let direction = json_string(candidate, "direction").unwrap_or("unknown");
                    let frame_start =
                        json_string(candidate, "frame_start_byte").unwrap_or("unknown");
                    let risk_class = json_string(candidate, "risk_class").unwrap_or("unknown");
                    let output_sendability_claim =
                        json_bool(candidate, "output_sendability_claim").unwrap_or(false);
                    out.push_str(&format!(
                        "| `{}` | `{}` | {} | `{}` | `{}` | `{}` | `{}` |\n",
                        markdown_escape(candidate_id),
                        semantics,
                        tuple_ids,
                        markdown_escape(direction),
                        markdown_escape(frame_start),
                        markdown_escape(risk_class),
                        output_sendability_claim
                    ));
                }
            }
        }
        if let Some(payload_gap_summary) = priority
            .get("payload_export_gap_summary")
            .filter(|summary| !summary.is_null())
        {
            let total_missing =
                json_u64(payload_gap_summary, "total_missing_packet_count").unwrap_or(0);
            let scenario_count = json_u64(payload_gap_summary, "scenario_count").unwrap_or(0);
            let output_sendability_claim =
                json_bool(payload_gap_summary, "output_sendability_claim").unwrap_or(false);
            out.push_str(&format!(
                "- Residual payload export gap packets: `{total_missing}`\n"
            ));
            out.push_str(&format!(
                "- Payload export gap scenarios: `{scenario_count}`\n"
            ));
            out.push_str(&format!(
                "- Payload gap sendability claim: `{output_sendability_claim}`\n"
            ));
            if let Some(scenarios) = payload_gap_summary
                .get("scenarios")
                .and_then(Value::as_array)
                .filter(|scenarios| !scenarios.is_empty())
            {
                out.push_str("\n| Payload gap scenario | Missing packets | Example packet | Data len | Sendable |\n");
                out.push_str("| --- | ---: | ---: | ---: | --- |\n");
                for scenario in scenarios {
                    let scenario_name = json_string(scenario, "scenario").unwrap_or("unknown");
                    let missing_count = json_u64(scenario, "missing_packet_count").unwrap_or(0);
                    let example = scenario
                        .get("missing_packet_examples")
                        .and_then(Value::as_array)
                        .and_then(|examples| examples.first());
                    let packet_ordinal = example
                        .and_then(|example| json_u64(example, "packet_ordinal"))
                        .unwrap_or(0);
                    let data_len = example
                        .and_then(|example| json_u64(example, "data_len"))
                        .unwrap_or(0);
                    let output_sendability_claim =
                        json_bool(scenario, "output_sendability_claim").unwrap_or(false);
                    out.push_str(&format!(
                        "| `{}` | {} | {} | {} | `{}` |\n",
                        markdown_escape(scenario_name),
                        missing_count,
                        packet_ordinal,
                        data_len,
                        output_sendability_claim
                    ));
                }
            }
        }
        if let Some(tuples) = priority
            .get("top_unknown_commanded_tuples")
            .and_then(Value::as_array)
            .filter(|tuples| !tuples.is_empty())
        {
            out.push_str("\n| Tuple | Count | Payload bytes | Scenarios |\n");
            out.push_str("| --- | ---: | ---: | ---: |\n");
            for tuple in tuples {
                let tuple_id = json_string(tuple, "tuple_id").unwrap_or("unknown");
                let total_count = json_u64(tuple, "total_count").unwrap_or(0);
                let payload_len_min = json_u64(tuple, "payload_len_min").unwrap_or(0);
                let payload_len_max = json_u64(tuple, "payload_len_max").unwrap_or(0);
                let scenario_count = json_u64(tuple, "scenario_count").unwrap_or(0);
                out.push_str(&format!(
                    "| `{}` | {} | {}..{} | {} |\n",
                    markdown_escape(tuple_id),
                    total_count,
                    payload_len_min,
                    payload_len_max,
                    scenario_count
                ));
            }
        }
        if let Some(hypotheses) = priority
            .pointer("/decode_candidate_semantic_hypothesis_summary/tuple_hypotheses")
            .and_then(Value::as_array)
            .filter(|hypotheses| !hypotheses.is_empty())
        {
            out.push_str("\n| Semantic hypothesis tuple | Pattern hint | Hypothesis | Confidence | Sendable |\n");
            out.push_str("| --- | --- | --- | --- | --- |\n");
            for hypothesis in hypotheses {
                let tuple_id = json_string(hypothesis, "tuple_id").unwrap_or("unknown");
                let pattern_hint =
                    json_string(hypothesis, "observed_pattern_hint").unwrap_or("unknown");
                let semantic_hypothesis =
                    json_string(hypothesis, "semantic_hypothesis").unwrap_or("unknown");
                let confidence = json_string(hypothesis, "confidence").unwrap_or("unknown");
                let output_sendability_claim =
                    json_bool(hypothesis, "output_sendability_claim").unwrap_or(false);
                out.push_str(&format!(
                    "| `{}` | `{}` | `{}` | `{}` | `{}` |\n",
                    markdown_escape(tuple_id),
                    markdown_escape(pattern_hint),
                    markdown_escape(semantic_hypothesis),
                    markdown_escape(confidence),
                    output_sendability_claim
                ));
            }
        }
        if let Some(shapes) = priority
            .pointer("/decode_candidate_payload_shape_summary/tuple_payload_shapes")
            .and_then(Value::as_array)
            .filter(|shapes| !shapes.is_empty())
        {
            out.push_str(
                "\n| Payload shape tuple | Samples | Payload bytes | Payload kinds | Sendable |\n",
            );
            out.push_str("| --- | ---: | ---: | --- | --- |\n");
            for shape in shapes {
                let tuple_id = json_string(shape, "tuple_id").unwrap_or("unknown");
                let sample_count = json_u64(shape, "sample_count").unwrap_or(0);
                let payload_len_min = json_u64(shape, "payload_len_min").unwrap_or(0);
                let payload_len_max = json_u64(shape, "payload_len_max").unwrap_or(0);
                let payload_kinds = shape
                    .get("payload_kinds")
                    .and_then(Value::as_array)
                    .map(|kinds| {
                        kinds
                            .iter()
                            .filter_map(Value::as_str)
                            .map(markdown_escape)
                            .collect::<Vec<_>>()
                            .join(", ")
                    })
                    .filter(|kinds| !kinds.is_empty())
                    .unwrap_or_else(|| "unknown".to_string());
                let output_sendability_claim =
                    json_bool(shape, "output_sendability_claim").unwrap_or(false);
                out.push_str(&format!(
                    "| `{}` | {} | {}..{} | `{}` | `{}` |\n",
                    markdown_escape(tuple_id),
                    sample_count,
                    payload_len_min,
                    payload_len_max,
                    payload_kinds,
                    output_sendability_claim
                ));
            }
        }
        if let Some(patterns) = priority
            .pointer("/decode_candidate_packet_group_summary/packet_patterns")
            .and_then(Value::as_array)
            .filter(|patterns| !patterns.is_empty())
        {
            out.push_str("\n| Packet group pattern | Packets | Samples | Scenarios | Sendable |\n");
            out.push_str("| --- | ---: | ---: | ---: | --- |\n");
            for pattern in patterns {
                let tuple_sequence = pattern
                    .get("tuple_sequence")
                    .and_then(Value::as_array)
                    .map(|tuples| {
                        tuples
                            .iter()
                            .filter_map(Value::as_str)
                            .map(markdown_escape)
                            .collect::<Vec<_>>()
                            .join(" -> ")
                    })
                    .filter(|sequence| !sequence.is_empty())
                    .unwrap_or_else(|| "unknown".to_string());
                let observed_packet_count = json_u64(pattern, "observed_packet_count").unwrap_or(0);
                let sample_count = json_u64(pattern, "sample_count").unwrap_or(0);
                let scenario_count = json_u64(pattern, "scenario_count").unwrap_or(0);
                let output_sendability_claim =
                    json_bool(pattern, "output_sendability_claim").unwrap_or(false);
                out.push_str(&format!(
                    "| `{tuple_sequence}` | {observed_packet_count} | {sample_count} | {scenario_count} | `{output_sendability_claim}` |\n"
                ));
            }
        }
        if let Some(motifs) = priority
            .pointer("/decode_candidate_packet_group_summary/repeated_contiguous_motifs")
            .and_then(Value::as_array)
            .filter(|motifs| !motifs.is_empty())
        {
            out.push_str("\n| Repeated motif | Length | Observed | Scenarios | Sendable |\n");
            out.push_str("| --- | ---: | ---: | ---: | --- |\n");
            for motif in motifs {
                let tuple_sequence = motif
                    .get("tuple_sequence")
                    .and_then(Value::as_array)
                    .map(|tuples| {
                        tuples
                            .iter()
                            .filter_map(Value::as_str)
                            .map(markdown_escape)
                            .collect::<Vec<_>>()
                            .join(" -> ")
                    })
                    .filter(|sequence| !sequence.is_empty())
                    .unwrap_or_else(|| "unknown".to_string());
                let motif_len = json_u64(motif, "motif_len").unwrap_or(0);
                let observed_count = json_u64(motif, "observed_count").unwrap_or(0);
                let scenario_count = json_u64(motif, "scenario_count").unwrap_or(0);
                let output_sendability_claim =
                    json_bool(motif, "output_sendability_claim").unwrap_or(false);
                out.push_str(&format!(
                    "| `{tuple_sequence}` | {motif_len} | {observed_count} | {scenario_count} | `{output_sendability_claim}` |\n"
                ));
            }
        }
        if let Some(fixtures) = priority
            .get("decode_candidate_sample_fixtures")
            .and_then(Value::as_array)
            .filter(|fixtures| !fixtures.is_empty())
        {
            out.push_str("\n| Sample fixture tuple | Samples | First frame | First payload bytes | Sendable |\n");
            out.push_str("| --- | ---: | --- | ---: | --- |\n");
            for fixture in fixtures {
                let tuple_id = json_string(fixture, "tuple_id").unwrap_or("unknown");
                let sample_count = json_u64(fixture, "sample_count").unwrap_or(0);
                let first_sample = fixture
                    .get("sample_frame_examples")
                    .and_then(Value::as_array)
                    .and_then(|samples| samples.first());
                let first_frame = first_sample
                    .and_then(|sample| json_string(sample, "frame_hex"))
                    .unwrap_or("none");
                let first_payload_len = first_sample
                    .and_then(|sample| json_u64(sample, "payload_len"))
                    .unwrap_or(0);
                let output_sendability_claim =
                    json_bool(fixture, "output_sendability_claim").unwrap_or(false);
                out.push_str(&format!(
                    "| `{}` | {} | `{}` | {} | `{}` |\n",
                    markdown_escape(tuple_id),
                    sample_count,
                    markdown_escape(first_frame),
                    first_payload_len,
                    output_sendability_claim
                ));
            }
        }
    }
    out.push('\n');
}

fn push_pit_house_compatibility_markdown(out: &mut String, receipt: &Value) {
    let Some(summary) = receipt.get("pit_house_compatibility") else {
        return;
    };
    if summary.is_null() {
        return;
    }

    let availability_status = json_string(summary, "availability_status").unwrap_or("unknown");
    let pit_house_available = json_bool(summary, "pit_house_available").unwrap_or(false);
    let coexistence_claimed = json_bool(summary, "pit_house_coexistence_claimed").unwrap_or(false);
    let gate_status = json_string(summary, "coexistence_gate_status").unwrap_or("unknown");
    let official_download_page =
        json_string(summary, "official_download_page").unwrap_or(MOZA_PIT_HOUSE_DOWNLOADS_URL);
    let install_guidance =
        json_string(summary, "install_guidance").unwrap_or(MOZA_PIT_HOUSE_INSTALL_GUIDANCE);
    let recorded_case_count = json_u64(summary, "recorded_case_count").unwrap_or(0);
    let required_case_count = json_u64(summary, "required_case_count").unwrap_or(0);

    out.push_str("## Pit House Compatibility\n\n");
    out.push_str("This section is external-smoke navigation only. Pit House is not required for native OpenRacing control, and these artifacts do not authorize hardware output.\n\n");
    out.push_str(&format!(
        "- Availability status: `{}`\n",
        markdown_escape(availability_status)
    ));
    out.push_str(&format!("- Pit House available: `{pit_house_available}`\n"));
    out.push_str(&format!(
        "- Official download page: `{}`\n",
        markdown_escape(official_download_page)
    ));
    out.push_str(&format!(
        "- Install guidance: {}\n",
        markdown_escape(install_guidance)
    ));
    out.push_str(&format!(
        "- Coexistence gate status: `{}`\n",
        markdown_escape(gate_status)
    ));
    out.push_str(&format!(
        "- Pit House coexistence claimed: `{coexistence_claimed}`\n"
    ));
    out.push_str(&format!(
        "- Recorded cases: `{recorded_case_count}` / `{required_case_count}`\n\n"
    ));

    out.push_str("| Case | Case Artifact | Observation Artifact | Status |\n");
    out.push_str("| --- | --- | --- | --- |\n");
    if let Some(cases) = summary.get("recorded_cases").and_then(Value::as_array) {
        for case in cases {
            push_pit_house_case_markdown_row(out, case, "recorded");
        }
    }
    if let Some(cases) = summary
        .get("observation_only_cases")
        .and_then(Value::as_array)
    {
        for case in cases {
            push_pit_house_case_markdown_row(out, case, "observation_only");
        }
    }
    if let Some(missing_cases) = summary.get("missing_cases").and_then(Value::as_array) {
        for missing_case in missing_cases {
            let case_id = missing_case.as_str().unwrap_or("unknown");
            if summary
                .get("observation_only_cases")
                .and_then(Value::as_array)
                .map(|cases| {
                    cases
                        .iter()
                        .any(|case| json_string(case, "case") == Some(case_id))
                })
                .unwrap_or(false)
            {
                continue;
            }
            let (case_artifact, observation_artifact) =
                pit_house_case_artifacts_for_markdown(case_id);
            out.push_str(&format!(
                "| `{}` | `{}` | `{}` | `missing` |\n",
                markdown_escape(case_id),
                markdown_escape(case_artifact),
                markdown_escape(observation_artifact)
            ));
        }
    }
    out.push('\n');
}

fn push_pit_house_case_markdown_row(out: &mut String, case: &Value, status: &str) {
    let case_id = json_string(case, "case").unwrap_or("unknown");
    let case_artifact = json_string(case, "case_artifact").unwrap_or("unknown");
    let observation_artifact = json_string(case, "observation_artifact").unwrap_or("unknown");
    out.push_str(&format!(
        "| `{}` | `{}` | `{}` | `{}` |\n",
        markdown_escape(case_id),
        markdown_escape(case_artifact),
        markdown_escape(observation_artifact),
        markdown_escape(status)
    ));
}

fn push_simulator_compatibility_markdown(out: &mut String, receipt: &Value) {
    let Some(summary) = receipt.get("simulator_compatibility") else {
        return;
    };
    if summary.is_null() {
        return;
    }

    let telemetry_claimed = json_bool(summary, "simulator_telemetry_claimed").unwrap_or(false);
    let bounded_ffb_claimed = json_bool(summary, "bounded_simulator_ffb_claimed").unwrap_or(false);
    let recorded_artifact_count = json_u64(summary, "recorded_artifact_count").unwrap_or(0);
    let required_artifact_count = json_u64(summary, "required_artifact_count").unwrap_or(0);
    let blocks_smoke_ready = json_bool(summary, "blocks_smoke_ready").unwrap_or(true);

    out.push_str("## Simulator Compatibility\n\n");
    out.push_str("This section is external-smoke navigation only. Simulator telemetry and bounded simulator FFB are not required for native OpenRacing control, and this navigation does not authorize hardware output.\n\n");
    out.push_str(&format!(
        "- Simulator telemetry claimed: `{telemetry_claimed}`\n"
    ));
    out.push_str(&format!(
        "- Bounded simulator FFB claimed: `{bounded_ffb_claimed}`\n"
    ));
    out.push_str(&format!(
        "- Recorded artifacts: `{recorded_artifact_count}` / `{required_artifact_count}`\n"
    ));
    out.push_str(&format!("- Blocks smoke-ready: `{blocks_smoke_ready}`\n\n"));

    out.push_str("| Gate | Artifact | Gate Status | Claim Status |\n");
    out.push_str("| --- | --- | --- | --- |\n");
    for (gate, pointer) in [
        ("simulator_telemetry", "telemetry"),
        ("simulator_ffb_bounded", "bounded_ffb"),
    ] {
        let item = summary.get(pointer).unwrap_or(&Value::Null);
        let artifact = json_string(item, "artifact").unwrap_or("unknown");
        let gate_status = json_string(item, "gate_status").unwrap_or("unknown");
        let claim_status = json_string(item, "claim_status").unwrap_or("unknown");
        out.push_str(&format!(
            "| `{}` | `{}` | `{}` | `{}` |\n",
            markdown_escape(gate),
            markdown_escape(artifact),
            markdown_escape(gate_status),
            markdown_escape(claim_status)
        ));
    }
    out.push('\n');
}

fn push_passive_sniff_navigation_markdown(out: &mut String, receipt: &Value) {
    let Some(summary) = receipt.get("passive_sniff_navigation") else {
        return;
    };
    if summary.is_null() {
        return;
    }

    let recorded_scenario_count = json_u64(summary, "recorded_scenario_count").unwrap_or(0);
    let required_scenario_count = json_u64(summary, "required_scenario_count").unwrap_or(0);
    let readiness_claim = json_bool(summary, "readiness_claim").unwrap_or(false);
    let blocks_native_control = json_bool(summary, "blocks_native_control").unwrap_or(false);
    let blocks_native_visible = json_bool(summary, "blocks_native_visible").unwrap_or(false);
    let blocks_smoke_ready = json_bool(summary, "blocks_smoke_ready").unwrap_or(false);

    out.push_str("## Passive USB Sniffing\n\n");
    out.push_str("This section is protocol research/support navigation only. Passive sniff artifacts do not authorize output, do not satisfy native-visible or smoke-ready gates, and are not required for native OpenRacing control.\n\n");
    out.push_str(&format!(
        "- Recorded scenarios: `{recorded_scenario_count}` / `{required_scenario_count}`\n"
    ));
    out.push_str(&format!("- Readiness claim: `{readiness_claim}`\n"));
    out.push_str(&format!(
        "- Blocks native control: `{blocks_native_control}`\n"
    ));
    out.push_str(&format!(
        "- Blocks native visible: `{blocks_native_visible}`\n"
    ));
    out.push_str(&format!("- Blocks smoke-ready: `{blocks_smoke_ready}`\n\n"));
    if let Some(next_gap) = summary.get("next_passive_gap")
        && !next_gap.is_null()
    {
        let scenario = json_string(next_gap, "scenario").unwrap_or("unknown");
        let label = json_string(next_gap, "label").unwrap_or("unknown");
        let capture_required = json_bool(next_gap, "capture_required").unwrap_or(false);
        out.push_str(&format!(
            "- Next passive gap: `{}` ({})\n",
            markdown_escape(scenario),
            markdown_escape(label)
        ));
        out.push_str(&format!(
            "- Next capture required: `{capture_required}`\n\n"
        ));
    }

    out.push_str("| Scenario | Status | Plan | Receipt | Summary |\n");
    out.push_str("| --- | --- | --- | --- | --- |\n");
    if let Some(scenarios) = summary.get("scenarios").and_then(Value::as_array) {
        for scenario in scenarios {
            let name = json_string(scenario, "scenario").unwrap_or("unknown");
            let status = json_string(scenario, "status").unwrap_or("unknown");
            let plan_status = json_string(scenario, "plan_status").unwrap_or("unknown");
            let receipt_status = json_string(scenario, "receipt_status").unwrap_or("unknown");
            let summary_status = json_string(scenario, "summary_status").unwrap_or("unknown");
            out.push_str(&format!(
                "| `{}` | `{}` | `{}` | `{}` | `{}` |\n",
                markdown_escape(name),
                markdown_escape(status),
                markdown_escape(plan_status),
                markdown_escape(receipt_status),
                markdown_escape(summary_status)
            ));
        }
    }
    out.push('\n');
}

fn push_next_operator_step_capture_checklist_markdown(out: &mut String, step: &Value) {
    let Some(checklist) = step.get("external_capture_checklist") else {
        return;
    };
    if checklist.is_null() {
        return;
    }

    let owner = json_string(checklist, "owner").unwrap_or("operator_external_capture_tool");
    let local_pcapng = json_string(checklist, "local_pcapng").unwrap_or("capture.pcapng");
    let openracing_output = json_bool(checklist, "openracing_output").unwrap_or(false);
    let external_app_may_send_output =
        json_bool(checklist, "external_app_may_send_output").unwrap_or(true);

    out.push_str("### External Capture Checklist\n\n");
    out.push_str("This checklist is for the operator's USB capture tool. It is not an OpenRacing command sequence and it does not authorize OpenRacing output.\n\n");
    out.push_str(&format!("- Owner: `{}`\n", markdown_escape(owner)));
    out.push_str(&format!(
        "- Local pcapng: `{}`\n",
        markdown_escape(local_pcapng)
    ));
    out.push_str(&format!("- OpenRacing output: `{openracing_output}`\n"));
    out.push_str(&format!(
        "- External app may send output: `{external_app_may_send_output}`\n\n"
    ));

    if let Some(steps) = checklist.get("steps").and_then(Value::as_array)
        && !steps.is_empty()
    {
        out.push_str("| Step | Operator Action |\n");
        out.push_str("| --- | --- |\n");
        for (index, step) in steps.iter().enumerate() {
            let text = step.as_str().unwrap_or("");
            out.push_str(&format!(
                "| `{}` | {} |\n",
                index + 1,
                markdown_escape(text)
            ));
        }
        out.push('\n');
    }

    if let Some(forbidden) = checklist.get("forbidden_actions").and_then(Value::as_array)
        && !forbidden.is_empty()
    {
        let actions = forbidden
            .iter()
            .filter_map(Value::as_str)
            .map(markdown_escape)
            .collect::<Vec<_>>()
            .join(", ");
        out.push_str(&format!("- Forbidden actions: `{actions}`\n\n"));
    }
}

fn push_next_operator_step_external_capture_commands_markdown(out: &mut String, step: &Value) {
    let Some(commands) = step
        .get("external_capture_commands")
        .and_then(Value::as_array)
    else {
        return;
    };
    if commands.is_empty() {
        return;
    }

    out.push_str("### External Capture Commands\n\n");
    out.push_str("These command templates are for passive USB capture, not for OpenRacing hardware output. Run the notes-template command first; it renders the concrete USBPcap selector-bound capture command from the fresh hardware doctor receipt. Commands marked as capture-runtime or post-capture prerequisites are sequencing references, not immediate next commands.\n\n");
    out.push_str("| Name | Status | Command Template |\n");
    out.push_str("| --- | --- | --- |\n");
    for command in commands {
        let name = json_string(command, "name").unwrap_or("unknown");
        let status = json_string(command, "next_operator_command_status").unwrap_or("unknown");
        let command_text = json_string(command, "command_template").unwrap_or("");
        out.push_str(&format!(
            "| `{}` | `{}` | `{}` |\n",
            markdown_escape(name),
            markdown_escape(status),
            markdown_escape(command_text)
        ));
    }
    out.push('\n');
    if commands.iter().any(|command| {
        json_bool(command, "must_not_run_unrendered_template") == Some(true)
            || json_bool(command, "command_has_selector_placeholders") == Some(true)
    }) {
        out.push_str("Do not run placeholder capture templates directly. Use the rendered command in `operator-notes.md` after `wheelctl hardware sniff-notes-template` reads the fresh hardware doctor selector.\n\n");
    }
}

fn push_next_operator_step_commands_markdown(out: &mut String, step: &Value) {
    let Some(commands) = step.get("commands").and_then(Value::as_array) else {
        return;
    };
    let runnable_commands = commands
        .iter()
        .filter(|command| json_bool(command, "runnable_next_operator_command") != Some(false))
        .collect::<Vec<_>>();
    if runnable_commands.is_empty() {
        return;
    }

    out.push_str("### Next Operator Commands\n\n");
    if commands.len() != runnable_commands.len() {
        out.push_str("This table includes only commands runnable in the current pre-capture phase. It omits placeholder capture templates, capture-runtime marker commands, and post-capture receipt/summary/bundle/review commands until their prerequisites exist.\n\n");
    }
    out.push_str("| Name | Command |\n");
    out.push_str("| --- | --- |\n");
    for command in runnable_commands {
        let name = json_string(command, "name").unwrap_or("unknown");
        let command_text = json_string(command, "command").unwrap_or("");
        out.push_str(&format!(
            "| `{}` | `{}` |\n",
            markdown_escape(name),
            markdown_escape(command_text)
        ));
    }
    out.push('\n');
}

fn pit_house_case_artifacts_for_markdown(case_id: &str) -> (&'static str, &'static str) {
    pit_house_case_navigation_requirements()
        .iter()
        .find_map(|(known_case_id, _, case_artifact, observation_artifact)| {
            (*known_case_id == case_id).then_some((*case_artifact, *observation_artifact))
        })
        .unwrap_or(("unknown", "unknown"))
}

fn markdown_escape(value: &str) -> String {
    value.replace('|', "\\|")
}

