    #[test]
    fn artifact_index_separates_artifact_validity_from_stage_claim_status() -> TestResult {
        let dir = tempfile::tempdir()?;
        write_test_json_file(
            &dir.path().join("native-visible-verification.json"),
            &serde_json::json!({
                "success": false,
                "command": "wheelctl moza verify-bundle",
                "requested_stage": "native_visible_ready",
                "failed_gates": 1,
                "missing_artifacts": 0
            }),
        )?;
        write_test_json_file(
            &dir.path().join("smoke-ready-verification.json"),
            &serde_json::json!({
                "success": false,
                "command": "wheelctl moza verify-bundle",
                "requested_stage": "smoke_ready",
                "failed_gates": 4,
                "missing_artifacts": 3
            }),
        )?;

        let receipt = moza_artifact_index_receipt(dir.path(), None, None)?;
        let artifact_index = receipt
            .get("required_artifact_index")
            .and_then(Value::as_array)
            .ok_or("expected required_artifact_index array")?;
        for (path, failed_gates, not_claimed_note) in [
            (
                "native-visible-verification.json",
                "failed_gates=1",
                "native_visible_not_claimed",
            ),
            (
                "smoke-ready-verification.json",
                "failed_gates=4",
                "smoke_ready_not_claimed",
            ),
        ] {
            let artifact = artifact_index
                .iter()
                .find(|artifact| artifact.get("path").and_then(Value::as_str) == Some(path))
                .ok_or_else(|| format!("expected {path} in artifact index"))?;
            assert_eq!(
                artifact.get("status").and_then(Value::as_str),
                Some("pass"),
                "{path} should remain a valid readable JSON artifact"
            );
            assert_eq!(
                artifact.get("claim_status").and_then(Value::as_str),
                Some("stage_failed"),
                "{path} must not render as a passed readiness claim"
            );
            let claim_notes = artifact
                .get("claim_notes")
                .and_then(Value::as_array)
                .ok_or("expected claim notes for failed verification")?;
            assert!(
                claim_notes
                    .iter()
                    .any(|note| note.as_str() == Some(failed_gates)),
                "expected {path} claim notes to include {failed_gates}: {claim_notes:?}"
            );
            assert!(
                claim_notes
                    .iter()
                    .any(|note| note.as_str() == Some(not_claimed_note)),
                "expected {path} claim notes to include {not_claimed_note}: {claim_notes:?}"
            );
        }

        assert_eq!(
            json_bool(&receipt, "hardware_output_authorized"),
            Some(false)
        );
        assert_eq!(json_bool(&receipt, "native_visible_claimed"), Some(false));
        let readiness = receipt.get("readiness").ok_or("expected readiness")?;
        assert_ne!(
            readiness
                .get("native_visible_motion_proven")
                .and_then(Value::as_bool),
            Some(true),
            "valid failed native-visible verifier receipt must not become native-visible readiness"
        );
        assert_ne!(
            readiness
                .get("ready_for_real_hardware_smoke")
                .and_then(Value::as_bool),
            Some(true),
            "valid failed smoke verifier receipt must not become smoke readiness"
        );

        let markdown = render_moza_lane_artifact_index_markdown(&receipt);
        assert!(markdown.contains("Artifact Status | Claim Status"));
        assert!(markdown.contains(
            "| `native-visible-verification.json` | `native_visible_ready` | `pass` | `stage_failed` |"
        ));
        assert!(markdown.contains(
            "| `smoke-ready-verification.json` | `smoke_ready` | `pass` | `stage_failed` |"
        ));

        let wizard_receipt = moza_bench_wizard_receipt(dir.path(), None, None)?;
        assert_eq!(
            json_bool(&wizard_receipt, "hardware_output_authorized"),
            Some(false)
        );
        assert_eq!(
            json_bool(&wizard_receipt, "native_visible_claimed"),
            Some(false)
        );
        assert_eq!(
            json_bool(&wizard_receipt, "smoke_ready_claimed"),
            Some(false)
        );
        let wizard_readiness = wizard_receipt
            .get("readiness")
            .ok_or("expected bench-wizard readiness")?;
        assert_ne!(
            wizard_readiness
                .get("native_visible_motion_proven")
                .and_then(Value::as_bool),
            Some(true),
            "bench-wizard must not convert a valid failed native-visible receipt into readiness"
        );
        assert_ne!(
            wizard_readiness
                .get("ready_for_real_hardware_smoke")
                .and_then(Value::as_bool),
            Some(true),
            "bench-wizard must not convert a valid failed smoke receipt into readiness"
        );
        assert_eq!(
            wizard_receipt
                .pointer("/next_operator_step/kind")
                .and_then(Value::as_str),
            Some("refresh_readiness")
        );
        let active_blockers = wizard_receipt
            .get("active_blockers")
            .and_then(Value::as_array)
            .ok_or("expected bench-wizard active blockers")?;
        assert!(
            active_blockers.iter().any(|blocker| {
                json_string(blocker, "name") == Some("native_visible_motion")
                    && json_string(blocker, "status") == Some("blocked")
            }),
            "bench-wizard must keep native visible blocked when the verifier receipt failed: {active_blockers:?}"
        );
        Ok(())
    }

    #[test]
    fn artifact_navigation_surfaces_generic_aux_input_roles_without_blocking_readiness()
    -> TestResult {
        let dir = tempfile::tempdir()?;
        fs::create_dir_all(dir.path())?;
        write_test_json_file(
            &dir.path().join("passive-verification.json"),
            &serde_json::json!({
                "success": true,
                "command": "wheelctl moza verify-bundle",
                "requested_stage": "passive",
                "role_evidence": [
                    {
                        "control": "brake",
                        "role": "brake",
                        "required": true,
                        "semantic_status": "generic_aux",
                        "parser_visible": true,
                        "evidence_capture": "captures/r5-brake-only-sweep.jsonl",
                        "moving_required_axes": ["r5_v1_extended_axis0_u16"],
                        "missing_requirements": [],
                        "notes": [
                            "role is backed by generic live R5 V1 extended fields; semantic control naming remains unproven"
                        ]
                    },
                    {
                        "control": "steering",
                        "role": "steering",
                        "required": true,
                        "semantic_status": "proven",
                        "parser_visible": true,
                        "evidence_capture": "captures/r5-steering-sweep.jsonl",
                        "missing_requirements": [],
                        "notes": []
                    }
                ]
            }),
        )?;

        let index_receipt = moza_artifact_index_receipt(dir.path(), None, None)?;
        let semantics = index_receipt
            .get("input_role_semantics")
            .ok_or("expected input_role_semantics")?;
        assert_eq!(
            json_string(semantics, "semantic_status"),
            Some("partial_generic_aux_mapping")
        );
        assert_eq!(
            json_bool(semantics, "semantic_mapping_complete"),
            Some(false)
        );
        assert_eq!(json_u64(semantics, "required_role_count"), Some(2));
        assert_eq!(
            json_u64(semantics, "required_parser_visible_count"),
            Some(2)
        );
        assert_eq!(json_u64(semantics, "generic_aux_role_count"), Some(1));
        assert_eq!(json_u64(semantics, "unproven_required_role_count"), Some(1));
        assert_eq!(json_u64(semantics, "semantic_candidate_count"), Some(1));
        assert_eq!(
            json_u64(semantics, "ambiguous_semantic_candidate_count"),
            Some(0)
        );
        assert_eq!(json_bool(semantics, "blocks_native_control"), Some(false));
        assert_eq!(json_bool(semantics, "blocks_native_visible"), Some(false));
        assert_eq!(json_bool(semantics, "readiness_claim"), Some(false));
        let generic_aux_roles = semantics
            .get("generic_aux_roles")
            .and_then(Value::as_array)
            .ok_or("expected generic_aux_roles")?;
        assert!(
            generic_aux_roles.iter().any(|role| {
                json_string(role, "control") == Some("brake")
                    && json_string(role, "semantic_status") == Some("generic_aux")
            }),
            "expected brake to be surfaced as generic_aux: {generic_aux_roles:?}"
        );
        let brake_role = generic_aux_roles
            .iter()
            .find(|role| json_string(role, "control") == Some("brake"))
            .ok_or("expected brake generic_aux role")?;
        let candidates = brake_role
            .get("semantic_candidates")
            .and_then(Value::as_array)
            .ok_or("expected semantic_candidates")?;
        assert!(
            candidates.iter().any(|candidate| {
                json_string(candidate, "axis") == Some("r5_v1_extended_axis0_u16")
                    && json_string(candidate, "claim_status") == Some("candidate_only")
                    && json_string(candidate, "confidence") == Some("isolated_candidate")
                    && json_bool(candidate, "readiness_claim") == Some(false)
            }),
            "expected candidate-only brake axis metadata: {candidates:?}"
        );

        let index_markdown = render_moza_lane_artifact_index_markdown(&index_receipt);
        assert!(index_markdown.contains("Input Role Semantics"));
        assert!(index_markdown.contains("generic_aux"));
        assert!(
            index_markdown.contains("Role-specific semantic mapping complete: `false`"),
            "generic_aux input evidence must not render as complete semantic mapping: {index_markdown}"
        );
        assert!(
            index_markdown.contains("Unproven required role semantics: `1`"),
            "generic_aux input evidence must count as unproven role semantics: {index_markdown}"
        );
        assert!(index_markdown.contains("captures/r5-brake-only-sweep.jsonl"));
        assert!(index_markdown.contains("r5_v1_extended_axis0_u16"));

        let wizard_receipt = moza_bench_wizard_receipt(dir.path(), None, None)?;
        let wizard_semantics = wizard_receipt
            .get("input_role_semantics")
            .ok_or("expected wizard input_role_semantics")?;
        assert_eq!(
            json_string(wizard_semantics, "semantic_status"),
            Some("partial_generic_aux_mapping")
        );
        assert_eq!(
            json_bool(wizard_semantics, "semantic_mapping_complete"),
            Some(false)
        );
        assert_eq!(
            json_u64(wizard_semantics, "unproven_required_role_count"),
            Some(1)
        );
        assert_eq!(
            json_bool(&wizard_receipt, "hardware_output_authorized"),
            Some(false)
        );
        assert_eq!(
            json_bool(&wizard_receipt, "native_visible_claimed"),
            Some(false)
        );
        let wizard_markdown = render_moza_bench_wizard_markdown(&wizard_receipt);
        assert!(wizard_markdown.contains("Input Role Semantics"));
        assert!(wizard_markdown.contains("valid parser-visible passive evidence"));
        Ok(())
    }

