    #[test]
    fn vendor_authority_navigation_surfaces_blocked_attempt_without_post_authority_progression()
    -> TestResult {
        let dir = tempfile::tempdir()?;
        fs::create_dir_all(dir.path())?;
        let selector = "hid-0x346E-0x0004-if2-0x0001-0x0004";
        write_failed_controlled_angle_output_receipt_at(
            dir.path(),
            selector,
            NATIVE_CONTROLLED_ANGLE_ATTEMPT_03_SMOKE_FILE,
        )?;
        write_failed_controlled_angle_closed_loop_output_receipt(dir.path(), selector)?;
        write_test_json_file(
            &dir.path().join(NATIVE_PIDFF_STANDARD_PATH_DIAGNOSIS_FILE),
            &serde_json::json!({
                "schema_version": 1,
                "success": true,
                "command": "wheelctl moza standard-pidff-path-diagnosis",
                "classification": "standard_pidff_controlled_angle_path_ineffective_in_current_r5_mode",
                "native_visible_claimed": false,
                "smoke_ready_claimed": false,
                "planned_next_output": {
                    "allowed": false
                }
            }),
        )?;
        write_test_json_file(
            &dir.path().join(VENDOR_AUTHORITY_ATTEMPT_BLOCKED_FILE),
            &serde_json::json!({
                "success": false,
                "artifact_kind": "moza_vendor_authority_attempt_blocked",
                "claim_scope": "bounded_vendor_authority_attempt_blocked_before_send",
                "authorization_consumed": false,
                "sent_authorized_frame": false
            }),
        )?;

        let receipt = moza_bench_wizard_receipt(dir.path(), None, None)?;
        let navigation = receipt
            .get("vendor_authority_navigation")
            .ok_or("expected vendor_authority_navigation")?;
        assert_eq!(
            json_string(navigation, "state"),
            Some("vendor_authority_attempt_blocked_before_send")
        );
        assert_eq!(
            json_bool(navigation, "vendor_authority_attempt_recorded"),
            Some(false)
        );
        assert_eq!(
            json_bool(navigation, "vendor_authority_attempt_blocked_recorded"),
            Some(true)
        );
        assert_eq!(
            json_bool(navigation, "hardware_output_authorized"),
            Some(false)
        );
        assert_eq!(json_bool(navigation, "native_visible_ready"), Some(false));

        let step = receipt
            .get("next_operator_step")
            .ok_or("expected next operator step")?;
        assert_eq!(
            json_string(step, "kind"),
            Some("vendor_authority_attempt_blocked_before_send")
        );
        assert_eq!(json_bool(step, "hardware_output_allowed_now"), Some(false));
        assert_eq!(
            json_bool(step, "requires_fresh_authorization_for_retry"),
            Some(true)
        );
        assert_eq!(
            json_string(step, "blocked_attempt_receipt"),
            Some(VENDOR_AUTHORITY_ATTEMPT_BLOCKED_FILE)
        );
        assert_eq!(
            json_string(step, "planned_output_receipt"),
            Some(VENDOR_AUTHORITY_ATTEMPT_FILE)
        );
        assert!(
            !step
                .get("commands")
                .and_then(Value::as_array)
                .is_some_and(|commands| commands.iter().any(|command| {
                    json_string(command, "command")
                        .is_some_and(|text| text.contains("vendor-post-authority-pidff-response"))
                })),
            "blocked attempts must not progress to post-authority comparison commands: {step}"
        );

        Ok(())
    }

    #[test]
    fn simulator_navigation_suppresses_unaccepted_receipt_output_fields() -> TestResult {
        let dir = tempfile::tempdir()?;
        fs::create_dir_all(dir.path())?;
        write_test_json_file(
            &dir.path().join("simulator-telemetry-proof.json"),
            &serde_json::json!({
                "success": false,
                "command": "wheelctl moza simulator-telemetry-proof",
                "game": "simhub-bridge",
                "telemetry_source": "simhub_bridge",
                "hardware_output_enabled": true,
                "no_ffb_writes": false,
                "normalized_snapshot_count": 120,
                "duration_ms": 5000,
                "recorder_artifact": "simulator-telemetry-recording.jsonl",
                "faults": ["invalid test receipt"]
            }),
        )?;
        write_test_json_file(
            &dir.path().join("simulator-ffb-smoke.json"),
            &serde_json::json!({
                "success": false,
                "command": "wheelctl moza simulator-ffb-smoke",
                "game": "simhub-bridge",
                "telemetry_source": "simhub_bridge",
                "hardware": "moza-r5",
                "hardware_output_enabled": true,
                "max_output_percent": 5.0,
                "final_zero_sent": true,
                "output_log_artifact": "simulator-ffb-output.jsonl",
                "faults": ["invalid test receipt"]
            }),
        )?;

        let receipt = moza_artifact_index_receipt(dir.path(), None, None)?;
        let simulator = receipt
            .get("simulator_compatibility")
            .ok_or("expected simulator_compatibility summary")?;
        assert_eq!(
            json_bool(simulator, "simulator_telemetry_claimed"),
            Some(false)
        );
        assert_eq!(
            json_bool(simulator, "bounded_simulator_ffb_claimed"),
            Some(false)
        );
        assert_eq!(json_u64(simulator, "recorded_artifact_count"), Some(2));

        let telemetry = simulator
            .get("telemetry")
            .ok_or("expected simulator telemetry navigation")?;
        assert_eq!(json_bool(telemetry, "artifact_exists"), Some(true));
        assert_eq!(
            json_string(telemetry, "claim_status"),
            Some("present_not_accepted")
        );
        assert_eq!(json_string(telemetry, "gate_status"), Some("fail"));
        assert!(
            telemetry.get("game").and_then(Value::as_str).is_none(),
            "unaccepted telemetry receipt metadata must not be surfaced"
        );
        assert!(
            telemetry
                .get("hardware_output_enabled")
                .and_then(Value::as_bool)
                .is_none(),
            "unaccepted telemetry output-looking fields must not be surfaced"
        );
        assert!(
            telemetry
                .get("no_ffb_writes")
                .and_then(Value::as_bool)
                .is_none(),
            "unaccepted telemetry safety fields must not be surfaced as claims"
        );

        let bounded_ffb = simulator
            .get("bounded_ffb")
            .ok_or("expected bounded simulator FFB navigation")?;
        assert_eq!(json_bool(bounded_ffb, "artifact_exists"), Some(true));
        assert_eq!(
            json_string(bounded_ffb, "claim_status"),
            Some("present_not_accepted")
        );
        assert_eq!(json_string(bounded_ffb, "gate_status"), Some("fail"));
        assert!(
            bounded_ffb
                .get("hardware_output_enabled")
                .and_then(Value::as_bool)
                .is_none(),
            "unaccepted FFB output-looking fields must not be surfaced"
        );
        assert!(
            bounded_ffb
                .get("final_zero_sent")
                .and_then(Value::as_bool)
                .is_none(),
            "unaccepted FFB cleanup-looking fields must not be surfaced"
        );
        assert!(
            bounded_ffb
                .get("max_output_percent")
                .and_then(Value::as_f64)
                .is_none(),
            "unaccepted FFB bound-looking fields must not be surfaced"
        );
        assert_eq!(
            json_bool(&receipt, "hardware_output_authorized"),
            Some(false)
        );
        assert_eq!(json_bool(&receipt, "native_visible_claimed"), Some(false));
        Ok(())
    }

    #[test]
    fn bench_wizard_is_no_output_frontier_navigation() -> TestResult {
        let dir = tempfile::tempdir()?;
        fs::create_dir_all(dir.path())?;
        write_test_json_file(
            &dir.path()
                .join(NATIVE_CONTROLLED_ANGLE_ATTEMPT_03_PREFLIGHT_FILE),
            &serde_json::json!({
                "success": true,
                "command": "wheelctl moza controlled-angle-smoke",
                "dry_run": true,
                "hardware_output_enabled": false,
                "no_hid_device_opened": true,
                "no_ffb_writes": true,
                "profile_cli": "bounded-pidff-effect-lifecycle-v1"
            }),
        )?;

        let receipt = moza_bench_wizard_receipt(dir.path(), None, None)?;

        assert_eq!(
            json_string(&receipt, "command"),
            Some("wheelctl moza bench-wizard")
        );
        assert_eq!(json_bool(&receipt, "no_hid_device_opened"), Some(true));
        assert_eq!(json_bool(&receipt, "no_ffb_writes"), Some(true));
        assert_eq!(
            json_bool(&receipt, "hardware_output_authorized"),
            Some(false)
        );
        assert_eq!(
            json_bool(&receipt, "authorization_receipt_created"),
            Some(false)
        );
        assert_eq!(json_bool(&receipt, "native_visible_claimed"), Some(false));
        assert_eq!(json_bool(&receipt, "smoke_ready_claimed"), Some(false));
        assert_eq!(
            json_string(&receipt, "frontier"),
            Some("repeated_safe_undertravel_attempt_03_preflight_recorded")
        );
        assert_eq!(
            receipt
                .pointer("/next_operator_step/kind")
                .and_then(Value::as_str),
            Some("awaiting_separate_attempt_03_authorization")
        );
        let step_summary = receipt
            .pointer("/next_operator_step/summary")
            .and_then(Value::as_str)
            .ok_or("expected next operator summary")?;
        assert!(
            step_summary.contains("attempt 03 preflight is recorded"),
            "bench wizard must report the completed no-output attempt-03 preflight: {step_summary}"
        );
        assert!(
            step_summary.contains("separate fresh command-bound bench-clear")
                && step_summary.contains("exact authorization receipt"),
            "bench wizard must keep output blocked on fresh clearance and exact authorization: {step_summary}"
        );
        assert_eq!(
            receipt
                .pointer("/next_operator_step/required_bench_clear_evidence")
                .and_then(Value::as_str),
            Some(NATIVE_CONTROLLED_ANGLE_ATTEMPT_03_BENCH_CLEAR_EVIDENCE)
        );
        assert_eq!(
            receipt
                .pointer("/next_operator_step/required_authorization_receipt")
                .and_then(Value::as_str),
            Some(NATIVE_CONTROLLED_ANGLE_ATTEMPT_03_AUTHORIZATION_FILE)
        );
        assert_eq!(
            receipt
                .pointer("/next_operator_step/planned_output_receipt")
                .and_then(Value::as_str),
            Some(NATIVE_CONTROLLED_ANGLE_ATTEMPT_03_SMOKE_FILE)
        );
        let active_blockers = receipt
            .get("active_blockers")
            .and_then(Value::as_array)
            .ok_or("expected active blockers")?;
        assert!(
            active_blockers.iter().any(|blocker| {
                json_string(blocker, "name") == Some("native_visible_motion")
                    && json_string(blocker, "blocking_stage") == Some("native_visible_ready")
                    && json_string(blocker, "status") == Some("blocked")
            }),
            "bench wizard must keep native visible motion blocked: {active_blockers:?}"
        );
        let safe_commands = receipt
            .get("safe_no_output_commands")
            .and_then(Value::as_array)
            .ok_or("expected safe_no_output_commands")?;
        for command in safe_commands {
            assert_eq!(
                command.get("output_enabled").and_then(Value::as_bool),
                Some(false)
            );
            let command_text = json_string(command, "command").unwrap_or("");
            assert!(
                !command_text.contains("authorize-controlled-angle-output"),
                "bench wizard must not emit authorization commands: {command_text}"
            );
            assert!(
                !command_text.contains("--confirm-controlled-angle"),
                "bench wizard must not emit output commands: {command_text}"
            );
        }
        let markdown = render_moza_bench_wizard_markdown(&receipt);
        assert!(markdown.contains("read-only operator navigation"));
        assert!(markdown.contains("Safe No-Output Commands"));
        assert!(markdown.contains("Output is not authorized by this wizard"));
        assert!(markdown.contains(NATIVE_CONTROLLED_ANGLE_ATTEMPT_03_BENCH_CLEAR_EVIDENCE));
        Ok(())
    }

