    #[test]
    fn pre_output_readiness_allows_pidff_zero_when_descriptor_lacks_direct_report() -> TestResult {
        let dir = tempfile::tempdir()?;
        write_minimal_passive_bundle(dir.path())?;
        write_service_status_artifacts(dir.path())?;
        write_lane_audit_receipts(dir.path(), MozaBundleStage::Passive)?;
        let mut manifest = sample_lane_manifest("passive_capture_ready", false, false);
        manifest["hardware"]["wheelbase_pid"] = serde_json::json!("0x0004");
        manifest["topology"] = moza_lane_manifest_topology_value(product_ids::R5_V1);
        write_test_json_file(&dir.path().join("manifest.json"), &manifest)?;
        write_test_json_file(
            &dir.path().join("descriptor.json"),
            &serde_json::json!({
                "success": true,
                "command": "hid-capture descriptor",
                "no_hid_device_opened": true,
                "no_ffb_writes": true,
                "no_serial_config_commands": true,
                "no_firmware_or_dfu_commands": true,
                "devices": [sample_trusted_r5_v1_json_device()]
            }),
        )?;

        let receipt = pre_output_readiness_dir(dir.path());

        assert!(receipt.success);
        assert!(receipt.ready_for_zero_torque);
        assert!(!receipt.ready_for_ffb);
        assert!(
            receipt.blocking_items.is_empty(),
            "PIDFF stop-all should satisfy zero-output readiness when descriptor metadata is trusted"
        );
        assert!(
            receipt
                .passed_items
                .iter()
                .any(|item| item == "zero_output_strategy_ready")
        );
        assert!(
            receipt
                .passed_items
                .iter()
                .any(|item| item == "ready_for_zero_torque")
        );
        let direct = receipt
            .zero_output_strategies
            .iter()
            .find(|strategy| strategy.name == "direct_report_0x20")
            .ok_or("expected direct zero-output strategy")?;
        assert!(direct.implemented);
        assert!(!direct.ready);
        assert!(!direct.descriptor_report_observed);
        assert!(
            direct
                .blocking_items
                .contains(&"direct_zero_report_metadata")
        );
        let pidff = receipt
            .zero_output_strategies
            .iter()
            .find(|strategy| strategy.name == "pidff_device_control_stop_all")
            .ok_or("expected PIDFF stop-all zero-output candidate")?;
        assert!(pidff.implemented);
        assert!(pidff.descriptor_report_observed);
        assert!(pidff.descriptor_metadata_trusted);
        assert!(pidff.ready);
        assert!(pidff.blocking_items.is_empty());
        Ok(())
    }

    #[test]
    fn pre_output_readiness_surfaces_generic_aux_input_semantics_without_readiness_blocker()
    -> TestResult {
        let dir = tempfile::tempdir()?;
        fs::create_dir_all(dir.path())?;
        write_test_json_file(
            &dir.path().join("passive-verification.json"),
            &serde_json::json!({
                "success": true,
                "command": "wheelctl moza verify-bundle",
                "lane": dir.path().display().to_string(),
                "requested_stage": "passive",
                "missing_artifacts": 0,
                "invalid_artifacts": 0,
                "failed_gates": 0,
                "no_hid_device_opened": true,
                "no_ffb_writes": true,
                "no_serial_config_commands": true,
                "no_firmware_or_dfu_commands": true,
                "gates": [
                    {"name": "lane_directory", "status": "pass"},
                    {"name": "manifest_no_overclaim", "status": "pass"},
                    {"name": "manifest_r5_pid_consistency", "status": "pass"},
                    {"name": "moza_r5_observed", "status": "pass"},
                    {"name": "moza_topology_observed", "status": "pass"},
                    {"name": "descriptor_metadata", "status": "pass"},
                    {"name": "passive_receipts_successful", "status": "pass"},
                    {"name": "passive_receipts_no_ffb_writes", "status": "pass"},
                    {"name": "passive_captures_parse", "status": "pass"},
                    {"name": "parser_fixture_validation", "status": "pass"},
                    {"name": "fixture_promotion", "status": "pass"}
                ],
                "role_evidence": [
                    {
                        "control": "brake",
                        "role": "brake",
                        "required": true,
                        "semantic_status": "generic_aux",
                        "parser_visible": true,
                        "evidence_capture": "captures/r5-brake-only-sweep.jsonl",
                        "moving_required_axes": ["r5_v1_extended_axis0_u16"],
                        "missing_requirements": [],
                        "notes": [
                            "role is backed by generic live R5 V1 extended fields; semantic control naming remains unproven"
                        ]
                    },
                    {
                        "control": "steering",
                        "role": "steering",
                        "required": true,
                        "semantic_status": "proven",
                        "parser_visible": true,
                        "evidence_capture": "captures/r5-steering-sweep.jsonl",
                        "missing_requirements": [],
                        "notes": []
                    }
                ]
            }),
        )?;

        let receipt = pre_output_readiness_dir(dir.path());

        assert!(!receipt.input_semantic_mapping_complete);
        let semantics = &receipt.input_role_semantics;
        assert_eq!(
            json_string(semantics, "semantic_status"),
            Some("partial_generic_aux_mapping")
        );
        assert_eq!(json_u64(semantics, "required_role_count"), Some(2));
        assert_eq!(
            json_u64(semantics, "required_parser_visible_count"),
            Some(2)
        );
        assert_eq!(json_u64(semantics, "generic_aux_role_count"), Some(1));
        assert_eq!(json_u64(semantics, "semantic_candidate_count"), Some(1));
        assert_eq!(json_bool(semantics, "blocks_native_control"), Some(false));
        assert_eq!(json_bool(semantics, "blocks_native_visible"), Some(false));
        assert_eq!(json_bool(semantics, "blocks_smoke_ready"), Some(false));
        assert_eq!(json_bool(semantics, "readiness_claim"), Some(false));
        let generic_aux_roles = semantics
            .get("generic_aux_roles")
            .and_then(Value::as_array)
            .ok_or("expected generic_aux_roles")?;
        let brake_role = generic_aux_roles
            .iter()
            .find(|role| json_string(role, "control") == Some("brake"))
            .ok_or("expected brake generic_aux role")?;
        let candidates = brake_role
            .get("semantic_candidates")
            .and_then(Value::as_array)
            .ok_or("expected semantic_candidates")?;
        assert!(
            candidates.iter().any(|candidate| {
                json_string(candidate, "axis") == Some("r5_v1_extended_axis0_u16")
                    && json_string(candidate, "claim_status") == Some("candidate_only")
                    && json_bool(candidate, "readiness_claim") == Some(false)
            }),
            "expected pre-output candidate-only brake metadata: {candidates:?}"
        );
        assert!(
            receipt
                .passed_items
                .iter()
                .any(|item| item == "role_evidence_complete")
        );
        assert!(
            !receipt
                .blocking_items
                .iter()
                .any(|item| item == "input_semantic_mapping_complete")
        );
        assert!(
            !receipt
                .passed_items
                .iter()
                .any(|item| item == "input_semantic_mapping_complete")
        );
        Ok(())
    }

    #[test]
    fn pre_output_readiness_surfaces_external_compatibility_without_native_prerequisite()
    -> TestResult {
        let dir = tempfile::tempdir()?;
        fs::create_dir_all(dir.path())?;
        write_pit_house_artifacts(dir.path())?;
        write_test_json_file(
            &dir.path().join("pit-house-availability.json"),
            &pit_house_availability_receipt_unavailable(),
        )?;
        for artifact in [
            "pit-house-open-standard.json",
            "pit-house-direct-blocked.json",
            "pit-house-mode-change.json",
            "pit-house-firmware-page.json",
            "pit-house-observation-open-standard.json",
            "pit-house-observation-open-direct.json",
            "pit-house-observation-mode-change.json",
            "pit-house-observation-firmware-page.json",
            "simulator-ffb-smoke.json",
        ] {
            let path = dir.path().join(artifact);
            if path.is_file() {
                fs::remove_file(path)?;
            }
        }
        write_test_json_file(
            &dir.path().join("smoke-ready-verification.json"),
            &serde_json::json!({
                "success": false,
                "command": "wheelctl moza verify-bundle",
                "lane": dir.path().display().to_string(),
                "requested_stage": "smoke_ready",
                "missing_artifacts": 0,
                "invalid_artifacts": 0,
                "failed_gates": 2,
                "no_hid_device_opened": true,
                "no_ffb_writes": true,
                "no_serial_config_commands": true,
                "no_firmware_or_dfu_commands": true,
                "artifacts": [],
                "gates": [
                    {"name": "simulator_telemetry", "status": "pass"},
                    {"name": "simulator_ffb_bounded", "status": "fail"},
                    {"name": "pit_house_coexistence", "status": "fail"}
                ],
                "role_evidence": []
            }),
        )?;

        let receipt = pre_output_readiness_dir(dir.path());

        let pit_house = &receipt.pit_house_compatibility;
        assert_eq!(
            json_string(pit_house, "claim_scope"),
            Some("external_compatibility_navigation_only")
        );
        assert_eq!(
            json_string(pit_house, "availability_status"),
            Some("not_installed_or_not_running")
        );
        assert_eq!(
            json_string(pit_house, "official_download_page"),
            Some(MOZA_PIT_HOUSE_DOWNLOADS_URL)
        );
        assert_eq!(
            json_string(pit_house, "install_guidance"),
            Some(MOZA_PIT_HOUSE_INSTALL_GUIDANCE)
        );
        assert_eq!(
            json_bool(pit_house, "pit_house_coexistence_claimed"),
            Some(false)
        );
        assert_eq!(json_u64(pit_house, "required_case_count"), Some(5));
        assert_eq!(json_u64(pit_house, "recorded_case_count"), Some(1));
        assert_eq!(json_bool(pit_house, "blocks_native_control"), Some(false));
        assert_eq!(json_bool(pit_house, "blocks_native_visible"), Some(false));
        assert_eq!(json_bool(pit_house, "blocks_smoke_ready"), Some(true));
        assert_eq!(json_bool(pit_house, "readiness_claim"), Some(false));

        let simulator = &receipt.simulator_compatibility;
        assert_eq!(
            json_string(simulator, "claim_scope"),
            Some("external_compatibility_navigation_only")
        );
        assert_eq!(
            json_bool(simulator, "simulator_telemetry_claimed"),
            Some(true)
        );
        assert_eq!(
            json_bool(simulator, "bounded_simulator_ffb_claimed"),
            Some(false)
        );
        assert_eq!(json_u64(simulator, "required_artifact_count"), Some(2));
        assert_eq!(json_u64(simulator, "recorded_artifact_count"), Some(1));
        assert_eq!(json_bool(simulator, "blocks_native_control"), Some(false));
        assert_eq!(json_bool(simulator, "blocks_native_visible"), Some(false));
        assert_eq!(json_bool(simulator, "blocks_smoke_ready"), Some(true));
        assert_eq!(json_bool(simulator, "readiness_claim"), Some(false));
        let bounded_ffb = simulator
            .get("bounded_ffb")
            .ok_or("expected bounded simulator FFB pre-output summary")?;
        assert_eq!(json_string(bounded_ffb, "claim_status"), Some("missing"));
        assert_eq!(json_bool(bounded_ffb, "readiness_claim"), Some(false));

        assert!(
            receipt
                .external_compatibility_blocking_items
                .iter()
                .any(|item| item == "pit_house_coexistence")
        );
        assert!(
            receipt
                .external_compatibility_blocking_items
                .iter()
                .any(|item| item == "simulator_ffb_bounded")
        );
        for external_gate in [
            "pit_house_coexistence",
            "simulator_telemetry",
            "simulator_ffb_bounded",
        ] {
            assert!(
                !receipt
                    .native_control_blocking_items
                    .iter()
                    .any(|item| item == external_gate),
                "native control readiness must not be blocked by {external_gate}"
            );
        }
        Ok(())
    }

