    #[tokio::test]
    async fn receipt_template_writes_verifier_rejected_planning_templates() -> TestResult {
        let dir = tempfile::tempdir()?;
        let follow_up_path = dir.path().join(NATIVE_VISIBLE_FOLLOW_UP_PLAN_FILE);
        let controlled_angle_path = dir.path().join(NATIVE_CONTROLLED_ANGLE_PLAN_FILE);
        let telemetry_path = dir.path().join("simulator-telemetry-proof.json");
        let ffb_path = dir.path().join("simulator-ffb-smoke.json");

        receipt_template(
            false,
            MozaReceiptTemplateKind::VisibleMotionFollowUp,
            &follow_up_path,
            false,
        )
        .await?;
        receipt_template(
            false,
            MozaReceiptTemplateKind::ControlledAnglePlan,
            &controlled_angle_path,
            false,
        )
        .await?;
        receipt_template(
            false,
            MozaReceiptTemplateKind::SimulatorTelemetry,
            &telemetry_path,
            false,
        )
        .await?;
        receipt_template(
            false,
            MozaReceiptTemplateKind::SimulatorFfb,
            &ffb_path,
            false,
        )
        .await?;

        let follow_up = read_json_path(&follow_up_path)?;
        let controlled_angle = read_json_path(&controlled_angle_path)?;
        let telemetry = read_json_path(&telemetry_path)?;
        let ffb = read_json_path(&ffb_path)?;
        assert_eq!(json_bool(&follow_up, "success"), Some(false));
        assert_eq!(
            json_string(&follow_up, "review_scope"),
            Some("native_actuator_visible_motion_failure")
        );
        assert_eq!(
            json_bool(&follow_up, "hardware_output_authorized"),
            Some(false)
        );
        assert_eq!(
            json_bool(&follow_up, "force_escalation_authorized"),
            Some(false)
        );
        assert_eq!(
            json_string(&follow_up, "prior_receipt"),
            Some("native-actuator-visible-smoke.json")
        );
        let Some(profile_design) = follow_up.get("intentional_profile_design") else {
            return Err("visible follow-up template missing intentional_profile_design".into());
        };
        assert_eq!(
            json_string(profile_design, "status"),
            Some("no_output_authorized")
        );
        let Some(limits) = profile_design.get("current_cli_limits") else {
            return Err("visible follow-up template missing current_cli_limits".into());
        };
        assert_eq!(json_u64(limits, "max_percent_limit"), Some(5));
        assert_eq!(json_u64(limits, "duration_ms_limit"), Some(2000));
        assert_eq!(json_bool(limits, "direct_report_0x20_allowed"), Some(false));
        assert_eq!(json_bool(limits, "high_torque_allowed"), Some(false));
        let Some(selected_profile) = profile_design.get("selected_next_profile") else {
            return Err("visible follow-up template missing selected_next_profile".into());
        };
        assert_eq!(
            json_string(selected_profile, "status"),
            Some("software_profile_implemented_no_output_authorized")
        );
        assert_eq!(
            json_string(selected_profile, "family"),
            Some("bounded_shaped_pidff_micro_profile")
        );
        assert_eq!(
            json_string(selected_profile, "current_cli_support"),
            Some("implemented_pending_bench_clear")
        );
        assert_eq!(
            json_string(selected_profile, "command_profile"),
            Some("bounded-shaped-pidff-micro-profile")
        );
        assert!(
            json_string(selected_profile, "reviewed_command_template")
                .map(|command| command.contains("--profile bounded-shaped-pidff-micro-profile"))
                .unwrap_or(false)
        );
        let Some(envelope) = selected_profile.get("expected_small_angle_envelope_degrees") else {
            return Err("visible follow-up template missing expected angle envelope".into());
        };
        assert_eq!(json_f64(envelope, "min"), Some(1.0));
        assert_eq!(json_f64(envelope, "max"), Some(3.0));
        let Some(later_controlled_angle) = profile_design.get("later_controlled_angle_profile")
        else {
            return Err("visible follow-up template missing later_controlled_angle_profile".into());
        };
        assert_eq!(
            json_bool(later_controlled_angle, "open_loop_dwell_allowed"),
            Some(false)
        );
        assert_eq!(
            json_bool(later_controlled_angle, "duration_only_profile_allowed"),
            Some(false)
        );
        assert_eq!(
            follow_up
                .get("controlled_angle_plan_artifact")
                .and_then(|artifact| json_string(artifact, "artifact")),
            Some(NATIVE_CONTROLLED_ANGLE_PLAN_FILE)
        );
        assert_eq!(json_bool(&controlled_angle, "success"), Some(false));
        assert_eq!(json_bool(&controlled_angle, "template"), Some(true));
        assert_eq!(
            json_string(&controlled_angle, "review_scope"),
            Some("native_controlled_angle_profile_design")
        );
        assert_eq!(
            json_bool(&controlled_angle, "hardware_output_authorized"),
            Some(false)
        );
        assert_eq!(
            json_bool(&controlled_angle, "force_escalation_authorized"),
            Some(false)
        );
        assert_eq!(
            json_bool(&controlled_angle, "no_hid_device_opened"),
            Some(true)
        );
        assert_eq!(json_bool(&controlled_angle, "no_ffb_writes"), Some(true));
        let Some(controlled_plan) = controlled_angle.get("controlled_angle_profile_plan") else {
            return Err("controlled-angle template missing controlled_angle_profile_plan".into());
        };
        assert_eq!(
            json_bool(controlled_plan, "open_loop_dwell_allowed"),
            Some(false)
        );
        assert_eq!(
            json_bool(controlled_plan, "duration_only_profile_allowed"),
            Some(false)
        );
        assert_eq!(
            json_string(controlled_plan, "status"),
            Some("retry_profile_implemented_no_output_authorized")
        );
        let Some(retry_profile) = controlled_plan.get("reviewed_retry_profile") else {
            return Err("controlled-angle template missing reviewed_retry_profile".into());
        };
        assert_eq!(
            json_string(retry_profile, "profile"),
            Some("bounded_pidff_micro_step_v2")
        );
        assert_eq!(
            json_bool(retry_profile, "hardware_output_authorized"),
            Some(false)
        );
        let Some(stages) = controlled_plan.get("stages").and_then(Value::as_array) else {
            return Err("controlled-angle template missing stages".into());
        };
        let targets = stages
            .iter()
            .map(|stage| json_u64(stage, "target_degrees").ok_or("stage missing target_degrees"))
            .collect::<Result<Vec<_>, _>>()?;
        assert_eq!(targets, vec![1, 3, 5, 10, 30, 90]);
        assert!(
            stages
                .iter()
                .all(|stage| json_string(stage, "status") == Some("not_authorized"))
        );
        assert_eq!(
            controlled_angle
                .get("planned_next_output")
                .and_then(|planned| json_bool(planned, "allowed")),
            Some(false)
        );
        assert_eq!(json_bool(&telemetry, "success"), Some(false));
        assert_eq!(json_bool(&ffb, "success"), Some(false));
        assert_eq!(json_bool(&telemetry, "no_ffb_writes"), Some(true));
        assert_eq!(
            json_string(&telemetry, "recorder_command"),
            Some(SIMULATOR_TELEMETRY_RECORDER_COMMAND)
        );
        assert_eq!(json_string(&telemetry, "recorder_session_id"), Some(""));
        assert_eq!(json_bool(&ffb, "high_torque"), Some(false));
        assert_eq!(
            json_bool(&ffb, "hardware_prerequisites_validated"),
            Some(false)
        );
        assert_eq!(
            json_string(&ffb, "writer_command"),
            Some(SIMULATOR_FFB_WRITER_COMMAND)
        );
        assert_eq!(json_string(&ffb, "writer_started_at_utc"), Some(""));
        assert_eq!(json_string(&ffb, "writer_endpoint_selector"), Some(""));
        assert_eq!(
            json_string(&ffb, "input_telemetry_recorder_session_id"),
            Some("")
        );

        let Some(prerequisite_gates) = ffb.get("prerequisite_gates").and_then(Value::as_array)
        else {
            return Err("simulator FFB template missing prerequisite_gates".into());
        };
        assert_eq!(
            prerequisite_gates.len(),
            SIMULATOR_FFB_PREREQUISITE_ARTIFACTS.len()
        );
        for ((gate_name, _), gate) in SIMULATOR_FFB_PREREQUISITE_ARTIFACTS
            .iter()
            .zip(prerequisite_gates)
        {
            assert_eq!(json_string(gate, "name"), Some(*gate_name));
            assert_eq!(json_string(gate, "status"), Some("operator_pending"));
        }

        let Some(prerequisite_artifacts) =
            ffb.get("prerequisite_artifacts").and_then(Value::as_array)
        else {
            return Err("simulator FFB template missing prerequisite_artifacts".into());
        };
        assert_eq!(
            prerequisite_artifacts.len(),
            SIMULATOR_FFB_PREREQUISITE_ARTIFACTS.len()
        );
        for ((gate_name, path), artifact) in SIMULATOR_FFB_PREREQUISITE_ARTIFACTS
            .iter()
            .zip(prerequisite_artifacts)
        {
            assert_eq!(json_string(artifact, "gate"), Some(*gate_name));
            assert_eq!(json_string(artifact, "path"), Some(*path));
            assert_eq!(json_string(artifact, "generated_at_utc"), Some(""));
            assert_eq!(json_string(artifact, "receipt_crc32"), Some(""));
        }

        let telemetry_gate = verify_simulator_telemetry_gate(dir.path());
        let ffb_gate = verify_simulator_ffb_gate(dir.path());
        assert_eq!(telemetry_gate.status, "fail");
        assert_eq!(ffb_gate.status, "fail");
        Ok(())
    }

