    #[test]
    fn verify_bundle_smoke_next_commands_stop_at_current_frontier() -> TestResult {
        let dir = tempfile::tempdir()?;
        write_minimal_passive_bundle(dir.path())?;
        write_zero_stage_receipts(dir.path())?;

        let receipt = verify_bundle_dir(dir.path(), MozaBundleStage::SmokeReady);
        let commands = receipt.next_commands.join("\n");
        assert!(
            commands.contains("wheelctl moza init --device")
                && commands.contains("--mode off")
                && commands.contains("--confirm-init")
                && commands.contains("--device hid-0x346E-0x0014-if2-0x0001-0x0004"),
            "zero-ready smoke guidance should first suggest only the off init receipt: {commands}"
        );
        for forbidden in [
            "--mode standard",
            "wheelctl moza torque-test",
            "wheelctl telemetry record",
            "wheelctl moza simulator-ffb-smoke",
            "wheelctl moza pit-house-proof",
        ] {
            assert!(
                !commands.contains(forbidden),
                "smoke-ready guidance must not include {forbidden} before off init passes: {commands}"
            );
        }

        write_test_json_file(
            &dir.path().join("init-off.json"),
            &receipt_with_lane_path(dir.path(), "init-off.json", real_init_receipt("off")),
        )?;
        let receipt = verify_bundle_dir(dir.path(), MozaBundleStage::SmokeReady);
        let commands = receipt.next_commands.join("\n");
        assert!(
            commands.contains("--mode standard") && !commands.contains("wheelctl moza torque-test"),
            "after off init passes, guidance should advance only to standard init: {commands}"
        );

        write_test_json_file(
            &dir.path().join("init-standard.json"),
            &receipt_with_lane_path(
                dir.path(),
                "init-standard.json",
                real_init_receipt("standard"),
            ),
        )?;
        let receipt = verify_bundle_dir(dir.path(), MozaBundleStage::SmokeReady);
        let commands = receipt.next_commands.join("\n");
        assert!(
            commands.contains("wheelctl moza status --device")
                && commands.contains("wheelctl device status")
                && commands.contains("wheelctl --json support-bundle")
                && !commands.contains("wheelctl moza torque-test"),
            "after both init receipts pass, guidance should refresh service/status receipts before low torque: {commands}"
        );

        write_service_status_artifacts(dir.path())?;
        let receipt = verify_bundle_dir(dir.path(), MozaBundleStage::SmokeReady);
        let commands = receipt.next_commands.join("\n");
        assert!(
            commands.contains("wheelctl moza torque-test --device")
                && commands.contains("--confirm-low-torque")
                && !commands.contains("wheelctl moza simulator-ffb-smoke"),
            "after service/status receipts pass, guidance should advance only to low torque: {commands}"
        );

        write_test_json_file(
            &dir.path().join("low-torque-proof.json"),
            &real_low_torque_receipt_for_lane(dir.path(), 2.0)?,
        )?;
        let receipt = verify_bundle_dir(dir.path(), MozaBundleStage::SmokeReady);
        let commands = receipt.next_commands.join("\n");
        assert!(
            commands.contains("wheelctl moza pre-output-readiness")
                && !commands.contains("wheelctl telemetry record")
                && !commands.contains("wheelctl moza simulator-ffb-smoke"),
            "after low torque passes, guidance should wait for native steering/actuator proof before external telemetry: {commands}"
        );

        write_test_json_file(
            &dir.path().join("steering-angle-stream-proof.json"),
            &steering_angle_stream_receipt(dir.path()),
        )?;
        write_test_json_file(
            &dir.path().join("native-actuator-profile-smoke.json"),
            &native_actuator_profile_smoke_receipt(dir.path()),
        )?;
        let receipt = verify_bundle_dir(dir.path(), MozaBundleStage::SmokeReady);
        let commands = receipt.next_commands.join("\n");
        assert!(
            commands.contains("wheelctl moza actuator-visible-smoke")
                && commands.contains("--confirm-actuator-visible")
                && commands.contains("--max-percent 5")
                && !commands.contains("wheelctl telemetry record")
                && !commands.contains("wheelctl moza simulator-ffb-smoke"),
            "after 1% native actuator profile passes, guidance should advance only to visible-motion proof: {commands}"
        );

        write_test_json_file(
            &dir.path().join("native-actuator-visible-smoke.json"),
            &failed_native_actuator_visible_smoke_receipt(dir.path(), product_ids::R5_V2),
        )?;
        let receipt = verify_bundle_dir(dir.path(), MozaBundleStage::SmokeReady);
        let commands = receipt.next_commands.join("\n");
        assert!(
            commands.contains("wheelctl moza receipt-template --kind visible-motion-follow-up")
                && commands.contains(NATIVE_VISIBLE_FOLLOW_UP_PLAN_FILE)
                && commands.contains("wheelctl moza pre-output-readiness")
                && !commands.contains("wheelctl moza actuator-visible-smoke")
                && !commands.contains("wheelctl telemetry record")
                && !commands.contains("wheelctl moza simulator-ffb-smoke"),
            "after a real visible-motion receipt fails, generated guidance must not rerun output automatically: {commands}"
        );
        write_test_json_file(
            &dir.path().join(NATIVE_VISIBLE_FOLLOW_UP_PLAN_FILE),
            &moza_receipt_template(MozaReceiptTemplateKind::VisibleMotionFollowUp),
        )?;
        let receipt = verify_bundle_dir(dir.path(), MozaBundleStage::SmokeReady);
        let commands = receipt.next_commands.join("\n");
        assert!(
            commands.contains("wheelctl moza pre-output-readiness")
                && !commands
                    .contains("wheelctl moza receipt-template --kind visible-motion-follow-up")
                && !commands.contains("wheelctl moza actuator-visible-smoke"),
            "after the follow-up plan template exists, generated guidance should not overwrite it: {commands}"
        );

        write_pre_output_ready_receipt(dir.path())?;
        let receipt = verify_bundle_dir(dir.path(), MozaBundleStage::SmokeReady);
        let commands = receipt.next_commands.join("\n");
        assert!(
            commands.contains("wheelctl moza receipt-template --kind controlled-angle-plan")
                && commands.contains(NATIVE_CONTROLLED_ANGLE_PLAN_FILE)
                && !commands.contains("wheelctl moza actuator-visible-smoke"),
            "after response-only visible-motion review and no-output readiness are both recorded, guidance should request the controlled-angle plan without output: {commands}"
        );

        write_test_json_file(
            &dir.path().join(NATIVE_CONTROLLED_ANGLE_PLAN_FILE),
            &moza_receipt_template(MozaReceiptTemplateKind::ControlledAnglePlan),
        )?;
        let receipt = verify_bundle_dir(dir.path(), MozaBundleStage::SmokeReady);
        let commands = receipt.next_commands.join("\n");
        assert!(
            commands.contains("wheelctl moza controlled-angle-smoke")
                && commands.contains("--dry-run")
                && commands.contains("--target-degrees 1")
                && commands.contains("--profile bounded-pidff-micro-step-v2")
                && commands.contains("--max-percent 5")
                && commands.contains("--timeout-ms 2000")
                && !commands.contains("wheelctl moza actuator-visible-smoke"),
            "after controlled-angle planning is recorded, guidance should allow only the no-output controlled-angle preflight: {commands}"
        );

        write_controlled_angle_dry_run_receipt(dir.path(), "hid-0x346E-0x0014-if2-0x0001-0x0004")?;
        let receipt = verify_bundle_dir(dir.path(), MozaBundleStage::SmokeReady);
        let commands = receipt.next_commands.join("\n");
        assert!(
            receipt.next_commands.is_empty()
                && !commands.contains("wheelctl moza authorize-controlled-angle-output")
                && !commands.contains(NATIVE_CONTROLLED_ANGLE_AUTHORIZATION_FILE)
                && !commands.contains("wheelctl moza controlled-angle-smoke")
                && !commands.contains("--confirm-controlled-angle"),
            "after response-only visible-motion review, no-output readiness, controlled-angle planning, and valid no-output preflight are recorded, verifier guidance must not generate an authorization or output command: {commands}"
        );
        let action_text = receipt.operator_actions.join("\n");
        assert!(
            action_text.contains("controlled_angle_plan_artifact=present_no_output")
                && action_text.contains("controlled_angle_no_output_ok=true")
                && action_text.contains("controlled_angle_ladder_ok=true")
                && action_text.contains("controlled_angle_preflight_artifact=present_no_output")
                && action_text.contains("controlled_angle_preflight_no_output_ok=true")
                && action_text.contains("controlled_angle_motion_unclaimed=true")
                && action_text.contains("wheelctl moza authorize-controlled-angle-output")
                && action_text.contains(NATIVE_CONTROLLED_ANGLE_AUTHORIZATION_FILE)
                && !action_text.contains("wheelctl moza authorize-visible-output"),
            "operator action should report the checked-in controlled-angle plan and preflight artifacts accurately and point at controlled-angle authorization: {action_text}"
        );
        let followup_commands = receipt
            .blocked_safe_followups
            .iter()
            .flat_map(|followup| followup.commands.iter())
            .cloned()
            .collect::<Vec<_>>()
            .join("\n");
        assert!(
            followup_commands.contains("wheelctl moza pit-house-availability")
                && followup_commands.contains("wheelctl telemetry record")
                && followup_commands.contains("wheelctl moza simulator-telemetry-proof")
                && !followup_commands.contains("wheelctl moza pit-house-observation")
                && !followup_commands.contains("wheelctl moza actuator-visible-smoke")
                && !followup_commands.contains("wheelctl moza simulator-ffb-smoke")
                && !followup_commands.contains("wheelctl moza pit-house-proof"),
            "blocked safe follow-ups should start with no-output Pit House availability and telemetry work: {followup_commands}"
        );
        write_test_json_file(
            &dir.path().join("pit-house-availability.json"),
            &pit_house_availability_receipt_available(),
        )?;
        let receipt = verify_bundle_dir(dir.path(), MozaBundleStage::SmokeReady);
        let followup_commands = receipt
            .blocked_safe_followups
            .iter()
            .flat_map(|followup| followup.commands.iter())
            .cloned()
            .collect::<Vec<_>>()
            .join("\n");
        assert!(
            followup_commands.contains("wheelctl moza pit-house-observation --case open-standard")
                && followup_commands
                    .contains("wheelctl moza pit-house-evidence --case open-standard")
                && followup_commands.contains("--require-match")
                && followup_commands.contains("wheelctl telemetry record")
                && !followup_commands.contains("wheelctl moza pit-house-proof"),
            "available Pit House follow-ups should expose only no-output pre-mode-change observations and telemetry: {followup_commands}"
        );
        assert!(
            receipt.blocked_safe_followups.iter().all(|followup| {
                !followup.hardware_output_enabled
                    && followup.no_hid_device_opened
                    && followup.no_ffb_writes
            }),
            "blocked safe follow-ups must remain no-output: {:?}",
            receipt.blocked_safe_followups
        );

        write_test_json_file(
            &dir.path().join("native-actuator-visible-smoke.json"),
            &native_actuator_visible_smoke_receipt(dir.path(), product_ids::R5_V2),
        )?;
        let receipt = verify_bundle_dir(dir.path(), MozaBundleStage::SmokeReady);
        let commands = receipt.next_commands.join("\n");
        assert!(
            receipt.blocked_safe_followups.is_empty(),
            "safe follow-ups should clear once visible motion passes"
        );
        assert!(
            commands.contains("wheelctl telemetry record")
                && commands.contains("--session-id")
                && commands.contains("simhub-bridge-")
                && commands.contains("wheelctl moza simulator-telemetry-proof")
                && !commands.contains("wheelctl moza simulator-ffb-smoke"),
            "after visible-motion proof passes, guidance should advance only to telemetry: {commands}"
        );

        write_simulator_artifacts(dir.path())?;
        let receipt = verify_bundle_dir(dir.path(), MozaBundleStage::SmokeReady);
        let commands_vec = receipt.next_commands;
        let commands = commands_vec.join("\n");
        let canonical_writer = commands_vec
            .iter()
            .position(|command| command.starts_with("wheeld --hardware-lane "))
            .ok_or("expected lane-bound simulator writer command")?;
        let ffb_smoke = commands_vec
            .iter()
            .position(|command| command.contains("wheelctl moza simulator-ffb-smoke"))
            .ok_or("expected simulator FFB smoke command")?;
        assert!(
            canonical_writer < ffb_smoke && !commands.contains("wheelctl moza pit-house-proof"),
            "after telemetry passes, guidance should advance only to simulator FFB smoke: {commands}"
        );

        write_test_json_file(
            &dir.path().join("simulator-ffb-smoke.json"),
            &simulator_ffb_receipt(),
        )?;
        let receipt = verify_bundle_dir(dir.path(), MozaBundleStage::SmokeReady);
        let commands = &receipt.next_commands;
        let index = |needle: &str| -> Result<usize, &'static str> {
            commands
                .iter()
                .position(|command| command.contains(needle))
                .ok_or("expected command not found")
        };
        let mode_change_observation =
            index("wheelctl moza pit-house-observation --case mode-change")?;
        let mode_change_case = commands
            .iter()
            .position(|command| {
                command.contains("wheelctl moza pit-house-case")
                    && command.contains("--case mode-change")
            })
            .ok_or("expected mode-change Pit House case command")?;
        let pit_house_proof = index("wheelctl moza pit-house-proof")?;
        let smoke_verification = index("--stage smoke-ready")?;
        assert!(
            mode_change_observation < mode_change_case,
            "mode-change Pit House case must run after its observation"
        );
        assert!(
            mode_change_case < pit_house_proof,
            "Pit House proof must run after the mode-change case"
        );
        assert!(
            pit_house_proof < smoke_verification,
            "smoke-ready verification must run after Pit House proof"
        );
        assert!(
            commands
                .iter()
                .all(|command| !command.contains("wheelctl moza torque-test")
                    && !command.contains("wheelctl moza simulator-ffb-smoke")),
            "Pit House frontier guidance must not repeat completed low-torque or simulator FFB commands: {commands:?}"
        );

        let observation_commands = commands
            .iter()
            .filter(|command| command.contains("wheelctl moza pit-house-observation"))
            .count();
        assert_eq!(observation_commands, 5);
        assert!(
            commands
                .iter()
                .filter(|command| command.contains("wheelctl moza pit-house-observation"))
                .all(|command| command.contains("--evidence-artifact pit-house-evidence-")),
            "every Pit House observation next_command must include a verifier-required evidence artifact"
        );
        let joined = commands.join("\n").replace('\\', "/");
        for artifact in [
            "pit-house-observation-closed.json",
            "pit-house-closed.json",
            "pit-house-direct-blocked.json",
            "pit-house-observation-mode-change.json",
            "pit-house-mode-change.json",
            "pit-house-firmware-page.json",
        ] {
            assert!(
                joined.contains(artifact),
                "smoke-ready next_commands should use documented Pit House artifact name {artifact}: {joined}"
            );
        }
        for stale_artifact in [
            "pit-house-closed-observation.json",
            "pit-house-closed-case.json",
            "pit-house-open-direct-case.json",
            "pit-house-firmware-page-case.json",
        ] {
            assert!(
                !joined.contains(stale_artifact),
                "smoke-ready next_commands should not use stale Pit House artifact name {stale_artifact}: {joined}"
            );
        }
        Ok(())
    }

    #[test]
    fn verify_bundle_smoke_pit_house_guidance_skips_completed_subcases() -> TestResult {
        let dir = tempfile::tempdir()?;
        write_smoke_ready_bundle(dir.path())?;
        fs::remove_file(dir.path().join("pit-house-coexistence.json"))?;
        for artifact in [
            "pit-house-evidence-open_idle_standard.json",
            "pit-house-observation-open-standard.json",
            "pit-house-open-standard.json",
            "pit-house-evidence-open_direct.json",
            "pit-house-observation-open-direct.json",
            "pit-house-direct-blocked.json",
            "pit-house-evidence-mode_change_during_run.json",
            "pit-house-observation-mode-change.json",
            "pit-house-mode-change.json",
            "pit-house-evidence-firmware_update_page_open.json",
            "pit-house-observation-firmware-page.json",
            "pit-house-firmware-page.json",
        ] {
            fs::remove_file(dir.path().join(artifact))?;
        }
        write_test_json_file(
            &dir.path().join("pit-house-availability.json"),
            &pit_house_availability_receipt_available(),
        )?;

        let receipt = verify_bundle_dir(dir.path(), MozaBundleStage::SmokeReady);
        let commands = receipt.next_commands.join("\n");

        assert!(
            !commands.contains("wheelctl moza pit-house-observation --case closed")
                && !receipt.next_commands.iter().any(|command| {
                    command.contains("wheelctl moza pit-house-case")
                        && command.contains("--case closed")
                }),
            "completed closed Pit House subcase should not be regenerated: {commands}"
        );
        assert!(
            !commands.contains("pit-house-evidence-closed.json")
                && !commands.contains("pit-house-observation-closed.json"),
            "completed closed Pit House observation should not be repeated: {commands}"
        );
        for expected in [
            "wheelctl moza pit-house-observation --case open-standard",
            "wheelctl moza pit-house-case",
            "--case open-standard",
            "wheelctl moza pit-house-observation --case mode-change",
            "--case mode-change",
            "wheelctl moza pit-house-proof",
        ] {
            assert!(
                commands.contains(expected),
                "missing Pit House frontier command {expected}: {commands}"
            );
        }
        let observation_commands = receipt
            .next_commands
            .iter()
            .filter(|command| command.contains("wheelctl moza pit-house-observation"))
            .count();
        assert_eq!(observation_commands, 4);
        Ok(())
    }

    #[test]
    fn pit_house_observation_guidance_refreshes_mismatched_evidence() -> TestResult {
        let dir = tempfile::tempdir()?;
        write_test_json_file(
            &dir.path().join("pit-house-evidence-open-standard.json"),
            &serde_json::json!({
                "success": true,
                "command": "wheelctl moza pit-house-evidence",
                "case": "pit_house_open_idle_standard",
                "evidence_kind": "process_window_snapshot",
                "pit_house_process_visible": false,
                "snapshot_matches_case": false,
                "no_hid_device_opened": true,
                "no_ffb_writes": true,
                "no_serial_config_commands": true,
                "no_firmware_or_dfu_commands": true
            }),
        )?;

        let mut commands = Vec::new();
        push_pit_house_observation_next_command(
            dir.path(),
            &mut commands,
            "open-standard",
            "pit-house-evidence-open-standard.json",
            "pit-house-observation-open-standard.json",
            "Pit House open and idle; standard mode observed",
        );
        let joined = commands.join("\n");

        assert!(
            commands.first().is_some_and(|command| command
                .contains("wheelctl moza pit-house-evidence")
                && command.contains("--require-match")),
            "mismatched generated Pit House evidence must be regenerated before observation: {joined}"
        );
        assert!(
            commands
                .get(1)
                .is_some_and(|command| command.contains("wheelctl moza pit-house-observation")),
            "open-standard observation should still follow evidence refresh: {joined}"
        );

        write_test_json_file(
            &dir.path().join("pit-house-evidence-open-standard.json"),
            &serde_json::json!({
                "success": true,
                "command": "wheelctl moza pit-house-evidence",
                "case": "pit_house_open_idle_standard",
                "evidence_kind": "process_window_snapshot",
                "pit_house_process_visible": true,
                "snapshot_matches_case": true,
                "no_hid_device_opened": true,
                "no_ffb_writes": true,
                "no_serial_config_commands": true,
                "no_firmware_or_dfu_commands": true
            }),
        )?;
        commands.clear();
        push_pit_house_observation_next_command(
            dir.path(),
            &mut commands,
            "open-standard",
            "pit-house-evidence-open-standard.json",
            "pit-house-observation-open-standard.json",
            "Pit House open and idle; standard mode observed",
        );
        let joined = commands.join("\n");
        assert!(
            !joined.contains("wheelctl moza pit-house-evidence"),
            "matching generated evidence should not be regenerated: {joined}"
        );
        assert!(
            joined.contains("wheelctl moza pit-house-observation --case open-standard"),
            "matching generated evidence should still allow observation guidance: {joined}"
        );
        Ok(())
    }

