    #[test]
    fn input_role_requirements_promote_brake_hbp_semantic_axes_only() -> TestResult {
        fn varied_axis(min: u16, max: u16) -> AxisRange {
            AxisRange {
                min: Some(min),
                max: Some(max),
            }
        }

        fn requirement(path: &str) -> TestResult<&'static PassiveCaptureRequirement> {
            passive_capture_requirements()
                .iter()
                .find(|requirement| requirement.relative_path == path)
                .ok_or_else(|| format!("missing requirement for {path}").into())
        }

        fn analysis_entry(
            capture: &str,
            moving_required_axes: Vec<String>,
        ) -> LaneCaptureAnalysisEntry {
            LaneCaptureAnalysisEntry {
                capture: capture.to_string(),
                fixture_id: capture.replace("captures/", "").replace(".jsonl", ""),
                success: true,
                total_reports: 2,
                decoded_reports: 2,
                rejected_reports: 0,
                moving_bytes: Vec::new(),
                unique_moving_bytes_vs_idle: Vec::new(),
                moving_words_le: Vec::new(),
                unique_moving_words_le_vs_idle: Vec::new(),
                moving_required_axes,
                control_evidence_ok: true,
                missing_requirements: Vec::new(),
            }
        }

        let mut brake_ranges = BTreeMap::new();
        brake_ranges.insert("brake_u16".to_string(), varied_axis(33, 65435));
        brake_ranges.insert(
            "r5_v1_extended_axis0_u16".to_string(),
            varied_axis(33, 65435),
        );
        let brake_axes = moving_required_axes(
            requirement("captures/r5-brake-only-sweep.jsonl")?,
            &brake_ranges,
        );
        assert_eq!(brake_axes, vec!["brake_u16".to_string()]);

        let mut handbrake_ranges = BTreeMap::new();
        handbrake_ranges.insert("handbrake_u16".to_string(), varied_axis(191, 65232));
        handbrake_ranges.insert(
            "r5_v1_extended_axis1_u16".to_string(),
            varied_axis(191, 65232),
        );
        handbrake_ranges.insert("r5_v1_extended_aux0_u16".to_string(), varied_axis(0, 65358));
        handbrake_ranges.insert("r5_v1_extended_aux1_u16".to_string(), varied_axis(0, 49057));
        let handbrake_axes = moving_required_axes(
            requirement("captures/r5-handbrake-only-sweep.jsonl")?,
            &handbrake_ranges,
        );
        assert_eq!(handbrake_axes, vec!["handbrake_u16".to_string()]);

        let mut clutch_ranges = BTreeMap::new();
        clutch_ranges.insert("r5_v1_extended_aux0_u16".to_string(), varied_axis(0, 62092));
        clutch_ranges.insert("r5_v1_extended_aux1_u16".to_string(), varied_axis(0, 48959));
        let clutch_axes = moving_required_axes(
            requirement("captures/r5-clutch-only-sweep.jsonl")?,
            &clutch_ranges,
        );
        assert_eq!(
            clutch_axes,
            vec![
                "r5_v1_extended_aux0_u16".to_string(),
                "r5_v1_extended_aux1_u16".to_string()
            ]
        );

        let mut notes = Vec::new();
        assert_eq!(
            role_semantic_status(
                true,
                Some(&analysis_entry(
                    "captures/r5-brake-only-sweep.jsonl",
                    brake_axes
                )),
                &mut notes
            ),
            "proven"
        );
        assert!(
            notes.is_empty(),
            "semantic brake evidence should not leave generic notes: {notes:?}"
        );

        let mut notes = Vec::new();
        assert_eq!(
            role_semantic_status(
                true,
                Some(&analysis_entry(
                    "captures/r5-handbrake-only-sweep.jsonl",
                    handbrake_axes
                )),
                &mut notes
            ),
            "proven"
        );
        assert!(
            notes.is_empty(),
            "semantic handbrake evidence should not leave generic notes: {notes:?}"
        );

        let mut notes = Vec::new();
        assert_eq!(
            role_semantic_status(
                true,
                Some(&analysis_entry(
                    "captures/r5-clutch-only-sweep.jsonl",
                    clutch_axes
                )),
                &mut notes
            ),
            "generic_aux"
        );
        assert!(
            notes
                .iter()
                .any(|note| note.contains("semantic control naming remains unproven")),
            "clutch should remain generic_aux: {notes:?}"
        );
        Ok(())
    }

    #[test]
    fn input_role_candidates_keep_shared_extended_axes_diagnostic_only() -> TestResult {
        let roles = vec![
            serde_json::json!({
                "control": "clutch",
                "role": "clutch",
                "moving_required_axes": ["r5_v1_extended_aux0_u16"]
            }),
            serde_json::json!({
                "control": "handbrake",
                "role": "handbrake",
                "moving_required_axes": ["r5_v1_extended_aux0_u16", "r5_v1_extended_axis1_u16"]
            }),
        ];
        let axis_controls = candidate_axis_controls_for_role_values(&roles);
        let clutch_candidates = semantic_candidate_values_for_role(
            "clutch",
            "clutch",
            Some("captures/r5-clutch-only-sweep.jsonl"),
            &["r5_v1_extended_aux0_u16".to_string()],
            &axis_controls,
        );
        let handbrake_candidates = semantic_candidate_values_for_role(
            "handbrake",
            "handbrake",
            Some("captures/r5-handbrake-only-sweep.jsonl"),
            &[
                "r5_v1_extended_aux0_u16".to_string(),
                "r5_v1_extended_axis1_u16".to_string(),
            ],
            &axis_controls,
        );

        let clutch_aux = clutch_candidates
            .iter()
            .find(|candidate| json_string(candidate, "axis") == Some("r5_v1_extended_aux0_u16"))
            .ok_or("expected clutch aux0 candidate")?;
        assert_eq!(
            json_string(clutch_aux, "confidence"),
            Some("ambiguous_candidate")
        );
        assert_eq!(
            json_string(clutch_aux, "claim_status"),
            Some("candidate_only")
        );
        assert_eq!(json_bool(clutch_aux, "readiness_claim"), Some(false));
        let ambiguous_with = clutch_aux
            .get("ambiguous_with_controls")
            .and_then(Value::as_array)
            .ok_or("expected ambiguous controls")?;
        assert!(
            ambiguous_with
                .iter()
                .any(|control| control.as_str() == Some("handbrake")),
            "expected clutch aux0 candidate to name handbrake ambiguity: {ambiguous_with:?}"
        );

        let handbrake_axis = handbrake_candidates
            .iter()
            .find(|candidate| json_string(candidate, "axis") == Some("r5_v1_extended_axis1_u16"))
            .ok_or("expected handbrake axis1 candidate")?;
        assert_eq!(
            json_string(handbrake_axis, "confidence"),
            Some("isolated_candidate")
        );
        assert_eq!(json_bool(handbrake_axis, "readiness_claim"), Some(false));
        Ok(())
    }

    #[test]
    fn sync_role_status_updates_manifest_from_lane_analysis() -> TestResult {
        let dir = tempfile::tempdir()?;
        write_minimal_passive_bundle(dir.path())?;
        write_text_file(
            &dir.path().join("captures/r5-throttle-only-sweep.jsonl"),
            &format!(
                "{}\n{}",
                capture_line(
                    product_ids::R5_V1,
                    &live_r5_v1_trailer_report_hex([0x00, 0x00, 0x00, 0x00])
                ),
                capture_line(
                    product_ids::R5_V1,
                    &live_r5_v1_trailer_report_hex([0xFF, 0xAA, 0x55, 0x40])
                )
            ),
        )?;

        let stale_check = sync_role_status_receipt(dir.path(), true)?;
        assert_eq!(json_bool(&stale_check, "success"), Some(false));
        assert!(
            json_u64(&stale_check, "stale_control_count").ok_or("missing stale control count")? > 0
        );

        let receipt = sync_role_status_receipt(dir.path(), false)?;
        assert_eq!(json_bool(&receipt, "success"), Some(true));
        assert_eq!(json_bool(&receipt, "manifest_written"), Some(true));
        assert_eq!(json_bool(&receipt, "lane_analysis_success"), Some(false));

        let manifest = read_json_path(&dir.path().join("manifest.json"))?;
        assert_eq!(
            json_string(
                manifest
                    .pointer("/topology/logical_controls/steering")
                    .ok_or("missing steering control")?,
                "semantic_status"
            ),
            Some("proven")
        );
        assert_eq!(
            json_string(
                manifest
                    .pointer("/topology/logical_controls/throttle")
                    .ok_or("missing throttle control")?,
                "semantic_status"
            ),
            Some("missing")
        );

        let fresh_check = sync_role_status_receipt(dir.path(), true)?;
        assert_eq!(json_bool(&fresh_check, "success"), Some(true));
        assert_eq!(json_u64(&fresh_check, "stale_control_count"), Some(0));
        assert_eq!(json_bool(&fresh_check, "artifact_map_changed"), Some(false));
        assert_eq!(json_bool(&fresh_check, "manifest_written"), Some(false));
        Ok(())
    }

    #[test]
    fn sync_role_status_refreshes_manifest_artifact_contract() -> TestResult {
        let dir = tempfile::tempdir()?;
        write_minimal_passive_bundle(dir.path())?;
        sync_role_status_receipt(dir.path(), false)?;

        let mut manifest = read_json_path(&dir.path().join("manifest.json"))?;
        manifest["artifacts"]
            .as_object_mut()
            .ok_or("expected artifacts map")?
            .remove("hardware_doctor");
        write_test_json_file(&dir.path().join("manifest.json"), &manifest)?;

        let stale_check = sync_role_status_receipt(dir.path(), true)?;
        assert_eq!(json_bool(&stale_check, "success"), Some(false));
        assert_eq!(json_bool(&stale_check, "artifact_map_changed"), Some(true));
        assert_eq!(json_u64(&stale_check, "stale_control_count"), Some(0));

        let receipt = sync_role_status_receipt(dir.path(), false)?;
        assert_eq!(json_bool(&receipt, "success"), Some(true));
        assert_eq!(json_bool(&receipt, "manifest_written"), Some(true));
        assert_eq!(json_bool(&receipt, "artifact_map_changed"), Some(true));

        let refreshed = read_json_path(&dir.path().join("manifest.json"))?;
        assert_eq!(
            json_string(
                refreshed
                    .get("artifacts")
                    .ok_or("missing artifacts map after refresh")?,
                "hardware_doctor"
            ),
            Some("hardware-doctor.json")
        );
        Ok(())
    }

